import { useGlobalState } from "../state/GlobalState";
import { SendNotification } from "engine/src/system/Notification";
import { useCallback, useEffect, useState } from "react";
import { HandleActions } from "engine/src/system/ActionExecutor";

const TextsComponent = () => {
    const { phoneState } = useGlobalState();

    const [currentConversation] = phoneState.currentTextConversation;
    const [openMessages] = phoneState.openMessages;

    const [, setConversations] = phoneState.textConversations;
    const [, setOptions] = phoneState.textMessageOptions;

    const [loadedConversations, setLoadedConversations] =
        phoneState.loadedTextConversations;
    const [unreadMessages, setUnreadMessages] = phoneState.unreadMessages;
    const [existingConvos, setExistingConvos] =
        phoneState.existingTextConversations;

    const [queueState, setQueueState] = useState<number>(-1);

    useEffect(() => {
        if (currentConversation !== -1) {
            if (!existingConvos.includes(currentConversation)) {
                const conversation = loadedConversations[currentConversation];

                setExistingConvos((val) => [...val, currentConversation]);

                setConversations((val) => [
                    ...val,
                    {
                        from: conversation.dialog.from,
                        avatar: conversation.dialog.avatar,
                        messages: [],
                    },
                ]);
            }

            setTimeout(() => {
                StartQueue();
            }, 2000);
        }
        // eslint-disable-next-line
    }, [
        currentConversation,
        loadedConversations,
        existingConvos,
        openMessages,
    ]);

    useEffect(() => {
        if (queueState !== -1) {
            if (currentConversation === -1) {
                setQueueState(-1);
                return;
            }

            SendMessage();

            setTimeout(() => {
                setQueueState((val) => {
                    if (val !== -1) {
                        return val + 1;
                    }
                    return val;
                });
            }, 2000);
        }
        // eslint-disable-next-line
    }, [queueState]);

    const StartQueue = () => {
        setQueueState((val) => {
            if (val === -1) {
                const convo = loadedConversations[currentConversation];
                if (convo.lastHandled >= convo.dialog.messages.length) {
                    return val;
                }
                return val + 1;
            }
            return val;
        });
    };

    const SendMessage = useCallback(() => {
        const convo = loadedConversations[currentConversation];

        if (!convo) return;

        if (convo.lastHandled >= convo.dialog.messages.length) {
            setQueueState(-1);
        } else {
            const message = convo.dialog.messages[convo.lastHandled];

            if (openMessages.index !== currentConversation) {
                if (message.source === "you") {
                    setQueueState(-1);
                    return;
                }
            }

            setConversations((val) => {
                return [
                    ...val.map((textConvo) => {
                        if (textConvo.from === convo.dialog.from) {
                            return {
                                ...textConvo,
                                messages: [
                                    ...textConvo.messages,
                                    {
                                        from: message.source,
                                        message: message.message,
                                    },
                                ],
                            };
                        }
                        return textConvo;
                    }),
                ];
            });

            setLoadedConversations((val) => {
                return [
                    ...val.map((convo, index) => {
                        if (index === currentConversation) {
                            return {
                                ...convo,
                                lastHandled: convo.lastHandled + 1,
                            };
                        }
                        return convo;
                    }),
                ];
            });

            if (openMessages.index !== currentConversation) {
                if (!unreadMessages.includes(currentConversation)) {
                    setUnreadMessages((val) => [...val, currentConversation]);

                    SendNotification({
                        type: "regular",
                        title: "New Text Message",
                        description: `You've received a new text message from ${convo.dialog.from}`,
                        color: "lime",
                        sound: "text",
                    });
                }
            } else {
                if (unreadMessages.includes(currentConversation)) {
                    setUnreadMessages((val) => {
                        return val.filter((i) => i !== currentConversation);
                    });
                }
            }

            if (message.type === "option") {
                setOptions({
                    messageName: convo.dialog.from,
                    options: message.options,
                });
            } else if (message.type === "action") {
                HandleActions(message.actions);
            }
        }
        // eslint-disable-next-line
    }, [
        currentConversation,
        loadedConversations,
        openMessages,
        unreadMessages,
    ]);

    return <></>;
};

export default TextsComponent;
