import { BaseGlobalState } from "engine/src/state/GlobalState";
import { Flag } from "../types/Flag";
import { SendFlagSet } from "./BackendSystem";

const listeners: Record<string, Array<() => void>> = {};

const Flags = {
    /**
     * Check if a flag has been set
     */
    checkFlag: (flag: string) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [unlockedFlags] = coreState.unlockedFlags;
        return unlockedFlags.find((flagObj) => flagObj === flag);
    },
    /**
     * Check all flags have been set
     */
    checkFlags: (flags: string[]) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [unlockedFlags] = coreState.unlockedFlags;

        for (const flag of flags) {
            if (!unlockedFlags.includes(flag)) return false;
        }
        return true;
    },
    checkFlagsOr: (flags: string[]) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [unlockedFlags] = coreState.unlockedFlags;

        for (const flag of flags) {
            if (unlockedFlags.includes(flag)) return true;
        }
        return false;
    },
    /**
     * Set a flag
     */
    setOrUnsetFlag: (newFlags: Flag[]) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [, setUnlockedFlags] = coreState.unlockedFlags;

        const addFlags = newFlags
            .filter((flag) => flag.flag_action === "give")
            .map((flag) => flag.flag_name);
        const removeFlags = newFlags
            .filter((flag) => flag.flag_action === "revoke")
            .map((flag) => flag.flag_name);

        setUnlockedFlags((flags) => {
            const addedFlags = [
                ...flags,
                ...addFlags.filter((flag) => !flags.includes(flag)),
            ];

            const newFlags = addedFlags.filter((f) => !removeFlags.includes(f));

            return newFlags;
        });

        for(const flag of newFlags) {
            SendFlagSet(flag.flag_name, coreState.appEnabled[1]);
        }
    },

    addListener: (flag: string, callback: () => void) => {
        if (Flags.checkFlag(flag)) {
            callback();
            return;
        }
        if (!listeners[flag]) listeners[flag] = [];
        listeners[flag].push(callback);
    },

    handleFlagChanged: (flag: string) => {
        if (listeners[flag]) {
            listeners[flag].forEach((listener) => listener());
            delete listeners[flag];
        }
    }
};

export default Flags;
