import { AppRegistry } from "engine/src/components/Phone";
import { PopupRegistry } from "engine/src/components/Popup";
import { CoreState, SettingsState } from "engine/src/state/GlobalState";
import {
    GameState,
    GlobalState,
    PhoneState,
    PlayerState,
} from "../state/GlobalState";
import { ParticipantSettings } from "../system/ParticipantSettings";
import { Activity } from "../types/Activity";
import { Minigame } from "../types/Minigame";
import { AchievementsApp } from "./apps/AchievementsApp";
import { DebugApp } from "./apps/DebugApp";
import { DictionaryComponent } from "./apps/Dictionary";
import { EmailApp } from "./apps/EmailApp";
import { JournalComponent } from "./apps/JournalApp";
import { MapComponent } from "./apps/MapApp";
import { SettingsApp } from "./apps/SettingsApp";
import { TextAppComponent } from "./apps/TextApp";
import { TodoApp } from "./apps/TodoApp";
import { BrowserComponent } from "./apps/Browser";

export const createAppRegistry = (
    coreState: CoreState<Activity, Minigame>,
    settingsState: SettingsState<ParticipantSettings>,
    gameState: GameState,
    playerState: PlayerState,
    phoneState: PhoneState,
    participantSettings: ParticipantSettings,
    popupRegistry: PopupRegistry
) => {
    const appRegistry: AppRegistry = {
        todo: {
            element: TodoApp,
            name: "todo",
            icon: "assets/images/elements/phone-icons/todo.svg",
            color: "linear-gradient(#f6d365, #fcb045)",
            notificationCount: () => {
                const state = GlobalState.getInstance();
                const todoList = state.playerState[0].todoList[0];
                let count = 0;
                count += todoList.story.filter(
                    (item: { complete: boolean; failed?: boolean }) =>
                        !item.complete && !item.failed
                ).length;
                count += todoList.optional.filter(
                    (item: { complete: boolean; failed?: boolean }) =>
                        !item.complete && !item.failed
                ).length;
                return count;
            },
        },
        mail: {
            element: EmailApp,
            name: "mail",
            icon: "assets/images/elements/phone-icons/mail.svg",
            color: "linear-gradient(#ff512f, #dd2476)",
            notificationCount: () => {
                const state = GlobalState.getInstance();
                let count = 0;
                state.phoneState[0].emails[0].forEach(
                    (_, index) =>
                        (count += phoneState.repliedEmails[0].includes(index)
                            ? 0
                            : 1)
                );
                return count;
            },
        },
        map: {
            element: MapComponent,
            name: "map",
            icon: "assets/images/elements/phone-icons/map.svg",
            color: "linear-gradient(#4ca1af, #c4e0e5)",
        },
        messages: {
            element: TextAppComponent,
            name: "messages",
            icon: "assets/images/elements/phone-icons/message.svg",
            color: "linear-gradient(#56ab2f, #a8e063)",
            notificationCount: () => {
                const state = GlobalState.getInstance();
                return state.phoneState[0].unreadMessages[0].length;
            },
        },
        journal: {
            element: JournalComponent,
            name: "journal",
            icon: "assets/images/elements/phone-icons/journal.svg",
            color: "linear-gradient(#de6262, #ffb88c)",
        },
        dictionary: {
            element: DictionaryComponent,
            name: "dictionary",
            icon: "assets/images/elements/phone-icons/dictionary.svg",
            color: "linear-gradient(#eacda3, #d6ae7b)",
        },
        achievements: {
            element: AchievementsApp,
            name: "achievements",
            icon: "assets/images/elements/phone-icons/achievements.svg",
            color: "linear-gradient(#a18cd1, #fbc2eb)",
        },
        settings: {
            element: SettingsApp,
            name: "settings",
            icon: "assets/images/elements/phone-icons/settings.svg",
            color: "linear-gradient(#bdc3c7, #2c3e50)",
        },
        browser: {
            element: BrowserComponent,
            name: "browser",
            icon: "assets/images/elements/phone-icons/browser.svg",
            color: "linear-gradient(#F7AD0D, #ffe86c)",
        },
    };

    if (participantSettings.DebugEnabled) {
        appRegistry.debug = {
            element: DebugApp,
            name: "debug",
            icon: "assets/images/elements/phone-icons/debug.svg",
            color: "linear-gradient(#bdc3c7, #2c3e50)",
        };
    }

    return appRegistry;
};

export const wallpapers = [
    "assets/images/elements/wallpaper1.png",
    "assets/images/elements/wallpaper2.png",
    "assets/images/elements/wallpaper3.png",
    "assets/images/elements/wallpaper4.png",
];
