import { useGlobalState } from "../../state/GlobalState";
import styles from "#styles/popup/Preamble.module.css";
import { LoadDialog } from "engine/src/system/DataLoader";
import { join } from "engine/src/system/Styles";

const Preamble = () => {
    const { coreState, settingsState } = useGlobalState();

    const setPopup = coreState.popup[1];
    const [participantSettings] = settingsState.participantSettings;
    const setScene = coreState.scene[1];
    const setPhoneOpen = coreState.phoneOpen[1];

    const [, setNotificationQueue] = coreState.notificationQueue;

    const continueToGame = () => {
        if (participantSettings.EnableKbControls) {
            setPopup("controls");
        } else {
            setPopup(null);
            coreState.transitioning[1](true);
            setTimeout(() => {
                LoadDialog("home/opening/1a").then((dialog) => {
                    coreState.dialog[1](dialog);
                    coreState.transitioning[1](false);
                });
            }, 1000);
        }
    };

    return (
        <div className={join(styles, "container")}>
            <h1>Welcome to GEARS</h1>
            <p>
                You're about to begin an interactive journey designed to help
                you explore, prepare, and plan for postsecondary. In this game,
                you'll collect information and uncover resources to guide your
                next steps toward college, university, trades, or other
                postsecondary pathways.
            </p>
            <p>
                This game has 6 chapters. Each chapter focuses on a key stage of
                your postsecondary planning journey—from understanding your
                unique learning needs to budgeting and managing challenges.
            </p>
            <p>
                As you move through the chapters, you'll gather information
                resources that can be saved and printed off later as your
                personalized Postsecondary Resource Guide.{" "}
            </p>
            <p>
                You can save your progress at any time and continue later—your
                journey continues where you left off. There are no wrong answers
                here. The goal is to help you feel more confident and prepared
                for what comes next.
            </p>
            <p>Your journey starts now.</p>
            <button onClick={continueToGame}>Continue</button>
        </div>
    );
};

export default Preamble;
