import { Fragment, useEffect, useRef, useState } from "react";
import { GlobalState, useGlobalState } from "../../state/GlobalState";
import styles from "#styles/popup/Credits.module.css";
import { join } from "engine/src/system/Styles";
import Flags from "engine/src/system/Flags";
import { LoadCredits } from "../../system/DataLoader";
import { Credits } from "../../types/Credits";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { useKeyDown } from "engine/src/system/Keyboard";

/**
 * The Credits popup
 */
const CreditsComponent = () => {
    const { coreState, playerState, gameState, phoneState, settingsState } =
        useGlobalState();

    const [, setPopup] = coreState.popup;
    const [keybinds] = settingsState.keybinds;

    const ref = useRef<HTMLDivElement>(null);

    const [content, setContent] = useState<Credits>();

    useEffect(() => {
        PlayAudio(`music/credits.mp3`, "music", true);

        LoadCredits("credits").then((credits) => {
            setContent(credits);
        });
    }, [coreState.popup]);

    useEffect(() => {
        let animationProgress = 0;
        const a = setInterval(() => {
            if (!ref.current) return;
            ref.current.style.transform = `translateY(calc(100vh - ${((ref.current.clientHeight + window.innerHeight * 0.7) * animationProgress) / 100}px))`;
            animationProgress += 0.025;
            if (animationProgress >= 100) animationProgress = 0;
        }, 10);

        return () => clearInterval(a);
    }, [ref, coreState.popup]);

    // Function to handle the credits fading out
    const handleFadeOut = () => {
        // Add the fade-out class to the credits background
        document
            .getElementById("credits-background")
            ?.classList.add(join(styles, "fade-out").trim());
    };

    // Function to handle returning to the main menu
    const returnToMainMenu = () => {
        handleFadeOut();

        if (Flags.checkFlag("save_after_credits")) {
            Flags.setOrUnsetFlag([
                {
                    flag_name: "save_after_credits",
                    flag_action: "revoke",
                },
            ]);
            setTimeout(() => {
                setPopup("saveGame");
            }, 1000); // Set the timeout value to match the duration of the fade-out animation (1s)
        } else {
            setTimeout(() => {
                GlobalState.getInstance().resetState(
                    coreState,
                    playerState,
                    gameState,
                    phoneState,
                    settingsState
                );
                setPopup("titleScreen");
            }, 1000); // Set the timeout value to match the duration of the fade-out animation (1s)
        }
    };

    useKeyDown(keybinds.General.Back, returnToMainMenu);

    return (
        <div
            id="credits-background"
            className={join(styles, "credits-background", "fade-in")}
        >
            <div className={join(styles, "header-layout")}>
                <button onClick={returnToMainMenu}>&larr;</button>
                <img src="assets/images/elements/Logo.png" alt="logo" />
            </div>
            <div className={join(styles, "text-holder")} ref={ref}>
                <h1 key="title">{content?.title}</h1>
                {content?.sections.map((section) => {
                    return (
                        <Fragment key={section.heading}>
                            <h2>{section.heading}</h2>
                            {section.entries.map((entry) => {
                                return <p key={entry}>{entry}</p>;
                            })}
                        </Fragment>
                    );
                })}
            </div>
        </div>
    );
};

export default CreditsComponent;
