import { useEffect, useRef, useState } from "react";
import minigameStyles from "../../styles/minigames/MinigameComponent.module.css";
import documentStyles from "../../styles/popup/document.module.css";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { joinWithOverride } from "engine/src/system/Styles";
import { ReactState, useBaseGlobalState } from "../../state/GlobalState";
import { GenericMinigame } from "../../types/Minigame";

type MinigameRenderer<MinigameType extends GenericMinigame<string>, T extends MinigameType["type"]> = (props: {minigame: Extract<MinigameType, {type: T}>, state: any}) => React.ReactNode;

type MinigameRegistryEntry<MinigameType extends GenericMinigame<string>, T extends MinigameType["type"]> = {
    renderer: MinigameRenderer<MinigameType, T>,
    dataGenerator: any 
}

export type MinigameRegistry<MinigameType extends GenericMinigame<string>> = {
    [type in MinigameType["type"]]: MinigameRegistryEntry<MinigameType, type>
}

export function MinigameComponent<MinigameType extends GenericMinigame<string>>({minigameRegistry, documentStyleOverride, styleOverride}: {minigameRegistry: MinigameRegistry<MinigameType>, documentStyleOverride: any, styleOverride: any}) {
    const { coreState, settingsState } = useBaseGlobalState();

    const [minigame, setMinigame] = coreState.minigame as ReactState<MinigameType | null>;
    const [popup, setPopup] = coreState.popup;

    const [participantSettings] = settingsState.participantSettings;

    const minigameState = useState<any>(null);

    const pageRef = useRef<HTMLDivElement | null>(null);

    function skipMinigame() {
        setMinigame(null);
        setPopup(null);
    }

    useEffect(() => {
        if (minigame) {
            minigameState[1](minigameRegistry[minigame.type as keyof typeof minigameRegistry].dataGenerator);
            PlayAudio(`music/${minigame.music}`, "music", true);
        }
        // eslint-disable-next-line
    }, [popup, minigame, minigameState[1]]);

    useEffect(() => {
        pageRef.current?.focus();
        // eslint-disable-next-line
    }, [pageRef.current]);

    if (!minigame) return <></>;

    const minigameRenderers = Object.fromEntries(
        Object.entries(minigameRegistry as Record<string, {
            renderer: (props: {minigame: any, state: any}) => JSX.Element,
            dataGenerator: any
        }>).map(([id, mg]) => [id, [<mg.renderer state={minigameState} minigame={minigame}/>]])
    )

    return (
        <div className={joinWithOverride(documentStyles, documentStyleOverride, "document-wrapper")}>
            {participantSettings.EnableSkipMinigames && (
                <div className={joinWithOverride(minigameStyles, styleOverride, "debug-minigame-skip")}>
                    <button onClick={skipMinigame}>Skip Minigame</button>
                </div>
            )}
            <div
                className={
                    joinWithOverride(documentStyles, documentStyleOverride, "document") +
                    joinWithOverride(minigameStyles, styleOverride, "minigame") + 
                    "minigame"
                }
                ref={pageRef}
            >
                {minigameState[0] !== null &&
                    minigame !== undefined &&
                    minigameState[0].type === minigame.type &&
                    minigameRenderers[minigame.type]}
            </div>
        </div>
    );
}
