import { useKeyDown } from "engine/src/system/Keyboard";
import { useEffect, useRef, useState } from "react";
import styles from "../styles/NotificationComponent.module.css";
import Flags from "engine/src/system/Flags";
import { joinWithOverride } from "../system/Styles";
import { useBaseGlobalState } from "../state/GlobalState";
import { dialogClean } from "../system/Dialog"

const NOTIFICATION_TIME = 10000;

/**
 * The notification renderer
 */
const NotificationComponent = ({styleOverride}: {styleOverride?: any}) => {
    const {coreState, settingsState} = useBaseGlobalState();

    const [notificationQueue, setNotificationQueue] = coreState.notificationQueue;
    const [notificationCounter] = coreState.notificationCounter;
    
    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    const [visibleNotifications, setVisibleNotifications] = useState<number[]>(
        []
    );

    const ref = useRef(notificationQueue);

    useEffect(() => {
        ref.current = notificationQueue;
    }, [notificationQueue]);

    const dismissNotification = (key: number) => {
        const notificationObject = document.getElementById(
            `notification-${key}`
        );
        if (notificationObject) {
            notificationObject.classList.remove(styles["notification-open"]);
            notificationObject.classList.add(styles["notification-close"]);
        }
        setTimeout(
            () =>
                setNotificationQueue((val) => {
                    const notifications = structuredClone(val);
                    delete notifications[key];
                    return notifications;
                }),
            1e3
        );
    };

    useEffect(() => {
        (Object.keys(ref.current) as unknown as number[])
            .filter((key) => !visibleNotifications.includes(key))
            .forEach((key) => {
                setVisibleNotifications((val) => [...val, key]);
                const notification = notificationQueue[key];
                if (notification.type === "permenant") {
                    if (Flags.checkFlag(notification.flag)) {
                        dismissNotification(key);
                        return;
                    }
                    Flags.addListener(
                        notification.flag,
                        dismissNotification.bind(null, key)
                    );
                } else {
                    setTimeout(
                        dismissNotification.bind(null, key),
                        NOTIFICATION_TIME
                    );
                }
            });
    // eslint-disable-next-line
    }, [notificationQueue, ref, setNotificationQueue]);

    useKeyDown(keybinds.General.Dismiss_Oldest_Notification, () => {
        let i = 0;
        while(
            notificationQueue[i] === undefined 
            || notificationQueue[i].type === "permenant"
        ) {
            i++;
            if(i > notificationCounter) {
                i = -1;
                break;
            }
        }
        if(i !== -1) {
            dismissNotification(i);
        }
    });

    // Render the notification
    return (
        <div className={joinWithOverride(styles, styleOverride, "notification-holder")}>
            {(Object.keys(notificationQueue) as unknown as number[]).map(
                (key) => (
                    <div
                        key={key}
                        className={joinWithOverride(
                            styles,
                            styleOverride,
                            "notification-open",
                            "notification-wrapper"
                        )}
                        id={`notification-${key}`}
                        style={
                            notificationQueue[key].color
                                ? { borderColor: notificationQueue[key].color }
                                : {}
                        }
                        onClick={() => {
                            if(notificationQueue[key].type === "permenant") return;
                            dismissNotification(key);
                        }}
                    >
                        <div className={joinWithOverride(styles, styleOverride, "notification-content")}>
                            <span>
                                <b>{notificationQueue[key]?.title}</b>
                            </span>
                            <span
                                dangerouslySetInnerHTML={{
                                    __html: notificationQueue[key]?.description,
                                }}
                            />
                            {notificationQueue[key].type !== "permenant" && 
                                <p className={joinWithOverride(styles, styleOverride, `notification-tooltip`)}>{
                                    participantSettings.EnableKbControls ? dialogClean(
                                        "Click to dismiss or press %key:general:dismiss_oldest_notification% to dismiss the oldest notification."
                                    ): "Click to dismiss."}</p>
                            }
                        </div>
                        {notificationQueue[key]?.icon ? (
                            <img
                                src={`assets/images/${notificationQueue[key]?.icon}`}
                                height={40}
                                alt="notification"
                            />
                        ) : (
                            <></>
                        )}
                    </div>
                )
            )}
        </div>
    );
};

export default NotificationComponent;
