import React, { useCallback, useEffect, useRef, useState, ReactElement } from "react";
import { renderToString } from "react-dom/server";
import activityStyles from "../../styles/popup/Activity.module.css";
import documentStyles from "../../styles/popup/document.module.css";
import { SendActivityEnded } from "engine/src/system/BackendSystem";
import { joinWithOverride } from "engine/src/system/Styles";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { ReactState, useBaseGlobalState } from "../../state/GlobalState";
import { ActivityElement, BindableElement } from "../../types/Activity";
import { GenericActivityPlayerData } from "../../types/ActivityPlayerData";

export type ActivityRenderer<Activities extends ActivityElement<string>, ActivityElementPlayerData extends GenericActivityPlayerData<string>, T extends Activities["type"]> = (
    arg0: Extract<Activities, { type: T }>,
    arg1: Extract<ActivityElementPlayerData, { type: T }>,
    arg2: (arg0: Extract<ActivityElementPlayerData, { type: T }>) => void,
    arg3: [
        Record<string, string>,
        (element: Activities, key: string, value: string) => void,
        Record<string, string>,
    ],
    registry: AcitivityRegistry<Activities, ActivityElementPlayerData>,
) => {
    appView: ReactElement;
    printView: ReactElement;
};

export type ActivityDefaultStateProvider<Activities extends ActivityElement<string>, ActivityElementPlayerData extends GenericActivityPlayerData<string>, T extends Activities["type"]> = (
    activity: Extract<Activities, { type: T }>,
    registry: AcitivityRegistry<Activities, ActivityElementPlayerData>,
) => Extract<ActivityElementPlayerData, { type: T }>;

export type ActivityRegistryEntry<Activities extends ActivityElement<string>, ActivityElementPlayerData extends GenericActivityPlayerData<string>, T extends Activities["type"]> = {
        renderer: ActivityRenderer<Activities, ActivityElementPlayerData, T>
        dataGenerator: ActivityDefaultStateProvider<Activities, ActivityElementPlayerData, T>
    }

export type AcitivityRegistry<Activities extends ActivityElement<string>, ActivityElementPlayerData extends GenericActivityPlayerData<string>> = {
    [type in Activities["type"]]: ActivityRegistryEntry<Activities, ActivityElementPlayerData, type>
}

export const calculateBoundBindings = (
    bindings: Record<string, string>,
    element: any
): Record<string, string> => {
    const _element = element as BindableElement<any>;
    const bound: Record<string, string> = {};
    if (_element.bindings) {
        const elementBindings = _element.bindings.recieves;
        if (!elementBindings) return {};
        Object.keys(elementBindings).forEach(
            (id) => (bound[id] = bindings[elementBindings[id]])
        );
    }
    return bound;
};

type Activity<Activities extends ActivityElement<string>> = {
    name: string,
    stylesheet?: string,
    activities: Activities[][];
    globalActivities?: Activities[];
}

type ActivityPlayerData<ActivityElementPlayerData extends GenericActivityPlayerData<string>> = {
    elements: ActivityElementPlayerData[][];
    globalElements: ActivityElementPlayerData[];
}

export function ActivityComponent<Activities extends ActivityElement<string>, ActivityElementPlayerData extends GenericActivityPlayerData<string>>({activityRegistry, activityDataState, styleOverride, documentStyleOverride}: {activityRegistry: AcitivityRegistry<Activities, ActivityElementPlayerData>, activityDataState: ReactState<Record<string, ActivityPlayerData<ActivityElementPlayerData>>>, styleOverride: any, documentStyleOverride: any}) {
    const { coreState } = useBaseGlobalState();

    const [activity, setActivity] = coreState.activity as ReactState<Activity<Activities> | null>;
    const [popup, setPopup] = coreState.popup;
    const [activityData, setActivityData] = activityDataState;

    const [bindings, setBindings] = useState<Record<string, string>>({});
    const [activityPage, setActivityPage] = useState(0);

    const topRef = useRef<HTMLDivElement | null>(null);

    const updateActivityData = useCallback(
        (name: string, index: number, data: ActivityElementPlayerData) => {
            if (!activityData[name])
                activityData[name] = { elements: [], globalElements: [] };

            setActivityData((val) => {
                const activity = structuredClone(val);

                activity[name].elements[activityPage][index] =
                    data as ActivityElementPlayerData & { type: "reflection" };
                return activity;
            });
        },
        [activityData, activityPage, setActivityData]
    );

    const calculateBindingsData = <T extends Activities["type"]>(
        element: Extract<Activities, { type: T }>
    ): Parameters<ActivityRenderer<Activities, ActivityElementPlayerData, T>>[3] => {
        return [
            calculateBoundBindings(bindings, element),
            (_element: any, key: string, value: string) => {
                if (!_element.bindings || !_element.bindings.provides) return;
                const id = _element.bindings.provides[key];
                if (!id) return;

                if (bindings[id] === value) return;

                setBindings((val) => {
                    if (!id) return val;

                    const old = structuredClone(val);
                    old[id] = value;
                    return old;
                });
            },
            bindings,
        ];
    };

    useEffect(() => {
        const printableElement = document.getElementById("print-content");
        if (!activity && printableElement) {
            printableElement.innerHTML = "";
        }
        if (activity && !activityData[activity.name]) {
            setActivityData((val) => {
                const newActivityData = structuredClone(val);

                const pages: ActivityElementPlayerData[][] = [];
                for (let i = 0; i < activity.activities.length; i++) {
                    const elements: ActivityElementPlayerData[] = [];
                    for (let element of activity.activities[i]) {
                        elements.push(
                            activityRegistry[element.type as keyof typeof activityRegistry].dataGenerator(element as never, activityRegistry)
                        );
                    }
                    pages.push(elements);
                }
                const global: ActivityElementPlayerData[] = [];
                for (let element of activity.globalActivities
                    ? activity.globalActivities
                    : []) {
                    global.push(
                        activityRegistry[element.type as keyof typeof activityRegistry].dataGenerator(element as never, activityRegistry)
                    );
                }

                newActivityData[activity.name] = {
                    elements: pages,
                    globalElements: global,
                };
                return newActivityData;
            });
        }
    }, [activity, activityData, activityPage, setActivityData]);

    useEffect(() => {
        const printableElement = document.getElementById("print-content");

        if (
            activity &&
            activityData[activity.name] &&
            printableElement &&
            popup === "activity"
        ) {
            document
                .getElementById("temporary-style")
                ?.setAttribute(
                    "href",
                    `/styles/activities/${activity.stylesheet}.css`
                );
            const printView = (
                <>
                    {activity.activities.map((page, page_index) =>
                        page
                            .map((a, i) =>
                                (
                                    activityRegistry[
                                        a.type as keyof typeof activityRegistry
                                    ] as ActivityRegistryEntry<Activities, ActivityElementPlayerData, typeof a.type>
                                ).renderer(
                                    a as any,
                                    activityData[activity.name].elements[
                                        page_index
                                    ][i] as any,
                                    () => {},
                                    calculateBindingsData(a as any),
                                    activityRegistry
                                )
                            )
                            .map((element) => <>{element.printView}</>)
                    )}
                </>
            );

            printableElement.innerHTML =
                `<div class="${activityStyles.activity}">` +
                renderToString(printView) +
                "</div>";
        }
        // eslint-disable-next-line
    }, [
        activity,
        activityData,
        updateActivityData,
        activityPage,
        popup,
        bindings,
        setBindings,
    ]);

    useEffect(() => {
        setActivityPage(0);
    }, [activity, setActivityPage]);

    useEffect(() => {
        topRef.current?.focus();
        // eslint-disable-next-line
    }, [activity, activityPage]);

    return (
        <div className={joinWithOverride(documentStyles, documentStyleOverride, "document-wrapper")}>
            <div className={joinWithOverride(activityStyles, styleOverride, "activity") + "activity"}>
                <div ref={topRef} tabIndex={0}></div>
                {activity && activityData[activity.name] && (
                    <>
                        {activity.activities[activityPage]
                            .map((a, i) =>
                                (
                                    activityRegistry[
                                        a.type as keyof typeof activityRegistry
                                    ] as ActivityRegistryEntry<Activities, ActivityElementPlayerData, typeof a.type>
                                ).renderer(
                                    a as never,
                                    activityData[activity.name].elements[
                                        activityPage
                                    ][i] as never,
                                    (b: ActivityElementPlayerData) => {
                                        updateActivityData(activity.name, i, b);
                                    },
                                    calculateBindingsData(a as never),
                                    activityRegistry,
                                )
                            )
                            .map((element, i) => (
                                <React.Fragment key={i}>
                                    {element.appView}
                                </React.Fragment>
                            ))}
                        {activity.globalActivities &&
                            activity.globalActivities
                                .map((a, i) =>
                                    (
                                        activityRegistry[
                                            a.type as keyof typeof activityRegistry
                                        ] as ActivityRegistryEntry<Activities, ActivityElementPlayerData, typeof a.type>
                                    ).renderer(
                                        a as never,
                                        activityData[activity.name]
                                            .globalElements[i] as never,
                                        (b: ActivityElementPlayerData) => {
                                            updateActivityData(
                                                activity.name,
                                                i,
                                                b
                                            );
                                        },
                                        calculateBindingsData(a as never),
                                        activityRegistry,
                                    )
                                )
                                .map((element, i) => (
                                    <React.Fragment key={i}>
                                        {element.appView}
                                    </React.Fragment>
                                ))}
                        <div
                            className={joinWithOverride(
                                activityStyles,
                                styleOverride,
                                "activity-controls"
                            ) + "activity-controls"}
                        >
                            <button
                                onClick={() => {
                                    PlayAudio("app-click.wav", "sounds");
                                    window.print();
                                }}
                                tabIndex={0}
                            >
                                Print
                            </button>
                            <button
                                onClick={() => {
                                    PlayAudio("page-flip.wav", "sounds");
                                    setActivityPage(activityPage - 1);
                                }}
                                disabled={activityPage <= 0}
                                tabIndex={0}
                            >
                                Previous Page
                            </button>
                            <button
                                onClick={() => {
                                    PlayAudio("page-flip.wav", "sounds");
                                    setActivityPage(activityPage + 1);
                                }}
                                disabled={
                                    activityPage >=
                                    activity.activities.length - 1
                                }
                                tabIndex={0}
                            >
                                Next Page
                            </button>
                            <button
                                onClick={() => {
                                    PlayAudio("app-click.wav", "sounds");
                                    setPopup(null);
                                    setActivity(null);
                                    SendActivityEnded(
                                        activity.name,
                                        coreState.appEnabled[1]
                                    );
                                }}
                                tabIndex={0}
                            >
                                Save and Close
                            </button>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
}
