import styles from "../../styles/popup/AppDisabled.module.css";
import { saveGame } from "engine/src/system/SaveSystem";
import { CoreState } from "engine/src/state/GlobalState";
import { joinWithOverride } from "../../system/Styles";

export const AppDisabled = ({
    coreState,
    styleOverride,
}: {
    coreState: CoreState<any, any>;
    styleOverride?: any,
}) => {
    return coreState.appEnabled[0] ? (
        <></>
    ) : (
        <div className={joinWithOverride(styles, styleOverride, "appDisabled")}>
            <div>
                <p>Failed to connect to server. Please wait...</p>
                {coreState.popup[0] === "titleScreen" ? (
                    <a
                        onClick={() => {
                            delete_cookie("user");
                            delete_cookie("password");
                            window.location.reload();
                        }}
                        href="/"
                    >
                        Logout
                    </a>
                ) : (
                    <button
                        onClick={() => {
                            saveGame();
                        }}
                    >
                        Save Game
                    </button>
                )}
            </div>
        </div>
    );
};

function delete_cookie(name: string) {
    if (get_cookie(name)) {
        document.cookie = name + "=;expires=Thu, 01 Jan 1970 00:00:01 GMT";
    }
}

function get_cookie(name: string) {
    return document.cookie.split(";").some((c) => {
        return c.trim().startsWith(name + "=");
    });
}
