import React, { useEffect, useRef, useState } from "react";
import { useGlobalState } from "../../state/GlobalState";
import styles from "#styles/popup/CharacterCreator.module.css";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { GetCharacters } from "engine/src/system/Characters";
import AvatarList from "./AvatarList";
import { keyDownHandler } from "engine/src/system/Keyboard";
import { join } from "engine/src/system/Styles";
import Registers from "engine/src/system/Registers";

/**
 * The Character Creator Popup
 */
const CharacterCreator = () => {
    const { playerState, coreState, settingsState } = useGlobalState();

    const [character] = playerState.character;
    const [playerPronouns, setPlayerPronouns] = playerState.playerPronouns;
    const [playerPitch, setPlayerPitch] = playerState.playerPitch;

    const [popup, setPopup] = coreState.popup;

    const [keybinds] = settingsState.keybinds;

    const [lowPitchButtonSelected, setLowPitchButtonSelected] = useState(false);
    const [highPitchButtonSelected, setHighPitchButtonSelected] =
        useState(true);
    const [screen, setScreen] = useState<"main" | "avatar">("main");

    const characterRef = useRef<HTMLInputElement | null>(null);

    // Function responsible for handling a name change in the GUI
    const handleNameChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        Registers.setTextRegisters([
            {
                register: "player",
                action: "set",
                value: event.target.value,
            },
        ]);
    };

    // Function responsible for handling a name change in the GUI
    const handlePronoun1Change = (
        event: React.ChangeEvent<HTMLInputElement>
    ) => {
        setPlayerPronouns([event.target.value, playerPronouns[1]]);
    };

    // Function responsible for handling a name change in the GUI
    const handlePronoun2Change = (
        event: React.ChangeEvent<HTMLInputElement>
    ) => {
        setPlayerPronouns([playerPronouns[0], event.target.value]);
    };

    const handleStartGame = () => {
        if (!playerPitch) {
            // Automatically select high pitch if no gender is selected
            setPlayerPitch("high-pitch");
        }

        (document.getElementById("start_button") as HTMLInputElement).disabled =
            true;
        const imageElement = document.getElementById("character_image");
        if (imageElement) {
            imageElement.remove();
        }
        const textElement = document.getElementById("character_text");
        if (textElement) {
            textElement.remove();
        }

        document
            .getElementById("character-editor")
            ?.classList.add(join(styles, "fade-out").trim());

        const playerName = Registers.getTextRegister("player");

        if (playerName.trim() === "") {
            Registers.setTextRegisters([
                {
                    register: "player",
                    action: "set",
                    value: "Riley",
                },
            ]);
        }

        setPopup("preamble");

        PlayAudio("character-creator-button.mp3", "sounds");
    };

    const handleEditCharacter = () => {
        const data = GetCharacters()?.path.map((e) => e.values[0]);
        if (!data) return;

        setScreen("avatar");
    };

    const handlePlayVoiceSample = (pitch: "high" | "low") => {
        const audioFile =
            pitch === "high" ? "high-pitch-voice.mp3" : "low-pitch-voice.mp3";
        PlayAudio(audioFile, "sounds");
    };

    useEffect(() => {
        characterRef.current?.focus();
    }, [popup]);

    // Render the character creator
    return screen === "main" ? (
        <div
            id="character-editor"
            className={[join(styles, "character-editor"), styles.main].join(
                " "
            )}
        >
            {screen === "main" && (
                <div className={join(styles, "character-preview")}>
                    <input
                        className={join(styles, "img")}
                        type="image"
                        id="character_image"
                        src={character.image}
                        alt="edit character button"
                        ref={characterRef}
                        onClick={handleEditCharacter}
                        onKeyDown={keyDownHandler(
                            keybinds.General.Select,
                            handleEditCharacter
                        )}
                    />
                    <b id="character_text">
                        <i>Click or select to change character avatar.</i>
                    </b>
                </div>
            )}
            <div className={join(styles, "character-desc-container")}>
                <div className={join(styles, "character-desc")}>
                    <p>Enter your character's name below:</p>
                    <input
                        className={join(styles, "character-name-textbox")}
                        type="text"
                        placeholder="Riley"
                        onChange={handleNameChange}
                        maxLength={40}
                    ></input>
                    <span>'Riley' will be used as default.</span>
                    <span className={join(styles, "pronouns")}>
                        <input
                            type="text"
                            placeholder="They"
                            onChange={handlePronoun1Change}
                            maxLength={40}
                        ></input>
                        /
                        <input
                            type="text"
                            placeholder="Them"
                            onChange={handlePronoun2Change}
                            maxLength={40}
                        ></input>
                    </span>
                </div>
                <div className={join(styles, "character-desc")}>
                    <p>Select your character's voice type:</p>
                    <div className={join(styles, "button-container")}>
                        <button
                            onClick={() => {
                                setPlayerPitch("low-pitch");
                                handlePlayVoiceSample("low");
                                setLowPitchButtonSelected(true);
                                setHighPitchButtonSelected(false);
                            }}
                            className={join(
                                styles,
                                lowPitchButtonSelected
                                    ? "pitch-button-lit"
                                    : "pitch-button"
                            )}
                        >
                            Low Pitch Voice
                        </button>
                        <button
                            onClick={() => {
                                setPlayerPitch("high-pitch");
                                handlePlayVoiceSample("high");
                                setHighPitchButtonSelected(true);
                                setLowPitchButtonSelected(false);
                            }}
                            className={join(
                                styles,
                                highPitchButtonSelected
                                    ? "pitch-button-lit"
                                    : "pitch-button"
                            )}
                        >
                            High Pitch Voice
                        </button>
                    </div>
                </div>
                <div className={join(styles, "character-desc")}>
                    <button id="start_button" onClick={handleStartGame}>
                        Start Game
                    </button>

                    <span>
                        You will be able to change your avatar, name and voice
                        later.
                    </span>
                </div>
            </div>
        </div>
    ) : (
        <AvatarList
            onDone={() => {
                setScreen("main");
            }}
        />
    );
};

export default CharacterCreator;
