import styles from "#styles/activities/renderers/floating.module.css";
import { join } from "engine/src/system/Styles";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";
import { editState } from "../../../state/Util";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
    calculateBoundBindings,
} from "engine/src/components/popup/ActivityComponent";
import { Activities, Activity } from "../../../types/Activity";

export const FloatingActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "floating"
> = (
    element,
    playerData,
    updateState,
    [bound, updateBinding, bindings],
    registry
) => {
    const updateActivityData = (b: ActivityElementPlayerData) => {
        editState(playerData, updateState, (old) => {
            old.element = b;
            old.complete = old.element.complete;
            return old;
        });
    };
    return {
        appView: (
            <div
                key={"a"}
                className={join(styles, "floating")}
                style={{
                    position: "fixed",
                }}
            >
                <div>
                    {
                        registry[element.element.type].renderer(
                            element.element as never,
                            playerData.element as never,
                            (b: ActivityElementPlayerData) => {
                                updateActivityData(b);
                            },
                            [
                                calculateBoundBindings(
                                    bindings,
                                    element.element
                                ),
                                updateBinding,
                                bindings,
                            ],
                            registry
                        ).appView
                    }
                </div>
            </div>
        ),
        printView: (
            <div
                key={"a"}
                className={join(styles, "floating")}
                style={{
                    position: "fixed",
                }}
            >
                <div>
                    {
                        registry[element.element.type].renderer(
                            element.element as never,
                            playerData.element as never,
                            (b: ActivityElementPlayerData) => {
                                updateActivityData(b);
                            },
                            [
                                calculateBoundBindings(
                                    bindings,
                                    element.element
                                ),
                                updateBinding,
                                bindings,
                            ],
                            registry
                        ).appView
                    }
                </div>
            </div>
        ),
    };
};

export const DefaultFloatingActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "floating"
> = (element, registry) => {
    const elem = registry[element.element.type].dataGenerator(
        element.element as never,
        registry
    );
    const complete = elem.complete;

    return {
        type: "floating",
        complete: complete,
        element: elem,
    };
};
