import React from "react";
import styles from "#styles/activities/renderers/callout.module.css";
import { join } from "engine/src/system/Styles";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const CalloutActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "callout"
> = (element, _playerData, _updateState, [bound]) => {
    if (Object.keys(bound).includes("visible") && bound.visible !== "true")
        return {
            appView: <></>,
            printView: <></>,
        };

    const subText = (text: string): string => {
        return text.replace(/\{[a-zA-Z0-9]*\}/g, (a) =>
            Object.keys(bound).includes(a.substring(1, a.length - 1))
                ? bound[a.substring(1, a.length - 1)]
                : a
        );
    };

    return {
        appView: (
            <React.Fragment key={element.title}>
                <div className={join(styles, `callout`, element.callout)}>
                    <b>{element.title}</b>
                    <p>{subText(element.text)}</p>
                </div>
            </React.Fragment>
        ),
        printView: (
            <React.Fragment key={element.title}>
                <div className={join(styles, `callout`, element.callout)}>
                    <b>{element.title}</b>
                    <p>{subText(element.text)}</p>
                </div>
            </React.Fragment>
        ),
    };
};

export const DefaultCalloutActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "callout"
> = () => {
    return {
        type: "callout",
        complete: true,
    };
};
