import { over } from "stompjs";
import SockJS from "sockjs-client";

import {
    BackendBuilder,
    BuildSender,
    CreateBasicMap,
    SendableObject,
} from "engine/src/system/BackendSystem";

export const WebSocketBackend: BackendBuilder = () => {
    let stompClient: any = null;
    let isConnected: boolean = false;

    const connect = () => {
        // Use this to connect to the production server (off-campus)
        const socket = new SockJS("http://198.48.146.93:8080/ws");

        // Use this to connect to the production server (university)
        //const socket = new SockJS("http://136.159.6.141:8080/ws");

        // Use this to connect to your local test server
        //const socket = new SockJS("http://localhost:8080/ws");

        stompClient = over(socket);
        stompClient.connect({}, onConnected, onError);
    };

    const onConnected = () => {
        isConnected = true;
    };

    const onError = (error: any) => {
        isConnected = false;
        console.error("Error while connecting to WebSocket:", error);
    };

    const be = {
        Connect: () => {
            connect();
            return isConnected;
        },
        IsConnected: () => isConnected,
        Disconnect: () => {
            if (stompClient) {
                stompClient.disconnect();
                isConnected = false;
            }
        },
        SendData: (data: SendableObject) => {
            if (isConnected && stompClient && stompClient.connected) {
                stompClient.send("/app/sendData", {}, JSON.stringify(data));
                return true;
            } else {
                be.Connect();
                console.error("Not connected to WebSocket");
                return false;
            }
        },
    };

    return be;
};

export const SendJeopardyQuestionSelected = BuildSender(
    "jeopardy_question_selected",
    (category: string, [clue]: [number]) => {
        return {
            category_title: category,
            clue_worth: clue,
        };
    }
);
