import styles from "#styles/apps/SettingsApp.module.css";
import phoneStyles from "#styles/apps/PhoneUIGeneric.module.css";
import dialogStyles from "#styles/dialog/Dialog.module.css";
import engineDialogStyles from "engine/src/styles/dialog/Dialog.module.css";
import {
    exportSave,
    saveGame,
    loadGame,
    saveSettings,
} from "engine/src/system/SaveSystem";
import {
    ChangeEventHandler,
    Fragment,
    MouseEventHandler,
    useEffect,
    useReducer,
    useRef,
    useState,
} from "react";
import AvatarList from "../popup/AvatarList";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { join, joinWithOverride } from "engine/src/system/Styles";
import { GlobalState, useGlobalState } from "../../state/GlobalState";
import { keyDownHandler, useKeyDown } from "engine/src/system/Keyboard";
import { resetSettingsState } from "engine/src/state/GlobalState";
import Registers from "engine/src/system/Registers";
import { SendNotification } from "engine/src/system/Notification";
import { defaultParticipantSettings } from "../../system/ParticipantSettings";

/**
 * The available wallpapers
 * This variable is also defined in Phone.tsx
string */
const wallpapers = [
    "assets/images/elements/wallpaper1.png",
    "assets/images/elements/wallpaper2.png",
    "assets/images/elements/wallpaper3.png",
    "assets/images/elements/wallpaper4.png",
];

const has_save = () => window.localStorage.getItem("game-state") !== null;

function debounce<T extends (...args: any[]) => any>(func: T, wait: number) {
    let timeout: ReturnType<typeof setTimeout>;
    return function (this: any, ...args: Parameters<T>) {
        clearTimeout(timeout);
        timeout = setTimeout(() => func.apply(this, args), wait);
    };
}

/**
 * The Settings app
 */
export const SettingsApp = ({ closeApp }: { closeApp: () => void }) => {
    const { playerState, coreState, gameState, phoneState, settingsState } =
        useGlobalState();

    const [wallpaperNumber, setWallpaperNumber] = coreState.wallpaperNumber;

    const [popup, setPopup] = coreState.popup;

    const [volume, setVolume] = settingsState.volume;
    const [textSize, setTextSize] = settingsState.textSize;
    const [textStyle, setTextStyle] = settingsState.textStyle;
    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    const [playerPronouns, setPlayerPronouns] = playerState.playerPronouns;
    const [character] = playerState.character;
    const [playerPitch, setPlayerPitch] = playerState.playerPitch;

    // used to force re-rendering the component after resetting settings
    const [renderKey, forceUpdate] = useReducer((x) => x + 1, 0);

    const [playerName, setPlayerName] = useState<string>(
        Registers.getTextRegister("player")
    );
    const [newName, setNewName] = useState<string>("");
    const [newPronouns, setNewPronouns] = useState<[string, string]>(["", ""]);

    const [avatarOpen, setAvatarOpen] = useState<boolean>(false);

    const updateNameButton = useRef<HTMLButtonElement>(null);
    const newPronouns1Field = useRef<HTMLInputElement>(null);
    const newPronouns2Field = useRef<HTMLInputElement>(null);
    const newNameField = useRef<HTMLInputElement>(null);

    useKeyDown(keybinds.General.Back, () => {
        if (avatarOpen) return setAvatarOpen(false);
        closeApp();
    });

    // Function to handle a name change
    const handleNameChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        setNewName(event.target.value);
        const button = updateNameButton.current;
        if (button) button.disabled = event.target.value.trim() === "";
    };

    function saveName() {
        setPlayerName(newName);

        Registers.setTextRegisters([
            {
                register: "player",
                action: "set",
                value: newName,
            },
        ]);

        SendNotification({
            type: "regular",
            title: "New Name!",
            description: `Your name has been changed!`,
            sound: "hint",
        });

        if (newNameField.current) {
            newNameField.current.value = "";
        }
    }

    const handlePronoun1Change = (
        event: React.ChangeEvent<HTMLInputElement>
    ) => {
        setNewPronouns([event.target.value, newPronouns[1]]);
    };

    const handlePronoun2Change = (
        event: React.ChangeEvent<HTMLInputElement>
    ) => {
        setNewPronouns([newPronouns[0], event.target.value]);
    };

    function savePronouns() {
        setPlayerPronouns([
            newPronouns1Field.current?.value.trim() || playerPronouns[0],
            newPronouns2Field.current?.value.trim() || playerPronouns[1],
        ]);

        SendNotification({
            type: "regular",
            title: "New Pronouns!",
            description: `Your pronouns have been changed!`,
            sound: "hint",
        });

        if (newPronouns1Field.current) {
            newPronouns1Field.current.value = "";
        }

        if (newPronouns2Field.current) {
            newPronouns2Field.current.value = "";
        }

        setNewPronouns(["", ""]);
    }

    // Function to handle changing the wallpaper
    function handleWallpaperChange() {
        PlayAudio("change-background.wav", "sounds");
    }

    const resetSettings = () => {
        resetSettingsState(settingsState, true, defaultParticipantSettings);
        forceUpdate();
    };

    const handleSoundChange: MouseEventHandler<HTMLInputElement> = (e) => {
        const slider = e.target as HTMLInputElement;

        setVolume((val) => {
            const newVolume = structuredClone(val);

            newVolume[slider.name as keyof typeof val] = parseInt(slider.value);
            return newVolume;
        });

        PlayAudio("mouse-click.wav", slider.valueAsNumber, false, true);
    };

    const handleSizeChange: MouseEventHandler<HTMLInputElement> = (e) => {
        const slider = e.target as HTMLInputElement;
        setTextSize(parseFloat(slider.value));
        document.documentElement.style.setProperty(
            "--font-scale",
            `${parseFloat(slider.value)}`
        );
    };

    const handleStyleChange: ChangeEventHandler<HTMLInputElement> = (e) => {
        const radio = e.target as HTMLInputElement;
        setTextStyle(radio.value);
        document.documentElement.style.setProperty(
            "--font-style",
            `${radio.value}`
        );
    };

    const openControls = () => {
        setPopup("controls");
    };

    const handlePlayerPitchChange = debounce(
        (newPlayerPitch: "low-pitch" | "high-pitch") => {
            setPlayerPitch(newPlayerPitch);
            const voiceSample =
                newPlayerPitch === "high-pitch"
                    ? "high-pitch-voice.mp3"
                    : "low-pitch-voice.mp3";
            PlayAudio(voiceSample, volume.voice, false, true);
        },
        300
    );

    const handleVoiceChange: MouseEventHandler<HTMLInputElement> = (e) => {
        const slider = e.target as HTMLInputElement;
        setVolume((val) => {
            const newVolume = structuredClone(val);
            newVolume.voice = parseInt(slider.value);
            return newVolume;
        });
        const voiceSample =
            playerPitch === "high-pitch"
                ? "high-pitch-voice.mp3"
                : "low-pitch-voice.mp3";
        PlayAudio(voiceSample, e.currentTarget.valueAsNumber, false, false);
    };

    useEffect(() => {
        document.documentElement.style.setProperty(
            "--font-scale",
            `${settingsState.textSize[0]}`
        );
        document.documentElement.style.setProperty(
            "--font-style",
            `${settingsState.textStyle[0]}`
        );
    }, [settingsState.textSize, settingsState.textStyle]);

    useEffect(() => {}, [volume]);

    useEffect(() => {
        return () => {
            saveSettings();
        };
    }, []);

    return (
        <div className={join(styles, "settings-app")}>
            {avatarOpen ? (
                <AvatarList onDone={() => setAvatarOpen(false)} />
            ) : (
                <>
                    {popup === null ? (
                        <>
                            <h1>Settings</h1>
                            <h2>Player Profile</h2>
                            <div className={join(phoneStyles, "column-30-60")}>
                                {!avatarOpen && (
                                    <button
                                        tabIndex={1}
                                        onKeyDown={keyDownHandler(
                                            keybinds.General.Select,
                                            () => setAvatarOpen(true)
                                        )}
                                    >
                                        <img
                                            alt="character-selector"
                                            src={character.image}
                                            onClick={() => setAvatarOpen(true)}
                                        />
                                    </button>
                                )}

                                <div
                                    className={join(
                                        phoneStyles,
                                        "column",
                                        "center",
                                        "middle"
                                    )}
                                >
                                    <b>{playerName}</b>
                                    <i>
                                        {playerPronouns[0]}/{playerPronouns[1]}
                                    </i>
                                    <div style={{ height: "100px" }} />
                                    <input
                                        style={{ width: "80%" }}
                                        ref={newNameField}
                                        type="text"
                                        placeholder="Change Player Name..."
                                        onChange={handleNameChange}
                                        maxLength={40}
                                        tabIndex={2}
                                    ></input>
                                    <button
                                        ref={updateNameButton}
                                        disabled={newName.trim() === ""}
                                        onClick={saveName}
                                        tabIndex={3}
                                    >
                                        Change Name
                                    </button>
                                    <span
                                        style={{
                                            display: "flex",
                                            width: "90%",
                                        }}
                                    >
                                        <input
                                            style={{ width: "100%" }}
                                            ref={newPronouns1Field}
                                            type="text"
                                            placeholder={playerPronouns[0]}
                                            maxLength={40}
                                            onChange={handlePronoun1Change}
                                            tabIndex={4}
                                        ></input>
                                        <input
                                            style={{ width: "100%" }}
                                            ref={newPronouns2Field}
                                            type="text"
                                            placeholder={playerPronouns[1]}
                                            maxLength={40}
                                            onChange={handlePronoun2Change}
                                            tabIndex={5}
                                        ></input>
                                    </span>
                                    <button
                                        disabled={
                                            newPronouns[0].trim() === "" &&
                                            newPronouns[1].trim() === ""
                                        }
                                        onClick={savePronouns}
                                        tabIndex={6}
                                    >
                                        Change Pronouns
                                    </button>
                                </div>
                            </div>
                            <h2>Change Pitch </h2>
                            <div>
                                <button
                                    className={join(
                                        styles,
                                        playerPitch === "low-pitch"
                                            ? "selected"
                                            : ""
                                    )}
                                    onClick={() =>
                                        handlePlayerPitchChange("low-pitch")
                                    }
                                >
                                    Low Pitch Voice
                                </button>
                                <button
                                    className={join(
                                        styles,
                                        playerPitch === "high-pitch"
                                            ? "selected"
                                            : ""
                                    )}
                                    onClick={() =>
                                        handlePlayerPitchChange("high-pitch")
                                    }
                                >
                                    High Pitch Voice
                                </button>
                            </div>
                            <h2>Phone Background</h2>
                            <div
                                className={join(styles, "background-container")}
                            >
                                <button
                                    onClick={() => {
                                        var i = wallpaperNumber - 1;
                                        if (i < 0) i = wallpapers.length - 1;
                                        handleWallpaperChange();
                                        setWallpaperNumber(i);
                                    }}
                                >
                                    &lt;
                                </button>
                                <div
                                    className={join(
                                        styles,
                                        "change-background-toggle"
                                    )}
                                    style={{
                                        backgroundImage:
                                            "url(" +
                                            wallpapers[wallpaperNumber] +
                                            ")",
                                    }}
                                ></div>
                                <button
                                    onClick={() => {
                                        var i = wallpaperNumber + 1;
                                        if (i > wallpapers.length - 1) i = 0;
                                        handleWallpaperChange();
                                        setWallpaperNumber(i);
                                    }}
                                >
                                    &gt;
                                </button>
                            </div>

                            {participantSettings.EnableKbControls && (
                                <>
                                    <h2>Keyboard Settings</h2>
                                    <div>
                                        <button onClick={openControls}>
                                            Keyboard Controls
                                        </button>
                                    </div>
                                </>
                            )}

                            <h1> </h1>
                            <h1>Global Settings</h1>

                            <div>
                                <button onClick={resetSettings}>
                                    Reset Global Settings
                                </button>
                            </div>

                            <Fragment key={renderKey}>
                                <h2>Sound Settings</h2>
                                <div className={join(phoneStyles, "column")}>
                                    <h3>Master</h3>
                                    <input
                                        type="range"
                                        min={0}
                                        max={100}
                                        defaultValue={
                                            settingsState.volume[0].master
                                        }
                                        name="master"
                                        onInput={handleSoundChange}
                                    />
                                    <h3>Sound Effects</h3>
                                    <input
                                        type="range"
                                        min={0}
                                        max={100}
                                        defaultValue={volume.sounds}
                                        name="sounds"
                                        onInput={handleSoundChange}
                                    />
                                    <h3>Music</h3>
                                    <input
                                        type="range"
                                        min={0}
                                        max={100}
                                        defaultValue={volume.music}
                                        name="music"
                                        onInput={handleSoundChange}
                                    />
                                    <h3>Voice</h3>
                                    <input
                                        type="range"
                                        min={0}
                                        max={100}
                                        defaultValue={volume.voice}
                                        name="voice"
                                        onInput={handleVoiceChange}
                                    />
                                </div>
                                <h2>Typography Settings</h2>
                                <div className={join(phoneStyles, "column")}>
                                    <h3>Font Size</h3>
                                    <input
                                        type="range"
                                        min={1.0}
                                        max={2.0}
                                        step={0.1}
                                        defaultValue={textSize}
                                        name="size"
                                        onInput={handleSizeChange}
                                    ></input>
                                </div>
                                <div className={join(phoneStyles, "column")}>
                                    <h3>Font Style</h3>
                                    <div
                                        className={join(
                                            styles,
                                            "text-style-radio"
                                        )}
                                    >
                                        <div className={join(styles, "arial")}>
                                            <input
                                                type="radio"
                                                name="style"
                                                id="Arial"
                                                value="'Arial', sans-serif"
                                                checked={
                                                    textStyle ===
                                                    "'Arial', sans-serif"
                                                }
                                                onChange={handleStyleChange}
                                            ></input>
                                            <label htmlFor="Arial">Arial</label>
                                        </div>
                                        <div
                                            className={join(
                                                styles,
                                                "comic-sans"
                                            )}
                                        >
                                            <input
                                                type="radio"
                                                name="style"
                                                id="Comic Sans"
                                                checked={
                                                    textStyle ===
                                                    "'Comic Sans MS', 'Comic Sans', cursive"
                                                }
                                                value="'Comic Sans MS', 'Comic Sans', cursive"
                                                onChange={handleStyleChange}
                                            ></input>
                                            <label htmlFor="Comic Sans">
                                                Comic Sans
                                            </label>
                                        </div>
                                    </div>
                                </div>
                                <div
                                    className={joinWithOverride(
                                        engineDialogStyles,
                                        dialogStyles,
                                        "dialog",
                                        "settings",
                                        "player",
                                        "dialog-text"
                                    )}
                                    style={{ margin: "auto", marginTop: "10%" }}
                                >
                                    <div
                                        className={join(
                                            dialogStyles,
                                            "dialog-text"
                                        )}
                                    >
                                        <b>Sample Name</b>
                                        <p
                                            dangerouslySetInnerHTML={{
                                                __html: "Sample Text",
                                            }}
                                        />
                                    </div>
                                </div>
                            </Fragment>

                            <h2>Save Management</h2>
                            <div className={join(phoneStyles, "column-50-50")}>
                                <button
                                    onClick={() => {
                                        saveGame();
                                    }}
                                >
                                    Save Game
                                </button>
                                <button
                                    className={join(
                                        styles,
                                        has_save() ? "" : "disabled"
                                    )}
                                    onClick={() => {
                                        loadGame(GlobalState.getInstance());
                                    }}
                                >
                                    Load Game
                                </button>
                                <button
                                    onClick={() => {
                                        exportSave();
                                    }}
                                >
                                    Export Save
                                </button>
                                <button
                                    onClick={() => {
                                        GlobalState.getInstance().resetState(
                                            coreState,
                                            playerState,
                                            gameState,
                                            phoneState,
                                            settingsState,
                                            "default"
                                        );
                                    }}
                                >
                                    Title Screen
                                </button>
                            </div>
                        </>
                    ) : (
                        <></>
                    )}
                </>
            )}
        </div>
    );
};
