import { ReactNode, useContext, useEffect } from "react";

export type States = Array<{func: (value: any) => void, context: React.Context<any>, value: any}>;

/**
 * Updates the global state to match the actual state of the application
 */
const GlobalStateNode = ({states, children}: {states: States, children: ReactNode[] | ReactNode}) => {
    const Provider = states[0].context.Provider;

    return <Provider value={states[0].value}>
        <GlobalStateListener context={states[0].context} func={states[0].func} />
        {states.length > 1 ? <GlobalStateNode states={states.slice(1)}>
            {children}
        </GlobalStateNode>
        : children}
    </Provider>
};

const GlobalStateListener = ({context, func}: {context: React.Context<any>, func: (value: any) => void}) => {
    
    const state = useContext(context);
    // When the player state changes, update the global state
    useEffect(() => {
        func(state);
    }, [state]);

    return <></>
}

export const GlobalStateProvider = ({states, children}: {states: States, children: ReactNode[] | ReactNode}) => {
    if(states.length === 0) return <>{children}</>

    return <GlobalStateNode states={states}>
        {children}
    </GlobalStateNode>
}
