import styles from "#styles/popup/CharacterCreator.module.css";
import { keyDownHandler } from "engine/src/system/Keyboard";
import { useGlobalState } from "../../state/GlobalState";
import { useState } from "react";
import { GetCharacters } from "engine/src/system/Characters";
import { join } from "engine/src/system/Styles";

function numberRange(start: number, end: number) {
    return new Array(end - start).fill(1).map((_, i) => i + start);
}

const AvatarList = ({ onDone }: { onDone: () => void }) => {
    const { playerState, settingsState } = useGlobalState();

    const [keybinds] = settingsState.keybinds;

    const [character, setCharacter] = playerState.character;

    const [screen, setScreen] = useState<number>(0);
    const characters = GetCharacters();

    if (!characters) return <></>;

    const baseImagePath = `assets/images/characters/${Array.from(
        Array(screen).keys()
    )
        .map((idx) => character.data[idx])
        .join("/")}/`.replaceAll("//", "/");
    const endImagePath = `${numberRange(screen + 1, characters.path.length)
        .map((idx) => characters.path[idx].values[0])
        .join("/")}/${characters.file_name}`;
    return (
        <div className={join(styles, "character-editor")}>
            <div className={join(styles, "character-editor-title")}>
                <h1>Choose your {GetCharacters()?.path[screen].name}</h1>
                <section className={join(styles, "character-list")}>
                    {characters.path[screen].values.map((item, i) => {
                        const characterImageSrc = `${baseImagePath}${item}${endImagePath}`;
                        const choseCharacter = () => {
                            setCharacter((val) => {
                                const chr = structuredClone(val);

                                chr.data[screen] = item;
                                chr.image = characterImageSrc;
                                return chr;
                            });

                            if (screen + 1 >= characters.path.length) {
                                onDone();
                            }
                            setScreen(screen + 1);
                        };

                        return (
                            <img
                                className={join(
                                    styles,
                                    character.image === characterImageSrc &&
                                        "selected-avatar"
                                )}
                                key={item}
                                alt="character option"
                                src={characterImageSrc}
                                tabIndex={i + 1}
                                onClick={choseCharacter}
                                onKeyDown={keyDownHandler(
                                    keybinds.General.Select,
                                    choseCharacter
                                )}
                            />
                        );
                    })}
                </section>
            </div>
        </div>
    );
};

export default AvatarList;
