import { GlobalState } from "../state/GlobalState";
import { Badge } from "../types/Badge";
import { BumperSticker } from "../types/BumperSticker";
import { JournalDocument } from "../types/Document";
import { Minigame, MinigameMetadata } from "../types/Minigame";
import { Strategy } from "../types/Strategy";
import {
    SendBadgeUnlock,
    SendDocumentUnlock,
    SendBumperStickerUnlock,
} from "./BackendSystem";
import {
    SendDocumentOpened,
    SendMinigameStarted,
} from "engine/src/system/BackendSystem";
import { SendNotification } from "engine/src/system/Notification";
import {
    createUnlockable,
    createStateProvider,
} from "engine/src/system/Unlockables";
import { LoadMinigame } from "engine/src/system/DataLoader";
import { DictionaryWords } from "engine/src/types/DictionaryWords";

const createPlayerStateProvider = createStateProvider.bind(
    null,
    () => GlobalState.getInstance().playerState[0]
);

export const Badges = createUnlockable<Badge>(
    "badges",
    createPlayerStateProvider("unlockedBadges"),
    {
        unlockAllMixin: () =>
            SendNotification({
                type: "regular",
                title: "Badges Unlocked!",
                description: `You unlocked multiple badges!`,
                icon: "badges/generic.png",
                color: "purple",
                sound: "badge",
            }),
        unlockMixin: (_: string, obj: Badge) => {
            SendNotification({
                type: "regular",
                title: "Badge Unlocked!",
                description: `You unlocked the ${obj.name} badge!`,
                icon: "badges/generic.png",
                color: "purple",
                sound: "badge",
            });
            const coreState = GlobalState.getInstance().coreState[0];
            SendBadgeUnlock(obj.name, coreState.appEnabled[1]);
        },
    }
);

export const BumperStickers = createUnlockable<BumperSticker>(
    "bumper_stickers",
    createPlayerStateProvider("unlockedBumperStickers"),
    {
        unlockMixin: (name: string, _: any) => {
            const coreState = GlobalState.getInstance().coreState[0];
            SendBumperStickerUnlock(name, coreState.appEnabled[1]);
        },
    }
);

export const Documents = createUnlockable<JournalDocument>(
    "documents",
    createPlayerStateProvider("unlockedDocuments"),
    {
        unlockMixin: (name: string) => {
            const coreState = GlobalState.getInstance().coreState[0];
            SendDocumentUnlock(name, coreState.appEnabled[1]);
        },
    },
    {
        open:
            (list: () => Record<string, JournalDocument>) => (name: string) => {
                const coreState = GlobalState.getInstance().coreState[0];
                SendDocumentOpened(name, coreState.appEnabled[1]);
                const document = list()[name];
                if (document) {
                    coreState.popupStateData[1](document);
                    coreState.popup[1]("document");
                }
            },
    }
);

export const Dictionary = createUnlockable<DictionaryWords>(
    "dictionary",
    createPlayerStateProvider("unlockedDictionary"),
    {}
);

export const Minigames = createUnlockable<MinigameMetadata>(
    "minigames",
    createPlayerStateProvider("unlockedMinigames"),
    {},
    {
        open:
            (_list: () => Record<string, MinigameMetadata>) =>
            (name: string) => {
                const coreState = GlobalState.getInstance().coreState[0];

                SendMinigameStarted(name, coreState.appEnabled[1]);
                Minigames.unlock(name);
                LoadMinigame<Minigame>(name).then((minigame) => {
                    SendMinigameStarted(minigame.type, coreState.appEnabled[1]);
                    coreState.minigame[1](minigame);
                    coreState.popup[1]("minigame");
                });
            },
    }
);

export const Strategies = createUnlockable<Strategy>(
    "strategies",
    createPlayerStateProvider("unlockedStrategies"),
    {
        unlockMixin: (_: string, obj: Strategy) => {
            SendNotification({
                type: "regular",
                title: `Unlocked Strategy: ${obj.title}`,
                description: obj.content,
                icon: "elements/book.png",
                color: "crimson",
                sound: "badge",
            });
        },
    },
    {}
);
