import styles from "#styles/minigames/MinigameProgressBar.module.css";
import { useEffect } from "react";
import { join } from "engine/src/system/Styles";

export const ProgressBar = ({
    current,
    total,
}: {
    current: number;
    total: number;
}) => {
    useEffect(() => {
        document.documentElement.style.setProperty(
            "--progress",
            `${(current / total) * 100}%`
        );
    }, [current, total]);
    return (
        <div className={join(styles, "progress")}>
            <h2>Minigame Progress Bar</h2>
            <div>
                <input
                    className={join(styles, "progress-bar")}
                    type="range"
                    min={0}
                    max={total}
                    defaultValue={0}
                    disabled
                ></input>
                {Number(current / total) * 100 >= 100
                    ? "100"
                    : Number(current / total) * 100}
                %
            </div>
        </div>
    );
};
