import { LoadJSON } from "./system/DataLoader";
import Flags from "./system/Flags";
import Registers from "./system/Registers";
import { Flag } from "./types/Flag";
import { RegisterUpdate } from "./types/Register";

// Change to false for participants
export const ALLOW_NO_DATABASE = true;

export interface BaseParticipantSettings extends Record<string, string | boolean | number> {
    name: string;
    EnableVoiceLines: boolean;
    EnableKbControls: boolean;
    EnableKbHints: boolean;
    EnableKeyRebinding: boolean;
    EnableDialogHistory: boolean;
    EnableSkipMinigames: boolean;
    EnableFailedTodo: boolean;
    SelectSecretProbability: number;

    DebugEnabled: boolean;
    AutoDialogueEnabled: boolean;
    ShowBoundingBoxes: boolean;
};


export type ParticipantConfiguration<S extends BaseParticipantSettings> = {
    useOptions: string[];
    options: S[];
};

export async function getNewParticipantSettings<S extends BaseParticipantSettings>(): Promise<S> {
    const data: ParticipantConfiguration<S> = await LoadJSON('participant_settings');
    
    const options = data.options.filter(option => data.useOptions.includes(option.name));
    const random = Math.floor(Math.random() * options.length);

    return options[random];
}

export async function getParticipantConfiguration<S extends BaseParticipantSettings>(): Promise<ParticipantConfiguration<S>> {
    const data: ParticipantConfiguration<S> = await LoadJSON('participant_settings');

    return data;
}

export function setParticipantFlags<S extends BaseParticipantSettings>(settings: S) {
    const flagActions: Flag[] = [];
    const registerActions: RegisterUpdate[] = [];

    let key: keyof S;
    for(key in settings) {
        if(key === "name") continue;

        const value = settings[key];

        if (typeof value === "boolean") {
            flagActions.push({
                flag_name: `participant:${key.toLowerCase()}`,
                flag_action: value === true ? "give" : "revoke",
            });
        } else {
            registerActions.push({
                register: `participant:${key.toLowerCase()}`,
                action: "set",
                value: value,
            });
        }
    }

    Flags.setOrUnsetFlag(flagActions);
    Registers.setRegisters(registerActions);
}
