import * as LZstring from "lz-string";
import { SendNotification } from "engine/src/system/Notification";
import { ChangeEvent } from "react";
import { SwitchSceneInstant } from "./SceneSwitcher";

// @ts-ignore
import Hashes from "jshashes";
import { LoadScene } from "./DataLoader";
import { BaseGlobalState, ReactState, SettingsState } from "engine/src/state/GlobalState";
import { Scene } from "engine/src/types/Scene";
import { BaseParticipantSettings } from "../ParticipantSettings";

type SavableSettings = Record<string, any>;

type SettingsSaveData = {
    state: SavableSettings,
    saveString: string,
    saveHash: string,
};

let LastSaveHash = "";
let LastSettingsHash = "";

const MD5 = new Hashes.MD5();

export const IsUnsavedChanges = () => {
    const CurrentSaveHash = generateSaveHash();
    return CurrentSaveHash !== LastSaveHash;
};

/**
 * Save the game
 */
export const saveGame = () => {
    // Generate the save game string
    const saveableState = generateSavableState();

    saveCustomGame(saveableState);
};

export function saveSettings() {
    const saveData = generateSettingsSaveData();

    if(LastSettingsHash !== saveData.saveHash) {
        LastSettingsHash = saveData.saveHash;
    
        localStorage.setItem("settings", saveData.saveString);
    }
}

/**
 * Saves the game with the provided state
 */
export const saveCustomGame = (state: SaveableState) => {
    // Genrate the string by compressing it to base64
    const saveableString = LZstring.compressToBase64(JSON.stringify(state));

    LastSaveHash = generateSaveHash();

    // Stringify's the state, base64 encodes it, and zip compresses it.
    localStorage.setItem("game-state", saveableString);
    //
    // Send the game saved notification
    SendNotification({
        type: "regular",
        title: "Saved the Game!",
        description: "The game was successfully saved!",
        color: "orange",
        sound: "hint",
    });
};

/**
 * Export the game save to a file
 */
export const exportSave = () => {
    // Generate the save game string
    const saveableString = LZstring.compressToBase64(
        JSON.stringify(generateSavableState())
    );

    // Create the download link
    let element = document.createElement("a");
    element.className = "debug-button";
    element.setAttribute(
        "href",
        "data:text/plain;charset=utf-8," + saveableString
    );
    element.setAttribute("download", "game.save");

    // Add the download link to the document
    document.body.appendChild(element);

    // Click the download link
    element.click();

    // Remove the download link from the document
    document.body.removeChild(element);

    // Send the game saved notification
    SendNotification({
        type: "regular",
        title: "Exported Save!",
        description: "The game save was successfully exported!",
        color: "orange",
        sound: "hint",
    });
};

/*
 * Load the game
 */
export const loadGame = <ActivityType, MinigameType, S extends BaseParticipantSettings>(
    state: BaseGlobalState<ActivityType, MinigameType, S>
) => {
    // Get the saved string
    const savedString = localStorage.getItem("game-state");

    // Make sure there is a string
    if (savedString === null) return;

    // Load the state
    loadState(savedString, state);
};

export function loadSettings<S extends BaseParticipantSettings>(settings: SettingsState<S>) {
    const savedString = localStorage.getItem("settings");
    if (savedString === null) return;

    const saveData = getSettingsDataFromString(savedString);

    LastSettingsHash = saveData.saveHash;

    loadData(saveData.state, settings, []);
};

function loadData<T>(
    data: Record<string, any>, 
    state: {
        [key in keyof T]: ReactState<any>
    },
    excludeKeys: string[],
) {
    (Object.keys(data) as Array<keyof T>)
        .filter(key => !excludeKeys.includes(key.toString()))
        .forEach(
            (key: keyof T) => {
                try {
                    state[key][1](data[key.toString()]);
                } catch (e) {
                    console.warn(
                        `Unknown state element ${key.toString()} of playerState. Ignoring...`
                    );
                }
            }
        );
}

/**
 * Import a save from a file
 */
export const importSave = <ActivityType, MinigameType, S extends BaseParticipantSettings>(
    state: BaseGlobalState<ActivityType, MinigameType, S>,
    e: ChangeEvent<HTMLInputElement>
) => {
    // Make sure the upload input exists
    if (!e || !e.target || !e.target.files) return;

    // Get the file
    let file = e.target.files[0];
    if (!file) return;

    // Get the reader
    let reader = new FileReader();

    reader.onload = function (e) {
        // Get the saved string
        let savedString = e.target?.result as string;

        // Make sure it exists
        if (!savedString) return;

        // Load the state
        loadState(savedString as string, state);
    };

    // Read the file
    reader.readAsText(file);
};

// The type representing a decoded saved state
type SaveableState = Record<string,
    Record<string, any>
>;

export const generateSavableState = (
): SaveableState => {
    const state = BaseGlobalState.getBaseInstance();
    // Get the state
    return createSaveableState(state);
};

export const createSaveableState = <ActivityType, MinigameType, S extends BaseParticipantSettings>(
    state: BaseGlobalState<ActivityType, MinigameType, S>,
): SaveableState => {
    // Set up the save object
    const saveableState: SaveableState = {};

    for(const categoryKey in state) {
        if(categoryKey === "settingsState")
            continue;
        const category: any = (state[categoryKey as keyof typeof state] as [any, any])[0];
        for(const itemKey in category) {
            const item = category[itemKey as keyof typeof category][0];
            if(itemKey === "notificationQueue") continue;
            if(!saveableState[categoryKey]) saveableState[categoryKey] = {};
            if(itemKey === "scene") {
                saveableState[categoryKey][itemKey] = generateLoadScene((item as Scene).path);
            } else {
                saveableState[categoryKey][itemKey] = item;
            }
        }
    }

    return saveableState;
};

export const generateLoadScene = (path: string) => {
    return {
        path: path,
        name: "loadScene",
        backgrounds: [{ image: "black_screen.jpg" }],
        elements: [],
        action: [],
    };
};

export function generateSettingsSaveData<S extends BaseParticipantSettings>(
    settings?: SettingsState<S>
): SettingsSaveData {
    settings = settings ?? BaseGlobalState.getBaseInstance().settingsState[0] as unknown as SettingsState<S>;
   
    const saveableState = getSavableData(settings, [], {});

    const saveString = stringifySave(saveableState);

    return {
        state: saveableState,
        saveString,
        saveHash: hashSaveString(saveString),
    }
};
function getSavableData<T>(
    object: {
        [key in keyof T]: ReactState<any>
    },
    excludeKeys: string[],
    replaceKeys: Record<string, any>
): Record<string, any> {
    let output: Record<string, any> = {};

    (Object.keys(object) as Array<keyof T>)
        .filter(key => !excludeKeys.includes(key.toString()))
        .forEach((key: keyof T) => {
            if(Object.keys(replaceKeys).includes(key.toString())) {
                output[key.toString()] = replaceKeys[key.toString()]
            } else {
                output[key.toString()] = object[key][0];
            }
        });

    return output;
}

function hashSaveString(saveString: string): string {
    return MD5.b64(saveString);
}


function stringifySave(state: SaveableState | SavableSettings): string {
    return LZstring.compressToBase64(JSON.stringify(state));
}

function getSettingsDataFromString(saveString: string): SettingsSaveData {
    // Get the saved state object from the string
    const savedState = JSON.parse(
        LZstring.decompressFromBase64(saveString)
    ) as SavableSettings;

    return {
        state: savedState,
        saveString,
        saveHash: hashSaveString(saveString)
    }
}

export function hasSavedSettings() {
    const settingsString = localStorage.getItem("settings");

    return !(settingsString === null || settingsString === '');
}

const HASH_IGNORE_KEYS: Array<string> = ["notificationQueue"];

const generateSaveHash = (): string => {
    const state = BaseGlobalState.getBaseInstance();

    // Set up the save object
    const saveableState: SaveableState = {
        playerState: {},
        phoneState: {},
        gameState: {},
    };

    for(const categoryKey in state) {
        const category: any = (state[categoryKey as keyof typeof state] as [any, any])[0];
        for(const itemKey in category) {
            const item = category[itemKey as keyof typeof category][0];
            if(!HASH_IGNORE_KEYS.includes(itemKey)) {
                if(!saveableState[categoryKey]) saveableState[categoryKey] = {};
                saveableState[categoryKey][itemKey] = item;
            }
        }
    }

    // Genrate the string by compressing it to base64
    const string = LZstring.compressToBase64(JSON.stringify(saveableState));

    // return the string
    return MD5.b64(string);
};

const generateLoadHash = (savedString: string): string => {
    // Get the saved state object from the string
    const state = JSON.parse(
        LZstring.decompressFromBase64(savedString)
    ) as SaveableState;

    const hashableState: SaveableState = {
        playerState: {},
        phoneState: {},
        gameState: {},
    };

    for(const categoryKey in state) {
        const category = state[categoryKey as keyof typeof state];
        for(const itemKey in category) {
            const item = category[itemKey as keyof typeof category];
            if(!HASH_IGNORE_KEYS.includes(itemKey)) {
                if(!hashableState[categoryKey]) hashableState[categoryKey] = {};
                hashableState[categoryKey][itemKey] = item;
            }
        }
    }

    const string = LZstring.compressToBase64(JSON.stringify(hashableState));

    return MD5.b64(string);
};

const loadState = <ActivityType, MinigameType, S extends BaseParticipantSettings>(
    savedString: string,
    state: BaseGlobalState<ActivityType, MinigameType, S>
) => {
    // Get the saved state object from the string
    const savedState = JSON.parse(
        LZstring.decompressFromBase64(savedString)
    ) as SaveableState;

    const scene = structuredClone(savedState.coreState.scene);
    delete savedState.coreState.scene;

    LastSaveHash = generateLoadHash(savedString);

    for(const categoryKey in savedState) {
        const category = savedState[categoryKey];
        for(const itemKey in category) {
            const item = category[itemKey as keyof typeof category];
            if(!["phoneOpen", "scene", "popup"].includes(itemKey)) {
                (state[categoryKey as keyof typeof state] as [Record<string, ReactState<any>>, any])[0][itemKey][1](item);
            }
        }
    }

    // Set the Flags
    state.coreState[0].unlockedFlags[1](savedState.coreState.unlockedFlags);

    state.coreState[0].popup[1](null);

    setTimeout(() => {

        LoadScene(scene.path).then((s) => {
            SwitchSceneInstant(s, state.coreState[0], state.coreState[0].phoneOpen[1], () => {});
        });

        setTimeout(() => {
            state.coreState[0].dialogHistory[1](savedState.coreState.dialogHistory);
        }, 100);

        SendNotification(
            {
                type: "regular",
                title: "Loaded Game!",
                description: "Your game has been loaded!",
                color: "orange",
                sound: "hint",
            }
        );
    }, 100);
};
