import styles from "#styles/activities/renderers/total.module.css";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { join } from "engine/src/system/Styles";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const TotalActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "total"
> = (_element, _playerData, _updateState, [bound]) => {
    const positive = !(bound.total || "0").includes("-");
    return {
        appView: (
            <div
                className={join(
                    styles,
                    `total`,
                    positive ? "positive" : "negative"
                )}
            >
                <span>Total</span>
                <b>{bound.total}</b>
            </div>
        ),
        printView: (
            <div
                className={join(
                    styles,
                    `total`,
                    positive ? "positive" : "negative"
                )}
            >
                <span>Total</span>
                <b>{bound.total}</b>
            </div>
        ),
    };
};

export const DefaultTotalActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "total"
> = () => {
    return {
        type: "total",
        complete: true,
    };
};
