import { BaseGlobalState, getBaseGlobalState } from "engine/src/state/GlobalState";

let ignored: Record<string, number[]> | null = null;
let current: Record<string, AudioBufferSourceNode> = {};
let loading: string[] = [];

const context = new AudioContext();
const masterMixer = context.createGain();
masterMixer.connect(context.destination);
const soundsMixer = context.createGain();
soundsMixer.connect(masterMixer);
const musicMixer = context.createGain();
musicMixer.connect(masterMixer);
const voiceMixer = context.createGain();
voiceMixer.connect(masterMixer);

const mixer = {
    sounds: soundsMixer,
    music: musicMixer,
    voice: voiceMixer,
    master: masterMixer,
};

const LoadAudio = async (fileName: string) => {
    const file = await fetch(`assets/sounds/${fileName}`);
    const arrayBuffer = await file.arrayBuffer();
    try {
        const audioBuffer = await context.decodeAudioData(arrayBuffer);
        return audioBuffer;
    } catch (err) {
        console.error(`Failed to load audio file for ${fileName}`);
    }
    return null;
};

let musicSeq = 0;
let ambienceSeq = 0;

export const PlayAudio = async (
    name: string,
    type: keyof typeof mixer | number,
    loop: boolean = false,
    restart: boolean = false
) => {
    if ((current[name] || loading.includes(name)) && !restart) return null;
    if (current[name]) {
        StopAudio(name);
    }

    loading.push(name);

    const isMusic = name.startsWith("music");
    const isAmb = name.startsWith("ambience");
    const mySeq = isMusic ? ++musicSeq : isAmb ? ++ambienceSeq : 0;

    const audioData = await LoadAudio(name);

    if (!audioData) {
        loading = loading.filter((n) => n !== name);
        return null;
    }

    if (isMusic && mySeq !== musicSeq) {
        loading = loading.filter((n) => n !== name);
        return null;
    }
    if (isAmb && mySeq !== ambienceSeq) {
        loading = loading.filter((n) => n !== name);
        return null;
    }
    if (isMusic) StopAllAudio("music");
    if (isAmb) StopAllAudio("ambience");

    const source = new AudioBufferSourceNode(context, {
        buffer: audioData,
        playbackRate: 1,
    });
    let gain: undefined | GainNode = undefined;
    if (typeof type === "number") {
        gain = context.createGain();
        gain.gain.setValueAtTime(type / 100, context.currentTime);
        gain.connect(context.destination);
        source.connect(gain);
    } else {
        source.connect(mixer[type]);
    }
    source.loop = loop;
    source.start();
    source.addEventListener("ended", () => {
        if (gain) gain.disconnect();
        source.disconnect();
        delete current[name];
    });
    current[name] = source;
    loading = loading.filter((n) => n !== name);

    return source;
};

export const StopAudio = (name: string) => {
    if (!current[name]) return;

    current[name].stop();
    current[name].disconnect();
    delete current[name];
};

export const StopAllAudio = (prefix?: string) => {
    for (const key in current) {
        if (!prefix || key.startsWith(prefix)) {
            StopAudio(key);
        }
    }
};

export const UpdateMixerVolume = (
    mixerName: keyof typeof mixer,
    value: number
) => {
    mixer[mixerName].gain.setValueAtTime(value / 100, context.currentTime);
};

export const IsAudioPlaying = (name: string) =>
    Object.keys(current).includes(name);

export const ListAllAudio = () => {
    return Object.keys(current);
};

export const PlayVoiceLine = async (
    dialogName: string,
    dialogIndex: number,
    source: string,
    playerVoiceModifier: string,
    bypassPopup: boolean = false
): Promise<AudioBufferSourceNode | null> => {
    const settings = BaseGlobalState.getBaseInstance().settingsState[0];
    const [participantSettings] = settings.participantSettings;

    if (!participantSettings.EnableVoiceLines) {
        return new Promise((resolve) => resolve(null));
    }

    if (ignored === null) {
        let res = await fetch("assets/sounds/voice-lines/ignored.json");
        ignored = await res.json();
    }

    if (
        ignored &&
        ignored[dialogName] &&
        ignored[dialogName].includes(dialogIndex)
    ) {
        return new Promise((resolve) => resolve(null));
    }

    const globalState = BaseGlobalState.getBaseInstance();
    const [popup] = globalState.coreState[0].popup;

    StopAllAudio("voice-lines");

    if (popup !== null && !bypassPopup) {
        return null;
    }

    let voiceFilePath: string;
    if (source === "%player%") {
        voiceFilePath = `voice-lines/${dialogName}/${playerVoiceModifier.toLowerCase()}/${dialogIndex}.mp3`;
    } else {
        voiceFilePath = `voice-lines/${dialogName}/${dialogIndex}.mp3`;
    }

    return await PlayAudio(voiceFilePath, "voice");
};
