import { BaseGlobalState } from "engine/src/state/GlobalState";
import { RegisterCondition, RegisterUpdate, TextRegisterUpdate } from "../types/Register";

const Registers = {
    getRegister: (name: string, defaultValue?: number) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [registers] = coreState.registers;

        let value: number | string = registers[name];
        if(value !== undefined) {
            return value;
        }

        return defaultValue || 0;
    },

    getTextRegister: (name: string, defaultValue?: string) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [textRegisters] = coreState.textRegisters;

        const value = textRegisters[name];
        if(value !== undefined) {
            return value;
        }

        return defaultValue || "";
    },

    setRegisters: (registerUpdates: RegisterUpdate[]) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [, setRegisters] = coreState.registers;

        setRegisters(registers => {
            const newRegisters = structuredClone(registers);

            registerUpdates.forEach(update => {
                if(update.action === "delete") {
                    delete newRegisters[update.register];
                    return;
                }

                let newValue = registers[update.register];
                let otherValue = undefined;
                if(typeof(update.value) === typeof(0)) {
                    otherValue = update.value as number;
                } else {
                    otherValue = registers[update.value];
                }

                if(otherValue !== undefined) {
                    switch (update.action) {
                        case "set":
                            newValue = otherValue;
                            break;
                        case "add":
                            newValue += otherValue;
                            break;
                        case "subtract":
                            newValue -= otherValue;
                            break;
                        case "multiply":
                            newValue *= otherValue;
                            break;
                    }
                }
                newRegisters[update.register] = newValue;
            });

            return newRegisters;
        });
    },

    setTextRegisters: (registerUpdates: TextRegisterUpdate[]) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [, setRegisters] = coreState.textRegisters;

        setRegisters(registers => {
            const newRegisters = structuredClone(registers);

            registerUpdates.forEach(update => {
                if(update.action === "delete") {
                    delete newRegisters[update.register];
                    return;
                } else {
                    if(registers[update.value] !== undefined) {
                        newRegisters[update.register] = registers[update.value];
                    } else {
                        newRegisters[update.register] = update.value;
                    }
                }
            });

            return newRegisters;
        });
    },

    checkConditions: (conditions: RegisterCondition[]) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [registers] = coreState.registers;

        let allTrue = true;

        conditions.forEach(condition => {
            const value = registers[condition.register];
            
            if(value !== undefined) {
                let otherValue = undefined;
                if(typeof(condition.value) === typeof(0)) {
                    otherValue = condition.value as number;
                } else {
                    otherValue = registers[condition.value];
                }

                if(otherValue === undefined) {
                    return;
                }

                switch (condition.condition) {
                    case ">":
                        if(!(value > otherValue)) allTrue = false
                        break;
                    case "<":
                        if(!(value < otherValue)) allTrue = false
                        break;
                    case ">=":
                        if(!(value >= otherValue)) allTrue = false
                        break;
                    case "<=":
                        if(!(value <= otherValue)) allTrue = false
                        break;
                    case "==":
                        if(!(value === otherValue)) allTrue = false
                        break;
                }
            } else {
                allTrue = false;
            }
        });

        return allTrue;
    }
}


export default Registers;
