import styles from "../../styles/popup/AppProtection.module.css";
import { ALLOW_NO_DATABASE } from "engine/src/ParticipantSettings";
import { useContext, useEffect, useRef, useState } from "react";
import { BaseGlobalState, ReactSetter } from "engine/src/state/GlobalState";

import { parseCookie, delete_cookie } from "engine/src/utils/cookie";
import { BackendBuilder, SetBackend } from "engine/src/system/BackendSystem";
import { joinWithOverride } from "../../system/Styles";

async function sha256(message: string): Promise<string> {
    // encode as UTF-8
    const msgBuffer = new TextEncoder().encode(message);

    // hash the message
    const hashBuffer = await crypto.subtle.digest("SHA-256", msgBuffer);

    // convert ArrayBuffer to Array
    const hashArray = Array.from(new Uint8Array(hashBuffer));

    // convert bytes to hex string
    const hashHex = hashArray
        .map((b) => b.toString(16).padStart(2, "0"))
        .join("");
    return hashHex;
}

/* checksum formula based on this:
https://boxshot.com/barcode/tutorials/ean-13-calculator/#:~:text=Check%20Digit%20Formula&text=Sum%20all%20the%20digits%20in,0%2C%20subtract%20it%20from%2010. */
function validateParticipantID(user: string) {
    const userID = user.trim();
    const isNumber = /^[0-9]+$/.test(userID);
    const EXPECTED_LENGTH = 5;

    if (ALLOW_NO_DATABASE && userID.length === 0) {
        return true;
    }
    if (!isNumber || userID.length !== EXPECTED_LENGTH) {
        return false;
    }

    let evenPosSum = 0;
    let oddPosSum = 0;

    for (let i = 0; i < EXPECTED_LENGTH - 1; i += 2) {
        evenPosSum += parseInt(userID[i + 1]);
        oddPosSum += parseInt(userID[i]);
    }
    evenPosSum *= 3;

    let checkSum = (oddPosSum + evenPosSum) % 10;
    if (checkSum !== 0) {
        checkSum = 10 - checkSum;
    }

    if (parseInt(userID[EXPECTED_LENGTH - 1]) === checkSum) {
        return true;
    }

    return false;
}

const AppProtection = ({
    authenticated,
    setAuthenticated,
    signedIn,
    setSignedIn,
    defaultBackend,
    styleOverride,
}: {
    authenticated: boolean;
    setAuthenticated: ReactSetter<boolean>;
    signedIn: boolean;
    setSignedIn: ReactSetter<boolean>;
    defaultBackend: BackendBuilder;
    styleOverride?: any;
}) => {
    const coreState = useContext(BaseGlobalState.getBaseInstance().coreState[1]);
    const [hashedPassword, setHashedPassword] = useState(
        "default_hash_change_me"
    );
    let savedPasswordHash = "";

    const cookie = parseCookie(document.cookie);
    if (!Object.keys(cookie).includes("password")) {
        document.cookie = "";
    } else {
        savedPasswordHash = cookie.password;
    }

    useEffect(() => {
        fetch("data/password.txt").then((res) =>
            res.text().then((password) => {
                setAuthenticated(password === savedPasswordHash);
                setHashedPassword(password);
            })
        );
    }, [savedPasswordHash, setAuthenticated, setHashedPassword]);

    useEffect(() => {
        if (authenticated || hashedPassword === "default_hash_change_me") {
            if (Object.keys(cookie).includes("user"))
                SetBackend(defaultBackend, coreState.appEnabled[1]);
            return;
        }
    }, [authenticated, hashedPassword, cookie, coreState.appEnabled]);

    return authenticated && signedIn ? (
        <></>
    ) : authenticated ? (
        <div className={joinWithOverride(styles, styleOverride, "signIn")}>
            <main>
                <h1>Welcome Back!</h1>
                <i>User Id: {cookie.user || "Developer"}</i>
                <button
                    onClick={() => {
                        setSignedIn(true);
                    }}
                >
                    Signin
                </button>
                <button
                    onClick={() => {
                        delete_cookie("user");
                        delete_cookie("password");
                        window.location.reload();
                        window.location.href = window.location.href;
                    }}
                >
                    Use another account
                </button>
            </main>
        </div>
    ) : (
        <div className={joinWithOverride(styles, styleOverride, "signIn")}>
            <main>
                <h1>Sign In</h1>
                <i>To use this application, you must first sign in.</i>
                <form
                    onSubmit={async (e) => {
                        e.preventDefault();
                        const pass = document.getElementById(
                            "password"
                        ) as HTMLInputElement;
                        const user = document.getElementById(
                            "user_id"
                        ) as HTMLInputElement;
                        if (
                            (await sha256(pass.value)) === hashedPassword &&
                            validateParticipantID(user.value)
                        ) {
                            setAuthenticated(true);
                            setSignedIn(true);
                            document.cookie =
                                "password=" + (await sha256(pass.value));
                            if (user.value.trim() !== "") {
                                SetBackend(
                                    defaultBackend,
                                    coreState.appEnabled[1]
                                );
                                document.cookie = "user=" + user.value;
                            }
                        } else if (!validateParticipantID(user.value)) {
                            alert("Invalid Participant ID");
                        } else {
                            alert("Invalid Password");
                        }
                    }}
                >
                    <p>
                        <input
                            id="user_id"
                            type="text"
                            placeholder="Participant ID"
                        />
                    </p>
                    <p>
                        <input
                            id="password"
                            type="password"
                            placeholder="Password"
                        />
                    </p>
                    <button type="submit">Sign In</button>
                </form>
            </main>
        </div>
    );
};

export default AppProtection;
