import { useGlobalState } from "../../state/GlobalState";
import styles from "#styles/popup/EndGame.module.css";
import { LoadScene } from "engine/src/system/DataLoader";
import { join } from "engine/src/system/Styles";

const EndGame = () => {
    const { coreState } = useGlobalState();

    const setPopup = coreState.popup[1];
    const setScene = coreState.scene[1];
    const setPhoneOpen = coreState.phoneOpen[1];

    const [, setNotificationQueue] = coreState.notificationQueue;

    LoadScene("endgame").then((scene) => {
        setScene(scene);
    });
    setPhoneOpen(false);

    return (
        <>
            <div className={join(styles, "endgame-container")}>
                <video
                    onLoadStart={() => {
                        setNotificationQueue({});
                    }}
                    id="endgame-video"
                    className={join(styles, "endgame-video")}
                    src="assets/videos/endgame.mp4"
                    autoPlay={true}
                    onEnded={() => {
                        const video = document.getElementById(
                            "endgame-video"
                        ) as HTMLVideoElement;
                        const background = document.getElementById(
                            "endgame-background"
                        ) as HTMLDivElement;

                        video.classList.add("anim");
                        background.classList.add("anim");

                        setTimeout(() => {
                            setPopup("credits");
                        }, 1000);
                    }}
                />
            </div>
            <div
                id="endgame-background"
                className={join(styles, "endgame-background")}
                style={{
                    backgroundImage:
                        "url(assets/images/backgrounds/endgame.webp)",
                }}
            />
        </>
    );
};

export default EndGame;
