import { getGlobalState } from "../state/GlobalState";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { LoadScene } from "engine/src/system/DataLoader";
import Flags from "engine/src/system/Flags";
import Registers from "engine/src/system/Registers";
import { PauseAfterChapter } from "../Config";

/**
 * The Chapter system
 */
const ChapterChanger = {
    // Change the current chapter
    setChapter: (chapter: number) => {
        const { coreState } = getGlobalState();

        const [, setPopup] = coreState.popup;
        const [, setScene] = coreState.scene;

        const previousChapter = Registers.getRegister("chapter");

        // Set the chapter number
        Registers.setRegisters([
            {
                register: "chapter",
                action: "set",
                value: chapter,
            },
        ]);

        if (PauseAfterChapter === previousChapter) {
            setPopup("pauseChapter");
        } else {
            setPopup("newChapter");
        }

        // Play the audio
        PlayAudio("bumper-sticker-chapter-change-unlock.wav", "sounds");
        Flags.setOrUnsetFlag([
            {
                flag_name: `bumper_sticker_unlocked:chapter_${chapter}`,
                flag_action: "give",
            },
            {
                flag_name: `chapter${previousChapter}:complete`,
                flag_action: "revoke",
            },
            {
                flag_name: `chapter${previousChapter}:set`,
                flag_action: "revoke",
            },
            {
                flag_name: `chapter${chapter}:set`,
                flag_action: "give",
            },
            {
                flag_name: "time:night",
                flag_action: "revoke",
            },
        ]);

        // Set the scene after 1 second
        setTimeout(() => {
            LoadScene("home/room").then((result) => {
                setScene(result);
            });
        }, 1000);
    },
};

export default ChapterChanger;
