import styles from "#styles/activities/renderers/verticallist.module.css";
import { join } from "engine/src/system/Styles";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";
import { editState } from "../../../state/Util";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
    calculateBoundBindings,
} from "engine/src/components/popup/ActivityComponent";
import { Activities } from "../../../types/Activity";

export const VerticalListActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "verticallist"
> = (
    element,
    playerData,
    updateState,
    [_bound, updateBinding, bindings],
    registry
) => {
    const updateActivityData = (i: number, b: ActivityElementPlayerData) => {
        editState(playerData, updateState, (old) => {
            old.elements[i] = b;
            old.complete =
                old.elements.map((elem) => elem.complete).filter((c) => c)
                    .length > 0;
            return old;
        });
    };
    return {
        appView: (
            <div
                key="a"
                className={join(styles, "verticallist")}
                style={{
                    display: "flex",
                    flexDirection: "column",
                    justifyContent: "space-between",
                    alignItems: "center",
                }}
            >
                <strong className={`title`}>{element.title}</strong>
                {element.elements.map((a, i) => (
                    <div key={i}>
                        {
                            registry[a.type].renderer(
                                a as never,
                                playerData.elements[i] as never,
                                (b: ActivityElementPlayerData) => {
                                    updateActivityData(i, b);
                                },
                                [
                                    calculateBoundBindings(bindings, a),
                                    updateBinding,
                                    bindings,
                                ],
                                registry
                            ).appView
                        }
                    </div>
                ))}
            </div>
        ),
        printView: (
            <div key="a">
                <div
                    key="a"
                    className={join(styles, "verticallist")}
                    style={{
                        display: "flex",
                        flexDirection: "column",
                        justifyContent: "space-between",
                    }}
                >
                    <strong className={`title`}>{element.title}</strong>
                    {element.elements.map((a, i) => (
                        <div key={i}>
                            {
                                registry[a.type].renderer(
                                    a as never,
                                    playerData.elements[i] as never,
                                    (b: ActivityElementPlayerData) => {
                                        updateActivityData(i, b);
                                    },
                                    [
                                        calculateBoundBindings(bindings, a),
                                        updateBinding,
                                        bindings,
                                    ],
                                    registry
                                ).printView
                            }
                        </div>
                    ))}
                </div>
            </div>
        ),
    };
};

export const DefaultVerticalListActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "verticallist"
> = (element, registry) => {
    const elements = element.elements.map((elem) =>
        registry[elem.type].dataGenerator(elem as never, registry)
    );

    const complete =
        elements.map((elem) => elem.complete).filter((c) => c).length > 0;

    return {
        type: "verticallist",
        complete: complete,
        elements: elements,
    };
};
