import { PlayAudio } from "engine/src/system/AudioSystem";
import { BaseGlobalState } from "engine/src/state/GlobalState";
import { Notification } from "engine/src/types/Notification";
import { dialogClean } from "./Dialog";

/**
 * Send a notification
 */
export const SendNotification = (
    notification: Notification,
    volume?: number
) => {
    // Get the state
    const coreState = BaseGlobalState.getBaseInstance().coreState[0];
    const [, setNotificationQueue] = coreState.notificationQueue;
    const [notificationCounter, setNotificationCounter] =
        coreState.notificationCounter;

    PlayAudio(
        `notifications/${notification.sound}.wav`,
        volume ? volume : "sounds"
    );
    // Set the state
    setNotificationQueue((val) => {
        return {
            ...val,
            [notificationCounter]: {
                ...notification,
                description: dialogClean(notification.description),
            }
        }
    });

    setNotificationCounter((n) => n + 1);
};
