import { TodoList, useGlobalState } from "../../state/GlobalState";
import styles from "#styles/apps/JournalApp.module.css";
import { join } from "engine/src/system/Styles";
import { GenericListApp } from "./GenericListApp";

type TodoItem = {
    type: "item";
    item: string;
    complete: boolean;
    failed?: boolean;
};

type ItemData =
    | {
          type: "chapter";
          chapter: number;
          items: TodoItem[];
      }
    | TodoItem;

/**
 * The Todo App
 */
export const TodoApp = ({ closeApp }: { closeApp: () => void }) => {
    const { playerState } = useGlobalState();

    const todoList = playerState.todoList[0];

    const pages: {
        name: string;
        title: string;
        description: JSX.Element;
        data: ItemData[];
    }[] = [
        {
            name: `To-do: Story`,
            title: `To-do: Story`,
            description: <p></p>,
            data: getStoryData(todoList),
        },
        {
            name: `To-do: Optional`,
            title: `To-do: Optional`,
            description: <p></p>,
            data: getOptionalData(todoList),
        },
    ];

    return (
        <GenericListApp
            title={`Achievements`}
            closeApp={closeApp}
            pages={pages}
            elementsSelectable={false}
            ItemComponent={ItemComponent}
        />
    );
};

function ItemComponent({ item, index }: { item: ItemData; index: number }) {
    if (item.type === "item") {
        return <Item item={item} />;
    }

    return (
        <div key={item.chapter}>
            <h2>
                {item.chapter === 0
                    ? "Uncategorized"
                    : `Chapter ${item.chapter}`}
            </h2>
            <ul>
                {item.items.map((entry, index) => (
                    <Item key={index} item={entry} />
                ))}
            </ul>
        </div>
    );
}

function Item({ item }: { item: TodoItem }) {
    const className = join(
        styles,
        item.failed ? "failed" : item.complete ? "complete" : ""
    );
    return <li className={className}>{item.item}</li>;
}

/**
 * The todo list story page
 */
function getStoryData(todoList: TodoList): ItemData[] {
    // Group by chapter number (defaulting to 0 if missing)
    const grouped: Record<
        number,
        { item: string; complete: boolean; failed?: boolean }[]
    > = {};

    todoList.story.forEach((entry) => {
        const chapter = entry.chapter ?? 0;
        if (!grouped[chapter]) grouped[chapter] = [];
        grouped[chapter].push(entry);
    });

    const sortedChapters = Object.keys(grouped)
        .map(Number)
        .sort((a, b) => b - a);

    return sortedChapters.map((chapter) => {
        return {
            type: "chapter",
            chapter,
            items: grouped[chapter]
                .sort((a, b) => {
                    const aDone = a.complete || a.failed;
                    const bDone = b.complete || b.failed;

                    if (aDone && !bDone) return 1;
                    if (!aDone && bDone) return -1;
                    return 0;
                })
                .map((item) => {
                    return {
                        type: "item",
                        ...item,
                    };
                }),
        };
    });
}

/**
 * The todo list optional page
 */
function getOptionalData(todoList: TodoList): ItemData[] {
    return todoList.optional
        .sort((a, b) => {
            const aDone = a.complete || a.failed;
            const bDone = b.complete || b.failed;

            if (aDone && !bDone) return 1;
            if (!aDone && bDone) return -1;
            return 0;
        })
        .map((item) => {
            return {
                type: "item",
                ...item,
            };
        });
}
