import {
    GenericAction,
    GenericConditionalAction,
} from "engine/src/types/Action";
import Flags from "engine/src/system/Flags";
import { SendNotification } from "engine/src/system/Notification";
import { PlayAudio } from "engine/src/system/AudioSystem";
import {
    LoadActivity,
    LoadScene,
    loadAppropriateDialog,
    LoadMinigame,
} from "engine/src/system/DataLoader";
import { SwitchScene } from "engine/src/system/SceneSwitcher";
import Registers from "engine/src/system/Registers";
import {
    SendActivityStarted,
    SendMinigameStarted,
} from "engine/src/system/BackendSystem";
import { BaseGlobalState } from "engine/src/state/GlobalState";
import { GenericConditionalElement } from "engine/src/types/Scene";

type ConditionChecker<
    ActionType extends
        | GenericConditionalAction<string>
        | GenericConditionalElement<string>,
> = (arg0: ActionType) => boolean;
const conditionalHandlers: Record<string, ConditionChecker<any>> = {
    flag: (action) => {
        for (const flag of action.flags) {
            if (!Flags.checkFlag(flag)) return false;
        }
        return true;
    },
    register: (action) => {
        return Registers.checkConditions(action.conditions);
    },
    negateFlag: (action) => {
        for (const flag of action.flags) {
            if (!Flags.checkFlag(flag)) return true;
        }
        return false;
    },
    flagOr: (action) => {
        return Flags.checkFlagsOr(action.flags);
    },
    scene: (action) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [scene] = coreState.scene;
        return scene.name === action.scene;
    },
    true: () => {
        return true;
    },
    probability: (action) => {
        const randomNumber = Math.random();
        return Number(action.probability) >= randomNumber;
    },
    repeat: (action) => {
        const isContinuous = action.repeat_type === "continuous";
        const isFixed = action.repeat_type === "fixed";

        const currentCount = Registers.getRegister(`repeat:${action.name}`);

        if (currentCount === 0) {
            Registers.setRegisters([
                {
                    register: `repeat:${action.name}`,
                    action: "set",
                    value: 1,
                },
            ]);

            return isContinuous;
        }

        if (currentCount < action.repeat - 1) {
            Registers.setRegisters([
                {
                    register: `repeat:${action.name}`,
                    action: "add",
                    value: 1,
                },
            ]);

            return isContinuous;
        }
        return isFixed;
    },
};

/**
 * Checks to see if a conditional action's condition is met
 */
export const CheckCondition = <
    ActionType extends GenericConditionalAction<string>,
    ElementType extends GenericConditionalElement<string>,
>(
    action: ActionType | ElementType
): boolean => conditionalHandlers[action.condition](action);

const actionQueue: GenericAction<string>[] = [];
let running = false;

export const HandleAction = <ActionType extends GenericAction<string>>(
    action: ActionType
): void => {
    actionQueue.push(action);
    if (!running) {
        running = true;
        setTimeout(StartActionExecutor, 1);
    }
};

export const HandleActions = <ActionType extends GenericAction<string>>(
    actions: Array<ActionType>
): void => {
    actions.forEach((action) => {
        actionQueue.push(action);
    });
    if (!running) {
        running = true;
        setTimeout(StartActionExecutor, 1);
    }
};

export const IsActionQueued = (action_type: string) => {
    for (const action of actionQueue) {
        if (action.type === action_type) return true;
    }
    return false;
};

export const StartActionExecutor = () => {
    if (actionQueue.length > 0) {
        DequeueAction(actionQueue.shift() as GenericAction<string>);
        setTimeout(StartActionExecutor, 0);
    } else {
        running = false;
    }
};

type ActionHandler<ActionType extends GenericAction<string>> = (
    arg0: ActionType
) => GenericAction<string>[] | void;

const handlers: Record<string, ActionHandler<any>[]> = {
    // A void action means do nothing
    void: [() => {}],
    // A go_to_scene action loads a scene, then sets the scene
    go_to_scene: [
        (action) => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            const scene = coreState.scene[0];
            const setTransitioning = coreState.transitioning[1];
            if (scene.name !== action.scene) {
                setTransitioning(true);
                setTimeout(() => {
                    LoadScene(action.scene).then((scene) => {
                        SwitchScene(scene, coreState, undefined, () =>
                            PlayAudio("go-to-scene.mp3", "sounds")
                        );
                    });
                }, 200);
            }
        },
    ],
    change_background: [
        (action) => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            const setSceneBackground = coreState.sceneBackground[1];
            setSceneBackground(action.index);
        },
    ],
    hint: [
        (action) => {
            SendNotification({
                type: "permenant",
                title: `Hint: ${action.title}`,
                description: action.description,
                flag: action.flag,
                color: "red",
                sound: "hint",
            });
        },
    ],
    notification: [
        (action) => {
            const sound = action.sound || "hint";
            SendNotification({
                type: "regular",
                title: action.title,
                description: action.description,
                color: action.color,
                sound: sound,
            });
        },
    ],
    open_popup: [
        (action) => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            const [, setPopup] = coreState.popup;
            setPopup(action.popup);
        },
    ],
    activity: [
        (action) => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            const [, setPopup] = coreState.popup;
            LoadActivity<any>(action.activity).then((activity) => {
                SendActivityStarted(activity.name, coreState.appEnabled[1]);
                coreState.activity[1](activity);
                setPopup("activity");
            });
        },
    ],
    minigame: [
        (action) => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            LoadMinigame<any>(action.minigame).then((minigame) => {
                SendMinigameStarted(minigame.type, coreState.appEnabled[1]);
                coreState.minigame[1](minigame);
                coreState.popup[1]("minigame");
            });
        },
    ],

    // An open_dialog action loads a digital_dialog, then sets the digital_dialog
    open_dialog: [
        (action) => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            const [, setDialog] = coreState.dialog;
            const [, setLoadingDialog] = coreState.loadingDialog;

            setLoadingDialog(true);
            const dialogPath = action.dialog[0]; // Assuming action.dialog contains one directory path... we can change this back later to the way it was before but it is not important
            loadAppropriateDialog(dialogPath).then((dialog) => {
                setDialog(dialog);
                setLoadingDialog(false);
            });
        },
    ],
    // A close_dialog action closes the currently open digital_dialog
    close_dialog: [
        () => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            const [, setDialog] = coreState.dialog;
            setDialog(null);
        },
    ],
    // a flag action grants or revokes a flag
    flag: [
        (action) => {
            Flags.setOrUnsetFlag(action.flag);
        },
    ],
    // a register action updates the value of a register
    register: [
        (action) => {
            Registers.setRegisters(action.registerActions);
        },
    ],
    text_register: [
        (action) => {
            Registers.setTextRegisters(action.registerActions);
        },
    ],
    document: [
        (action) => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            if (!action.open) return;
            fetch(`data/documents.json`).then(async (result) => {
                const json = await result.json();
                coreState.popupStateData[1](json[action.document]);
                coreState.popup[1]("document");
            });
        },
    ],
    // A conditional digital_dialog runs another action if the condition is met
    conditional: [
        (action) => {
            if (CheckCondition(action)) return action.actions;
            return action.else_actions;
        },
    ],

    // A combo action runs multiple actions
    combo: [
        (action) => {
            return action.actions;
        },
    ],
    // A waterfall action attempts to handle conditional actions in sequence.
    // The first one to be handled will be the only one handled.
    // This is useful for effects based on the progress through the game.
    waterfall: [
        (action) => {
            for (const a of action.actions) {
                if (CheckCondition(a)) {
                    return a.actions;
                }
            }
        },
    ],
};

/**
 * Handle an action
 */
const DequeueAction = <ActionType extends GenericAction<string>>(
    action: ActionType
): void => {
    if (
        !action ||
        !action.type ||
        !Object.keys(handlers).includes(action.type)
    ) {
        console.warn(
            "Tried to run unregistered action!",
            action,
            "skipping..."
        );
        return;
    }
    return handlers[action.type]
        .map((handler) => handler(action))
        .forEach((children) => (children ? HandleActions(children) : {}));
};

export const RegisterActionHandler = <ActionType extends GenericAction<string>>(
    type: ActionType["type"],
    handler: (arg0: ActionType) => GenericAction<string>[] | void
) => {
    if (!handlers[type]) handlers[type] = [];
    handlers[type].push(handler);
};
