import React, { useEffect, useState } from "react";
import styles from "#styles/activities/renderers/checklist_advanced2.module.css";
import { join } from "engine/src/system/Styles";
import { Activities } from "../../../types/Activity";
import {
    ActivityElementPlayerData,
    AdvancedChecklistActivity2PlayerData,
} from "../../../types/ActivityPlayerData";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { editState } from "../../../state/Util";
import { keyDownHandler } from "engine/src/system/Keyboard";

export const AdvancedChecklistActivity2Renderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "checklist_advanced_2"
> = (element, playerData, updateState, [_0, updateBinding, _1]) => {
    const handleChangeSelection = (index: number, localIndex: number) => {
        editState(playerData, updateState, (data) => {
            if (!data.indices) {
                data.indices = [];
            }
            data.indices[index] = localIndex;
            let complete = true;
            for (let i = 0; i < element.questions.length; i++) {
                if (data.indices[i] === undefined) {
                    complete = false;
                    break;
                }
            }
            data.complete = complete;

            return data;
        });
    };

    return {
        appView: (
            <React.Fragment key={element.header}>
                {element.header && (
                    <div className={join(styles, "checklist-header")}>
                        <p>{element.header}</p>
                    </div>
                )}
                <table className={join(styles, "checklist")}>
                    <thead>
                        <tr>
                            <th className={join(styles, "checklist th")}></th>

                            {element.table_headers.map((header, index) => (
                                <th
                                    key={index}
                                    className={join(styles, "checklist th")}
                                >
                                    {header}
                                </th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {element.questions.map((question, qindex) => {
                            return (
                                <tr>
                                    <td>{question.question}</td>
                                    {element.scaleTitles.map((title, i) => {
                                        return (
                                            <td
                                                className={join(
                                                    styles,
                                                    playerData.indices
                                                        ? `${
                                                              playerData
                                                                  .indices[
                                                                  qindex
                                                              ] === i
                                                          }`
                                                        : false,
                                                    `radio-container`
                                                )}
                                                key={`${question.question}-${title}`}
                                            >
                                                <input
                                                    type="radio"
                                                    id={`${qindex}-${i}`}
                                                    checked={
                                                        playerData.indices
                                                            ? playerData
                                                                  .indices[
                                                                  qindex
                                                              ] === i
                                                            : false
                                                    }
                                                    onChange={() =>
                                                        handleChangeSelection(
                                                            qindex,
                                                            i
                                                        )
                                                    }
                                                />
                                                <label
                                                    htmlFor={`${qindex}-${i}`}
                                                    tabIndex={0}
                                                    onKeyDown={keyDownHandler(
                                                        ["Enter"],
                                                        () => {
                                                            handleChangeSelection(
                                                                qindex,
                                                                i
                                                            );
                                                        }
                                                    )}
                                                >
                                                    <span>{title}</span>
                                                </label>
                                            </td>
                                        );
                                    })}
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </React.Fragment>
        ),
        printView: (
            <React.Fragment key={element.header}>
                {element.header && (
                    <div className={join(styles, "checklist-header")}>
                        <p>{element.header}</p>
                    </div>
                )}
                <table className={join(styles, "checklist")}>
                    <thead>
                        <tr>
                            <th className={join(styles, "checklist th")}></th>

                            {element.table_headers.map((header, index) => (
                                <th
                                    key={index}
                                    className={join(styles, "checklist th")}
                                >
                                    {header}
                                </th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {element.questions.map((question, qindex) => {
                            return (
                                <tr>
                                    <td>{question.question}</td>
                                    {element.scaleTitles.map((title, i) => {
                                        return (
                                            <td
                                                className={join(
                                                    styles,
                                                    playerData.indices
                                                        ? `${
                                                              playerData
                                                                  .indices[
                                                                  qindex
                                                              ] === i
                                                          }`
                                                        : false,
                                                    `radio-container`
                                                )}
                                                key={`${question.question}-${title}`}
                                            >
                                                <input
                                                    type="radio"
                                                    id={`${qindex}-${i}`}
                                                    checked={
                                                        playerData.indices
                                                            ? playerData
                                                                  .indices[
                                                                  qindex
                                                              ] === i
                                                            : false
                                                    }
                                                    onChange={() =>
                                                        handleChangeSelection(
                                                            qindex,
                                                            i
                                                        )
                                                    }
                                                />
                                                <label
                                                    htmlFor={`${qindex}-${i}`}
                                                    tabIndex={0}
                                                    onKeyDown={keyDownHandler(
                                                        ["Enter"],
                                                        () => {
                                                            handleChangeSelection(
                                                                qindex,
                                                                i
                                                            );
                                                        }
                                                    )}
                                                >
                                                    <span>{title}</span>
                                                </label>
                                            </td>
                                        );
                                    })}
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </React.Fragment>
        ),
    };
};

export const AdvancedDefaultChecklistActivity2State: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "checklist_advanced_2"
> = () => ({
    type: "checklist_advanced_2",
    complete: false,
    indices: [],
    rows: [],
});
