import { useEffect, useState } from "react";
import styles from "../styles/KeyboardHints.module.css";
import { LoadJSON } from "engine/src/system/DataLoader";
import {
    updateKeyRegisters,
    useKeyboardToggle,
} from "engine/src/system/Keyboard";
import { dialogClean } from "engine/src/system/Dialog";
import { joinWithOverride } from "engine/src/system/Styles";
import { useBaseGlobalState } from "../state/GlobalState";

type TutorialKey =
    | `popup:minigame:${string}`
    | `popup:${string}`
    | `phone:${string}`
    | `dialog_history`
    | `dialog`
    | `scene`
    | `none`;

type Tutorials = {
    [name in TutorialKey]: {
        title: string;
        position?: "tr" | "tl" | "bl" | "br";
        lines: string[];
    };
};

function KeyboardHints({styleOverride}: {styleOverride?: any}) {
    const { coreState, settingsState } = useBaseGlobalState();

    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    const [tutorials, setTutorials] = useState<Tutorials>();
    const [currentScreen, setCurrentScreen] = useState<TutorialKey>(`scene`);

    const [showHints] = useKeyboardToggle(
        keybinds.General.Keyboard_Hints,
        [],
        []
    );

    useEffect(() => {
        updateKeyRegisters(settingsState);

        LoadJSON("keyboard_hints").then((json) => {
            setTutorials(json);
        });
        // eslint-disable-next-line
    }, []);

    useEffect(() => {
        if (!showHints) return;

        if (
            coreState.popup[0] === `minigame` &&
            coreState.minigame[0] !== null
        ) {
            return setCurrentScreen(
                `popup:minigame:${(coreState.minigame[0] as any).type}`
            );
        }

        if (coreState.popup[0] !== null) {
            return setCurrentScreen(`popup:${coreState.popup[0]}`);
        }

        if (coreState.phoneOpen[0]) {
            return setCurrentScreen(`phone:${coreState.openApp[0]}`);
        }

        if (coreState.dialogHistoryOpen[0]) {
            return setCurrentScreen(`dialog_history`);
        }

        if (coreState.dialog[0] !== null) {
            return setCurrentScreen(`dialog`);
        }

        if (!coreState.transitioning[0] && !coreState.loadingDialog[0]) {
            return setCurrentScreen(`scene`);
        }

        setCurrentScreen(`none`);
    }, [showHints, coreState, coreState.openApp]);

    if (
        !showHints ||
        tutorials === undefined ||
        currentScreen === "none" ||
        (tutorials[currentScreen] !== undefined &&
            tutorials[currentScreen].lines.length === 0)
    )
        return <></>;

    return (
        <div
            className={joinWithOverride(
                styles,
                styleOverride,
                "keyboard-info-wrapper",
                tutorials[currentScreen]?.position ?? "tr"
            )}
        >
            {tutorials[currentScreen] === undefined ? (
                <>
                    <h2>Tutorial not found for {currentScreen}</h2>
                    <p>
                        Please define a tutorial in data/keyboard_tutorials.json
                    </p>
                </>
            ) : (
                <>
                    <h2>{tutorials[currentScreen].title}</h2>
                    {tutorials[currentScreen].lines.map((line, i) => {
                        if (line.startsWith(`<h>`)) {
                            return (
                                <h3 key={i}>
                                    {dialogClean(line.replace(`<h>`, ``))}
                                </h3>
                            );
                        }

                        return <p key={i}>{dialogClean(line)}</p>;
                    })}
                </>
            )}
            <p>
                {participantSettings.EnableKeyRebinding && (
                    <>
                        you can rebind controls in the settings app
                        <br />
                    </>
                )}
                <b>
                    {dialogClean(
                        `Press %key:general:keyboard_hints% to hide this menu`
                    )}
                </b>
            </p>
        </div>
    );
}

export default KeyboardHints;
