type ValidClasses = string | boolean | undefined | ValidClasses[];

export const join = (style: any, ...classes: ValidClasses[]) => {
    let className = "";

    let actual_classes = deconstruct(classes);

    for (const clazz of actual_classes) {
        if (typeof clazz === "string" && clazz) {
            className += style[clazz] + " ";
        }
    }
    return className;
};

export const joinWithOverride = (style: any, override?: any, ...classes: ValidClasses[]) => {
    if(!override) return join(style, ...classes);

    let d = join(style, ...classes);
    let o = join(override, ...classes)

    return `${d} ${o}`
}

export const joinExternal = (style: any, ...classes: ValidClasses[]) => {
    let className = "";

    let actual_classes = deconstruct(classes);

    for (const clazz of actual_classes) {
        if (typeof clazz === "string" && clazz) {
            className += style[clazz] + " " + clazz + " ";
        }
    }
    return className;
};

const deconstruct = (
    classes: ValidClasses[]
): (string | boolean | undefined)[] => {
    if (classes.length === 0) return [];

    return classes
        .map((clazz) => {
            switch (typeof clazz) {
                case "object":
                    return deconstruct(clazz);
                default:
                    return [clazz];
            }
        })
        .flat();
};
