import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import styles from "../styles/Phone.module.css";
import { HandleAction } from "engine/src/system/ActionExecutor";
import {
    SendAppChanged,
    SendPhoneToggled,
} from "engine/src/system/BackendSystem";
import Flags from "engine/src/system/Flags";
import { joinWithOverride } from "engine/src/system/Styles";
import { LoadAction } from "engine/src/system/DataLoader";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { updateKeyRegisters, useKeyDown } from "engine/src/system/Keyboard";
import { BaseGlobalState, useBaseGlobalState } from "../state/GlobalState";
import { PhoneToggle } from "./PhoneToggle";
import { BaseParticipantSettings } from "../ParticipantSettings";

type AppMetaData = {
    element: ({closeApp}: {closeApp: () => void}) => JSX.Element,
    icon: string;
    color: string;
    name: string;
    notificationCount?: <ActivityType, MinigameType>(
        globalState: BaseGlobalState<ActivityType, MinigameType, BaseParticipantSettings>,
    ) => number;
};

export type AppRegistry = Record<string, AppMetaData>;

export type PhoneCustomization = {
    phoneImage: string;
}

/**
 * The core phone system
 */
const PhoneComponent = ({
    phoneOpen,
    setPhoneOpen,
    appRegistry,
    wallpapers,
    theming,
    styleOverride,
}: {
    phoneOpen: boolean;
    setPhoneOpen: React.Dispatch<React.SetStateAction<boolean>>;
    appRegistry: AppRegistry;
    wallpapers: string[];
    theming: PhoneCustomization;
    styleOverride: any
}) => {
    // Get the phone state
    const { coreState, settingsState } = useBaseGlobalState();
    const [openApp, setOpenApp] = coreState.openApp;
    const [wallpaperNumber] = coreState.wallpaperNumber;
    const [keybinds] = settingsState.keybinds;

    const phoneRef = useRef<HTMLDivElement>(null);

    const closePhone = useCallback(() => {
        setPhoneOpen(false);
        setOpenApp(null);
        Flags.setOrUnsetFlag([
            { flag_name: "hint:closed_phone", flag_action: "give" },
            { flag_name: "hint:opened_phone", flag_action: "revoke" },
        ]);

        Flags.setOrUnsetFlag([
            {
                flag_name: `phone:closed_app:${openApp && appRegistry[openApp] ? appRegistry[openApp]?.name : ""}`,
                flag_action: "give",
            },
        ]);

        LoadAction("on_phone_close").then((action) => {
            HandleAction(action);
        });

        PlayAudio("phone-toggle.wav", "sounds");
    }, [openApp, setPhoneOpen, setOpenApp]);

    useEffect(() => {
        setOpenApp(null);
        SendPhoneToggled(phoneOpen, coreState.appEnabled[1]);
        // eslint-disable-next-line
    }, [phoneOpen]);

    useEffect(() => {
        SendAppChanged(
            openApp !== null,
            coreState.appEnabled[1],
            openApp === null ? undefined : appRegistry[openApp]?.name
        );
        // eslint-disable-next-line
    }, [openApp]);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (
                phoneRef.current &&
                !phoneRef.current.contains(event.target as Node) &&
                coreState.popup[0] === null
            ) {
                closePhone();
            }
        }

        if (phoneOpen) {
            document.addEventListener("mousedown", handleClickOutside);
        } else {
            document.removeEventListener("mousedown", handleClickOutside);
        }

        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [phoneOpen, setPhoneOpen, coreState.popup, openApp, closePhone]);

    // Function to handle clicking the home button
    const homeButtonClick = useCallback(() => {
        if (coreState.popup[0] !== null) return;
        PlayAudio("home-button-click.wav", "sounds");

        Flags.setOrUnsetFlag([
            {
                flag_name: `phone:closed_app:${openApp && appRegistry[openApp] ? appRegistry[openApp]?.name : ""}`,
                flag_action: "give",
            },
        ]); 

        LoadAction("on_phone_close").then((action) => {
            HandleAction(action);
        });

        setOpenApp(null);
    }, [openApp, coreState.popup, setOpenApp]);

    const appComponents = Object.fromEntries(
        Object.entries(appRegistry).map(([identifier, app]) => [identifier, <app.element closeApp={() => setOpenApp(null)} />])
    )

    useKeyDown(
        keybinds.General.Back,
        useCallback(() => {
            if (openApp === null) closePhone();
        }, [openApp, closePhone]),
        !phoneOpen || coreState.popup[0] !== null
    );

    // If the phone isn't open, don't render anything
    if (!phoneOpen) return <></>;

    // Render the phone
    return (
        <div className={joinWithOverride(styles, styleOverride, "phone-wrapper")}>
            <PhoneToggle phoneOpen={phoneOpen} setPhoneOpen={setPhoneOpen} />
            <div className={joinWithOverride(styles, styleOverride, "phone")} ref={phoneRef} style={{backgroundImage: `url(${theming.phoneImage})`}}>
                <div
                    className={joinWithOverride(styles, styleOverride, "phone-wallpaper")}
                    style={{
                        backgroundImage: `linear-gradient(rgba(0, 0, 0, 0.6), rgba(0, 0, 0, 0.6)), url(${wallpapers[wallpaperNumber]})`,
                        //backgroundImage: "url(" + wallpapers[wallpaperNumber] + ")",
                    }}
                />
                <img
                    tabIndex={-1}
                    className={joinWithOverride(styles, styleOverride, "phone-home-toggle")}
                    src="assets/images/elements/home_button.png"
                    alt="Home Button"
                    onClick={homeButtonClick}
                />
                <div className={joinWithOverride(styles, styleOverride, "phone-content")}>
                    {openApp === null ? (
                        <HomeScreen
                            setOpenApp={setOpenApp}
                            appRegistry={appRegistry}
                            styleOverride={styleOverride}
                        />
                    ) : (
                        appComponents[openApp]
                    )}
                </div>
            </div>
        </div>
    );
};

const appTutorial = (appName: string) => {
    if (!Flags.checkFlag(`${appName}:tutorial:done`)) {
        Flags.addListener(`${appName}:tutorial`, () => {
            LoadAction("on_app_tutorial").then((action) => {
                HandleAction(action);
            });
        })
        HandleAction({
            type: "flag",
            flag: [
                {
                    flag_name: `${appName}:tutorial`,
                    flag_action: "give",
                },
            ],
        });
    }
};

const appClick = (appName: string) => {
    setTimeout(() => {
            LoadAction(`on_app_click_${appName}`).then((action) => {
                HandleAction(action);
            }).catch(() => {})
    }, 0);
}

/**Phone.tsx
 * The home screen
 */
function HomeScreen({
    setOpenApp,
    appRegistry,
    styleOverride,
}: {
    setOpenApp: React.Dispatch<React.SetStateAction<string | null>>;
    appRegistry: AppRegistry;
    styleOverride: any,
}) {
    const state = useBaseGlobalState();

    const [keybinds] = state.settingsState.keybinds;

    const mediaQuery = "(min-height: 700px)";
    const [vertical, setVertical] = useState(
        window.matchMedia(mediaQuery).matches
    );

    useEffect(() => {
        const mediaQueryList = window.matchMedia(mediaQuery);
        const handler = (e: MediaQueryListEvent) => setVertical(e.matches);

        mediaQueryList.addEventListener("change", handler);
        return () => mediaQueryList.removeEventListener("change", handler);
    }, []);

    const enabledApps: { app: AppMetaData; id: string }[] = useMemo(() => {
        let newEnabledApps: { app: AppMetaData; id: string }[] = [];

        Object.values(appRegistry).forEach((app) => {
            if (app === undefined) return;

            if (
                Flags.checkFlag(`${app.name}_unlocked`) ||
                app.name === "debug"
            ) {
                newEnabledApps.push({ app, id: app.name });
            }
        });

        return newEnabledApps;
    }, []);

    const selectedIndex = useSelectedApp(enabledApps, vertical ? 3 : 4);

    const clickApp = useCallback(
        (id: string) => {
            if(!id) return;
            const app = appRegistry[id];
            if (app === undefined) return;

            PlayAudio("app-click.wav", "sounds");
            setOpenApp(id);
            Flags.setOrUnsetFlag([
                {
                    flag_name: `phone:opened_app:${app.name}`,
                    flag_action: "give",
                },
            ]);
            appTutorial(app.name);
            appClick(app.name);
        },
        [setOpenApp]
    );

    useKeyDown(
        keybinds.General.Select,
        useCallback(() => {
            if (selectedIndex >= 0) clickApp(enabledApps[selectedIndex].id);
        }, [selectedIndex, clickApp, enabledApps])
    );

    let tutorialApp: string | null = null;

    // Return the home screen
    return (
        <div className={joinWithOverride(styles, styleOverride, "home-screen")}>
            {enabledApps.map(({ app, id }, i) => {
                let notificationCount: number = 0;
                let countSource = app.notificationCount;
                if (countSource) {
                    notificationCount = countSource(state as unknown as BaseGlobalState<any, any, BaseParticipantSettings>);
                }
                if (
                    !Flags.checkFlag(`${app.name}_unlocked`) &&
                    app.name !== "debug"
                ) {
                    return null;
                }

                if(tutorialApp === null) {
                    if(!Flags.checkFlag(`${app.name}:tutorial:done`)) {
                        tutorialApp = id;
                    }
                }

                return (
                    <div className={joinWithOverride(styles, styleOverride, "app-wrapper")} key={i}>
                        <div
                            className={joinWithOverride(
                                styles,
                                styleOverride,
                                "app-icon",
                                i === selectedIndex ? "selected" : ""
                            )}
                            style={{ backgroundImage: app.color }}
                            onClick={() => {
                                clickApp(id);
                            }}
                        >
                            {id === tutorialApp && <div className={joinWithOverride(styles, styleOverride, "app-highlight")}> </div>}
                            {notificationCount > 0 ? (
                                <span
                                    className={joinWithOverride(styles, styleOverride, "app-notification")}
                                >
                                    {notificationCount}
                                </span>
                            ) : null}
                            <img
                                alt={`${app.name} app icon`}
                                src={app.icon}
                                className={joinWithOverride(styles, styleOverride, "app-image")}
                            />
                        </div>
                        <b style={{ lineHeight: "30px" }}>
                            {app.name === "todo" ? "to-do" : app.name}
                        </b>
                    </div>
                );
            })}
        </div>
    );
}

function useSelectedApp(
    enabledApps: { app: AppMetaData; id: string }[],
    numCols: number
) {
    const { settingsState } = useBaseGlobalState();

    const [keybinds] = settingsState.keybinds;

    const rows = Math.ceil(enabledApps.length / numCols);

    const [selectedIndex, setSelectedIndex] = useState<number>(-1);

    const [i, setI] = useState<number>(-1);
    const [j, setJ] = useState<number>(-1);

    useEffect(() => {
        updateKeyRegisters(settingsState);
        // eslint-disable-next-line
    }, []);

    useKeyDown(
        keybinds.General.Up,
        useCallback(() => {
            setI((i) => (i === -1 ? 0 : (i - 1 + rows) % rows));
            return true;
        }, [rows])
    );

    useKeyDown(
        keybinds.General.Left,
        useCallback(() => {
            setJ((j) => {
                let cols = numCols;
                if (i === rows - 1) {
                    cols = enabledApps.length % numCols || numCols;
                }
                return j === -1 ? 0 : (j - 1 + cols) % cols;
            });
            return true;
        }, [i, rows, enabledApps.length, numCols])
    );

    useKeyDown(
        keybinds.General.Down,
        useCallback(() => {
            setI((i) => (i === -1 ? rows - 1 : (i + 1) % rows));
            return true;
        }, [rows])
    );

    useKeyDown(
        keybinds.General.Right,
        useCallback(() => {
            setJ((j) => {
                let cols = numCols;
                if (i === rows - 1) {
                    cols = enabledApps.length % numCols || numCols;
                }
                return j === -1 ? cols - 1 : (j + 1) % cols;
            });
            return true;
        }, [i, rows, enabledApps.length, numCols])
    );

    useEffect(() => {
        if (i === -1 && j !== -1) setI(0);
        if (j === -1 && i !== -1) setJ(0);

        const val = i * numCols + j;
        if (val >= enabledApps.length) {
            setSelectedIndex(enabledApps.length - 1);
            setJ((enabledApps.length % numCols) - 1);
        } else {
            setSelectedIndex(val);
        }
    }, [i, j, enabledApps.length, numCols]);

    return selectedIndex;
}

export default PhoneComponent;
