import styles from "#styles/minigames/renderers/JeopardyMinigame.module.css";
import { useState, useEffect, useRef } from "react";
import { GlobalState, useGlobalState } from "../../../state/GlobalState";
import {
    SendJeopardyQuestionAnswered,
    SendJeopardyQuestionSelected,
} from "../../../system/BackendSystem";
import { Badges } from "../../../system/Unlockables";
import { JeopardyMinigame, Minigame } from "../../../types/Minigame";
import { ProgressBar } from "../MinigameProgressBar";
import { PlayAudio, StopAllAudio } from "engine/src/system/AudioSystem";
import { join } from "engine/src/system/Styles";
import {
    useKeyDown,
    useSelectedIndex,
    useSelectedIndexGrid,
} from "engine/src/system/Keyboard";
import { SendMinigameEnded } from "engine/src/system/BackendSystem";
import { dialogClean } from "engine/src/system/Dialog";
import { ReactState } from "engine/src/state/GlobalState";

type State = {
    type: Minigame["type"];
    data: {
        answered: [number, number][];
        score: number;
        currentQuestion: [number, number] | null;
    };
};

export const JeopardyMinigameRenderer = ({
    minigame,
    state,
}: {
    minigame: JeopardyMinigame;
    state: ReactState<State>;
}) => {
    const { coreState, settingsState } = useGlobalState();

    const setPopup = coreState.popup[1];
    const setMinigame = coreState.minigame[1];
    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    const { answered, score, currentQuestion } = state[0].data;
    const answerQuestion = (question: [number, number], won: number) => {
        state[1]((current: State) => {
            return {
                type: "jeopardy",
                data: {
                    answered: [...current.data.answered, question],
                    score: current.data.score + won,
                    currentQuestion: current.data.currentQuestion,
                },
            };
        });
    };
    const setCurrentQuestion = (question: [number, number] | null) => {
        state[1]((current: State) => {
            return {
                type: "jeopardy",
                data: {
                    answered: current.data.answered,
                    score: current.data.score,
                    currentQuestion: question,
                },
            };
        });
    };

    const exit = () => {
        setMinigame(null);
        setPopup(null);
        SendMinigameEnded(minigame.type, coreState.appEnabled[1]);
        StopAllAudio("music");
        PlayAudio("minigame-click.mp3", "sounds");

        const maximumScore = minigame.categories.reduce(
            (acc, c) =>
                (acc += c.questions.reduce(
                    (acc2, _, i) => (acc2 += (i + 1) * 100),
                    0
                )),
            0
        );

        if (score === maximumScore) Badges.unlock("minigame:flawless");
    };

    const requiredQuestionCount = Math.min(
        minigame.categories.reduce(
            (prev, current) => prev + current.questions.length,
            0
        ),
        10
    );

    useKeyDown(
        keybinds.General.Back,
        exit,
        currentQuestion !== null || answered.length < requiredQuestionCount
    );

    return (
        <div className={join(styles, "jeopardy-wrapper")}>
            <div className={join(styles, "quiz-avatar-wrapper")}>
                <div
                    className={join(styles, "quiz-avatar")}
                    style={{
                        backgroundImage: `url(assets/images/characters/${minigame.avatar}.png)`,
                    }}
                ></div>
                <div className={join(styles, "instructions")}>
                    <span className={join(styles, "title")}>How To Play:</span>
                    <br></br>
                    Select options with
                    {participantSettings.EnableKbControls
                        ? dialogClean(
                              " either the directional keys and %key:general:select%, or "
                          )
                        : " "}
                    the mouse. Select a dollar amount to choose a question. Pick
                    the answer you think is correct. After reading the
                    explanation, select "Try Another One!" to return. Answer 10
                    to unlock the Exit button. Get all correct for a special
                    badge!
                </div>
            </div>

            <div className={join(styles, "jeopardy")}>
                {currentQuestion === null ? (
                    <Board
                        minigame={minigame}
                        answered={answered}
                        setCurrentQuestion={setCurrentQuestion}
                    />
                ) : (
                    <Question
                        minigame={minigame}
                        answered={answered}
                        currentQuestion={currentQuestion}
                        answerQuestion={answerQuestion}
                        setCurrentQuestion={setCurrentQuestion}
                    />
                )}

                <div className={join(styles, "controls")}>
                    <b>Score: {score}</b>
                    <ProgressBar
                        current={answered.length}
                        total={requiredQuestionCount}
                    ></ProgressBar>
                    <button
                        disabled={answered.length < requiredQuestionCount}
                        onClick={exit}
                    >
                        {answered.length < requiredQuestionCount
                            ? `Solved: ${answered.length}/${requiredQuestionCount}`
                            : dialogClean(
                                  participantSettings.EnableKbControls
                                      ? "Exit (%key:general:back%)"
                                      : "Exit"
                              )}
                    </button>
                </div>
            </div>
        </div>
    );
};

function Board({
    minigame,
    answered,
    setCurrentQuestion,
}: {
    minigame: JeopardyMinigame;
    answered: [number, number][];
    setCurrentQuestion: (question: [number, number] | null) => void;
}) {
    const { coreState, settingsState } = useGlobalState();

    const [keybinds] = settingsState.keybinds;

    const [jndex, index, setJ, setI] = useSelectedIndexGrid(
        minigame.categories[0].questions.length,
        minigame.categories.length
    );

    const selectQuestion = (title: string, i: number, j: number) => {
        PlayAudio("minigame-click.mp3", "sounds");
        setCurrentQuestion([i, j]);
        SendJeopardyQuestionSelected(
            title,
            coreState.appEnabled[1],
            (j + 1) * 100
        );
    };

    useKeyDown(keybinds.Minigames.Select, () => {
        selectQuestion(minigame.categories[index].title, index, jndex);
    });

    return (
        <>
            <span className={join(styles, "title")}>{minigame.name}</span>
            <section className={join(styles, "board")}>
                {minigame.categories.map((category, i) => (
                    <div className={join(styles, "category")} key={i}>
                        <h2>{category.title}</h2>
                        {category.questions.map((_, j) => (
                            <button
                                key={j}
                                className={join(
                                    styles,
                                    wasAnswered([i, j], answered)
                                        ? "answered"
                                        : "",
                                    i === index && j === jndex ? "selected" : ""
                                )}
                                onClick={() =>
                                    selectQuestion(category.title, i, j)
                                }
                                onMouseEnter={() => {
                                    setI(i);
                                    setJ(j);
                                }}
                            >
                                {(j + 1) * 100}
                            </button>
                        ))}
                    </div>
                ))}
            </section>
        </>
    );
}

function Question({
    minigame,
    answered,
    currentQuestion,
    answerQuestion,
    setCurrentQuestion,
}: {
    minigame: JeopardyMinigame;
    answered: [number, number][];
    currentQuestion: [number, number];
    answerQuestion: (question: [number, number], won: number) => void;
    setCurrentQuestion: (question: [number, number] | null) => void;
}) {
    const { settingsState } = useGlobalState();
    const [keybinds] = settingsState.keybinds;

    const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);

    const answerRef = useRef<HTMLDivElement>(null);

    const question =
        minigame.categories[currentQuestion[0]].questions[currentQuestion[1]];

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        wasAnswered(currentQuestion, answered)
            ? question.options.length + 1
            : question.options.length,
        keybinds.General.Up,
        keybinds.General.Down
    );

    const answer = (ans: number) => {
        PlayAudio("minigame-click.mp3", "sounds");
        if (question.answer === ans) {
            PlayAudio("minigame-correct.mp3", "sounds");
        } else {
            PlayAudio("minigame-wrong.mp3", "sounds");
        }

        setSelectedAnswer(ans);
        const coreState = GlobalState.getInstance().coreState[0];
        const correct = question.answer === ans;
        const won = correct ? (currentQuestion[1] + 1) * 100 : 0;
        answerQuestion(currentQuestion, won);
        SendJeopardyQuestionAnswered(
            minigame.categories[currentQuestion[0]].title,
            coreState.appEnabled[1],
            (currentQuestion[1] + 1) * 100,
            correct
        );
    };

    const exitQuestion = () => {
        PlayAudio("minigame-click.mp3", "sounds");
        setCurrentQuestion(null);
    };

    useEffect(() => {
        if (wasAnswered(currentQuestion, answered) && answerRef.current) {
            const timer = setTimeout(() => {
                answerRef.current?.scrollIntoView({ behavior: "smooth" });
            }, 500);
            return () => clearTimeout(timer);
        }
    }, [answered, currentQuestion]);

    useKeyDown(keybinds.General.Back, exitQuestion);

    useKeyDown(
        keybinds.Minigames.Select,
        () => {
            if (selectedIndex === question.options.length)
                return exitQuestion();

            if (wasAnswered(currentQuestion, answered)) return;
            answer(selectedIndex);
        },
        selectedIndex === -1
    );

    return (
        <>
            <span className={join(styles, "title")}>{minigame.name}</span>
            <section className={join(styles, "question")}>
                <h2>{question.question}</h2>
                <div className={join(styles, "options")}>
                    {question.options.map((option, index) => (
                        <button
                            disabled={wasAnswered(currentQuestion, answered)}
                            key={option}
                            onClick={() => answer(index)}
                            className={join(
                                styles,
                                wasAnswered(currentQuestion, answered) &&
                                    selectedAnswer === index
                                    ? index === question.answer
                                        ? "correct-answer"
                                        : "wrong-answer"
                                    : "",
                                index === selectedIndex ? "selected" : ""
                            )}
                            onMouseEnter={() => {
                                if (selectedIndex !== -1)
                                    setSelectedIndex(index);
                            }}
                        >
                            {option}
                        </button>
                    ))}
                </div>

                {wasAnswered(currentQuestion, answered) && (
                    <div
                        className={join(styles, "answer-section")}
                        ref={answerRef}
                    >
                        <div className={join(styles, "answer")}>
                            <div className={join(styles, "answer-content")}>
                                <i>{question.reason}</i>
                                {question.pdf && question.pdf_title && (
                                    <div className={join(styles, "pdf")}>
                                        download link to file:{" "}
                                        <a
                                            href={`/${question.pdf}`}
                                            target="_blank"
                                            rel="noreferrer"
                                        >
                                            {question.pdf_title}
                                        </a>
                                    </div>
                                )}
                            </div>
                        </div>
                        <button
                            onClick={exitQuestion}
                            className={join(
                                styles,
                                "next-question-btn",
                                selectedIndex === question.options.length
                                    ? "selected"
                                    : ""
                            )}
                            onMouseEnter={() =>
                                setSelectedIndex(question.options.length)
                            }
                        >
                            Try Another One!
                        </button>
                    </div>
                )}
            </section>
        </>
    );
}

function wasAnswered(question: [number, number], answered: [number, number][]) {
    return answered.some(
        (r) =>
            r.length === question.length &&
            r.every((value, index) => question[index] === value)
    );
}
