import { Dialog } from "engine/src/types/Dialog";
import { GenericAction } from "../types/Action";
import { Scene } from "../types/Scene";

const cache: Record<string, Record<string, any>> = {};

export async function LoadItem<T>(path: string, name: string): Promise<T> {
    let itemCache: Record<string, T> = cache[path];
    if (!itemCache) {
        itemCache = {};
        cache[path] = itemCache;
    } else if (Object.keys(itemCache).includes(name)) {
        return itemCache[name];
    }

    // Load activity from file and save in the cache before returning
    let data = await fetch(`data/${path}${path ? "/" : ""}${name}.json`);

    // Convert the raw data to json
    let json;
    try {
        json = await data.json();
    } catch (e: any) {
        throw Error(
            `Failed to load data: ${path}/${name}. Following is a stack trace for this error.`
        );
    }

    // Convert the json to the target type
    const item = json as T;

    // Cache the activity
    itemCache[name] = item;

    // Return the activity
    return item;
}

export const LoadJSON = (name: string) => LoadItem<any>("", name);

export const LoadAction = (name: string) => LoadItem<GenericAction<string>>("actions", name);
export const LoadScene = async (name: string) => {
    const scene = await LoadItem<Scene>("scene", name);
    scene.path = name;
    return scene;
};
export const LoadDialog = async (name: string): Promise<Dialog> => {
    const _dialog = await LoadItem<Dialog["dialog"]>("dialog", name);
    return {
        name: name,
        dialog: _dialog,
    };
};
export const LoadActivity = <ActivityType>(name: string) =>
    LoadItem<ActivityType>("activity", name);
export const LoadMinigame = <MinigameType>(name: string) =>
    LoadItem<MinigameType>("minigame", name);

const getRandomFileFromDirectory = async (
    directoryPath: string
): Promise<string> => {
    const availableFiles: string[] = [];
    const MAX_FILES = 10000;

    for (let fileName = 1; fileName <= MAX_FILES; fileName++) {
        try {
            await LoadItem<Dialog["dialog"]>(
                "dialog",
                `${directoryPath}${fileName}`
            );

            availableFiles.push(`${fileName}`);
        } catch (_) {
            break;
        }
    }
    const randomIndex = Math.floor(Math.random() * availableFiles.length);
    return availableFiles[randomIndex];
};

export const loadAppropriateDialog = async (
    dialogPath: string
): Promise<Dialog> => {
    if (dialogPath.endsWith("/")) {
        const randomFile = await getRandomFileFromDirectory(dialogPath);
        return LoadDialog(dialogPath + randomFile);
    } else {
        return LoadDialog(dialogPath);
    }
};
