type CharactersData = {
    path: {
        name: string;
        values: string[];
    }[];
    file_name: string;
};

let characters: CharactersData | null = null;

export const InitCharacters = () => {
    if (characters === null) {
        fetch("data/players.json").then((data) =>
            data.json().then((json) => {
                characters = json as CharactersData;
            })
        );
    }
};

export const GetCharacters = (): CharactersData | null => {
    return characters;
};
