import { useGlobalState } from "../../state/GlobalState";
import styles from "#styles/apps/DictionaryApp.module.css";
import { join } from "engine/src/system/Styles";
import { Dictionary } from "../../system/Unlockables";
import { useEffect, useRef } from "react";
import { useKeyDown } from "engine/src/system/Keyboard";

/**
 * The Dictionary App
 */
export const DictionaryComponent = ({ closeApp }: { closeApp: () => void }) => {
    const { settingsState } = useGlobalState();
    const [keybinds] = settingsState.keybinds;

    const contentRef = useRef<HTMLDivElement | null>(null);

    const sortDictionary = Object.keys(Dictionary.list())
        .filter((id: string) => Dictionary.unlocked(id))
        .map((id: string) => ({ id, word: Dictionary.get(id) }))
        .sort((a, b) => a.word.words[0].localeCompare(b.word.words[0]));

    useKeyDown(keybinds.General.Back, closeApp);

    useEffect(() => {
        contentRef.current?.focus();
    });

    // Return the rendered dictionary app
    return (
        <div className={join(styles, "dictionary-content")}>
            <h1>Dictionary</h1>
            <div></div>
            <div ref={contentRef} className={join(styles, "dictionary-list")}>
                {sortDictionary.map(({ id, word }) => (
                    <div
                        className={join(styles, "word-box")}
                        key={id}
                        style={{ marginBottom: 40 }}
                    >
                        <h2>{word.words.join(" ")}</h2>
                        <p>{word.definition}</p>
                    </div>
                ))}
            </div>
        </div>
    );
};
