import styles from "../../styles/popup/PortraitWarning.module.css";
import { join, joinWithOverride } from "engine/src/system/Styles";

/**
 * Portrait warning screen
 */
const PortraitWarning = ({styleOverride}: {styleOverride?: any}) => {
    // Return the warning
    return (
        <div className={joinWithOverride(styles, styleOverride, "portrait-warning")}>
            <h1>Please rotate your device to landscape mode</h1>
        </div>
    );
};

export const WideScreenWarning = ({styleOverride}: {styleOverride?: any}) => {
    // Return the warning
    return (
        <div className={joinWithOverride(styles, styleOverride, "wide-screen-warning")}>
            <h1>Please play on full screen</h1>
        </div>
    );
};

export default PortraitWarning;
