import { useEffect } from "react";
import { useGlobalState } from "../../state/GlobalState";
import styles from "#styles/popup/MinigameSelector.module.css";
import { join } from "engine/src/system/Styles";
import { Minigames } from "../../system/Unlockables";
import { useKeyDown, useSelectedIndex } from "engine/src/system/Keyboard";
import { LoadMinigame } from "engine/src/system/DataLoader";
import { SendMinigameStarted } from "engine/src/system/BackendSystem";

const MinigameSelectorComponent = () => {
    const { coreState, settingsState } = useGlobalState();

    const [popup, setPopup] = coreState.popup;

    const [keybinds] = settingsState.keybinds;

    useKeyDown(
        keybinds.General.Back,
        () => {
            setPopup(null);
        },
        popup !== "minigameSelector"
    );

    const minigames = Object.keys(Minigames.list()).filter(Minigames.unlocked);

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        minigames.length,
        keybinds.General.Left,
        keybinds.General.Right,
        popup !== "minigameSelector"
    );

    useEffect(() => {
        setSelectedIndex(-1);
    }, [setSelectedIndex]);

    useKeyDown(
        keybinds.General.Select,
        () => {
            Minigames.open(minigames[selectedIndex]);
        },
        selectedIndex === -1
    );

    return (
        <div className={join(styles, "minigame-selector")}>
            <div className={styles.window}>
                <header>
                    <b>Minigame Selector</b>
                    <button onClick={() => setPopup(null)}>x</button>
                </header>
                <main>
                    {minigames.length > 0 ? (
                        minigames.map((key, index) => (
                            <div key={Minigames.get(key).name}>
                                <b>{Minigames.get(key).name}</b>
                                <p>
                                    Unlocked in chapter{" "}
                                    <b>{Minigames.get(key).chapter}</b>
                                </p>
                                <p>{Minigames.get(key).description}</p>
                                <button
                                    className={
                                        index === selectedIndex
                                            ? join(styles, "selected")
                                            : ""
                                    }
                                    onClick={() => {
                                        LoadMinigame<any>(key).then(
                                            (minigame) => {
                                                SendMinigameStarted(
                                                    minigame.type,
                                                    coreState.appEnabled[1]
                                                );
                                                coreState.minigame[1](minigame);
                                                coreState.popup[1]("minigame");
                                            }
                                        );
                                    }}
                                >
                                    Play Now
                                </button>
                            </div>
                        ))
                    ) : (
                        <p>Keep playing to unlock minigames!</p>
                    )}
                </main>
            </div>
        </div>
    );
};

export default MinigameSelectorComponent;
