import { useEffect } from "react";
import { GlobalState, useNewState } from "./state/GlobalState";
import { InitCharacters } from "engine/src/system/Characters";
import { Activity } from "./types/Activity";
import { Minigame } from "./types/Minigame";
import { Game } from "engine/src/Game";
import { WebSocketBackend } from "./system/BackendSystem";
import { Dictionary } from "./system/Unlockables";
import { createAppRegistry, wallpapers } from "./components/AppRegistry";
import { createPopupRegistry } from "./components/PopupRegistry";
import { StrategyUnlockButton } from "./components/dialog/StrategyUnlockButton";
import TextsComponent from "./components/TextsComponent";
import { RegisterCustomActions } from "./system/ActionExecutor";
import { hasSavedSettings, loadSettings } from "engine/src/system/SaveSystem";
import { resetSettingsState } from "engine/src/state/GlobalState";
import {
    defaultParticipantSettings,
    ParticipantSettings,
} from "./system/ParticipantSettings";
import { getNewParticipantSettings } from "engine/src/ParticipantSettings";
import Registers from "engine/src/system/Registers";
import { PauseAfterChapter } from "./Config";
import { styleConfig } from "./Style";

RegisterCustomActions();

/**
 * The main application
 */
function App() {
    const { coreState, playerState, gameState, phoneState, settingsState } =
        useNewState<Activity, Minigame>();

    useEffect(() => {
        if (hasSavedSettings()) {
            loadSettings(settingsState);
        } else {
            console.warn("Resetting Settings State!");
            resetSettingsState(
                settingsState,
                false,
                defaultParticipantSettings
            );
            getNewParticipantSettings<ParticipantSettings>().then(
                (participantSettings) => {
                    settingsState.participantSettings[1](participantSettings);
                }
            );
        }
        //eslint-disable-next-line
    }, []);

    // Create the global state if it does not already exist
    if (!GlobalState.getInstance()) {
        console.log("Creating Global State!");
        new GlobalState(
            coreState,
            playerState,
            gameState,
            phoneState,
            settingsState
        );
    }

    useEffect(() => {
        InitCharacters();
    }, []);

    const [participantSettings] = settingsState.participantSettings;

    const state = GlobalState.getInstance();

    const popupRegistry = createPopupRegistry();
    const appRegistry = createAppRegistry(
        coreState,
        settingsState,
        gameState,
        playerState,
        phoneState,
        participantSettings,
        popupRegistry
    );

    useEffect(() => {
        if (Registers.getRegister("chapter") - 1 === PauseAfterChapter)
            coreState.popup[1]("pauseChapter");
    }, [coreState.scene[0]]);

    return (
        <Game
            gameConfig={{
                sceneConfig: {
                    defaultScene: {
                        path: "default",
                        name: "title_screen",
                        canSafelyUnload: true,
                    },
                },
                phoneConfig: {
                    theming: {
                        phoneImage: "assets/images/elements/phone-frame.png",
                    },
                    appRegistry: appRegistry,
                    wallpapers: wallpapers,
                },
                dialogConfig: {
                    additionalDialogElement: StrategyUnlockButton,
                    newWordCallback: Dictionary.unlock,
                    dictionary: Dictionary.list(),
                    character: playerState.character[0].image,
                    pitch: playerState.playerPitch[0],
                },
                popupConfig: {
                    popupRegistry: popupRegistry,
                    activityDataState: playerState.activityData,
                },
                keyboardConfig: {
                    enableHints: participantSettings.EnableKbHints,
                    enableControls: participantSettings.EnableKbControls,
                },
                backendConfig: {
                    backend: WebSocketBackend,
                },
                styleOverrides: styleConfig,
            }}
            state={{
                states: [
                    {
                        func: state.setCoreState.bind(state),
                        context: GlobalState.getInstance().coreState[1],
                        value: coreState,
                    },
                    {
                        func: state.setSettingsState.bind(state),
                        context: GlobalState.getInstance().settingsState[1],
                        value: settingsState,
                    },
                    {
                        func: state.setGameState.bind(state),
                        context: GlobalState.getInstance().gameState[1],
                        value: gameState,
                    },
                    {
                        func: state.setPlayerState.bind(state),
                        context: GlobalState.getInstance().playerState[1],
                        value: playerState,
                    },
                    {
                        func: state.setPhoneState.bind(state),
                        context: GlobalState.getInstance().phoneState[1],
                        value: phoneState,
                    },
                ],
                coreState: coreState,
            }}
        >
            <TextsComponent />
        </Game>
    );
}

export default App;
