import React from 'react';
import PhoneComponent, { AppRegistry, PhoneCustomization } from "./components/Phone";
import { GlobalStateProvider, States } from "./state/GlobalStateListener";
import { DictionaryWords } from "./types/DictionaryWords";
import PopupComponent, { PopupRegistry } from "./components/Popup";
import { LoadScene } from "./system/DataLoader";
import { SwitchSceneInstant } from "./system/SceneSwitcher";
import { IsUnsavedChanges } from "./system/SaveSystem";
import { AppDisabled } from './components/popup/AppDisabled';
import SceneComponent from './components/Scene';
import NotificationComponent from './components/NotificationComponent';
import PortraitWarning, { WideScreenWarning } from './components/popup/PortraitWarning';
import AppProtection from './components/popup/AppProtection';
import { BackendBuilder } from './system/BackendSystem';
import { CoreState, ReactState } from './state/GlobalState';
import { Dialog } from './types/Dialog';
import KeyboardSystem from './components/KeyboardSystem';
import KeyboardHints from './components/KeyboardHints';
import { FlagListener } from './components/FlagListener';
import { BaseGlobalState } from './state/GlobalState';
import { UpdateMixerVolume } from './system/AudioSystem';

type GameConfig = {
    sceneConfig: {
        defaultScene: {
            path: string,
            name: string,
            canSafelyUnload?: boolean,
        },
    },
    phoneConfig: {
        theming: PhoneCustomization,
        wallpapers: string[],
        appRegistry: AppRegistry,
    },
    dialogConfig: {
        pitch: 'high-pitch' | 'low-pitch',
        character: string,
        dictionary: Record<string, DictionaryWords>,
        newWordCallback: (word: string) => void,
        additionalDialogElement: (dialog: Dialog["dialog"][0]) => [React.ReactNode, boolean],
    },
    popupConfig: {
        popupRegistry: PopupRegistry,
        activityDataState: ReactState<any>,
    },
    keyboardConfig: {
        enableControls: boolean,
        enableHints: boolean,
    },
    backendConfig: {
        backend: BackendBuilder,
    },
    styleOverrides?: StyleConfig,
}

export type StyleConfig = {
    dialog?: {
        Dialog?: any,
        DialogHistory?: any,
        DialogSkip?: any,
    },
    minigames?: {
        MinigameComponent?: any,
    },
    popup?: {
        Activity?: any,
        AppDisabled?: any,
        AppProtection?: any,
        document?: any,
        Popup?: any,
        PortraitWarning?: any
    },
    KeyboardHint?: any,
    NotificationComponent?: any,
    Phone?: any,
    PhoneToggle?: any,
    Scene?: any,
    AppProtection?: any,
}

export const Game = ({
    gameConfig,
    state,
    children,
}: {
    gameConfig: GameConfig,
    state: {
        states: States,
        coreState: CoreState<any, any>,
    },
    children: React.ReactNode | React.ReactNode[]
}) => {
    const {states, coreState} = state;

    const [authenticated, setAuthenticated] = React.useState(false);
    const [signedIn, setSignedIn] = React.useState(false);

    // Load the default scene when the application is first loaded
    const setScene = coreState.scene[1];

    React.useEffect(() => {
        if(!signedIn) return;
        LoadScene(gameConfig.sceneConfig.defaultScene.path).then((s) =>
            SwitchSceneInstant(s, coreState, coreState.phoneOpen[1])
        );
        window.onbeforeunload = (e) => {
            if (BaseGlobalState.getBaseInstance().coreState[0].scene[0].canSafelyUnload) return undefined;
            if (!IsUnsavedChanges()) return undefined;
            if (!authenticated || !signedIn) return undefined;

            e.returnValue = true;
            e.preventDefault();
        };
        // eslint-disable-next-line
    }, [setScene, signedIn]);

    const settingsState = BaseGlobalState.getBaseInstance().settingsState[0];

    const [textSize] = settingsState.textSize;
    const [textStyle] = settingsState.textStyle;

    document.documentElement.style.setProperty("--font-scale", `${textSize}`);
    document.documentElement.style.setProperty("--font-style", `${textStyle}`);

    for (const key in settingsState.volume[0]) {
        UpdateMixerVolume(
            key as Parameters<typeof UpdateMixerVolume>[0],
            settingsState.volume[0][
                key as Parameters<typeof UpdateMixerVolume>[0]
            ]
        );
        console.log(`${key}: ${settingsState.volume[0][key as Parameters<typeof UpdateMixerVolume>[0]]}`)
    }


    // Render the application
    return authenticated && signedIn ? (
        <>
            <AppDisabled coreState={coreState} styleOverride={gameConfig.styleOverrides?.popup?.AppDisabled} />
            <PortraitWarning styleOverride={gameConfig.styleOverrides?.popup?.PortraitWarning} />
            <WideScreenWarning styleOverride={gameConfig.styleOverrides?.popup?.PortraitWarning} />
            <GlobalStateProvider
                states={states}
            >
                {
                    children
                }

                <FlagListener />

                {gameConfig.keyboardConfig.enableControls && <KeyboardSystem />}
                {gameConfig.keyboardConfig.enableHints && <KeyboardHints styleOverride={gameConfig.styleOverrides?.KeyboardHint} />}

                <PopupComponent registry={gameConfig.popupConfig.popupRegistry} activityDataState={gameConfig.popupConfig.activityDataState} styleOverride={gameConfig.styleOverrides?.popup?.Popup} />
                <NotificationComponent styleOverride={gameConfig.styleOverrides?.NotificationComponent} />
                <SceneComponent
                    popupRegistry={gameConfig.popupConfig.popupRegistry}
                    pitch={gameConfig.dialogConfig.pitch}
                    character={gameConfig.dialogConfig.character}
                    dictionary={gameConfig.dialogConfig.dictionary}
                    newWordCallback={gameConfig.dialogConfig.newWordCallback}
                    additionalDialogElement={gameConfig.dialogConfig.additionalDialogElement}
                    sceneStyleOverride={gameConfig.styleOverrides?.Scene}
                    dialogStyleOverride={gameConfig.styleOverrides?.dialog?.Dialog}
                    dialogHistoryStyleOverride={gameConfig.styleOverrides?.dialog?.DialogHistory}
                    dialogSkipStyleOverride={gameConfig.styleOverrides?.dialog?.DialogSkip}
                />
                <PhoneComponent
                    phoneOpen={coreState.phoneOpen[0]}
                    setPhoneOpen={coreState.phoneOpen[1]}
                    appRegistry={gameConfig.phoneConfig.appRegistry}
                    wallpapers={gameConfig.phoneConfig.wallpapers}
                    theming={gameConfig.phoneConfig.theming}
                    styleOverride={gameConfig.styleOverrides?.Phone}
                />
            </GlobalStateProvider>
        </>
    ) : (
        <AppProtection
            authenticated={authenticated}
            setAuthenticated={setAuthenticated}
            signedIn={signedIn}
            setSignedIn={setSignedIn}
            defaultBackend={gameConfig.backendConfig.backend}
            styleOverride={gameConfig.styleOverrides?.AppProtection}
        />
    );
}
