import skipStyles from "../styles/dialog/DialogSkip.module.css";
import { joinWithOverride } from "../system/Styles";
import { useState } from "react";

export const DialogSkipComponent = ({ dialogName, styleOverride }: { dialogName: string, styleOverride: any }) => {
    const [isAutoSkipping, setIsAutoSkipping] = useState(false);

    function skipDialogSection() {
        if (autoSkipInterval) {
            clearInterval(autoSkipInterval);
            autoSkipInterval = null;
            setIsAutoSkipping(false);
            return;
        }

        autoSkipInterval = window.setInterval(() => {
            const selectors = ["[class^='Dialog_dialog-text']"];

            selectors.forEach((sel) => {
                document.querySelectorAll(sel).forEach((el) => {
                    el.dispatchEvent(
                        new window.MouseEvent("click", {
                            bubbles: true,
                            cancelable: true,
                        })
                    );
                });
            });
        }, 300);
        setIsAutoSkipping(true);
    }

    return (
        <button
            className={joinWithOverride(
                skipStyles,
                styleOverride,
                "chat-skip",
                isAutoSkipping ? "skip-active" : "skip-inactive"
            )}
            onClick={() => {
                skipDialogSection();
            }}
        >
            {isAutoSkipping
                ? "Stop Auto Skip Dialog\n\n"
                : "Start Auto Skip Dialog\n\n"}
            <div className={joinWithOverride(skipStyles, styleOverride, "dialog-file")}>{dialogName}</div>
        </button>
    );
};

let autoSkipInterval: number | null = null;
