import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import React from "react";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const DangerousEvalActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "dangerous_eval"
> = (element, _1, _2, [bound, updateBinding, bindings]) => {
    const fn = Function(...element.bindingInputs, element.function);

    const args = element.bindingInputs.map((binding) =>
        bound[binding]
            ? bound[binding]
            : element.defaultInputValues
              ? element.defaultInputValues[binding]
              : undefined
    );

    let valid = true;
    for (const arg of args) {
        if (arg === undefined) {
            valid = false;
        }
    }

    if (valid) {
        setTimeout(() => {
            const result = fn(...args);
            updateBinding(element, "result", result);
        }, 1);
    }

    return {
        appView: <React.Fragment key={element.function}></React.Fragment>,
        printView: <React.Fragment key={element.function}></React.Fragment>,
    };
};

export const DefaultDangerousEvalActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "dangerous_eval"
> = () => {
    return {
        type: "dangerous_eval",
        complete: true,
    };
};
