import journalStyles from "#styles/apps/JournalApp.module.css";
import { join } from "engine/src/system/Styles";
import { Badges, BumperStickers } from "../../system/Unlockables";
import { Badge } from "../../types/Badge";
import { BumperSticker } from "../../types/BumperSticker";
import { GenericListApp } from "./GenericListApp";

type ItemData = {
    title: string;
    description: string;
    image: string;
    imageText: string;
    imageClass: string;
    unlocked: boolean;
    hidden: boolean;
};

/**
 * The Achievements App
 */
export const AchievementsApp = ({ closeApp }: { closeApp: () => void }) => {
    const badges: Record<string, Badge> = Badges.list();
    const unlockedBadges = Object.keys(badges).filter(Badges.unlocked).length;
    const totalBadges = Object.keys(badges).filter(
        (b) => Badges.unlocked(b) || !badges[b].hidden
    ).length;

    const stickers: Record<string, BumperSticker> = BumperStickers.list();
    const totalStickers = Object.keys(stickers).length;
    const unlockedStickers = Object.keys(stickers).filter(
        BumperStickers.unlocked
    ).length;

    const pages: {
        name: string;
        title: string;
        description: JSX.Element;
        data: ItemData[];
    }[] = [
        {
            name: `Badges`,
            title: `Badges ${unlockedBadges} / ${totalBadges}`,
            description: (
                <p>
                    Badges are awarded for completing side quests and extra
                    challenges in the game. Keep your eyes peeled for extra
                    rewards!
                </p>
            ),
            data: getBadgesData(badges),
        },
        {
            name: `Bumper Stickers`,
            title: `Bumper Stickers ${unlockedStickers} / ${totalStickers}`,
            description: (
                <p>
                    Bumper stickers are awarded for completing a chapter in the
                    game. Keep playing and earn more stickers!
                </p>
            ),
            data: getStickersData(stickers),
        },
    ];

    return (
        <GenericListApp
            title={`Achievements`}
            closeApp={closeApp}
            pages={pages}
            elementsSelectable={false}
            ItemComponent={ItemComponent}
        />
    );
};

function ItemComponent({ item, index }: { item: ItemData; index: number }) {
    return (
        <div
            className={join(
                journalStyles,
                "unlockable",
                item.unlocked ? "" : "locked"
            )}
            key={index}
        >
            <h2>{item.title}</h2>
            <div className={join(journalStyles, "unlockable-content")}>
                <div
                    className={join(journalStyles, item.imageClass, "icon")}
                    style={{
                        backgroundImage: `url(assets/images/${item.image})`,
                    }}
                >
                    <p>{item.imageText}</p>
                </div>
                <p>{item.description}</p>
            </div>
        </div>
    );
}

function getBadgesData(badges: Record<string, Badge>): ItemData[] {
    return Object.keys(badges)
        .filter((badge) => !badges[badge].hidden || Badges.unlocked(badge))
        .map((id) => {
            const badge = badges[id];
            return {
                title: badge.name,
                description: badge.description,
                image: "badges/generic.png",
                imageText: badge.name,
                imageClass: "badge-icon",
                unlocked: Badges.unlocked(id),
                hidden: badge.hidden,
            };
        })
        .sort((a, b) => {
            if (!a.unlocked && a.hidden) return 1;
            if (!b.unlocked && b.hidden) return -1;
            if (!a.unlocked) return 1;
            if (!b.unlocked) return -1;
            return 0;
        });
}

function getStickersData(stickers: Record<string, BumperSticker>): ItemData[] {
    return Object.keys(stickers)
        .map((id) => {
            const sticker = stickers[id];

            return {
                title: sticker.name,
                description: sticker.description,
                image: `stickers/${sticker.image}`,
                imageText: "",
                imageClass: "sticker-icon",
                unlocked: BumperStickers.unlocked(id),
                hidden: false,
            };
        })
        .sort((a, b) => {
            if (!a.unlocked) return 1;
            if (!b.unlocked) return -1;
            return 0;
        });
}
