import styles from "#styles/apps/EmailApp.module.css";
import phoneStyles from "#styles/apps/PhoneUIGeneric.module.css";
import { HandleActions } from "engine/src/system/ActionExecutor";
import React, { useCallback, useEffect, useRef, useState } from "react";
import Registers from "engine/src/system/Registers";
import { ReactSetter } from "engine/src/state/GlobalState";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { useKeyDown, useSelectedIndex } from "engine/src/system/Keyboard";
import { Option } from "engine/src/types/Dialog";
import { dialogClean } from "engine/src/system/Dialog";
import { useGlobalState } from "../../state/GlobalState";
import { join } from "engine/src/system/Styles";

/**
 * The email app
 */
export const EmailApp = ({ closeApp }: { closeApp: () => void }) => {
    const { phoneState, settingsState } = useGlobalState();

    const [keybinds] = settingsState.keybinds;

    const [emails] = phoneState.emails;
    const [repliedEmails] = phoneState.repliedEmails;

    const [openEmail, setOpenEmail] = useState<number | null>(null);

    useEffect(() => {
        for (let i = emails.length - 1; i >= 0; i--) {
            if (!repliedEmails.includes(i) && emails[i].important) {
                setOpenEmail(i);
                break;
            }
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [emails]);

    useKeyDown(
        keybinds.General.Back,
        useCallback(() => {
            if (openEmail === null) closeApp();
        }, [openEmail, closeApp])
    );

    // Return the rendered email app
    return (
        <div className={join(styles, "email-app")} tabIndex={-1}>
            <h1>Emails</h1>
            {openEmail === null && <EmailList setOpenEmail={setOpenEmail} />}
            {openEmail !== null && (
                <EmailView openEmail={openEmail} setOpenEmail={setOpenEmail} />
            )}
        </div>
    );
};

/**
 * Renders the email list
 */
function EmailList({
    setOpenEmail,
}: {
    setOpenEmail: React.Dispatch<React.SetStateAction<number | null>>;
}) {
    const { phoneState, settingsState } = useGlobalState();
    // Get the global state

    const [keybinds] = settingsState.keybinds;
    const [emails] = phoneState.emails;

    const [repliedEmails] = phoneState.repliedEmails;

    const [selectedIndex] = useSelectedIndex(
        emails.length,
        keybinds.General.Down,
        keybinds.General.Up
    );

    const selectedRef = useRef<null | HTMLDivElement>(null);

    // Function to handle playing audio when an email is opened
    const openSelectedEmail = useCallback(
        (index: number) => {
            setOpenEmail(index);
            PlayAudio("email-list-click.mp3", "sounds");
        },
        [setOpenEmail]
    );

    const getColorFromEmail = (email: string) => {
        const hash = email
            .split("")
            .reduce((acc, char) => acc + char.charCodeAt(0), 0);
        return `hsl(${hash % 360}, 50%, 50%)`;
    };

    useKeyDown(
        keybinds.General.Select,
        useCallback(() => {
            if (selectedIndex === -1) return;
            openSelectedEmail(selectedIndex);
        }, [selectedIndex, openSelectedEmail])
    );

    useEffect(() => {
        selectedRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [selectedIndex]);

    // Return the rendered email list
    return (
        <div>
            <div className={join(phoneStyles, "list")}>
                {emails.map((email, index) => (
                    <div
                        className={join(
                            phoneStyles,
                            "column-icon-text",
                            "clickable",
                            index === selectedIndex ? "selected" : ""
                        )}
                        onClick={() => openSelectedEmail(index)}
                        key={index}
                        ref={index === selectedIndex ? selectedRef : null}
                    >
                        <div
                            className={join(phoneStyles, "sender-icon")}
                            style={{
                                backgroundColor: getColorFromEmail(email.from),
                            }}
                        >
                            <span>
                                {email.from
                                    .split(" ")
                                    .map((word) => word[0].toUpperCase())
                                    .join("")}
                            </span>
                        </div>
                        <div
                            className={join(
                                phoneStyles,
                                "column",
                                "no-overflow"
                            )}
                        >
                            <p
                                className={
                                    repliedEmails.includes(index)
                                        ? ""
                                        : join(styles, "email-unread")
                                }
                            >
                                {email.subject}
                                {`${email.important ? "⭐" : ""}`}
                            </p>

                            <p
                                className={join(styles, "email-preview")}
                                dangerouslySetInnerHTML={{
                                    __html: dialogClean(email.content),
                                }}
                            ></p>
                        </div>
                    </div>
                ))}
            </div>
            <i className={join(styles, "inbox-end")}>
                Reached the end of your inbox
            </i>
        </div>
    );
}

/**
 * A component to view an open email
 */
function EmailView({
    openEmail,
    setOpenEmail,
}: {
    openEmail: number;
    setOpenEmail: ReactSetter<number | null>;
}) {
    const { coreState, phoneState, settingsState } = useGlobalState();

    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    // Get the global state
    const [emails] = phoneState.emails;
    const [replies, setReplies] = phoneState.replies;
    const [repliedEmails, setRepliedEmails] = phoneState.repliedEmails;

    const email = emails[openEmail];
    const options = email.attachments
        ? email.attachments.length
        : email.options
          ? email.options.length
          : 0;

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        options,
        keybinds.General.Up,
        keybinds.General.Down,
        coreState.popup[0] !== null
    );
    const optionRef = useRef<null | HTMLButtonElement>(null);
    const attachmentRef = useRef<null | HTMLDivElement>(null);

    const playerName = Registers.getTextRegister("player");

    // Button handle to play audio when the back button is pressed
    function backButton() {
        setOpenEmail(null);
        PlayAudio("email-back-button.mp3", "sounds");
        return true;
    }

    useEffect(() => {
        if (repliedEmails.includes(openEmail)) return;
        if (!email.options || email.options.length === 0) {
            setRepliedEmails((val) => [...val, openEmail]);
        }
    }, [openEmail, repliedEmails, setRepliedEmails, emails, email]);

    const handleReply = useCallback(
        (option: Option) => {
            HandleActions(option.actions);
            PlayAudio("email-reply.mp3", "sounds");

            setRepliedEmails((val) => [...val, openEmail]);

            setReplies((prevReplies) => ({
                ...prevReplies,
                [openEmail.toString()]: dialogClean(option.text),
            }));
        },
        [openEmail, setRepliedEmails, setReplies]
    );

    useEffect(() => {
        optionRef.current?.scrollIntoView({ behavior: "smooth" });
        attachmentRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [selectedIndex]);

    useKeyDown(keybinds.General.Back, backButton, coreState.popup[0] !== null);
    useKeyDown(
        keybinds.General.Select,
        useCallback(() => {
            if (email.attachments) {
                HandleActions(email.attachments[selectedIndex].actions);
                setSelectedIndex(-1);
                return;
            }

            if (email.options) {
                if (!repliedEmails.includes(openEmail)) {
                    handleReply(email.options[selectedIndex]);
                    email.options = [];
                    setSelectedIndex(-1);
                }
            }
        }, [
            email,
            selectedIndex,
            openEmail,
            repliedEmails,
            handleReply,
            setSelectedIndex,
        ]),
        selectedIndex === -1 || coreState.popup[0] !== null
    );

    // Render the email view
    return (
        <div className={join(styles, "email-wrapper")} tabIndex={-1}>
            <div className={join(phoneStyles, "header")}>
                <button tabIndex={-1} onClick={backButton}>
                    {dialogClean(
                        participantSettings.EnableKbControls
                            ? "Back (%key:general:back%)"
                            : "Back"
                    )}
                </button>
            </div>
            <div className={join(styles, "email-field")}>
                <span className={join(styles, "email-field-label")}>
                    From:{" "}
                </span>
                <span className={join(styles, "email-field-content")}>
                    {email.from}
                </span>
                <span
                    className={join(styles, "star")}
                >{`${email.important ? "⭐" : ""}`}</span>
            </div>
            <div className={join(styles, "email-field")}>
                <span className={join(styles, "email-field-label")}>To: </span>
                <span className={join(styles, "email-field-content")}>
                    {playerName}
                </span>
            </div>
            <div className={join(styles, "email-field")}>
                <span className={join(styles, "email-field-label")}>
                    Subject:{" "}
                </span>
                <span>{email.subject}</span>
            </div>
            <div className={join(styles, "email-field")}>
                <p
                    dangerouslySetInnerHTML={{
                        __html: dialogClean(email.content),
                    }}
                />
            </div>
            {email.attachments ? (
                email.attachments.map((attachment, index) => (
                    <div
                        onClick={() => {
                            HandleActions(attachment.actions);
                        }}
                        className={join(
                            styles,
                            "attachment",
                            index === selectedIndex ? "selected" : ""
                        )}
                        key={index}
                        ref={index === selectedIndex ? attachmentRef : null}
                    >
                        <img
                            src="assets/images/icons/attachment.svg"
                            alt={"email attatchment"}
                        />
                        <div>
                            <b>{attachment.text}</b>
                            <p>Click or select to open attachment</p>
                        </div>
                    </div>
                ))
            ) : (
                <></>
            )}
            {!repliedEmails.includes(openEmail) ? (
                <div className={join(styles, "email-reply-options")}>
                    <p style={{ color: "blue" }}>
                        Select an option below to reply:
                    </p>
                    {email.options &&
                        email.options.map((option, index) => (
                            <button
                                key={index}
                                className={join(
                                    styles,
                                    "email-reply-option",
                                    index === selectedIndex ? "selected" : ""
                                )}
                                onClick={() => handleReply(option)}
                                dangerouslySetInnerHTML={{
                                    __html: dialogClean(option.text),
                                }}
                                ref={
                                    index === selectedIndex
                                        ? optionRef
                                        : undefined
                                }
                            />
                        ))}
                </div>
            ) : (
                <div>
                    <i className={join(styles, "email-replied")}>
                        {email.options && replies[openEmail]
                            ? "You've already replied to this email:"
                            : ""}
                    </i>
                    {replies[openEmail] && (
                        <div className={join(styles, "email-field")}>
                            <p
                                dangerouslySetInnerHTML={{
                                    __html: `${replies[openEmail]}`,
                                }}
                            />
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}
