import styles from "#styles/minigames/renderers/TextbookMinigame.module.css";
import { ReactState } from "engine/src/state/GlobalState";
import { PlayAudio, StopAllAudio } from "engine/src/system/AudioSystem";
import {
    useKeyDown,
    useKeyHeld,
    useSelectedIndex,
} from "engine/src/system/Keyboard";
import { useCallback, useEffect, useState } from "react";
import { useGlobalState } from "../../../state/GlobalState";
import { join } from "engine/src/system/Styles";
import { Badges } from "../../../system/Unlockables";
import { Minigame, TextbookMinigame } from "../../../types/Minigame";
import { dialogClean } from "engine/src/system/Dialog";

type State = {
    type: Minigame["type"];
    data: {
        score: number;
        books: number;
        answeredQuestions: number[];
        state: "collection" | "question" | "feedback" | "game_over";
        current_question: number;
        current_answer: number;
    };
};

type MinigameState = {
    running: boolean;
    book_locations: [number, number][];
    bomb_locations: [number, number, number][];
    initialized: boolean;
    collection: number;
    books: number;
};

const book = new Image();
book.src = "assets/images/elements/book.png";

const bomb = new Image();
bomb.src = "assets/images/elements/bomb.png";

const pow = new Image();
pow.src = "assets/images/elements/pow.png";

const backpack = new Image();
backpack.src = "assets/images/elements/backpack.png";

const BOOK_COUNT = 3;
const BOOK_SPEED = 3;

const BOMB_COUNT = 10;
const BOMB_SPEED = 2;

const BOOKS_PER_QUESTION = 5;

const MOVE_SPEED = 8;
const SLOW_MOVE_SPEED = 4;

export const TextbookMinigameRenderer = ({
    minigame,
    state,
}: {
    minigame: TextbookMinigame;
    state: ReactState<State>;
}) => {
    const { settingsState } = useGlobalState();
    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    const [minigameState, setMinigameState] = useState<MinigameState>({
        running: false,
        book_locations: [] as [number, number][],
        bomb_locations: [] as [number, number, number][],
        initialized: false,
        collection: 10,
        books: 0,
    });
    const [tick, setTick] = useState<number>(0);

    const leftHeld = useKeyHeld(keybinds.Textbook_Minigame.Left);
    const rightHeld = useKeyHeld(keybinds.Textbook_Minigame.Right);
    const shiftHeld = useKeyHeld(keybinds.Textbook_Minigame.Slow_Movement);

    const move = (e: MouseEvent) => {
        const c = e.target as HTMLCanvasElement;

        const offsetX = e.offsetX;

        setMinigameState((val) => {
            return {
                ...val,
                collection: Math.min(
                    Math.max(0, offsetX - c.width / 40),
                    c.width - c.width / 20
                ),
            };
        });
    };

    const initialize = (
        c: HTMLCanvasElement,
        size: number,
        width: number,
        height: number
    ) => {
        setMinigameState((val) => {
            let book_locations = structuredClone(val.book_locations);
            let bomb_locations = structuredClone(val.bomb_locations);

            for (let i = 0; i < BOOK_COUNT; i++) {
                book_locations[i] = generateRandomPosition(size, width, height);
            }
            for (let i = 0; i < BOMB_COUNT; i++) {
                bomb_locations[i] = [
                    ...generateRandomPosition(size, width, height),
                    100,
                ];
            }
            return {
                ...val,
                initialized: true,
                book_locations,
                bomb_locations,
            };
        });
        c.addEventListener("mousemove", move);
    };

    const drawEntity = (
        ctx: CanvasRenderingContext2D,
        image: HTMLImageElement,
        position: [number, number],
        size: number
    ) => {
        ctx.drawImage(image, position[0], position[1], size, size);
    };

    const isCollected = useCallback(
        (entityPosition: number[], size: number, bottom: number) => {
            const center = entityPosition[0] + size / 2;

            return (
                center > minigameState.collection &&
                center < minigameState.collection + size &&
                entityPosition[1] > bottom - size
            );
        },
        [minigameState.collection]
    );

    const generateRandomPosition = (
        size: number,
        width: number,
        height: number
    ): [number, number] => {
        return [
            Math.random() * (width - size),
            -height / 20 - Math.random() * 100,
        ];
    };

    const handleEntityMovement = (
        entityPositions: number[][],
        index: number,
        speed: number,
        size: number,
        width: number,
        height: number
    ) => {
        if (
            entityPositions[index][1] > height ||
            isCollected(entityPositions[index], size, height)
        ) {
            entityPositions[index] = generateRandomPosition(
                size,
                width,
                height
            );
        }
        entityPositions[index][1] +=
            (index / (entityPositions.length / 2) + 1) * speed;
    };

    const answeredAllQuestions = () => {
        return (
            state[0].data.answeredQuestions.length === minigame.questions.length
        );
    };

    const runTick = useCallback(() => {
        let c = document.getElementById(
            "textbook-minigame-canvas"
        ) as HTMLCanvasElement;
        let wrapper = document.getElementById(
            "textbook-minigame-outer"
        ) as HTMLDivElement;

        if (!wrapper || !c) return;

        c.width = wrapper.clientWidth;
        c.height = wrapper.clientHeight;

        if (
            !state[0] ||
            state[0].data.state !== "collection" ||
            !c ||
            !wrapper
        ) {
            return;
        }
        if (!minigameState.initialized) {
            initialize(c, c.width / 20, c.width, c.height);
        }

        if (answeredAllQuestions()) {
            state[1]((val) => {
                return {
                    ...val,
                    data: {
                        ...val.data,
                        state: "game_over",
                    },
                };
            });
            return;
        }

        const ctx = c.getContext("2d") as CanvasRenderingContext2D;

        for (let i = 0; i < minigameState.book_locations.length; i++) {
            drawEntity(
                ctx,
                book,
                minigameState.book_locations[i],
                c.width / 20
            );

            if (
                isCollected(
                    minigameState.book_locations[i],
                    c.width / 20,
                    c.height
                )
            ) {
                PlayAudio("page-flip.wav", "sounds", false);
                if ((minigameState.books + 1) % BOOKS_PER_QUESTION === 0) {
                    const incomplete_question_indices: number[] =
                        minigame.questions
                            .map((_, i) => i)
                            .filter(
                                (i) =>
                                    !state[0].data.answeredQuestions.includes(i)
                            );
                    state[1]((val) => {
                        return {
                            ...val,
                            data: {
                                ...val.data,
                                state: "question",
                                books: minigameState.books + 1,
                                current_question:
                                    incomplete_question_indices[
                                        Math.floor(
                                            Math.random() *
                                                incomplete_question_indices.length
                                        )
                                    ],
                            },
                        };
                    });

                    setMinigameState((val) => {
                        return {
                            ...val,
                            initialized: false,
                            book_locations: [],
                            books: val.books + 1,
                        };
                    });
                    return;
                } else {
                    state[1]((val) => {
                        return {
                            ...val,
                            data: {
                                ...val.data,
                                books: minigameState.books + 1,
                            },
                        };
                    });
                    setMinigameState((val) => {
                        return { ...val, books: val.books + 1 };
                    });
                }
            }

            handleEntityMovement(
                minigameState.book_locations,
                i,
                BOOK_SPEED,
                c.width / 20,
                c.width,
                c.height
            );
        }

        if (leftHeld) {
            setMinigameState((val) => {
                return {
                    ...val,
                    collection: Math.min(
                        Math.max(
                            0,
                            val.collection -
                                (shiftHeld ? SLOW_MOVE_SPEED : MOVE_SPEED)
                        ),
                        c.width - c.width / 20
                    ),
                };
            });
        } else if (rightHeld) {
            setMinigameState((val) => {
                return {
                    ...val,
                    collection: Math.min(
                        Math.max(
                            0,
                            val.collection +
                                (shiftHeld ? SLOW_MOVE_SPEED : MOVE_SPEED)
                        ),
                        c.width - c.width / 20
                    ),
                };
            });
        }

        for (let i = 0; i < minigameState.bomb_locations.length; i++) {
            if (
                isCollected(
                    [
                        minigameState.bomb_locations[i][0],
                        minigameState.bomb_locations[i][1],
                    ],
                    c.width / 20,
                    c.height
                ) &&
                minigameState.bomb_locations[i][2] >= 100
            ) {
                PlayAudio("explosionretro.wav", "sounds", false);
                state[1]((val) => {
                    return {
                        ...val,
                        data: {
                            ...val.data,
                            score: Math.floor(val.data.score / 2),
                        },
                    };
                });
                drawEntity(
                    ctx,
                    pow,
                    [
                        minigameState.bomb_locations[i][0],
                        minigameState.bomb_locations[i][1],
                    ],
                    c.width / 20
                );

                setMinigameState((val) => {
                    let bomb_locations = structuredClone(val.bomb_locations);
                    bomb_locations[i][2]--;

                    return {
                        ...val,
                        bomb_locations,
                    };
                });
            } else if (minigameState.bomb_locations[i][2] >= 100) {
                drawEntity(
                    ctx,
                    bomb,
                    [
                        minigameState.bomb_locations[i][0],
                        minigameState.bomb_locations[i][1],
                    ],
                    c.width / 20
                );

                if (minigameState.bomb_locations[i][1] > c.height) {
                    setMinigameState((val) => {
                        let bomb_locations = structuredClone(
                            val.bomb_locations
                        );
                        bomb_locations[i] = [
                            ...generateRandomPosition(
                                c.width / 29,
                                c.width,
                                c.height
                            ),
                            100,
                        ];

                        return {
                            ...val,
                            bomb_locations,
                        };
                    });
                }
                setMinigameState((val) => {
                    let bomb_locations = structuredClone(val.bomb_locations);
                    bomb_locations[i][1] +=
                        (i / (minigameState.bomb_locations.length / 2) + 1) *
                        BOMB_SPEED;

                    return {
                        ...val,
                        bomb_locations,
                    };
                });
            }
        }

        ctx.strokeStyle = "#000";
        drawEntity(
            ctx,
            backpack,
            [minigameState.collection, c.height - c.width / 20],
            c.width / 20
        );

        for (let i = 0; i < minigameState.bomb_locations.length; i++) {
            if (
                minigameState.bomb_locations[i][2] > 0 &&
                minigameState.bomb_locations[i][2] < 100
            ) {
                const size =
                    (c.width / 20) *
                    ((150 - minigameState.bomb_locations[i][2]) / 100);
                drawEntity(
                    ctx,
                    pow,
                    [
                        minigameState.bomb_locations[i][0] +
                            (c.width / 20 - size) / 2,
                        minigameState.bomb_locations[i][1] +
                            (c.width / 20 - size) / 2,
                    ],
                    size
                );
                setMinigameState((val) => {
                    let bomb_locations = structuredClone(val.bomb_locations);
                    bomb_locations[i][2] -= 4;

                    return {
                        ...val,
                        bomb_locations,
                    };
                });
            }
        }

        if (minigameState.collection < 1) {
            setMinigameState((val) => {
                return { ...val, collection: 1 };
            });
        }
        if (minigameState.collection > c.width - c.width / 20) {
            setMinigameState((val) => {
                return { ...val, collection: c.width - c.width / 20 };
            });
        }
        // eslint-disable-next-line
    }, [minigameState, isCollected, minigame.questions, state]);

    useEffect(() => {
        if (!minigameState.running) return;
        setTimeout(() => {
            setTick((i) => i + 1);
        }, 10);

        runTick();
        // eslint-disable-next-line
    }, [minigameState.running, tick]);

    if (
        !minigameState.running &&
        state[0] &&
        state[0].data.state === "collection"
    ) {
        setMinigameState((val) => {
            return { ...val, running: true };
        });
    }

    const states: Record<State["data"]["state"], any> = {
        collection: <Collection />,
        question: (
            <Question
                state={state}
                minigame={minigame}
                minigameState={[minigameState, setMinigameState]}
            />
        ),
        game_over: (
            <GameOver
                state={state}
                minigame={minigame}
                minigameState={[minigameState, setMinigameState]}
            />
        ),
        feedback: <Feedback state={state} minigame={minigame} />,
    };

    return (
        <div
            id="textbook-minigame-outer"
            className={join(styles, "textbook-minigame-outer")}
            style={{
                height: "100%",
                width: "100%",
                position: "relative",
            }}
        >
            <div className={join(styles, "textbook-minigame-info")}>
                <p>Score:</p>
                <i>{state[0].data.score}</i>
                <p>Books:</p>
                <i>{state[0].data.books}</i>
                <p>Questions:</p>
                <i>
                    {state[0].data.answeredQuestions.length}/
                    {minigame.questions.length}
                </i>
            </div>
            {!["question", "feedback", "game_over"].includes(
                state[0].data.state
            ) ? (
                <div
                    className={join(
                        styles,
                        "textbook-minigame-info",
                        "textbook-minigame-instructions"
                    )}
                >
                    <p>How to play:</p>
                    <p>
                        Catch the falling books using the bag at the bottom, and
                        avoid the bombs. Move the mouse to control the bag
                        {participantSettings.EnableKbControls
                            ? dialogClean(
                                  " or use %key:textbook_minigame:left% and %key:textbook_minigame:right%. You can also use %key:textbook_minigame:slow_movement% to move slower with the keyboard."
                              )
                            : "."}
                    </p>
                </div>
            ) : (
                <></>
            )}
            {states[state[0].data.state]}
        </div>
    );
};

const Collection = () => {
    return (
        <>
            <canvas id="textbook-minigame-canvas" width={0}>
                outdated browser
            </canvas>
        </>
    );
};

const Feedback = ({
    state,
    minigame,
}: {
    state: ReactState<State>;
    minigame: TextbookMinigame;
}) => {
    const { settingsState } = useGlobalState();
    const [keybinds] = settingsState.keybinds;

    const question = minigame.questions[state[0].data.current_question];
    const answer = question.answers[state[0].data.current_answer];

    const onContinue = () => {
        state[1]((val) => {
            return {
                ...val,
                data: {
                    ...val.data,
                    state: "collection",
                    score: val.data.score + answer.score,
                    answeredQuestions: [
                        ...val.data.answeredQuestions,
                        state[0].data.current_question,
                    ],
                },
            };
        });
    };

    useKeyDown(keybinds.Minigames.Select, onContinue);

    return (
        <div style={{ width: "80%", display: "flex", flexDirection: "column" }}>
            <b>{question.question}</b>
            <p>{answer.feedback}</p>
            <i>
                You {answer.score > 0 ? "gained" : "lost"}{" "}
                {Math.abs(answer.score)} point
                {Math.abs(answer.score) === 1 ? "" : "s"}
            </i>
            <button onClick={onContinue}>continue</button>
        </div>
    );
};

const Question = ({
    state,
    minigame,
    minigameState,
}: {
    state: ReactState<State>;
    minigame: TextbookMinigame;
    minigameState: ReactState<MinigameState>;
}) => {
    const { settingsState } = useGlobalState();
    const [keybinds] = settingsState.keybinds;

    if (minigameState[0].running) {
        minigameState[1]((val) => {
            return { ...val, running: false };
        });
    }
    const question = minigame.questions[state[0].data.current_question];

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        question.answers.length,
        keybinds.General.Up,
        keybinds.General.Down
    );

    const chooseOption = (index: number) => {
        state[1]((val) => {
            return {
                ...val,
                data: {
                    ...val.data,
                    state: "feedback",
                    current_answer: index,
                },
            };
        });
    };

    useKeyDown(
        keybinds.Minigames.Select,
        () => chooseOption(selectedIndex),
        selectedIndex === -1
    );

    return (
        <div style={{ width: "80%", display: "flex", flexDirection: "column" }}>
            <b>{question.question}</b>
            {question.answers.map((a, i) => (
                <button
                    className={join(
                        styles,
                        i === selectedIndex ? "selected" : ""
                    )}
                    key={a.answer}
                    onClick={() => chooseOption(i)}
                    onMouseEnter={() => setSelectedIndex(i)}
                >
                    {a.answer}
                </button>
            ))}
        </div>
    );
};

const GameOver = ({
    state,
    minigame,
    minigameState,
}: {
    state: ReactState<State>;
    minigame: TextbookMinigame;
    minigameState: ReactState<MinigameState>;
}) => {
    const { coreState, settingsState } = useGlobalState();

    const [, setPopup] = coreState.popup;
    const [, setMinigame] = coreState.minigame;
    const [keybinds] = settingsState.keybinds;

    if (minigameState[0].running) {
        minigameState[1]((val) => {
            return {
                ...val,
                running: false,
                interval: null,
                book_locations: [],
                initialized: false,
                collection: 10,
                movement: 0,
            };
        });
    }

    const exit = () => {
        setPopup(null);
        setMinigame(null);
        StopAllAudio("music");
        minigameState[1]((val) => {
            return { ...val, running: false, books: 0 };
        });

        if (
            state[0].data.score ===
            minigame.questions.reduce(
                (acc, question) =>
                    acc +
                    question.answers.reduce(
                        (max, answer) => Math.max(max, answer.score),
                        question.answers[0].score
                    ),
                0
            )
        ) {
            Badges.unlock("minigame:bomb_defuser");
        }
    };

    useKeyDown([...keybinds.Minigames.Select, ...keybinds.General.Back], exit);

    return (
        <div style={{ width: "80%", display: "flex", flexDirection: "column" }}>
            <b>Game Over</b>
            <p>
                Congratulations! You have learned some good habits to take with
                you.
            </p>
            <button onClick={exit}>Exit</button>
        </div>
    );
};
