import { useEffect, useRef, useState } from "react";
import journalStyles from "#styles/apps/JournalApp.module.css";
import { join } from "engine/src/system/Styles";
import { useGlobalState } from "../../state/GlobalState";
import {
    Keybinds,
    useKeyDown,
    useSelectedIndex,
} from "engine/src/system/Keyboard";
import { PlayAudio } from "engine/src/system/AudioSystem";

export function GenericListApp<ItemData>({
    title,
    closeApp,
    pages,
    elementsSelectable,
    ItemComponent,
}: {
    title: string;
    closeApp: () => void;
    pages: {
        name: string;
        title: string;
        description: JSX.Element;
        data: ItemData[];
    }[];
    elementsSelectable: boolean;
    ItemComponent: ({
        item,
        index,
        selected,
    }: {
        item: ItemData;
        index: number;
        selected: boolean;
        keybinds: Keybinds;
    }) => JSX.Element;
}) {
    const { coreState, settingsState } = useGlobalState();

    const [keybinds] = settingsState.keybinds;

    const [popup] = coreState.popup;

    const [onContent, setOnContent] = useState<boolean>(false);
    const [currentPage, setCurrentPage] = useState<{
        title: string;
        description: JSX.Element;
        data: ItemData[];
    }>(pages[0]);

    const contentRef = useRef<HTMLDivElement | null>(null);

    const [page, setPage] = useSelectedIndex(
        pages.length,
        keybinds.General.Up,
        keybinds.General.Down,
        popup !== null || onContent
    );
    const [selectedItem, setSelectedItem] = useSelectedIndex(
        currentPage.data.length,
        keybinds.General.Up,
        keybinds.General.Down,
        popup !== null || !onContent || !elementsSelectable
    );

    useKeyDown(keybinds.General.Back, () => {
        if (onContent) return setOnContent(false);
        closeApp();
    });
    useKeyDown(keybinds.General.Right, () => setOnContent(true));
    useKeyDown(keybinds.General.Left, () => setOnContent(false));

    useEffect(() => {
        if (page === -1) {
            setPage(0);
        } else {
            setCurrentPage(pages[page]);
        }
        // eslint-disable-next-line
    }, [page, setPage]);

    useEffect(() => {
        if (onContent) {
            setSelectedItem(0);
        } else {
            setSelectedItem(-1);
        }
    }, [onContent, setSelectedItem]);

    useEffect(() => {
        if (onContent) {
            contentRef.current?.focus();
        }
    }, [onContent]);

    return (
        <div className={join(journalStyles, "journal")}>
            <div className={join(journalStyles, "journal-margin")}>
                <ul className={join(journalStyles, "journal-controls")}>
                    {pages.map((pageItem, index) => (
                        <li
                            key={index}
                            className={join(
                                journalStyles,
                                `journal-control`,
                                page === index && !onContent ? "selected" : ""
                            )}
                            onClick={() => {
                                setPage(index);
                                PlayAudio("journal-page-flip.mp3", "sounds");
                            }}
                        >
                            {pageItem.name}
                        </li>
                    ))}
                </ul>
            </div>
            <h1>{title}</h1>
            {!elementsSelectable && (
                <div
                    className={
                        onContent ? join(journalStyles, `section-selected`) : ""
                    }
                ></div>
            )}
            <div
                className={join(journalStyles, "journal-section")}
                ref={contentRef}
            >
                <h1>{currentPage.title}</h1>
                {currentPage.description}
                <ul>
                    {currentPage.data.map((item, index) => (
                        <ItemComponent
                            key={index}
                            item={item}
                            index={index}
                            selected={index === selectedItem}
                            keybinds={keybinds}
                        />
                    ))}
                </ul>
            </div>
        </div>
    );
}
