import { useBaseGlobalState } from "../state/GlobalState";
import {useEffect, useRef} from "react";
import Flags from "../system/Flags";

export const FlagListener = () => {
    const {coreState} = useBaseGlobalState();
    
    const [flags] = coreState.unlockedFlags;

    const oldFlags = useRef<string[]>(flags);

    useEffect(() => {
        const old = oldFlags.current;
        const newFlags = flags.filter(flag => !old.includes(flag));

        for(const flag of newFlags) {
            Flags.handleFlagChanged(flag);
        }

        oldFlags.current = flags;
    }, [flags]);
    
    return null;
}
