const formatTime = (number: number) => {
    let hours = Math.floor(number) % 12;
    let minutes = Math.ceil((number - Math.floor(number)) * 60);
    if (hours === 0) hours = 12;

    return `${hours}:${(minutes + "").padStart(2, "0")}${number < 12 ? "am" : "pm"}`;
};

const formatHour = (number: number) => {
    let hours = Math.floor(number) % 12;
    if (hours === 0) hours = 12;

    return `${hours}${number < 12 ? "am" : "pm"}`;
};

const getOverlappingWith = (
    overlap: ReturnType<typeof findOverlap>,
    code: string,
    type: string,
    section: number
) => {
    const overlappingWith: (typeof overlap)[number][number][] = [];

    for (const o of overlap) {
        if (
            o[0].code === code &&
            o[0].type === type &&
            o[0].section === section
        ) {
            overlappingWith.push(o[1]);
        }
        if (
            o[1].code === code &&
            o[1].type === type &&
            o[1].section === section
        ) {
            overlappingWith.push(o[0]);
        }
    }
    return overlappingWith;
};

