import { useEffect, useRef, useState } from "react";
import { useGlobalState } from "../../state/GlobalState";
import activityStyles from "#styles/popup/Activity.module.css";
import documentStyles from "#styles/popup/document.module.css";
import { JournalDocument } from "../../types/Document";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { useKeyDown } from "engine/src/system/Keyboard";
import { join } from "engine/src/system/Styles";
import { SendDocumentClosed } from "engine/src/system/BackendSystem";

function DocumentPopup() {
    const { coreState, settingsState } = useGlobalState();

    const popupData = coreState.popupStateData[0] as JournalDocument;
    const [popup] = coreState.popup;

    const [keybinds] = settingsState.keybinds;

    const [content, setContent] = useState<string>("");

    const pageRef = useRef<HTMLDivElement | null>(null);

    useEffect(() => {
        const domDocument = document.getElementById("document");
        if (domDocument) {
            domDocument.scrollTo(0, 0);
        }

        if (
            !popupData ||
            !popupData.name ||
            !popupData.file ||
            popup !== "document"
        )
            return;
        fetch(`data/document/${popupData.file}.html`).then((res) => {
            res.text().then((data) => {
                setContent(data);
                const printableElement: HTMLDivElement =
                    document.getElementById(
                        "print-content"
                    ) as HTMLTableCellElement;
                printableElement.innerHTML = `<div class="document-wrapper">
                    <div class="document">
                        <div class="doc-header">
                            <div>
                                <h1 class="chapter-document">CH ${popupData.chapter}</h1>
                                <h1 class="doc-title">${popupData.name}</h1>
                            </div>
                            <img src="assets/images/elements/Logo.png" />
                        </div>
                        <main>
                            ${data}
                        </main>
                    </div>
                </div>`;
            });
        });

        document
            .getElementById("temporary-style")
            ?.setAttribute(
                "href",
                `styles/documents/${popupData.stylesheet}.css`
            );
    }, [popupData, popup, setContent]);

    const onClose = () => {
        PlayAudio("app-click.wav", "sounds");
        coreState.popup[1](null);
        SendDocumentClosed(popupData.file, coreState.appEnabled[1]);
    };

    useEffect(() => {
        pageRef.current?.focus();
        // eslint-disable-next-line
    }, []);

    const hidden =
        !popupData ||
        !popupData.name ||
        popup !== "document" ||
        !popupData.file;

    useKeyDown(keybinds.General.Back, onClose, hidden);

    if (hidden) return <></>;

    const innerHTML = {
        __html: content,
    };

    return (
        <div className={join(documentStyles, "document-wrapper")}>
            <div
                className={join(documentStyles, "document") + " document"}
                id="document"
                ref={pageRef}
                tabIndex={0}
            >
                <div className={join(documentStyles, "doc-header")}>
                    <h1 className={join(documentStyles, "chapter-document")}>
                        CH {popupData.chapter}
                    </h1>
                    <h1 className={join(documentStyles, "doc-title")}>
                        {popupData.name}
                    </h1>
                </div>
                <main dangerouslySetInnerHTML={innerHTML} />
                <div className={join(activityStyles, "activity-controls")}>
                    <button
                        onClick={() => {
                            PlayAudio("app-click.wav", "sounds");
                            window.print();
                        }}
                    >
                        Print
                    </button>
                    <button onClick={onClose}>Close</button>
                </div>
            </div>
        </div>
    );
}

export default DocumentPopup;
