import { Scene } from "engine/src/types/Scene";
import styles from "../styles/Scene.module.css";
import { CoreState, ReactSetter } from "engine/src/state/GlobalState";
import { SendSceneChange } from "engine/src/system/BackendSystem";

const SwitchCallback = (
    newScene: Scene,
    setScene: ReactSetter<Scene>,
    sceneElement: HTMLDivElement
) => {
    setScene(newScene);
    setTimeout(() => {
        sceneElement.classList.add(styles["fade-in"]);
    }, 500);
};

export const SwitchScene = (
    newScene: Scene,
    coreState: CoreState<any, any>,
    setPhoneOpen?: ReactSetter<boolean>,
    mixin?: () => void
) => {
    const sceneState = coreState.scene;
    const [, setSceneBackground] = coreState.sceneBackground;
    if (sceneState[0].name === newScene.name) return;

    const sceneElement: HTMLDivElement = document.getElementById(
        "scene"
    ) as HTMLDivElement;
    if (!sceneElement) {
        setTimeout(
            () => SwitchScene(newScene, coreState, setPhoneOpen, mixin),
            100
        );
        return;
    }
    sceneElement.classList.remove(styles["fade-in"]);
    sceneElement.classList.add(styles["fade-out"]);

    setTimeout(() => {
        const sceneBackground = new Image();
        sceneBackground.onload = () => {
            SwitchCallback(newScene, sceneState[1], sceneElement);
            setTimeout(() => {
                sceneElement.classList.remove(styles["fade-out"]);
            }, 100);
        };
        setSceneBackground(0);
        sceneBackground.onerror = (e) => console.error(e);
        sceneBackground.src = `assets/images/backgrounds/${newScene.backgrounds[0].image}`;
    }, 500);

    if (setPhoneOpen) setPhoneOpen(false);
    if (mixin) mixin();

    SendSceneChange(newScene.name, coreState.appEnabled[1]);
};

export const SwitchSceneInstant = (
    newScene: Scene,
    coreState: CoreState<any, any>,
    setPhoneOpen?: ReactSetter<boolean>,
    mixin?: () => void
) => {
    const sceneElement: HTMLDivElement = document.getElementById(
        "scene"
    ) as HTMLDivElement;

    const sceneState = coreState.scene;
    if (sceneState[0].name === newScene.name) {
        sceneElement.classList.add(styles["fade-in"]);
        return;
    }

    if (!sceneElement) {
        console.warn("Could not find scene element!");
        setTimeout(
            () => SwitchSceneInstant(newScene, coreState, setPhoneOpen, mixin),
            100
        );
        return;
    }

    sceneState[1](newScene);
    sceneElement.classList.add(styles["fade-in"]);

    if (setPhoneOpen) setPhoneOpen(false);
    if (mixin) mixin();

    SendSceneChange(newScene.name, coreState.appEnabled[1]);
};
