import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const ImageActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "image"
> = (element, playerData, updateState) => {
    return {
        appView: (
            <img
                src={element.imagePath}
                height={element.height}
                width={element.width}
                alt={element.imagePath}
            ></img>
        ),
        printView: (
            <img
                src={element.imagePath}
                height={element.height}
                width={element.width}
                alt={element.imagePath}
            ></img>
        ),
    };
};

export const DefaultImageActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "image"
> = () => {
    return {
        type: "image",
        complete: true,
    };
};
