import styles from "#styles/activities/renderers/spreadsheet.module.css";
import {
    Activities,
    SpreadsheetActivityElement,
} from "../../../types/Activity";
import {
    ActivityElementPlayerData,
    SpreadsheetActivityPlayerData,
} from "../../../types/ActivityPlayerData";
import { editState } from "../../../state/Util";
import { useEffect, useState } from "react";
import { join } from "engine/src/system/Styles";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";

export const SpreadsheetActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "spreadsheet"
> = (element, playerData, updateState, [binds, updateBinding]) => {
    const updateTable = (
        index: number,
        tableData: (typeof playerData)["tables"][0]
    ) => {
        editState(playerData, updateState, (old) => {
            old.tables[index] = tableData;
            return old;
        });
    };

    return {
        appView: (
            <div
                className={join(styles, "spreadsheet-holder")}
                key={`spreadsheet-${element.tables[0].categoryHeader}`}
            >
                {element.tables.map((table, i) => (
                    <SpreadsheetTable
                        id={i}
                        key={i}
                        element={element}
                        table={table}
                        playerData={playerData.tables[i]}
                        updateState={updateTable.bind(null, i)}
                        binds={binds}
                        updateBinding={updateBinding}
                    />
                ))}
            </div>
        ),
        printView: (
            <div
                className={
                    join(styles, "spreadsheet-holder") + " spreadsheet-holder"
                }
                key={`spreadsheet-${element.tables[0].categoryHeader}`}
            >
                {element.tables.map((table, i) => (
                    <SpreadsheetTable
                        key={i}
                        id={i}
                        element={element}
                        table={table}
                        playerData={playerData.tables[i]}
                        binds={binds}
                        updateBinding={updateBinding}
                    />
                ))}
            </div>
        ),
    };
};

const rowMajorToColumnMajor = (
    rowMajor: SpreadsheetActivityPlayerData["tables"][0]["rows"]
) => {
    const columns: number[][] = [];

    rowMajor.forEach((row, i) => {
        row.columns.forEach((col, j) => {
            if (!columns[j]) columns[j] = [];
            columns[j][i] = col;
        });
    });

    return columns;
};

const SpreadsheetTable = ({
    id,
    element,
    table,
    playerData,
    updateState,
    binds,
    updateBinding,
}: {
    id: number;
    element: SpreadsheetActivityElement;
    table: SpreadsheetActivityElement["tables"][0];
    playerData: SpreadsheetActivityPlayerData["tables"][0];
    updateState?: (arg0: SpreadsheetActivityPlayerData["tables"][0]) => void;
    binds: Record<string, string>;
    updateBinding: (element: Activities, key: string, value: string) => void;
}) => {
    const [internalState, updateInternalState] = useState({ ...playerData });

    const handleChange = (
        row: number,
        column: number
    ): React.ChangeEventHandler<HTMLInputElement> => {
        return (e) =>
            updateState &&
            updateInternalState((val) => {
                const old = structuredClone(val);

                old.rows[row].columns[column] = e.target.valueAsNumber || -1;
                return old;
            });
    };

    const handleBlur = (
        row: number,
        column: number
    ): React.ChangeEventHandler<HTMLInputElement> => {
        return (e) =>
            updateState &&
            editState(playerData, updateState, (old) => {
                old.rows[row].columns[column] = e.target.valueAsNumber || -1;

                return old;
            });
    };

    const editRowName = (
        row: number
    ): React.ChangeEventHandler<HTMLInputElement> => {
        return (e) =>
            updateState &&
            editState(playerData, updateState, (old) => {
                old.rows[row].name = e.target.value;
                return old;
            });
    };

    const deleteRow = (
        row: number
    ): React.MouseEventHandler<HTMLButtonElement> => {
        return () =>
            updateState &&
            editState(playerData, updateState, (old) => {
                old.rows = old.rows.filter((_, i) => i !== row);
                return old;
            });
    };

    const addRow: React.ChangeEventHandler<HTMLInputElement> = (e) => {
        if (e.target.value.trim() === "") return;
        if (!updateState) return;
        editState(playerData, updateState, (old) => {
            old.rows.push({
                name: e.target.value,
                columns: new Array(table.valueHeaders.length).fill(-1),
            });
            e.target.value = "";
            return old;
        });
    };

    useEffect(() => {
        updateInternalState(playerData);
    }, [playerData]);

    const columnTotals =
        playerData.rows.length > 0
            ? rowMajorToColumnMajor(playerData.rows).map((col) =>
                  col
                      .filter((num) => num !== -1)
                      .reduce((prev, curr) => prev + curr, 0)
              )
            : new Array<number>(table.valueHeaders.length).fill(0);

    columnTotals.forEach((value, i) =>
        updateBinding(element, `total-${id}-${i}`, value.toLocaleString())
    );

    playerData.rows.forEach((row, rowIdx) => {
        row.columns.forEach((cell, colIdx) => {
            updateBinding(
                element,
                `celldata-${id}-${rowIdx}-${colIdx}`,
                cell.toLocaleString()
            );
        });
    });

    // Update cells based on bindings
    const toChange: [number, number, number][] = [];
    for (let binding in binds) {
        if (binding.split("-").length !== 4) continue;

        if (binding.split("-")[1] !== id.toString()) continue;

        const row = parseInt(binding.split("-")[2]);
        const col = parseInt(binding.split("-")[3]);

        const newDataStr = binds[binding];
        const oldData = playerData.rows[row].columns[col];

        if (newDataStr === undefined || newDataStr === null) continue;

        const newData = Math.floor(parseInt(newDataStr.replace(/\D/g, "")));

        if (newData !== oldData) {
            toChange.push([row, col, newData]);
        }
    }

    if (toChange.length > 0) {
        setTimeout(
            () =>
                updateState &&
                editState(playerData, updateState, (old) => {
                    for (const record of toChange) {
                        old.rows[record[0]].columns[record[1]] = record[2];
                    }
                    return old;
                }),
            1
        );
    }

    return (
        <div
            className={join(styles, `spreadsheet-sheet`) + " spreadsheet-sheet"}
            key={table.categoryHeader}
        >
            {table.header && <h2>{table.header}</h2>}
            <table
                className={
                    join(styles, "spreadsheet-table") + " spreadsheet-table"
                }
            >
                <thead>
                    <tr>
                        {table.canRemoveRows && updateState && (
                            <th
                                className={
                                    join(styles, "delete-col") + " delete-col"
                                }
                            ></th>
                        )}
                        <th
                            style={{
                                width: `calc(100% / ${table.valueHeaders.length + 1}`,
                            }}
                        >
                            {table.categoryHeader}
                        </th>
                        {table.valueHeaders.map((header) => (
                            <th key={header}>{header}</th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {internalState.rows.map((row, i) => (
                        <tr key={i}>
                            {table.canRemoveRows &&
                                updateState &&
                                (table.initialCategories.includes(row.name) ? (
                                    <td />
                                ) : (
                                    <td
                                        className={
                                            join(styles, "delete-col") +
                                            " delete-col"
                                        }
                                    >
                                        <button onClick={deleteRow(i)}>
                                            ×
                                        </button>
                                    </td>
                                ))}
                            <td>
                                <input
                                    className={
                                        join(styles, "name-col") + " name-col"
                                    }
                                    type="text"
                                    key={row.name}
                                    style={{
                                        width: "calc(100% - 8px)",
                                        height: "100%",
                                    }}
                                    defaultValue={row.name}
                                    disabled={
                                        !table.canEditCellName ||
                                        table.initialCategories.includes(
                                            row.name
                                        )
                                    }
                                    onBlur={editRowName(i)}
                                />
                            </td>
                            {row.columns.map((value, j) => (
                                <td key={`${i}-${j}`}>
                                    <input
                                        type="number"
                                        placeholder="enter value"
                                        style={{
                                            width: "calc(100% - 8px)",
                                            height: "100%",
                                        }}
                                        min={0}
                                        value={value === -1 ? "" : value}
                                        disabled={!table.canEditCellValue}
                                        onChange={handleChange(i, j)}
                                        onBlur={handleBlur(i, j)}
                                    />
                                </td>
                            ))}
                        </tr>
                    ))}
                    {table.canAddRows && updateState ? (
                        <tr className={join(styles, "addNew") + " addNew"}>
                            {table.canRemoveRows && (
                                <td
                                    className={
                                        join(styles, "delete-col") +
                                        " delete-col"
                                    }
                                />
                            )}
                            <td>
                                <input
                                    type="text"
                                    style={{
                                        width: "calc(100% - 8px)",
                                        height: "100%",
                                    }}
                                    placeholder="Add Row"
                                    onBlur={addRow}
                                />
                            </td>
                        </tr>
                    ) : (
                        <></>
                    )}
                </tbody>
                <tfoot>
                    <tr>
                        {table.canRemoveRows && updateState && (
                            <td
                                className={
                                    join(styles, "delete-col") + " delete-col"
                                }
                            />
                        )}
                        <td className={join(styles, "total") + " total"}>
                            {table.totalText}
                        </td>
                        {columnTotals.map((value, col) => (
                            <td key={`${table.categoryHeader}-${col}-footer`}>
                                <span>{"$" + value.toLocaleString()}</span>
                            </td>
                        ))}
                    </tr>
                </tfoot>
            </table>
        </div>
    );
};

export const DefaultSpreadsheetActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "spreadsheet"
> = (element) => {
    return {
        type: "spreadsheet",
        complete: false,
        tables: element.tables.map((table) => ({
            rows: table.initialCategories.map((row) => ({
                name: row,
                columns: new Array<number>(table.valueHeaders.length).fill(-1),
            })),
        })),
    };
};
