import { join } from "engine/src/system/Styles";
import styles from "#styles/dialog/StrategyUnlockButton.module.css";
import { Strategies } from "../../system/Unlockables";
import { useGlobalState } from "../../state/GlobalState";
import { useKeyboardToggle, useKeyDown } from "engine/src/system/Keyboard";
import { useState } from "react";
import { Dialog } from "engine/src/types/Dialog";

type ModifiedDialogType = Dialog["dialog"][0] & {
    strategy: string;
};

export const StrategyUnlockButton = (
    dialog: Dialog["dialog"][0]
): [React.ReactNode, boolean] => {
    const expandedDialog = dialog as ModifiedDialogType;
    const strategy = expandedDialog.strategy;

    const { playerState, settingsState, coreState } = useGlobalState();

    const [keybinds] = settingsState.keybinds;

    const [disabled, setDisabled] = useState<boolean>(false);
    const [selected, setSelected] = useKeyboardToggle(
        [],
        keybinds.General.Right,
        keybinds.General.Left,
        disabled || coreState.dialogHistoryOpen[0]
    );

    const [strats] = playerState.unlockedStrategies;

    function onSelected() {
        setDisabled(true);
        setSelected(false);
    }

    useKeyDown(
        keybinds.General.Select,
        () => {
            if (strategy) {
                Strategies.unlock(strategy);
                onSelected();
            }
        },
        !strategy || !selected
    );

    if (!strategy) return [<></>, false];

    return strats.includes(strategy)
        ? [<></>, false]
        : [
              <button
                  className={join(
                      styles,
                      "unlock-btn",
                      selected ? "selected" : ""
                  )}
                  onClick={(e) => {
                      e.stopPropagation();
                      Strategies.unlock(strategy);
                      onSelected();
                  }}
              >
                  <img
                      src="assets/images/elements/book.png"
                      alt="select to unlock a strategy"
                  />
              </button>,
              selected,
          ];
};
