import styles from "#styles/activities/renderers/piechart.module.css";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { join } from "engine/src/system/Styles";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

const COLOURS = ["#97E2BD", "#5B6EE1", "#D8A67A", "#FDF9E0", "#E29897"];

export const PieChartActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "pie_chart"
> = (element, playerData, updateState, [bound, updateBinding, bindings]) => {
    const keys = element.inputNames;
    const values = keys
        .map((key) => bound[key])
        .map((value) => (value ? value : "0"))
        .map((value) =>
            value.includes("-")
                ? "-" + value.replace(/\D/g, "")
                : value.replace(/\D/g, "")
        )
        .map((value) => Math.floor(parseInt(value)));

    const total = values
        .filter((value) => value >= 0)
        .reduce((prev, curr) => prev + curr, 0);

    const percentages_int = values
        .map((value) => value / total)
        .map((value) => (value >= 0.05 ? value : 0));

    const total_percentages_int = percentages_int.reduce(
        (prev, curr) => prev + curr,
        0
    );

    const percentages = percentages_int.map(
        (value) => value / total_percentages_int
    );

    const startAngle = (i: number) => {
        let prev = 0;
        for (let j = 0; j < i; j++) {
            prev += percentages[j];
        }
        prev *= 360; // Angle of all previous segments

        return prev;
    };

    const endAngle = (i: number) => {
        return startAngle(i) + percentages[i] * 360;
    };

    const r = 50;
    const s = 2;

    return {
        appView: (
            <div className={join(styles, "pie-chart")} key={""}>
                {total === 0 ? (
                    <>
                        <p key={""}>no data</p>
                    </>
                ) : (
                    <svg
                        viewBox={`0 0 ${(r + s) * 3} ${(r + s) * 3}`}
                        xmlns="http://www.w3.org/2000/svg"
                    >
                        {values.map((_, i) => (
                            <PieSegmentPath
                                key={i}
                                startAngle={startAngle(i)}
                                endAngle={endAngle(i)}
                                radius={r}
                                spacing={s}
                                rounding={5}
                                colour={COLOURS[i % COLOURS.length]}
                            />
                        ))}
                    </svg>
                )}
                <div className={join(styles, "legend")}>
                    {keys.map((key, i) => (
                        <div
                            key={i}
                            style={{ display: "flex", flexDirection: "row" }}
                        >
                            <div
                                className={join(styles, "indicator")}
                                style={{
                                    paddingLeft: "25px",
                                    paddingRight: "25px",
                                    height: "50px",
                                    backgroundColor:
                                        COLOURS[i % COLOURS.length],
                                }}
                            />
                            <div
                                style={{
                                    display: "flex",
                                    flexDirection: "column",
                                }}
                            >
                                <b className={join(styles, "key")}>{key}</b>
                                <i className={join(styles, "value")}>
                                    {values[i]}
                                </i>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        ),
        printView: (
            <div className={join(styles, "pie-chart")} key={""}>
                {total === 0 ? (
                    <>
                        <p>no data</p>
                    </>
                ) : (
                    <svg
                        viewBox={`0 0 ${(r + s) * 3} ${(r + s) * 3}`}
                        xmlns="http://www.w3.org/2000/svg"
                        style={{ width: "80%", aspectRatio: "1" }}
                    >
                        {values.map((_, i) => (
                            <PieSegmentPath
                                key={1}
                                startAngle={startAngle(i)}
                                endAngle={endAngle(i)}
                                radius={r}
                                spacing={s}
                                rounding={5}
                                colour={COLOURS[i % COLOURS.length]}
                            />
                        ))}
                    </svg>
                )}
                <div className={join(styles, "legend")}>
                    {keys.map((key, i) => (
                        <div
                            key={i}
                            style={{ display: "flex", flexDirection: "row" }}
                        >
                            <div
                                className={join(styles, "indicator")}
                                style={{
                                    width: "50px",
                                    height: "50px",
                                    backgroundColor:
                                        COLOURS[i % COLOURS.length],
                                }}
                            />
                            <div
                                style={{
                                    display: "flex",
                                    flexDirection: "column",
                                }}
                            >
                                <b className={join(styles, "key")}>{key}</b>
                                <i className={join(styles, "value")}>
                                    {values[i]}
                                </i>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        ),
    };
};

const PieSegmentPath = ({
    startAngle,
    endAngle,
    radius,
    spacing,
    rounding,
    colour,
}: {
    startAngle: number;
    endAngle: number;
    radius: number;
    spacing: number;
    rounding: number;
    colour: string;
}) => {
    const r = radius;
    const s = spacing;
    const S = 2 * r * Math.sin(s / (2 * r));
    const p = rounding;

    const o = [(r + s) * 1.5, (r + s) * 1.5];

    const a = ((startAngle * Math.PI) / 180) % 360;
    const b = ((endAngle * Math.PI) / 180) % 360;

    if (b - a <= 0) return <></>;
    if (b - a >= 2 * Math.PI)
        return (
            <circle cx={(r + s) * 1.5} cy={(r + s) * 1.5} r={r} fill={colour} />
        );

    const t_s = s / r;
    const t_sp = (s + p) / r;

    const t = (b - a) / 2 + a;
    const c = t - a - Math.PI / 2;

    const T = S / Math.cos(c);

    const point = [T * Math.sin(t) + o[0], T * -Math.cos(t) + o[1]];

    const arc_start: [number, number] = [
        r * Math.sin(a + t_s) + o[0],
        r * -Math.cos(a + t_s) + o[1],
    ];
    const arc_end: [number, number] = [
        r * Math.sin(b - t_s) + o[0],
        r * -Math.cos(b - t_s) + o[1],
    ];

    const p1: [number, number] = [
        point[0] + p * Math.sin(a),
        point[1] + p * -Math.cos(a),
    ];
    const p2: [number, number] = [
        arc_start[0] - p * Math.sin(a),
        arc_start[1] - p * -Math.cos(a),
    ];
    const p3: [number, number] = [
        r * Math.sin(a + t_sp) + o[0],
        r * -Math.cos(a + t_sp) + o[1],
    ];
    const p4: [number, number] = [
        r * Math.sin(b - t_sp) + o[0],
        r * -Math.cos(b - t_sp) + o[1],
    ];
    const p5: [number, number] = [
        arc_end[0] - p * Math.sin(b),
        arc_end[1] - p * -Math.cos(b),
    ];
    const p6: [number, number] = [
        point[0] + p * Math.sin(b),
        point[1] + p * -Math.cos(b),
    ];

    return (
        <path
            d={
                endAngle - startAngle < 14.4
                    ? `
            M ${point[0]} ${point[1]}
            L ${arc_start[0]} ${arc_start[1]}
            A ${r} ${r} 0 ${endAngle - startAngle > 180 ? 1 : 0} 1 ${arc_end[0]} ${arc_end[1]}
            L ${point[0]} ${point[1]}
        `
                    : `
            M ${p1[0]} ${p1[1]}
            L ${p2[0]} ${p2[1]} 
            S ${arc_start[0]} ${arc_start[1]} ${p3[0]} ${p3[1]} 
            A ${r} ${r} 0 ${endAngle - startAngle > 180 ? 1 : 0} 1 ${p4[0]} ${p4[1]} 
            S ${arc_end[0]} ${arc_end[1]} ${p5[0]} ${p5[1]} 
            L ${p6[0]} ${p6[1]}
            S ${point[0]} ${point[1]} ${p1[0]} ${p1[1]}
        `
            }
            fill={colour}
        />
    );
};

export const DefaultPieChartActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "pie_chart"
> = () => {
    return {
        type: "pie_chart",
        complete: true,
    };
};
