import React from "react";
import styles from "#styles/activities/renderers/checklist.module.css";
import { join } from "engine/src/system/Styles";
import { editState } from "../../../state/Util";
import { keyDownHandler } from "engine/src/system/Keyboard";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";

export const ChecklistActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "checklist"
> = (element, playerData, updateState) => {
    const numberOfPrompts = Object.keys(element.categories).reduce(
        (prev, curr) => {
            return prev + element.categories[curr].length;
        },
        0
    );

    const handleChangeSelection = (index: number, localIndex: number) => {
        editState(playerData, updateState, (data) => {
            if (!data.indices) {
                data.indices = [];
            }
            data.indices[index] = localIndex;
            let complete = true;
            for (let i = 0; i < numberOfPrompts; i++) {
                if (data.indices[i] === undefined) {
                    complete = false;
                    break;
                }
            }
            data.complete = complete;
            return data;
        });
    };

    const generateResponse = () => {
        let prompts: Array<{
            prompt: string;
            scores: number[];
        }> = [];
        for (let category of Object.keys(element.categories)) {
            element.categories[category].forEach((prompt) =>
                prompts.push(prompt)
            );
        }
        for (let range of Object.keys(
            element.responseText
        ) as `${number}..${number}`[]) {
            let min = parseInt(range.split("..")[0]);
            let max = parseInt(range.split("..")[1]);
            let score = 0;
            for (let i = 0; i < playerData.indices.length; i++) {
                score += prompts[i].scores[playerData.indices[i]];
            }

            if (min <= score && score <= max) {
                return element.responseText[range];
            }
        }
        return "Thanks for completing";
    };

    return {
        appView: (
            <React.Fragment key={element.header}>
                {element.header && (
                    <div className={join(styles, "checklist-header")}>
                        <p>{element.header}</p>
                    </div>
                )}
                <table className={join(styles, "checklist")}>
                    <tbody>
                        {element.elementTitle && (
                            <tr>
                                <th className={join(styles, "category")}>
                                    {element.elementTitle}
                                </th>
                                {element.scaleTitles.map((_, index) => (
                                    <th key={index} />
                                ))}
                            </tr>
                        )}
                        {(() => {
                            let index = 0;
                            return Object.keys(element.categories).map(
                                (category) => {
                                    return (
                                        <React.Fragment key={category}>
                                            {Object.keys(element.categories)
                                                .length > 1 ? (
                                                <tr>
                                                    <th
                                                        className={join(
                                                            styles,
                                                            "prompt"
                                                        )}
                                                    >
                                                        {category}
                                                    </th>
                                                    {element.scaleTitles.map(
                                                        (_, index) => (
                                                            <td
                                                                key={`blank-${category}-${index}`}
                                                                className={join(
                                                                    styles,
                                                                    "radio"
                                                                )}
                                                            />
                                                        )
                                                    )}
                                                </tr>
                                            ) : (
                                                <></>
                                            )}
                                            {element.categories[category].map(
                                                (item) => {
                                                    let localIndex = 0;
                                                    const idx = structuredClone(
                                                        index++
                                                    );
                                                    return (
                                                        <tr key={item.prompt}>
                                                            <td
                                                                className={join(
                                                                    styles,
                                                                    "prompt"
                                                                )}
                                                            >
                                                                {item.prompt}
                                                            </td>
                                                            {element.scaleTitles.map(
                                                                (title, i) => {
                                                                    const lidx =
                                                                        structuredClone(
                                                                            localIndex++
                                                                        );
                                                                    return (
                                                                        <td
                                                                            className={join(
                                                                                styles,
                                                                                playerData.indices
                                                                                    ? `${
                                                                                          playerData
                                                                                              .indices[
                                                                                              idx
                                                                                          ] ===
                                                                                          lidx
                                                                                      }`
                                                                                    : false,
                                                                                `radio-container`
                                                                            )}
                                                                            key={`${item.prompt}-${title}`}
                                                                        >
                                                                            <input
                                                                                type="radio"
                                                                                id={`${index}-${i}`}
                                                                                checked={
                                                                                    playerData.indices
                                                                                        ? playerData
                                                                                              .indices[
                                                                                              idx
                                                                                          ] ===
                                                                                          lidx
                                                                                        : false
                                                                                }
                                                                                onChange={() =>
                                                                                    handleChangeSelection(
                                                                                        idx,
                                                                                        lidx
                                                                                    )
                                                                                }
                                                                            />
                                                                            <label
                                                                                htmlFor={`${index}-${i}`}
                                                                                tabIndex={
                                                                                    0
                                                                                }
                                                                                onKeyDown={keyDownHandler(
                                                                                    [
                                                                                        "Enter",
                                                                                    ],
                                                                                    () => {
                                                                                        handleChangeSelection(
                                                                                            idx,
                                                                                            lidx
                                                                                        );
                                                                                    }
                                                                                )}
                                                                            >
                                                                                <span>
                                                                                    {
                                                                                        title
                                                                                    }
                                                                                </span>
                                                                            </label>
                                                                        </td>
                                                                    );
                                                                }
                                                            )}
                                                        </tr>
                                                    );
                                                }
                                            )}
                                        </React.Fragment>
                                    );
                                }
                            );
                        })()}
                    </tbody>
                </table>
                {playerData.complete ? (
                    <p
                        className={join(styles, "info-text")}
                        dangerouslySetInnerHTML={{
                            __html: !playerData.indices
                                ? "Please answer each question"
                                : generateResponse(),
                        }}
                    />
                ) : (
                    <p className={join(styles, "info-text")}>
                        Please answer each question
                    </p>
                )}
            </React.Fragment>
        ),
        printView: (
            <React.Fragment key={element.header}>
                <div className={join(styles, "checklist-header")}>
                    <p>{element.header}</p>
                </div>
                <table className={join(styles, "checklist")}>
                    <tbody>
                        {element.elementTitle && (
                            <tr>
                                <th className={join(styles, "category")}>
                                    {element.elementTitle}
                                </th>
                                {element.scaleTitles.map((_, index) => (
                                    <th key={index} />
                                ))}
                            </tr>
                        )}
                        {(() => {
                            let index = 0;
                            return Object.keys(element.categories).map(
                                (category) => {
                                    return (
                                        <React.Fragment key={category}>
                                            {Object.keys(element.categories)
                                                .length > 1 ? (
                                                <tr>
                                                    <th
                                                        className={join(
                                                            styles,
                                                            "prompt"
                                                        )}
                                                    >
                                                        {category}
                                                    </th>
                                                    {element.scaleTitles.map(
                                                        (_, index) => (
                                                            <td
                                                                key={`blank-${category}-${index}`}
                                                                className={join(
                                                                    styles,
                                                                    "radio"
                                                                )}
                                                            />
                                                        )
                                                    )}
                                                </tr>
                                            ) : (
                                                <></>
                                            )}
                                            {element.categories[category].map(
                                                (item) => {
                                                    let localIndex = 0;
                                                    const idx = structuredClone(
                                                        index++
                                                    );
                                                    return (
                                                        <tr key={item.prompt}>
                                                            <td
                                                                className={join(
                                                                    styles,
                                                                    "prompt"
                                                                )}
                                                            >
                                                                {item.prompt}
                                                            </td>
                                                            {element.scaleTitles.map(
                                                                (title) => {
                                                                    const lidx =
                                                                        structuredClone(
                                                                            localIndex++
                                                                        );
                                                                    return (
                                                                        <td
                                                                            className={join(
                                                                                styles,
                                                                                playerData.indices
                                                                                    ? `${
                                                                                          playerData
                                                                                              .indices[
                                                                                              idx
                                                                                          ] ===
                                                                                          lidx
                                                                                      }`
                                                                                    : false,
                                                                                `radio-container`
                                                                            )}
                                                                            key={`${item.prompt}-${title}`}
                                                                        >
                                                                            <label>
                                                                                <input
                                                                                    readOnly
                                                                                    type="radio"
                                                                                    checked={
                                                                                        playerData.indices
                                                                                            ? playerData
                                                                                                  .indices[
                                                                                                  idx
                                                                                              ] ===
                                                                                              lidx
                                                                                            : false
                                                                                    }
                                                                                />
                                                                                <span>
                                                                                    {
                                                                                        title
                                                                                    }
                                                                                </span>
                                                                            </label>
                                                                        </td>
                                                                    );
                                                                }
                                                            )}
                                                        </tr>
                                                    );
                                                }
                                            )}
                                        </React.Fragment>
                                    );
                                }
                            );
                        })()}
                    </tbody>
                </table>
                {playerData.complete ? (
                    <p
                        className={join(styles, "info-text")}
                        dangerouslySetInnerHTML={{
                            __html: !playerData.indices
                                ? "Please answer each question"
                                : generateResponse(),
                        }}
                    />
                ) : (
                    <p className={join(styles, "info-text")}>
                        Please answer each question
                    </p>
                )}
            </React.Fragment>
        ),
    };
};

export const DefaultChecklistActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "checklist"
> = () => ({
    type: "checklist",
    complete: false,
    indices: [],
});
