import styles from "#styles/apps/MapApp.module.css";
import phoneStyles from "#styles/apps/PhoneUIGeneric.module.css";
import React, { useCallback, useState } from "react";
import { useGlobalState } from "../../state/GlobalState";
import Flags from "engine/src/system/Flags";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { LoadAction, LoadScene } from "engine/src/system/DataLoader";
import { SwitchScene } from "engine/src/system/SceneSwitcher";
import { useKeyDown, useSelectedIndex } from "engine/src/system/Keyboard";
import { HandleAction } from "engine/src/system/ActionExecutor";
import { join } from "engine/src/system/Styles";

type Target = {
    className: string;
    sceneName: string;
    name: string;
    description: string;
    requiredFlag?: string;
};

const university: Target = {
    className: "university",
    sceneName: "university/map",
    name: "University",
    description: "The University you are planning to attend.",
    requiredFlag: "unlocked_university",
};

const home: Target = {
    className: "house",
    sceneName: "home/room",
    name: "Home",
    description: "Your home.",
};

const high_school: Target = {
    className: "high-school",
    sceneName: "high_school/entrance",
    name: "High School",
    description: "Your current high school.",
    requiredFlag: "unlocked_high_school",
};

const destinations = [high_school, university, home];

/**
 * The Map app
 */
export const MapComponent = ({ closeApp }: { closeApp: () => void }) => {
    const { coreState, settingsState } = useGlobalState();

    const [keybinds] = settingsState.keybinds;

    const [, setPopup] = coreState.popup;
    const [, setTransitioning] = coreState.transitioning;
    const [phoneOpen, setPhoneOpen] = coreState.phoneOpen;

    const [scene] = coreState.scene;

    const [destination, setDestination] = useState<Target | null>(null);

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        destinations.length,
        [...keybinds.General.Up, ...keybinds.General.Right],
        [...keybinds.General.Down, ...keybinds.General.Left],
        destination !== null
    );

    // Load and set a named scene
    const loadAndSetScene = (scene: string) => {
        LoadScene(scene).then((s) => {
            SwitchScene(s, coreState, setPhoneOpen, () => {
                PlayAudio("map-switch.wav", "sounds");
            });
        });
    };

    const loadSceneIfFlagSet = (scene: string, flag: string) => {
        if (Flags.checkFlag(flag)) {
            setTransitioning(true);
            loadAndSetScene(scene);
            setDestination(null);
        }
    };

    const isUnlocked = (destination: Target) => {
        if (!destination.requiredFlag) return true;
        return Flags.checkFlag(destination.requiredFlag);
    };

    const attemptTravel = useCallback(() => {
        if (!destination) return;

        if (destination.sceneName === scene.name.replaceAll(":", "/")) {
            return;
        }

        if (
            Flags.checkFlag("time:night") ||
            Flags.checkFlag("map:travel_blocked")
        ) {
            LoadAction("on_map_travel_blocked").then((action) => {
                HandleAction(action);
            });
        } else {
            if (destination.requiredFlag) {
                loadSceneIfFlagSet(
                    destination.sceneName,
                    destination.requiredFlag
                );
            } else {
                loadAndSetScene(destination.sceneName);
                setDestination(null);
            }
        }
        // eslint-disable-next-line
    }, [destination, setPopup, scene]);

    useKeyDown(
        keybinds.General.Back,
        useCallback(() => {
            if (destination === null) return closeApp();
            setDestination(null);
        }, [destination, closeApp])
    );

    useKeyDown(
        keybinds.General.Select,
        useCallback(() => {
            if (destination !== null) attemptTravel();
            if (selectedIndex !== -1)
                setDestination(destinations[selectedIndex]);
        }, [selectedIndex, destination, attemptTravel])
    );

    return (
        <div className={join(styles, "map-content")}>
            {destinations.map((location, index) => {
                return (
                    <div
                        key={index}
                        className={join(styles, location.className)}
                        onClick={() => {
                            setDestination(location);
                        }}
                        onMouseEnter={() => {
                            if (selectedIndex !== -1) {
                                setSelectedIndex(index);
                            }
                        }}
                    >
                        <Pin
                            name={location.name}
                            selected={index === selectedIndex}
                        />
                    </div>
                );
            })}
            {destination ? (
                <div className={join(styles, "UI-wrapper")}>
                    <div className={join(styles, "UI")}>
                        <h2>{destination.name}</h2>
                        <span
                            className={join(styles, "Exit")}
                            onClick={() => setDestination(null)}
                        >
                            x
                        </span>
                        <div className={join(phoneStyles, "column-60-30")}>
                            <p>{destination.description}</p>
                            <button
                                className={
                                    isUnlocked(destination) &&
                                    destination.sceneName !==
                                        scene.name.replaceAll(":", "/")
                                        ? styles.unlocked
                                        : styles.locked
                                }
                                onClick={attemptTravel}
                            >
                                {isUnlocked(destination)
                                    ? destination.sceneName !==
                                      scene.name.replaceAll(":", "/")
                                        ? "Travel"
                                        : "Already Here"
                                    : "Locked"}
                            </button>
                        </div>
                    </div>
                </div>
            ) : (
                <></>
            )}
        </div>
    );
};

const Pin = ({ name, selected }: { name: string; selected: boolean }) => (
    <div className={join(styles, "pin", selected ? "selected" : "")}>
        <img alt="pin" src="assets/images/elements/pin.png" />
        <span>{name}</span>
        {selected && <div className={join(styles, "highlight")}></div>}
    </div>
);
