/**
 * Basic react types
 */
export type ReactSetter<T> = React.Dispatch<React.SetStateAction<T>>;
export type ReactState<T> = [T, ReactSetter<T>];

/**
 * The game state
 */
export type CoreState<ActivityType,MinigameType> = {
    scene: ReactState<Scene>;
    sceneBackground: ReactState<number>;
    dialog: ReactState<Dialog | null>;
    dialogIndex: ReactState<number>;
    popup: ReactState<string | null>;
    notificationQueue: ReactState<Record<number, Notification>>;
    notificationCounter: ReactState<number>;
    unlockedFlags: ReactState<string[]>;
    registers: ReactState<Record<string, number>>;
    textRegisters: ReactState<Record<string, string>>;
    popupStateData: ReactState<any>;
    activity: ReactState<ActivityType | null>;
    minigame: ReactState<MinigameType | null>;
    appEnabled: ReactState<boolean>;
    phoneOpen: ReactState<boolean>;
    dialogHistoryOpen: ReactState<boolean>;
    dialogHistory: ReactState<DialogHistoryDialog[]>;
    loadingDialog: ReactState<boolean>;
    transitioning: ReactState<boolean>;
    openApp: ReactState<string | null>;
    wallpaperNumber: ReactState<number>;
};

export type SettingsState<S extends BaseParticipantSettings> = {
    volume: ReactState<{
        sounds: number;
        music: number;
        voice: number;
        master: number;
    }>;
    textSize: ReactState<number>;
    textStyle: ReactState<string>;
    keybinds: ReactState<Keybinds>;
    participantSettings: ReactState<S>;
}

/**
 * The global state
 */
export abstract class BaseGlobalState<ActivityType, MinigameType, S extends BaseParticipantSettings> {
    // The react states
    public coreState: [CoreState<ActivityType, MinigameType>, React.Context<CoreState<ActivityType, MinigameType>>];
    public settingsState: [SettingsState<S>, React.Context<SettingsState<S>>];

    public static instance: BaseGlobalState<any, any, any>;

    // Create a global state
    constructor(
        coreState: CoreState<ActivityType, MinigameType>,
        settingsState: SettingsState<S>,
    ) {
        this.coreState = [coreState, createContext(coreState)];
        this.settingsState = [settingsState, createContext(settingsState)];

        BaseGlobalState.instance = this;
    }

    public static getBaseInstance<ActivityType, MinigameType, S extends BaseParticipantSettings>() {
        return this.instance as BaseGlobalState<ActivityType, MinigameType, S>;
    }

    // Set the current game state
    public setCoreState(current: CoreState<ActivityType, MinigameType>) {
        this.coreState[0] = current;
    }

    public setSettingsState(current: SettingsState<S>) {
        this.settingsState[0] = current;
    }
}

export function useNewCoreState<ActivityType, MinigameType>(): CoreState<ActivityType, MinigameType> {
    const coreState: CoreState<ActivityType, MinigameType> = {
        scene: React.useState<Scene>(defaultCoreState.scene),
        sceneBackground: React.useState<number>(defaultCoreState.sceneBackground),
        dialog: React.useState<Dialog | null>(defaultCoreState.dialog),
        dialogIndex: React.useState<number>(defaultCoreState.dialogIndex),
        popup: React.useState<string | null>(defaultCoreState.popup),
        unlockedFlags: React.useState<string[]>(defaultCoreState.unlockedFlags),
        registers: React.useState<Record<string, number>>(defaultCoreState.registers),
        textRegisters: React.useState<Record<string, string>>(defaultCoreState.textRegisters),
        notificationQueue: React.useState<Record<number, Notification>>(defaultCoreState.notificationQueue),
        notificationCounter: React.useState<number>(defaultCoreState.notificationCounter),
        popupStateData: React.useState<any>(defaultCoreState.popupStateData),
        activity: React.useState<ActivityType | null>(defaultCoreState.activity),
        minigame: React.useState<MinigameType | null>(defaultCoreState.minigame),
        appEnabled: React.useState<boolean>(defaultCoreState.appEnabled),
        phoneOpen: React.useState<boolean>(defaultCoreState.phoneOpen),
        dialogHistoryOpen: React.useState<boolean>(defaultCoreState.dialogHistoryOpen),
        dialogHistory: React.useState<DialogHistoryDialog[]>(defaultCoreState.dialogHistory),
        loadingDialog: React.useState<boolean>(defaultCoreState.loadingDialog),
        transitioning: React.useState<boolean>(defaultCoreState.transitioning),
        openApp: React.useState<string | null>(defaultCoreState.openApp),
        wallpaperNumber: React.useState<number>(defaultCoreState.wallpaperNumber),
    }

    return coreState;
}

export function useNewSettingsState<S extends BaseParticipantSettings>(defaultParticipantSettings: S): SettingsState<S> {
    const settingsState: SettingsState<S> = {
        volume: React.useState<{
            sounds: number;
            music: number;
            voice: number;
            master: number;
        }>(defaultSettings(defaultParticipantSettings).volume),
        textSize: React.useState<number>(defaultSettings(defaultParticipantSettings).textSize),
        textStyle: React.useState<string>(defaultSettings(defaultParticipantSettings).textStyle),
        keybinds: React.useState<Keybinds>(defaultSettings(defaultParticipantSettings).keybinds),
        participantSettings: React.useState<S>(defaultSettings(defaultParticipantSettings).participantSettings),
    }

    return settingsState;
}

export const useBaseGlobalState = <ActivityType, MinigameType, S extends BaseParticipantSettings>(globalState?: BaseGlobalState<ActivityType, MinigameType, S>) => {
    const gs = globalState ?? BaseGlobalState.getBaseInstance();
    
    return {
        coreState: React.useContext(gs.coreState[1]),
        settingsState: React.useContext(gs.settingsState[1]),
    }
}

export const getBaseGlobalState = <ActivityType, MinigameType, S extends BaseParticipantSettings>(globalState?: BaseGlobalState<ActivityType, MinigameType, S>) => {
    const gs = globalState ?? BaseGlobalState.getBaseInstance();
    
    return {
        coreState: gs.coreState[0],
        settingsState: gs.settingsState[0],
    }
}

