import { useGlobalState } from "../../state/GlobalState";
import { copingStrategies } from "../../types/copingStrategies";
import { join } from "engine/src/system/Styles";
import styles from "#styles/apps/CopingStrategyPage.module.css";

export const CopingStrategyPage = ({ id }: { id: string }) => {
    const { phoneState, settingsState } = useGlobalState();
    const strategy = copingStrategies.find((s) => s.id === id);
    if (!strategy) {
        phoneState.browserPage[1]("search");
        phoneState.activeStrategyId[1](null);

        return <div></div>;
    }

    return (
        <div>
            <div className={join(styles, "page-content-wrapper")}>
                <button
                    onClick={() => {
                        phoneState.browserPage[1]("search");
                        phoneState.activeStrategyId[1](null);
                    }}
                    className={join(styles, "page-back-button")}
                >
                    <img
                        src="/assets/images/elements/phone-icons/browser-back.png"
                        alt="Click me"
                        className={join(styles, "button-img")}
                    />
                </button>
                <div className={join(styles, "page-topper-wrapper")}>
                    <img
                        src="/assets/images/elements/coping-page-topper-left.png"
                        alt="The right stuff logo"
                        className={join(styles, "page-topper-left")}
                    />
                    <img
                        src="/assets/images/elements/coping-page-topper-right.png"
                        alt="The right stuff logo"
                        className={join(styles, "page-topper-right")}
                    />
                </div>
                <div className={join(styles, "page-title")}>
                    {strategy.title}
                </div>
                <div className="relative w-64 h-40">
                    <img
                        src={strategy.picture}
                        alt="Book and pencil"
                        className={join(styles, "page-photo")}
                    />
                </div>
                {strategy.intro.map((text, i) => (
                    <p key={i} className={join(styles, "page-intro")}>
                        {text.split("\n").map((line, j) => (
                            <span key={j}>
                                {line}
                                <br />
                            </span>
                        ))}
                    </p>
                ))}

                {strategy.checklist_titles.map((text, i) => (
                    <div key={i}>
                        <p className={join(styles, "checklist-titles")}>
                            {text}
                        </p>
                        <p className={join(styles, "checklist-descriptions")}>
                            {strategy.checklist_descriptions[i]
                                .split("\n")
                                .map((line, j) =>
                                    line.trim().startsWith("-") ? (
                                        <p
                                            key={j}
                                            className={join(
                                                styles,
                                                "page-bullet-line"
                                            )}
                                        >
                                            {line.trim()}
                                        </p>
                                    ) : (
                                        <p key={j}>{line.trim()}</p>
                                    )
                                )}
                        </p>
                    </div>
                ))}
                {strategy.conclusion.map((text, i) => (
                    <p key={i} className={join(styles, "page-conclusion")}>
                        {text}
                    </p>
                ))}
            </div>
        </div>
    );
};
