import styles from "#styles/activities/renderers/barchart.module.css";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { join } from "engine/src/system/Styles";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

const COLOURS = ["#97E2BD", "#5B6EE1", "#D8A67A", "#FDF9E0", "#E29897"];

export const BarChartActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "bar_chart"
> = (element, _playerData, _updateState, [bound]) => {
    const keys = element.inputNames;
    const values = keys
        .map((key) => bound[key])
        .map((value) => (value ? value : "0"))
        .map((value) =>
            value.includes("-")
                ? "-" + value.replace(/\D/g, "")
                : value.replace(/\D/g, "")
        )
        .map((value) => Math.floor(parseInt(value)));

    const maxValue = values.reduce(
        (prev, curr) => (prev > curr ? prev : curr),
        -Infinity
    );
    const barWidth = 20;

    const data: Record<string, number> = {};
    keys.forEach((key, i) => {
        data[key] = values[i];
    });

    const width = barWidth * values.length;
    const height = width / 4;

    return {
        appView: (
            <div className={join(styles, "bar-chart")} key={""}>
                <svg
                    viewBox={`0 0 ${width} ${height}`}
                    xmlns="http://www.w3.org/2000/svg"
                >
                    {keys.map((key, index) => {
                        const value = data[key];
                        const barHeight = (value / maxValue) * height; // 20px padding at top
                        return (
                            <g key={key}>
                                <rect
                                    x={index * barWidth + 5}
                                    y={height - barHeight}
                                    width={barWidth - 10} // spacing between bars
                                    height={barHeight - 2}
                                    fill={COLOURS[index]}
                                    rx={1}
                                />
                                <text
                                    x={
                                        index * barWidth +
                                        (barWidth - 10) / 2 +
                                        5
                                    }
                                    y={height - 0.5}
                                    fontSize="1"
                                    textAnchor="middle"
                                    fill="white"
                                >
                                    {key}
                                </text>
                            </g>
                        );
                    })}
                </svg>
            </div>
        ),
        printView: (
            <div
                className={join(styles, "bar-chart")}
                key={""}
                style={{ display: "grid", gridTemplateColumns: "75% 25%" }}
            ></div>
        ),
    };
};

export const DefaultBarChartActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "bar_chart"
> = () => {
    return {
        type: "bar_chart",
        complete: true,
    };
};
