import styles from "#styles/activities/renderers/checkbox.module.css";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { keyDownHandler } from "engine/src/system/Keyboard";
import { join } from "engine/src/system/Styles";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const CheckboxActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "checkbox"
> = (element, playerData, updateState, [bound]) => {
    return {
        appView: (
            <div className={join(styles, "checkbox")} key={element.label}>
                {element.checkbox === "true" ? (
                    <input
                        type="checkbox"
                        checked={playerData.checked}
                        onChange={() =>
                            updateState({
                                type: "checkbox",
                                checked: !playerData.checked,
                                complete: true,
                            })
                        }
                        onKeyDown={keyDownHandler(["Enter"], () => {
                            updateState({
                                type: "checkbox",
                                checked: !playerData.checked,
                                complete: true,
                            });
                        })}
                    />
                ) : (
                    ""
                )}

                <span dangerouslySetInnerHTML={{ __html: element.label }} />
                {Object.keys(bound).includes("subtitle") && (
                    <p>{bound.subtitle}</p>
                )}
            </div>
        ),
        printView: (
            <div className={join(styles, "checkbox")} key={element.label}>
                {element.checkbox === "true" ? (
                    <input
                        readOnly
                        type="checkbox"
                        defaultChecked={playerData.checked}
                    />
                ) : (
                    <></>
                )}
                <span dangerouslySetInnerHTML={{ __html: element.label }} />
            </div>
        ),
    };
};

export const DefaultCheckboxActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "checkbox"
> = () => ({
    type: "checkbox",
    complete: true,
    checked: false,
});
