import React from "react";
import styles from "../../../styles/activities/renderers/titledblock.module.css";
import { join } from "engine/src/system/Styles";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const TitledBlockActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "titledblock"
> = (element) => {
    const innerhtml = {
        __html: element.html,
    };

    return {
        appView: (
            <React.Fragment key={element.html}>
                <div className={join(styles, "titledblock")}>
                    <strong>{element.title}</strong>
                    <div dangerouslySetInnerHTML={innerhtml} />
                </div>
            </React.Fragment>
        ),
        printView: (
            <React.Fragment key={element.html}>
                <div className={join(styles, "titledblock")}>
                    <strong>{element.title}</strong>
                    <div dangerouslySetInnerHTML={innerhtml} />
                </div>
            </React.Fragment>
        ),
    };
};

export const DefaultTitledBlockActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "titledblock"
> = () => {
    return {
        type: "titledblock",
        complete: true,
    };
};
