import { KeyEvent, updateKeyRegisters } from "engine/src/system/Keyboard";
import { useEffect } from "react";
import { useBaseGlobalState } from "../state/GlobalState";

const KeyboardSystem = () => {    
    const {settingsState} = useBaseGlobalState();

    useEffect(() => {
        updateKeyRegisters(settingsState);
        // eslint-disable-next-line
    }, []);

    const onKeyDown = (event: KeyboardEvent) => {
        window.dispatchEvent(
            new CustomEvent(`key:${event.code}:down`, {
                bubbles: true,
                detail: {}
            }),
        );
    }
    
    const onKeyUp = (event: KeyboardEvent) => {
        window.dispatchEvent(
            new CustomEvent(`key:${event.code}:up`, {
                bubbles: true,
                detail: {}
            }),
        );
    }

    useEffect(() => {
        window.addEventListener(KeyEvent.KeyPress, onKeyDown, false);
        window.addEventListener(KeyEvent.KeyRelease, onKeyUp, false);

        return () => {
            window.removeEventListener(KeyEvent.KeyPress, onKeyDown, false);
            window.removeEventListener(KeyEvent.KeyRelease, onKeyUp, false);
        };
    });

    return <></>
}

export default KeyboardSystem;
