import styles from "#styles/activities/renderers/grid.module.css";
import { join } from "engine/src/system/Styles";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";
import { editState } from "../../../state/Util";
import {
    AcitivityRegistry,
    ActivityDefaultStateProvider,
    ActivityRegistryEntry,
    ActivityRenderer,
    calculateBoundBindings,
} from "engine/src/components/popup/ActivityComponent";
import { Activities } from "../../../types/Activity";

export const GridActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "grid"
> = (
    element,
    playerData,
    updateState,
    [bound, updateBinding, bindings],
    registry
) => {
    const updateActivityData = (i: number, b: ActivityElementPlayerData) => {
        editState(playerData, updateState, (old) => {
            old.elements[i] = b;
            old.complete =
                old.elements.map((elem) => elem.complete).filter((c) => c)
                    .length > 0;
            return old;
        });
    };

    return {
        appView: (
            <div
                key={"a"}
                className={join(styles, "grid")}
                style={{
                    display: "grid",
                    gridTemplateColumns: element.columnWeights
                        .map(
                            (dec, i) =>
                                `calc(${dec * 100}% - ${i === element.columnWeights.length - 1 ? 0 : element.spacing}px)`
                        )
                        .join(" "),
                    gridTemplateRows: element.rowWeights
                        ? element.rowWeights
                              .map((dec) => dec * 100 + "%")
                              .join(" ")
                        : undefined,
                    gridGap: element.spacing + "px",
                }}
            >
                {element.elements.map((a, i) => {
                    return (
                        <div
                            key={i}
                            style={
                                a.position && a.size
                                    ? {
                                          gridColumnStart: a.position[0],
                                          gridColumnEnd:
                                              a.position[0] + a.size[0],
                                          gridRowStart: a.position[1],
                                          gridRowEnd: a.position[1] + a.size[1],
                                          display: "flex",
                                          flexDirection: "column",
                                      }
                                    : {
                                          display: "flex",
                                          flexDirection: "column",
                                      }
                            }
                        >
                            {
                                (
                                    registry[
                                        a.element.type
                                    ] as ActivityRegistryEntry<
                                        Activities,
                                        ActivityElementPlayerData,
                                        typeof a.element.type
                                    >
                                ).renderer(
                                    a.element,
                                    playerData.elements[i],
                                    (b: ActivityElementPlayerData) => {
                                        updateActivityData(i, b);
                                    },
                                    [
                                        calculateBoundBindings(
                                            bindings,
                                            a.element
                                        ),
                                        updateBinding,
                                        bindings,
                                    ],
                                    registry
                                ).appView
                            }
                        </div>
                    );
                })}
            </div>
        ),
        printView: (
            <div key={"a"} className={join(styles, "grid")} style={{}}>
                {element.elements.map((a, i) => (
                    <div
                        key={i}
                        style={
                            a.position && a.size
                                ? {
                                      gridColumnStart: a.position[0],
                                      gridColumnEnd: a.position[0] + a.size[0],
                                      gridRowStart: a.position[1],
                                      gridRowEnd: a.position[1] + a.size[1],
                                      display: "flex",
                                      flexDirection: "column",
                                  }
                                : {
                                      display: "flex",
                                      flexDirection: "column",
                                  }
                        }
                    >
                        {
                            (
                                registry[
                                    a.element.type
                                ] as ActivityRegistryEntry<
                                    Activities,
                                    ActivityElementPlayerData,
                                    typeof a.element.type
                                >
                            ).renderer(
                                a.element as never,
                                playerData.elements[i] as never,
                                (b: ActivityElementPlayerData) => {
                                    updateActivityData(i, b);
                                },
                                [
                                    calculateBoundBindings(bindings, a.element),
                                    updateBinding,
                                    bindings,
                                ],
                                registry
                            ).printView
                        }
                    </div>
                ))}
            </div>
        ),
    };
};

export const DefaultGridActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "grid"
> = (element, registry) => {
    const elements = element.elements.map((elem) =>
        registry[elem.element.type].dataGenerator(
            elem.element as never,
            registry
        )
    );

    const complete =
        elements.map((elem) => elem.complete).filter((c) => c).length > 0;

    return {
        type: "grid",
        complete: complete,
        elements: elements,
    };
};
