import { CSSProperties, useEffect, useRef, useState } from "react";
import { useGlobalState } from "../../state/GlobalState";
import styles from "#styles/popup/zoom.module.css";
import { PlayVoiceLine } from "engine/src/system/AudioSystem";
import {
    Message,
    Poll,
    ZoomChatProps,
    ZoomFaceCamProps,
    ZoomParticipantsProps,
    ZoomPollProps,
    ZoomSettingsProps,
} from "../../types/Zoom";
import { HandleAction } from "engine/src/system/ActionExecutor";
import { Badges } from "../../system/Unlockables";
import { LoadAction } from "engine/src/system/DataLoader";
import { join } from "engine/src/system/Styles";
import { keyDownHandler, useKeyDown } from "engine/src/system/Keyboard";
import Registers from "engine/src/system/Registers";

const ZoomParticipants = ({
    participantsContainerRef,
    playerName,
    cameraOn,
    participantsOpen,
    slideShowData,
    selectedPoll,
}: ZoomParticipantsProps) => {
    return (
        <div
            className={join(styles, "zoom_face_cam_grid")}
            ref={participantsContainerRef}
            tabIndex={selectedPoll === -1 ? 9 : -1}
        >
            <FaceCam
                name={playerName}
                camera={
                    cameraOn
                        ? "assets/images/backgrounds/zoom/participant0.png"
                        : "assets/images/icons/empty_profile.svg"
                }
            />
            {participantsOpen &&
                slideShowData.participants.map((p, i) => (
                    <FaceCam
                        name={p}
                        key={p}
                        camera={`assets/images/backgrounds/zoom/participant${i + 1}.png`}
                    />
                ))}
        </div>
    );
};

const FaceCam = ({ name, camera }: ZoomFaceCamProps) => {
    const [imageSrc, setImageSrc] = useState(
        camera || "assets/images/icons/empty_profile.svg"
    );
    useEffect(() => {
        setImageSrc(camera || "assets/images/icons/empty_profile.svg");
    }, [camera]);

    return (
        <div className={join(styles, "zoom_face_cam")}>
            <img
                src={imageSrc}
                alt={`${name}'s Camera`}
                onError={() =>
                    setImageSrc("assets/images/icons/empty_profile.svg")
                }
                className={join(styles, "zoom_face_img")}
            />
            <span className={join(styles, "zoom_face_name")}>{name}</span>
        </div>
    );
};

const ZoomChat = ({
    messages,
    setMessages,
    selectedPollChoices,
    handlePollChoiceChange,
    handleSubmitPoll,
    handleGoBack,
    handleReset,
    handleForward,
    setSelectedPollChoices,
    slideShowIndex,
    sharingDone,
    slideShowData,
    selectedPoll,
    setSelectedPoll,
}: ZoomChatProps) => {
    const chatContainerRef = useRef<HTMLDivElement>(null);

    const playerName = Registers.getTextRegister("player");

    useEffect(() => {
        chatContainerRef.current?.scrollTo({
            top: chatContainerRef.current.scrollHeight,
            behavior: "smooth",
        });
    }, [messages]);

    const handleSendMessage = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key !== "Enter" || !e.currentTarget.value.trim()) return;
        const messageText = e.currentTarget.value.trim();
        setMessages((prev) => [
            ...prev,
            {
                from: playerName,
                message: messageText,
            },
        ]);
        e.currentTarget.value = "";
    };

    const allOptional = slideShowData.chat[slideShowIndex].messages.every(
        (messageData) => {
            if (typeof messageData.message === "string") return true;
            const poll = messageData.message as Poll;
            return poll.optional;
        }
    );

    return (
        <div className={join(styles, "zoom_chat_window")}>
            <h6>CHAT</h6>
            <div
                ref={chatContainerRef}
                className={join(styles, "zoom_chat_messages")}
                tabIndex={selectedPoll === -1 ? 8 : -1}
            >
                {messages.map((message, index) =>
                    typeof message.message === "string" ? (
                        <div
                            key={index}
                            className={join(
                                styles,
                                message.from === playerName
                                    ? "own_message"
                                    : "received_message"
                            )}
                        >
                            <b>{message.from}</b>
                            <p className={join(styles, "zoom_message")}>
                                {message.message}
                            </p>
                        </div>
                    ) : (
                        <ChatPoll
                            key={index}
                            index={index}
                            poll={message.message as Poll}
                            pollId={`${(message.message as Poll).id}`}
                            selectedChoices={
                                selectedPollChoices.get(
                                    `${(message.message as Poll).id}`
                                )?.choices || []
                            }
                            submitted={
                                selectedPollChoices.get(
                                    `${(message.message as Poll).id}`
                                )?.submitted || false
                            }
                            handlePollChoiceChange={handlePollChoiceChange}
                            setSelectedPollChoices={setSelectedPollChoices}
                            handleSubmitPoll={handleSubmitPoll}
                            selectedPoll={selectedPoll}
                            setSelectedPoll={setSelectedPoll}
                        />
                    )
                )}
            </div>

            <div className={join(styles, "zoom_controls")}>
                <button
                    disabled={slideShowIndex <= 0}
                    onClick={handleGoBack}
                    tabIndex={selectedPoll === -1 ? 4 : -1}
                >
                    Previous Slide
                </button>
                <button
                    disabled={sharingDone}
                    onClick={handleReset}
                    tabIndex={selectedPoll === -1 ? 5 : -1}
                >
                    Restart Slide
                </button>
                <button
                    disabled={
                        slideShowIndex >= slideShowData.chat.length - 1 ||
                        !allOptional
                    }
                    onClick={handleForward}
                    tabIndex={selectedPoll === -1 ? 6 : -1}
                >
                    Next Slide
                </button>
            </div>

            <input
                id="chat_messages"
                type="text"
                autoComplete="off"
                placeholder="Type a message..."
                onKeyDown={handleSendMessage}
                tabIndex={selectedPoll === -1 ? 7 : -1}
            />
        </div>
    );
};

const ChatPoll = ({
    index,
    poll,
    pollId,
    selectedChoices = [],
    submitted,
    handlePollChoiceChange,
    setSelectedPollChoices,
    handleSubmitPoll,
    selectedPoll,
    setSelectedPoll,
}: ZoomPollProps) => {
    const { settingsState } = useGlobalState();
    const [keybinds] = settingsState.keybinds;

    useKeyDown(keybinds.General.Back, () => setSelectedPoll(-1));

    return (
        <div
            className={join(styles, "zoom_poll")}
            tabIndex={selectedPoll === -1 ? index + 10 : -1}
            onKeyDown={keyDownHandler(keybinds.General.Select, () =>
                setSelectedPoll(index)
            )}
        >
            <h5>{poll.title}</h5>
            <div className={join(styles, "zoom_poll_choices")}>
                {poll.choices.map((choice, idx) => (
                    <label
                        key={idx}
                        tabIndex={selectedPoll !== index ? -1 : idx + 1}
                        htmlFor={`${pollId}-${choice}`}
                        className={join(
                            styles,
                            `zoom_poll_choice`,
                            submitted ? "no-hover" : "",
                            selectedChoices.includes(choice) ? "selected" : ""
                        )}
                        onClick={() =>
                            handlePollChoiceChange(pollId, {
                                choice: choice,
                                submitted: false,
                            })
                        }
                        onKeyDown={keyDownHandler(keybinds.General.Select, () =>
                            handlePollChoiceChange(pollId, {
                                choice: choice,
                                submitted: false,
                            })
                        )}
                    >
                        {choice}
                    </label>
                ))}
            </div>
            <h3>
                {poll.optional
                    ? "Submit Answer by Clicking Below:"
                    : "Required Submission to Continue:"}
            </h3>
            <button
                className={join(
                    styles,
                    `zoom_poll_choice`,
                    `bright`,
                    submitted ? "no-hover" : "",
                    submitted ? "selected" : ""
                )}
                onClick={() => {
                    handleSubmitPoll(poll);
                    setSelectedPoll(-1);
                }}
                disabled={selectedChoices.length <= 0}
                tabIndex={selectedPoll !== index ? -1 : poll.choices.length + 1}
            >
                {submitted ? "Submitted!" : "Submit"}
            </button>
            {submitted && (
                <button
                    className={join(styles, `zoom_poll_choice`, `bright`)}
                    onClick={() => {
                        setSelectedPollChoices((prev) => {
                            const newMap = new Map(prev);
                            newMap.set(poll.id, {
                                choices: [],
                                submitted: false,
                            });
                            return newMap;
                        });
                        setSelectedPoll(-1);
                    }}
                    tabIndex={
                        selectedPoll !== index ? -1 : poll.choices.length + 2
                    }
                >
                    Reselect Choices
                </button>
            )}
        </div>
    );
};

const ZoomSettings = ({
    setCameraOn,
    cameraOn,
    setParticipantsOpen,
    participantsOpen,
    handleLeaveMeeting,
    sharingDone,
    selectedPoll,
}: ZoomSettingsProps) => {
    return (
        <div className={join(styles, "zoom_controls")}>
            <div className={join(styles, "zoom_control_block")}>
                <button
                    onClick={() => {
                        setCameraOn(!cameraOn);
                    }}
                    tabIndex={selectedPoll === -1 ? 1 : -1}
                >
                    {cameraOn ? "Hide" : "Show"} Camera
                </button>
            </div>
            <div className={join(styles, "zoom_control_block")}>
                <button
                    onClick={() => {
                        setParticipantsOpen(!participantsOpen);
                    }}
                    tabIndex={selectedPoll === -1 ? 2 : -1}
                >
                    {participantsOpen ? "Hide" : "Show"} Participants
                </button>
            </div>
            <div className={join(styles, "zoom_control_block")}>
                <button
                    disabled={!sharingDone}
                    className={join(styles, "zoom_exit_button")}
                    onClick={() => {
                        handleLeaveMeeting();

                        LoadAction("on_zoom_exit").then((action) => {
                            HandleAction(action);
                        });
                    }}
                    tabIndex={selectedPoll === -1 ? 3 : -1}
                >
                    Leave Meeting
                </button>
            </div>
        </div>
    );
};

const ZoomPopup = () => {
    const { gameState, coreState, playerState } = useGlobalState();

    const popup = coreState.popup[0];
    const slideShowData = gameState.zoom[0];
    const [participantsOpen, setParticipantsOpen] = useState<boolean>(true);
    const [cameraOn, setCameraOn] = useState<boolean>(true);
    const [messages, setMessages] = useState<Message[]>([]);
    const [pitch] = playerState.playerPitch;
    const [sharingDone, setSharingDone] = useState<boolean>(false);
    const [pollSubmittedNextSlide, setPollSubmittedNextSlide] =
        useState<boolean>(false);
    const [badgeUnlock, setBadgeUnlock] = useState<string>("");
    const [reset, setReset] = useState<boolean>(false);
    const [slideShowIndex, setslideShowIndex] = useState<number>(0);
    const [selectedPollChoices, setSelectedPollChoices] = useState<
        Map<string, { choices: string[]; submitted: boolean }>
    >(new Map());
    const [selectedPoll, setSelectedPoll] = useState<number>(-1);

    const participantsContainerRef = useRef<HTMLDivElement>(null);
    const timersRef = useRef<number[]>([]);
    const audioElementsRef = useRef<AudioBufferSourceNode[]>([]);
    const pageRef = useRef<HTMLDivElement | null>(null);

    const playerName = Registers.getTextRegister("player");

    useEffect(() => {
        if (popup !== "zoom") return;
        setReset(false);

        if (
            !slideShowData ||
            !slideShowData.chat ||
            slideShowIndex >= slideShowData.chat.length ||
            sharingDone
        ) {
            return;
        }

        const currentSlide = slideShowData.chat[slideShowIndex];
        const voices = currentSlide.voices || [];

        timersRef.current.forEach(clearTimeout);
        timersRef.current = [];
        audioElementsRef.current.forEach((audio) => {
            audio.stop();
        });
        audioElementsRef.current = [];

        voices.forEach(({ dialogIndex, startTime }) => {
            const timer = setTimeout(async () => {
                const audioElement = await PlayVoiceLine(
                    `zoom/${slideShowData.presentation}/slideshow${slideShowIndex}`,
                    dialogIndex,
                    "speaker",
                    pitch,
                    true
                );

                if (audioElement !== null) {
                    audioElementsRef.current.push(audioElement);
                }
            }, startTime * 1000);

            timersRef.current.push(timer as unknown as number);
        });

        const maxStartTime = Math.max(...voices.map((v) => v.startTime), 0);
        const totalDuration = maxStartTime + (currentSlide.endDelay || 0);

        const endDelayTimer = setTimeout(() => {
            const hasUnsubmitted = slideShowData.chat[
                slideShowIndex
            ].messages.some((messageData) => {
                if (typeof messageData.message === "string") return false;
                const poll = messageData.message as Poll;
                const pollId = `${poll.id}`;
                return !selectedPollChoices.get(pollId)?.submitted;
            });

            const allOptional = slideShowData.chat[
                slideShowIndex
            ].messages.every((messageData) => {
                if (typeof messageData.message === "string") return false;
                const poll = messageData.message as Poll;
                return poll.optional;
            });

            if (hasUnsubmitted && !allOptional) {
                setPollSubmittedNextSlide(true);
                return;
            }

            if (slideShowIndex === slideShowData.chat.length - 1) {
                setSharingDone(true);
                return;
            }
            setslideShowIndex((prev) => prev + 1);
        }, totalDuration * 1000);

        timersRef.current.push(endDelayTimer as unknown as number);

        return () => {
            timersRef.current.forEach(clearTimeout);
            timersRef.current = [];
            audioElementsRef.current.forEach((audio) => {
                audio.stop();
            });
            audioElementsRef.current = [];
        };
    }, [slideShowIndex, popup, sharingDone, reset, slideShowData]);

    useEffect(() => {
        pageRef.current?.focus();
        // eslint-disable-next-line
    }, [pageRef.current]);

    useEffect(() => {
        if (!pollSubmittedNextSlide || !slideShowData) return;

        const hasUnsubmitted = slideShowData.chat[slideShowIndex].messages.some(
            (msg) => {
                if (typeof msg.message === "string") return false;
                const poll = msg.message as Poll;
                return !selectedPollChoices.get(poll.id)?.submitted;
            }
        );

        if (!hasUnsubmitted) {
            setslideShowIndex((prev) => prev + 1);
            setPollSubmittedNextSlide(false);
        }
    }, [
        pollSubmittedNextSlide,
        slideShowData,
        slideShowIndex,
        selectedPollChoices,
    ]);

    useEffect(() => {
        if (popup !== "zoom" || !slideShowData) return;

        const currentSlide = slideShowData.chat[slideShowIndex];

        currentSlide.messages.forEach((messageData) => {
            const timeout = setTimeout(() => {
                setMessages((prevMessages) => {
                    return [
                        ...prevMessages,
                        {
                            from: messageData.from,
                            message: messageData.message,
                        },
                    ];
                });
            }, messageData.delay * 1000);

            timersRef.current.push(timeout as unknown as number);
        });

        return () => {
            timersRef.current.forEach(clearTimeout);
            timersRef.current = [];
        };
    }, [slideShowIndex, popup, reset, slideShowData]);

    if (!slideShowData) return <></>;

    const handleLeaveMeeting = () => {
        coreState.popup[1](null);
        if (badgeUnlock) Badges.unlock(badgeUnlock);
    };

    const handleReset = () => {
        setReset(true);
        setMessages((prev) => [
            ...prev,
            {
                from: playerName,
                message:
                    "Could you please go over this slide again? I missed part of it. Thanks!",
            },
        ]);
    };

    const handleGoBack = () => {
        if (slideShowIndex > 0) {
            if (!sharingDone) setslideShowIndex((prev) => prev - 1);
            if (sharingDone) setSharingDone(false);
            setMessages((prev) => [
                ...prev,
                {
                    from: playerName,
                    message:
                        "Could you please go back to the previous slide? I missed something. Thanks!",
                },
            ]);
        }
    };

    const handleForward = () => {
        if (slideShowIndex < slideShowData.chat.length - 1) {
            setslideShowIndex((prev) => prev + 1);
            setMessages((prev) => [
                ...prev,
                {
                    from: playerName,
                    message:
                        "Could you please move to the next slide? I think I've got this one. Thanks!",
                },
            ]);
        }
    };

    const handlePollChoiceChange = (
        pollId: string,
        pollSelection: { choice: string; submitted: boolean }
    ) => {
        setSelectedPollChoices((prev) => {
            const currentChoices = prev.get(pollId)?.choices || [];

            if (prev.get(pollId)?.submitted) {
                return prev;
            }

            const newChoices = currentChoices.includes(pollSelection.choice)
                ? currentChoices.filter((c) => c !== pollSelection.choice)
                : [...currentChoices, pollSelection.choice];

            const newMap = new Map(prev);
            newMap.set(pollId, { choices: newChoices, submitted: false });
            return newMap;
        });
    };

    const handleSubmitPoll = (poll: Poll) => {
        setSelectedPollChoices((prev) => {
            const newMap = new Map(prev);
            newMap.set(poll.id, {
                choices: prev.get(poll.id)?.choices || [],
                submitted: true,
            });
            return newMap;
        });
        if (
            poll.badge?.reason.type === "choice" &&
            Array.from(selectedPollChoices.values()).some((entry) =>
                entry.choices.includes(
                    poll.choices?.[poll.badge?.reason.choice as number] ?? ""
                )
            )
        )
            setBadgeUnlock(poll.badge.name);

        if (
            poll.badge?.reason.type === "count" &&
            (selectedPollChoices.get(poll.id)?.choices.length ?? 0) >=
                poll.badge.reason.count
        ) {
            setBadgeUnlock(poll.badge.name);
        }
    };

    return (
        <div
            className={join(styles, `zoom`, sharingDone ? "sharing_done" : "")}
            style={
                {
                    "--participants-open": Number(participantsOpen),
                } as CSSProperties
            }
            ref={pageRef}
            tabIndex={1}
        >
            <div className={join(styles, "zoom_content")}>
                {participantsOpen && (
                    <ZoomParticipants
                        participantsContainerRef={participantsContainerRef}
                        playerName={playerName}
                        cameraOn={cameraOn}
                        participantsOpen={participantsOpen}
                        slideShowData={slideShowData}
                        selectedPoll={selectedPoll}
                    />
                )}
                {!sharingDone && (
                    <div className={join(styles, "zoom_video_container")}>
                        <img
                            src={`assets/images/zoom/${slideShowData.presentation}/Slide${slideShowIndex + 1}.JPG`}
                            className={join(styles, "zoom_slideshow")}
                            alt={`Slide ${slideShowIndex + 1}`}
                        />
                    </div>
                )}
            </div>
            <ZoomSettings
                setCameraOn={setCameraOn}
                cameraOn={cameraOn}
                setParticipantsOpen={setParticipantsOpen}
                participantsOpen={participantsOpen}
                handleLeaveMeeting={handleLeaveMeeting}
                sharingDone={sharingDone}
                selectedPoll={selectedPoll}
            />
            <ZoomChat
                messages={messages}
                setMessages={setMessages}
                selectedPollChoices={selectedPollChoices}
                handlePollChoiceChange={handlePollChoiceChange}
                handleSubmitPoll={handleSubmitPoll}
                handleReset={handleReset}
                handleGoBack={handleGoBack}
                handleForward={handleForward}
                setSelectedPollChoices={setSelectedPollChoices}
                slideShowIndex={slideShowIndex}
                sharingDone={sharingDone}
                slideShowData={slideShowData}
                selectedPoll={selectedPoll}
                setSelectedPoll={setSelectedPoll}
            />
        </div>
    );
};

export default ZoomPopup;
