import React from "react";
import styles from "#styles/activities/renderers/scale.module.css";
import { join } from "engine/src/system/Styles";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";
import { Activities } from "../../../types/Activity";

export const ScaleActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "scale"
> = (element, playerData, updateState, [binds]) => {
    const isVisible =
        !Object.keys(binds).includes("visible") || binds.visible === "true";
    return {
        appView: (
            <React.Fragment key={element.prompt}>
                {isVisible && (
                    <div className={join(styles, "scale-component")}>
                        <div className={join(styles, "scale-header")}>
                            <span>{element.number}</span>
                            <h2>{element.prompt}</h2>
                        </div>

                        <div className={join(styles, "scale-slider")}>
                            <input
                                type="range"
                                min={0}
                                max={10}
                                list="values"
                                defaultValue={0 || playerData.value}
                                onChange={(e) => {
                                    updateState({
                                        type: "scale",
                                        complete: true,
                                        value: parseInt(
                                            (e.target as HTMLInputElement).value
                                        ),
                                    });
                                }}
                            />
                            <datalist id="values">
                                <option value="0" label="0"></option>
                                <option value="1" label="1"></option>
                                <option value="2" label="2"></option>
                                <option value="3" label="3"></option>
                                <option value="4" label="4"></option>
                                <option value="5" label="5"></option>
                                <option value="6" label="6"></option>
                                <option value="7" label="7"></option>
                                <option value="8" label="8"></option>
                                <option value="9" label="9"></option>
                                <option value="10" label="10"></option>
                            </datalist>
                        </div>
                    </div>
                )}
            </React.Fragment>
        ),
        printView: (
            <React.Fragment key={element.prompt}>
                {isVisible && (
                    <div className={join(styles, "scale-component")}>
                        <div className={join(styles, "scale-header")}>
                            <span>{element.number}</span>
                            <h2>{element.prompt}</h2>
                        </div>

                        <div className={join(styles, "scale-slider")}>
                            <input
                                readOnly
                                type="range"
                                min={0}
                                max={10}
                                list="values"
                                defaultValue={0 || playerData.value}
                            />
                            <datalist id="values">
                                <option value="0" label="0"></option>
                                <option value="1" label="1"></option>
                                <option value="2" label="2"></option>
                                <option value="3" label="3"></option>
                                <option value="4" label="4"></option>
                                <option value="5" label="5"></option>
                                <option value="6" label="6"></option>
                                <option value="7" label="7"></option>
                                <option value="8" label="8"></option>
                                <option value="9" label="9"></option>
                                <option value="10" label="10"></option>
                            </datalist>
                        </div>
                    </div>
                )}
            </React.Fragment>
        ),
    };
};

export const DefaultScaleActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "scale"
> = () => ({
    type: "scale",
    complete: false,
    value: -1,
});
