import { useEffect, useRef } from "react";
import Flags from "engine/src/system/Flags";
import styles from "../styles/PhoneToggle.module.css";
import { join } from "engine/src/system/Styles";
import { ReactSetter, useBaseGlobalState } from "engine/src/state/GlobalState";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { useKeyDown } from "engine/src/system/Keyboard";

export const PhoneToggle = ({
    phoneOpen,
    setPhoneOpen,
}: {
    phoneOpen: boolean;
    setPhoneOpen: ReactSetter<boolean>;
}) => {
    const {coreState, settingsState} = useBaseGlobalState();
    
    const [keybinds] = settingsState.keybinds;

    const buttonRef = useRef<HTMLButtonElement | null>(null);

    function phoneToggle() {
        buttonRef.current?.blur();

        PlayAudio("phone-toggle.wav", "sounds");
        
        setPhoneOpen(val => !val);
    }

    useEffect(() => {
        Flags.setOrUnsetFlag([
            {
                flag_name: "hint:closed_phone",
                flag_action: phoneOpen ? "revoke" : "give",
            },
            {
                flag_name: "hint:opened_phone",
                flag_action: phoneOpen ? "give" : "revoke",
            },
        ]);
    }, [phoneOpen]);

    useKeyDown(keybinds.General.Open_Phone, phoneToggle,
        phoneOpen || coreState.transitioning[0]
    );

    return (
        <button
            ref={buttonRef}
            tabIndex={-1}
            className={join(
                styles, `phone-toggle`,
                phoneOpen ? "phone-open" : ""
            )}
            onClick={phoneToggle}
        ></button>
    );
};
