import React from "react";
import styles from "#styles/activities/renderers/multiselect.module.css";
import { join } from "engine/src/system/Styles";
import { editState } from "../../../state/Util";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const MultiselectActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "multiselect"
> = (element, playerData, updateState, [_, updateBinding]) => {
    const toggle = (index: number) => {
        updateBinding(
            element,
            index.toString(),
            `${playerData.selected ? !playerData.selected.includes(index) : true}`
        );
        editState(playerData, updateState, (data) => {
            if (!data.selected) data.selected = [];
            if (data.selected.includes(index)) {
                data.selected.splice(data.selected.indexOf(index), 1);
            } else {
                data.selected.push(index);
            }
            return data;
        });
    };
    return {
        appView: (
            <React.Fragment key={element.prompt}>
                <div className={join(styles, "multiselect-component")}>
                    <div className={join(styles, "multiselect-header")}>
                        {element.number && <span>{element.number}</span>}
                        <h2 className={join(styles, "multiselect-title")}>
                            {element.prompt}
                        </h2>
                    </div>

                    <div className={join(styles, "multiselect-items")}>
                        {element.options.map((option, index) => (
                            <button
                                key={index}
                                className={
                                    playerData.selected?.includes(index)
                                        ? join(styles, "selected")
                                        : ""
                                }
                                onClick={() => toggle(index)}
                            >
                                {option}
                            </button>
                        ))}

                        {element.other_fields.map((field, i) => (
                            <button
                                key={`other-${i}`}
                                className={join(
                                    styles,
                                    `multiselect-input`,
                                    playerData.other_values &&
                                        playerData.other_values[i]
                                        ? "selected"
                                        : ""
                                )}
                            >
                                <span>{field} </span>
                                <input
                                    type="text"
                                    value={
                                        playerData.other_values &&
                                        playerData.other_values[i]
                                            ? playerData.other_values[i]
                                            : ""
                                    }
                                    onChange={(e) => {
                                        editState(
                                            playerData,
                                            updateState,
                                            (data) => {
                                                if (!data.other_values)
                                                    data.other_values = [];
                                                data.other_values[i] =
                                                    e.target.value;
                                                return data;
                                            }
                                        );
                                    }}
                                ></input>
                            </button>
                        ))}
                    </div>
                </div>
            </React.Fragment>
        ),
        printView: (
            <React.Fragment key={element.prompt}>
                <div className={join(styles, "multiselect-component")}>
                    <div className={join(styles, "multiselect-header")}>
                        {element.number && <span>{element.number}</span>}
                        <h2 className={join(styles, "multiselect-title")}>
                            {element.prompt}
                        </h2>
                    </div>

                    <div className={join(styles, "multiselect-items")}>
                        {element.options.map((option, index) => (
                            <button
                                key={index}
                                className={
                                    playerData.selected?.includes(index)
                                        ? join(styles, "selected")
                                        : ""
                                }
                            >
                                {option}
                            </button>
                        ))}

                        {element.other_fields.map((field, i) => (
                            <button
                                key={`other-${i}`}
                                className={join(
                                    styles,
                                    `multiselect-input`,
                                    playerData.other_values &&
                                        playerData.other_values[i]
                                        ? "selected"
                                        : ""
                                )}
                            >
                                <span>{field} </span>
                                <input
                                    type="text"
                                    value={
                                        playerData.other_values &&
                                        playerData.other_values[i]
                                            ? playerData.other_values[i]
                                            : ""
                                    }
                                    readOnly
                                ></input>
                            </button>
                        ))}
                    </div>
                </div>
            </React.Fragment>
        ),
    };
};

export const DefaultMultiselectActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "multiselect"
> = () => ({
    type: "multiselect",
    complete: true,
    selected: [],
    other_values: [],
});
