import { useCallback, useEffect, useState } from "react";
import { PlayerState, useGlobalState } from "../../state/GlobalState";
import styles from "#styles/apps/JournalApp.module.css";
import { Documents, Strategies } from "../../system/Unlockables";
import { GenericListApp } from "./GenericListApp";
import {
    Keybinds,
    useKeyDown,
    useSelectedIndex,
} from "engine/src/system/Keyboard";
import { CoreState } from "engine/src/state/GlobalState";
import { Activity } from "../../types/Activity";
import { Minigame } from "../../types/Minigame";
import { LoadActivity } from "engine/src/system/DataLoader";
import { join } from "engine/src/system/Styles";

type ItemData = {
    title: string;
    description: string;
    onSelect: null | (() => void);
};

/**
 * The Journal App
 */
export const JournalComponent = ({ closeApp }: { closeApp: () => void }) => {
    const { playerState, coreState, settingsState } = useGlobalState();

    const [popup] = coreState.popup;
    const [keybinds] = settingsState.keybinds;

    const pages: {
        name: string;
        title: string;
        description: JSX.Element;
        data: ItemData[];
    }[] = [
        {
            name: "Documents",
            title: "Documents",
            description: <p></p>,
            data: getDocumentsData(),
        },
        {
            name: "Journal Activities",
            title: "Journal Activities",
            description: <p></p>,
            data: getActivitiesData(playerState, coreState),
        },
        {
            name: "Strategies",
            title: "Strategies",
            description: (
                <p>
                    Unlock strategies to help your transition to post secondary
                    by finding and clicking on{" "}
                    <img
                        className={join(styles, "strat-icon")}
                        src="assets/images/elements/book.png"
                        alt=""
                    />{" "}
                    icons!
                </p>
            ),
            data: getStrategiesData(),
        },
    ];

    const [onItems, setOnItems] = useState<boolean>(false);

    const [currentPage, setCurrentPage] = useState<{
        name: string;
        description: JSX.Element;
        data: ItemData[];
    }>(pages[0]);

    const [page, setPage] = useSelectedIndex(
        pages.length,
        keybinds.General.Up,
        keybinds.General.Down,
        popup !== null || onItems
    );
    const [selectedItem, setSelectedItem] = useSelectedIndex(
        currentPage.data.length,
        keybinds.General.Up,
        keybinds.General.Down,
        popup !== null || !onItems
    );

    useKeyDown(keybinds.General.Back, () => {
        if (onItems) return setOnItems(false);
        closeApp();
    });
    useKeyDown(keybinds.General.Right, () => setOnItems(true));
    useKeyDown(keybinds.General.Left, () => setOnItems(false));
    useKeyDown(
        keybinds.General.Select,
        useCallback(() => {
            if (!onItems) return setOnItems(true);

            const callback = currentPage.data[selectedItem].onSelect;
            if (callback !== null) {
                callback();
            }
        }, [currentPage.data, onItems, selectedItem]),
        popup !== null
    );

    useEffect(() => {
        if (page === -1) {
            setPage(0);
        } else {
            setCurrentPage(pages[page]);
        }
        // eslint-disable-next-line
    }, [page, setPage]);

    useEffect(() => {
        if (onItems) {
            setSelectedItem(0);
        } else {
            setSelectedItem(-1);
        }
    }, [onItems, setSelectedItem]);

    // Return the journal content with the embedded page
    return (
        <GenericListApp
            title="Journal"
            closeApp={closeApp}
            pages={pages}
            elementsSelectable={true}
            ItemComponent={ItemComponent}
        />
    );
};

function ItemComponent({
    item,
    index,
    selected,
    keybinds,
}: {
    item: ItemData;
    index: number;
    selected: boolean;
    keybinds: Keybinds;
}) {
    useKeyDown(keybinds.General.Select, item.onSelect || (() => {}), !selected);

    return (
        <div
            key={index}
            className={join(
                styles,
                "documentButton",
                item.onSelect !== null && selected ? "selected" : ""
            )}
            onClick={item.onSelect || (() => {})}
            style={
                item.onSelect === null ? { scale: "1", cursor: "default" } : {}
            }
        >
            <h2>{item.title}</h2>
            <p>{item.description}</p>
        </div>
    );
}

function getDocumentsData(): ItemData[] {
    return Object.keys(Documents.list())
        .filter((id: string) => Documents.unlocked(id))
        .map((id: string) => {
            const document = Documents.get(id);
            return {
                title: document.name,
                description: document.description,
                onSelect: () => Documents.open(id),
            };
        })
        .reverse();
}

function getActivitiesData(
    playerState: PlayerState,
    coreState: CoreState<Activity, Minigame>
): ItemData[] {
    const activityData = playerState.activityData[0];

    return Object.keys(activityData)
        .map((entry) => {
            return {
                title: entry.replaceAll("_", " "),
                description: `Select to open Journal Activity`,
                onSelect: () => {
                    LoadActivity<Activity>(entry).then((activity) => {
                        coreState.activity[1](activity);
                        coreState.popup[1]("activity");
                    });
                },
            };
        })
        .reverse();
}

function getStrategiesData(): ItemData[] {
    return Object.keys(Strategies.list())
        .filter(Strategies.unlocked)
        .map((id: string) => {
            const strategy = Strategies.get(id);
            return {
                title: strategy.title,
                description: strategy.content,
                onSelect: strategy.attachment
                    ? () => {
                          window.open(
                              `assets/PDF/strategies/${id.split(":")[0]}/${id.split(":")[1]}.pdf`,
                              "_blank",
                              "width=800,height=600"
                          );
                      }
                    : null,
            };
        });
}
