import Registers from "./Registers";

export const dialogClean = (text: string) => {
    let output = text;

    // regex matches instances of %something%
    text.match(/(?<=%)(.*?)(?=%)/g)?.forEach((match, index) => {
        if (index % 2 === 1) return;

        let value: number | string = Registers.getTextRegister(match);
        if (value === "") value = Registers.getRegister(match);

        if (value !== undefined) {
            output = output.replace(`%${match}%`, `${value}`);
        }
    });

    return output;
};

