import React, { useCallback, useEffect, useState } from "react";
import { SettingsState, useBaseGlobalState } from "../state/GlobalState";
import Registers from "./Registers";
import { TextRegisterUpdate } from "../types/Register";
import { BaseParticipantSettings } from "../ParticipantSettings";

// see docs/controls.md for more explaination

export enum KeyEvent {
    KeyPress = "keydown",
    KeyRelease = "keyup",
}

export type Keybind = string[]

export type Keybinds = Record<string, 
    Record<string, Keybind>
>

// Default values for all the keybinds
export const defaultKeybinds: Keybinds = {
    General: {
        Keyboard_Hints: ["Backquote"],
        Up: ["ArrowUp"],
        Down: ["ArrowDown"],
        Left: ["ArrowLeft"],
        Right: ["ArrowRight"],
        Select: ["Enter", "Space"],
        Back: ["Escape"],
        Open_Phone: ["Digit1"],
        Open_Dialog_History: ["KeyH"],
        Save_Game: ["KeyS"],
        Dismiss_Oldest_Notification: ["KeyQ"],
    },
    Minigames: {
        Select: ["Enter"],
    },
    Textbook_Minigame: {
        Left: ["ArrowLeft"],
        Right: ["ArrowRight"],
        Slow_Movement: ["ShiftLeft"],
    },
    Urgency_Matrix_Minigame: {
        Next_Cell: ["ArrowRight"],
        Previous_Cell: ["ArrowLeft"]
    }
}

// converts a keycode to a string that is easier to understand for a user
export function humanReadableKey(key: string): string {
    switch (key) {
        case "ShiftLeft":
        case "AltLeft":
        case "ControlLeft":
        case "MetaLeft":
            return `Left ${key.replaceAll("Left", "")}`;
        case "ShiftRight":
        case "AltRight":
        case "ControlRight":
        case "MetaRight":
            return `Right ${key.replaceAll("Right", "")}`;
        case "Escape":
            return "Esc";
        case "Backquote":
            return "~";
    }

    return key
        .replaceAll("Arrow", "")
        .replaceAll("Key", "")
        .replaceAll("Digit", "")
    ;
}

// Converts a list of keys to a human readable format
export function keyList(keys: string[]): string {
    const output = keys.map(humanReadableKey).join(`, `);

    // replace the last comma with " or "
    const match = output.match(/, (?:.(?!, ))+$/g);
    if(match) {
        return output.replace(match[0], ` or ${match[0].slice(2)}`);
    }

    return output;
}

// Gets the key to store in registers
export function registerKey(keys: string[]): string {
    return humanReadableKey(keys[0]);
}

// sets a keybind to a user specified value
// keybind is the category and name of the keybind, eg: ["Genearal", "Up"]
// updates the registers accordingly
export function setKeybind<S extends BaseParticipantSettings>(settings: SettingsState<S>, keybind: [string, string], code: string) {
    const [, setKeybinds] = settings.keybinds;

    setKeybinds(val => {
        const currentBinds = val[keybind[0]][keybind[1]];

        if(!currentBinds.includes(code)) {
            Registers.setTextRegisters([{
                register: `key:${keybind[0]}:${keybind[1]}`.toLowerCase(),
                action: `set`,
                value: `${registerKey([...currentBinds, code])}`
            }]);

            return {
                ...val,
                [keybind[0]]: {
                    ...val[keybind[0]],
                    [keybind[1]]: [...currentBinds, code]
                }
            };
        }

        if(currentBinds.length === 1) {
            return val;
        }
        
        Registers.setTextRegisters([{
            register: `key:${keybind[0]}:${keybind[1]}`.toLowerCase(),
            action: `set`,
            value: `${registerKey(currentBinds.filter(key => key !== code))}`
        }]);

        return {
            ...val,
            [keybind[0]]: {
                ...val[keybind[0]],
                [keybind[1]]: currentBinds.filter(key => key !== code),
            }
        };
    });
}

// resets all keybinds to their default value
export function resetKeybinds<S extends BaseParticipantSettings>(settings: SettingsState<S>) {
    const [, setKeybinds] = settings.keybinds;

    setKeybinds(defaultKeybinds);
    updateKeyRegisters(settings);
}

// resets a given keybind to its default value
// keybind is the category and name of the keybind, eg: ["Genearal", "Up"]
export function resetKeybind<S extends BaseParticipantSettings>(settings: SettingsState<S>, keybind: [string, string]) {
    const [, setKeybinds] = settings.keybinds;
    const defaultBinds = defaultKeybinds[keybind[0]][keybind[1]];

    setKeybinds(val => {
        Registers.setTextRegisters([{
            register: `key:${keybind[0]}:${keybind[1]}`.toLowerCase(),
            action: `set`,
            value: `${registerKey(defaultBinds)}`
        }]);

        return {
            ...val,
            [keybind[0]]: {
                ...val[keybind[0]],
                [keybind[1]]: defaultBinds,
            }
        };
    });
}

// updates all the registers to the current value of keys
// should only need to be done at the start of the game and when all keybinds are reset
export function updateKeyRegisters<S extends BaseParticipantSettings>(settings: SettingsState<S>) {
    const [keybinds] = settings.keybinds;

    let updates: TextRegisterUpdate[] = []

    Object.keys(keybinds).forEach(group => {
        Object.keys(keybinds[group]).forEach(key => {
            updates.push({
                register: `key:${group}:${key}`.toLowerCase(),
                action: `set`,
                value: `${registerKey(keybinds[group][key])}`,
            });
        });
    });

    Registers.setTextRegisters(updates);
}

// A custom hook that runs the call back when any of the keys are pressed down
// and disableInput is not `true`
export function useKeyDown(
    keys: Keybind,
    callback: () => void,
    disableInput?: boolean,
) {
    const handler = useCallback(() => {
        if(!disableInput) callback();
    }, [disableInput, callback]);

    useEffect(() => {
        keys.forEach(key => {
            window.addEventListener(`key:${key}:down`, handler, false);
        });
        
        return () => {
            keys.forEach(key => {
                window.removeEventListener(`key:${key}:down`, handler, false);
            });
        };
    });
}

// A custom hook that runs the call back when any of the keys are released
// and disableInput is not `true`
export function useKeyUp(
    keys: Keybind,
    callback: () => void,
    disableInput?: boolean,
) {
    const handler = useCallback(() => {
        if(!disableInput) callback();
    }, [disableInput, callback]);

    useEffect(() => {
        keys.forEach(key => {
            window.addEventListener(`key:${key}:up`, handler, false);
        });
        
        return () => {
            keys.forEach(key => {
                window.removeEventListener(`key:${key}:up`, handler, false);
            });
        };
    });
}

// A custom hook that returns a state value that is true when one of the keys
// is pressed untill one of them is released
// the value will not change when diableInput is `true`
export function useKeyHeld(keys: Keybind, disableInput?: boolean) {
    const [held, setHeld] = useState<boolean>(false);

    useKeyDown(keys, () => setHeld(true), disableInput);
    useKeyUp(keys, () => setHeld(false), disableInput);

    return held;
}

// A custom hook that returns a state value that is toggled by the keys specified
// toggleKeys: when one is pressed the value goes from `true` <=> `false`
// setKeys: when one is pressed the value is set to `true`
// resetKeys: when one is pressed the value is set to `false`
// returns [toggle, setToggle]
// the value will not change when diableInput is `true`
export function useKeyboardToggle(
    toggleKeys: Keybind,
    setKeys: Keybind,
    resetKeys: Keybind,
    disableInput?: boolean
): [boolean, React.Dispatch<React.SetStateAction<boolean>>] {
    const [toggle, setToggle] = useState<boolean>(false);

    useKeyDown(toggleKeys, () => setToggle(val => !val), disableInput);
    useKeyDown(setKeys, () => setToggle(true), disableInput);
    useKeyDown(resetKeys, () => setToggle(false), disableInput);

    return [toggle, setToggle];
}


// A custom hook that returns a state value that is incramented and decremented by the keys specified
// length: the counter will reset to 0 when past this number, and go to this number when less than 0
// returns [I, setI]
// the value will not change when diableInput is `true`
export function useSelectedIndex(
    length: number,
    upKeys: Keybind,
    downKeys: Keybind,
    disableInput?: boolean
): [number, React.Dispatch<React.SetStateAction<number>>] {
    const [selectedIndex, setSelectedIndex] = useState<number>(-1);
    
    useKeyDown(upKeys, () => {
        setSelectedIndex((i) =>
            i === -1 ? length - 1 : (i - 1 + length) % length
        );
    }, disableInput || length === 0);

    useKeyDown(downKeys, () => {
        setSelectedIndex((i) => (i + 1) % length);
    }, disableInput || length === 0);

    return [selectedIndex, setSelectedIndex];
}

// A custom hook that returns a state value that is incramented and decremented by the keys specified
// length: the counter will reset to 0 when past this number, and go to this number when less than 0
// filter: a function that takes a number and returns a boolean, numbers where filter evaluates to false will be skipped
// returns [I, setI]
// the value will not change when diableInput is `true`
export function useSelectedIndexFiltered(
    length: number,
    upKeys: Keybind,
    downKeys: Keybind,
    filter: (index: number) => boolean,
    disableInput: boolean
): [number, React.Dispatch<React.SetStateAction<number>>] {
    const [selectedIndex, setSelectedIndex] = useState<number>(-1);

    useKeyDown(upKeys, useCallback(() => {
        setSelectedIndex((i) => {
            let counter = 0;
            let val = i === -1 ? length - 1 : (i - 1 + length) % length;
            while (val === -1 || !filter(val)) {
                val = (val - 1) % length;
                counter++;
                if(counter > length) {
                    break;
                }
            }
            if(counter > length) return -1;

            return val;
        });
        return true;
    }, [length, filter]), disableInput);

    useKeyDown(downKeys, useCallback(() => {
        setSelectedIndex((i) => {
            let counter = 0;
            let val = (i + 1) % length;
            while (val === -1 || !filter(val)) {
                val = (val + 1) % length;
                counter++;
                if(counter > length) {
                    break;
                }
            }
            if(counter > length) return -1;

            return val;
        });
        return true;
    }, [length, filter]), disableInput);

    return [selectedIndex, setSelectedIndex];
}

// A custom hook that returns two state values (I, J) that are incramented and decremented as the coordinates of a grid
// uses the Genera up, down, left, and right keybinds
// rows: number of items on the I axis
// cols: number of items on the J axis
// returns [I, J, setI, setJ]
// the values will not change when diableInput is `true`
export function useSelectedIndexGrid(
    rows: number,
    cols: number
): [
    number,
    number,
    React.Dispatch<React.SetStateAction<number>>,
    React.Dispatch<React.SetStateAction<number>>,
] {
    const {settingsState} = useBaseGlobalState();

    const [keybinds] = settingsState.keybinds;
    
    const [selectedIndex, setSelectedIndex] = useState<number>(0);
    const [selectedJndex, setSelectedJndex] = useState<number>(0);

    useKeyDown(keybinds.General.Up, useCallback(() => {
        setSelectedIndex((i) =>
            i === -1 ? rows - 1 : (i - 1 + rows) % rows
        );
        return true;
    }, [rows]));

    useKeyDown(keybinds.General.Left, useCallback(() => {
        setSelectedJndex((j) =>
            j === -1 ? cols - 1 : (j - 1 + cols) % cols
        );
        return true;
    }, [cols]));

    useKeyDown(keybinds.General.Down, useCallback(() => {
        setSelectedIndex((i) => (i + 1) % rows);
        return true;
    }, [rows]));

    useKeyDown(keybinds.General.Right, useCallback(() => {
        setSelectedJndex((j) => (j + 1) % cols);
        return true;
    }, [cols]));

    return [selectedIndex, selectedJndex, setSelectedIndex, setSelectedJndex];
}

// a helper function for adding keyDownHandlers to elements
// eg: onKeyDown={keyDownHandler(["Enter"], onClick)}
// if the callback returns `true` event.preventDefault() will be called
export function keyDownHandler(keys: Keybind, callback: () => boolean | void) {
    return (event: React.KeyboardEvent<HTMLElement>) => {
        if (keys.includes(event.code)) {
            if (callback()) {
                event.preventDefault();
            }
        }
    };
}
