import React, {
    useCallback,
    useEffect,
    useRef,
    useState,
} from "react";
import styles from "../styles/Scene.module.css";
import { CheckCondition, HandleAction } from "engine/src/system/ActionExecutor";
import Flags from "engine/src/system/Flags";
import {
    IsAudioPlaying,
    ListAllAudio,
    PlayAudio,
    StopAllAudio,
} from "../system/AudioSystem";
import { joinWithOverride } from "../system/Styles";
import {
    BoundingBoxSceneElement,
    ImageSceneElement,
    PopoverSceneElement,
    Scene,
    SceneElement,
} from "engine/src/types/Scene";
import DialogComponent from "./Dialog";
import DialogHistoryComponent from "./DialogHistory";
import { useKeyDown, useSelectedIndexFiltered } from "engine/src/system/Keyboard";
import { saveGame } from "engine/src/system/SaveSystem";
import { PhoneToggle } from "engine/src/components/PhoneToggle";
import Registers from "engine/src/system/Registers";
import { useBaseGlobalState } from "../state/GlobalState";
import { PopupRegistry } from "./Popup";
import { DictionaryWords } from "../types/DictionaryWords";
import { Dialog } from "../types/Dialog";
import { DialogSkipComponent } from "./DialogSkip";

/**
 * The component responsible for rendering the current scene
 */
const SceneComponent = ({popupRegistry, dictionary, newWordCallback, pitch, character, additionalDialogElement, sceneStyleOverride, dialogStyleOverride, dialogHistoryStyleOverride, dialogSkipStyleOverride}: {popupRegistry: PopupRegistry, dictionary: Record<string, DictionaryWords>, newWordCallback: (word: string) => void, pitch: 'low-pitch' | 'high-pitch', character: string, additionalDialogElement: (dialog: Dialog["dialog"][0]) => [React.ReactNode, boolean], sceneStyleOverride: any, dialogStyleOverride: any, dialogHistoryStyleOverride: any, dialogSkipStyleOverride: any}) => {
    // Get the state from the global state
    const {coreState, settingsState} = useBaseGlobalState();

    const [phoneOpen, setPhoneOpen] = coreState.phoneOpen;
    const [dialogHistoryOpen, setDialogHistoryOpen] = coreState.dialogHistoryOpen;
    const [scene] = coreState.scene;
    const [sceneBackground] = coreState.sceneBackground;
    const [dialog] = coreState.dialog;
    const [loadingDialog] = coreState.loadingDialog;
    const [dialogIndex] = coreState.dialogIndex;
    const [popup] = coreState.popup;
    const [minigame] = coreState.minigame;
    const [dialogHistory] = coreState.dialogHistory;

    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    const [transitioning, setTransitioning] = coreState.transitioning;

    const chapterNumber = Registers.getRegister("chapter");

    const elementEnabled = useCallback(
        (index: number) => {
            const element = scene.elements[index];

            if (element.type !== "conditional_bounding_box") {
                if ((element.type === "bounding_box" || element.type === "popover") && element.secret) {
                    return (
                        Math.random() <=
                        participantSettings.SelectSecretProbability
                    );
                }
                return true;
            }

            if (CheckCondition(element)) {
                const isSecret = element.elements.reduce((acc, current) => {
                    return acc || checkSecret(current);
                }, false);

                if (isSecret) {
                    return (
                        Math.random() <=
                        participantSettings.SelectSecretProbability
                    );
                }

                return true;
            }
            return false;

            function checkSecret(element: SceneElement) {
                if (element.type === "bounding_box" && element.secret) {
                    return true;
                }
                return false;
            }
        },
        [scene, participantSettings]
    );

    // State to hold the window size and a reference to the background image
    const [windowBounds, setWindowBounds] = useState([
        window.innerWidth,
        window.innerHeight,
    ]);
    const imageRef = useRef<HTMLImageElement>(null);

    // The bounds of the image
    const [bounds, setBounds] = useState({
        x: 0,
        y: 0,
        dx: windowBounds[0],
        dy: windowBounds[1],
    });

    const dialogOpen =
        (dialog && dialogIndex < dialog.dialog.length) || loadingDialog;

    const inputDisabled =
        dialogOpen ||
        dialogHistoryOpen ||
        phoneOpen ||
        popup !== null;

    const [selectedIndex, setSelectedIndex] = useSelectedIndexFiltered(
        scene.elements.length,
        [...keybinds.General.Up, ...keybinds.General.Right],
        [...keybinds.General.Down, ...keybinds.General.Left],
        elementEnabled,
        inputDisabled
    );
    const [selectedElement, setSelectedElement] = useState<SceneElement>();

    useKeyDown(
        keybinds.General.Save_Game,
        useCallback(() => {
            if (!inputDisabled || phoneOpen) {
                saveGame();
            }
        }, [inputDisabled, phoneOpen]),
        popup !== null
    );

    // Function to update the bounds of the image
    const updateBounds = useCallback(
        (image: HTMLImageElement) => {
            // If there is no image, do nothing
            if (image === null) return;

            // Set up the new bounds
            const newBounds = {
                x: 0,
                y: 0,
                dx: windowBounds[0],
                dy: windowBounds[1],
            };

            // Calculate actual coordinates of the image
            const aspectRatio = image.naturalWidth / image.naturalHeight;

            // Calculate the bounds of the background image

            // If the image's width is larger than the width of the scene display, than it
            // has been scaled down to match the width
            if (windowBounds[1] * aspectRatio > windowBounds[0]) {
                newBounds.x = 0;
                newBounds.y =
                    (windowBounds[1] - windowBounds[0] / aspectRatio) / 2;
                newBounds.dx = windowBounds[0];
                newBounds.dy = windowBounds[0] / aspectRatio;
            }

            // If the image's height is larger than the width of the scene display, than it
            // has been scaled down to match the height of the window
            if (windowBounds[0] / aspectRatio > windowBounds[1]) {
                newBounds.x =
                    (windowBounds[0] - windowBounds[1] * aspectRatio) / 2;
                newBounds.y = 0;
                newBounds.dx = windowBounds[1] * aspectRatio;
                newBounds.dy = windowBounds[1];
            }

            // Set the bounds
            setBounds(newBounds);
        },
        [windowBounds]
    );

    /**
     * Handle a click in the scene area
     */
    const handleClick = (e: React.MouseEvent<HTMLImageElement>) => {
        // If nothing was clicked, return
        if (
            e.currentTarget === null ||
            scene === undefined ||
            dialogOpen ||
            dialogHistoryOpen
        )
            return;

        // Get the location of the click relative to the background image
        const clickX = (e.clientX - bounds.x) / bounds.dx;
        const clickY = (e.clientY - bounds.y) / bounds.dy;

        console.log(clickX, clickY);

        // If the click was outside the image, ignore the event
        if (clickX < 0 || clickX > 1 || clickY < 0 || clickY > 1) return;

        // Play audio when the scene is clicked
        PlayAudio("mouse-click.wav", "sounds");

        // Check each interactable area of the scene to see if that area was clicked
        for (const element of scene.elements) {
            if (
                element.type === "conditional_bounding_box" &&
                CheckCondition(element)
            ) {
                for (const nestedElement of element.elements) {
                    if (nestedElement.type !== "bounding_box") continue;
                    handleBoundingBox(nestedElement, clickX, clickY);
                }
            }

            if (element.type !== "bounding_box" && element.type !== "popover") continue;

            handleBoundingBox(element, clickX, clickY);
        }
    };

    function handleBoundingBox(
        element: BoundingBoxSceneElement | PopoverSceneElement,
        clickX: number,
        clickY: number
    ) {
        if (
            clickX > element.x &&
            clickX < element.x2 &&
            clickY > element.y &&
            clickY < element.y2
        ) {
            triggerElement(element);
        }
    }

    const triggerElement = useCallback(
        (element: BoundingBoxSceneElement | PopoverSceneElement) => {
            // Handle the interactable area's action
            HandleAction(element.action);
            PlayAudio(`scene-click/${element.sound}.wav`, "sounds");

            setSelectedIndex(-1);
        },
        [setSelectedIndex]
    );

    useKeyDown(
        keybinds.General.Select,
        useCallback(() => {
            if (selectedElement === undefined || inputDisabled) return;

            if (selectedElement.type === "conditional_bounding_box") {
                for (const nestedElement of selectedElement.elements) {
                    if (nestedElement.type !== "bounding_box") continue;
                    triggerElement(nestedElement);
                }
                return;
            }

            if (selectedElement.type === "bounding_box" || selectedElement.type === "popover") {
                triggerElement(selectedElement);
                return;
            }
        }, [selectedElement, triggerElement, inputDisabled])
    );

    const handleMouseEnter = (e: React.MouseEvent<HTMLImageElement>) => {
        if (e.currentTarget === null || scene === undefined) return;

        if (dialogOpen || dialogHistoryOpen) {
            e.currentTarget.classList.remove(styles.hovered);
            e.currentTarget.classList.remove(styles.popover);
            return;
        }

        // Get the location of the click relative to the background image
        const currentX = (e.clientX - bounds.x) / bounds.dx;
        const currentY = (e.clientY - bounds.y) / bounds.dy;

        e.currentTarget.style.setProperty("--hover-x", currentX * 100 + "%");
        e.currentTarget.style.setProperty("--hover-y", currentY * 100 + "%");

        if (currentX < 0 || currentX > 1 || currentY < 0 || currentY > 1)
            return;

        if (scene.elements.length === 0) {
            e.currentTarget.classList.remove(styles.hovered);
            return;
        }

        for (const element of scene.elements) {
            if(element.type === "popover") {
                if (
                    currentX > element.x &&
                    currentX < element.x2 &&
                    currentY > element.y &&
                    currentY < element.y2
                ) {
                    // Handle the interactable area's action
                    e.currentTarget.style.setProperty("--hover-text", JSON.stringify(element.message));
                    e.currentTarget.classList.add(styles.popover);
                }
            }
            if (element.type === "bounding_box" || element.type === "popover") {
                if (
                    currentX > element.x &&
                    currentX < element.x2 &&
                    currentY > element.y &&
                    currentY < element.y2
                ) {
                    // Handle the interactable area's action
                    e.currentTarget.classList.add(styles.hovered);
                    return;
                }
            }
            if (
                element.type === "conditional_bounding_box" &&
                CheckCondition(element)
            ) {
                for (const nestedElement of element.elements) {
                    if (
                        (nestedElement.type === "bounding_box" || nestedElement.type === "popover") &&
                        currentX > nestedElement.x &&
                        currentX < nestedElement.x2 &&
                        currentY > nestedElement.y &&
                        currentY < nestedElement.y2
                    ) {
                        e.currentTarget.classList.add(styles.hovered);
                        return;
                    }
                }
            }
        }
        e.currentTarget.classList.remove(styles.hovered);
        e.currentTarget.classList.remove(styles.popover);
    };

    // If the window resizes, update the window bounds
    useEffect(() => {
        window.addEventListener("resize", () => {
            setWindowBounds([window.innerWidth, window.innerHeight]);
        });
    }, []);

    // Update the image bounds when the window bounds updates
    useEffect(() => {
        if (imageRef.current) updateBounds(imageRef.current);
    }, [windowBounds, updateBounds]);

    // If the scene has an action associated with it, run the action when the scene is first loaded.
    useEffect(() => {
        if (scene.action) HandleAction(scene.action);
        Flags.setOrUnsetFlag([
            {
                flag_name: `scene:visited:${scene.name}`,
                flag_action: "give",
            },
        ]);

        setTimeout(() => {
            setTransitioning(false);
        }, 1000);

        setSelectedIndex(-1);
    }, [scene, setTransitioning, setSelectedIndex]);

    useEffect(() => {
        if (!scene.backgrounds[sceneBackground]) return;
        if (
            minigame ||
            !(popup === null || popupRegistry[popup].keepAudio)
        ) {
            StopAllAudio("music");
            StopAllAudio("ambience");
            return;
        }

        const musicName = `music/${scene.backgrounds[sceneBackground].music}`;
        const ambienceName = `ambience/${scene.backgrounds[sceneBackground].ambience}`;

        if (scene.backgrounds[sceneBackground].ambience) {
            if (!IsAudioPlaying(ambienceName)) {
                PlayAudio(ambienceName, "sounds", true);
            }
        } else {
            StopAllAudio("ambience");
        }

        const playingMusic = ListAllAudio().find((k) => k.startsWith("music/"));

        if (scene.backgrounds[sceneBackground].music) {
            if (playingMusic !== musicName && !IsAudioPlaying(musicName)) {
                PlayAudio(musicName, "music", true);
            }
        } else {
            StopAllAudio("music");
        }

        // eslint-disable-next-line
    }, [scene, minigame, sceneBackground]);

    useEffect(() => {
        if (selectedIndex !== -1) {
            setSelectedElement(scene.elements[selectedIndex]);
        } else {
            setSelectedElement(undefined);
        }
    }, [selectedIndex, scene.elements]);

    // If there is no scene to render, don't render anything
    if (!scene) {
        console.warn(
            "No scene is currently selected. Either the application is still loading, or there was an internal error while loading the current scene."
        );
        return <h1>Loading...</h1>;
    }

    // Render the scene
    return (
        <>
            {transitioning && (
                <div className={joinWithOverride(styles, sceneStyleOverride, "screen-blocker")}></div>
            )}
            <div
                id="scene"
                className={joinWithOverride(
                    styles,
                    sceneStyleOverride,
                    `scene`,
                    popup && [
                        "titleScreen",
                        "credits",
                        "saveGame",
                    ].includes(popup)
                        ? ["title", "fade-in"]
                        : ""
                )}
                onClick={handleClick}
                onMouseMove={handleMouseEnter}
            >
                {popup === null && !dialogOpen && (
                    <PhoneToggle
                        phoneOpen={phoneOpen}
                        setPhoneOpen={setPhoneOpen}
                    />
                )}
                <img
                    className={joinWithOverride(styles, sceneStyleOverride, `scene-background`)}
                    alt="Scene background"
                    src={`assets/images/backgrounds/${scene.backgrounds[sceneBackground] !== undefined ? scene.backgrounds[sceneBackground].image : ""}`}
                    onClick={handleClick}
                    ref={imageRef}
                    onLoad={(e) => {
                        updateBounds(e.currentTarget as HTMLImageElement);
                    }}
                />
                <div
                    style={{
                        position: "absolute",
                        left: `${bounds.x}px`,
                        top: `${bounds.y}px`,
                        width: `${bounds.dx}px`,
                        height: `${bounds.dy}px`,
                        display: "flex",
                    }}
                >
                    {selectedElement && (
                        <DrawSelectedElement
                            element={selectedElement}
                            scene={scene}
                            window={bounds}
                            sceneStyleOverride={sceneStyleOverride}
                        />
                    )}
                    {participantSettings.ShowBoundingBoxes && (
                        <DebugDrawElements scene={scene} window={bounds} />
                    )}
                    {popup === null && (
                        <div
                            className={joinWithOverride(
                                styles,
                                sceneStyleOverride,
                                "chapter",
                                participantSettings.EnableDialogHistory
                                    ? ""
                                    : "lower"
                            )}
                        >
                            Chapter {chapterNumber}
                        </div>
                    )}

                    {(
                        scene.elements.filter(
                            (e) => e.type === "image"
                        ) as ImageSceneElement[]
                    ).map((element, index) => {
                        // if dialog is running dont render images
                        return !dialog ? (
                            <img
                                key={index}
                                alt="scene-element"
                                src={`assets/images/elements/${element.image}`}
                                style={{
                                    position: "absolute",
                                    left: `${element.x * 100}%`,
                                    top: `${element.y * 100}%`,
                                    width: `${element.scale * 100}%`,
                                }}
                                onClick={() => {
                                    HandleAction(element.action);
                                }}
                            />
                        ) : (
                            <></>
                        );
                    })}
                    <DialogComponent setPhoneOpen={setPhoneOpen} pitch={pitch} additionalComponent={additionalDialogElement} character={character} dictionary={dictionary} newWordCallback={newWordCallback} dialogStyleOverride={dialogStyleOverride} />
                    {participantSettings.EnableDialogHistory && (
                        <DialogHistoryComponent
                            dialogHistoryOpen={dialogHistoryOpen}
                            setDialogHistoryOpen={setDialogHistoryOpen}
                            dialogHistory={dialogHistory}
                            dictionary={dictionary}
                            newWordCallback={newWordCallback}
                            pitch={pitch}
                            dialogStyleOverride={dialogStyleOverride}
                            styleOverride={dialogHistoryStyleOverride}
                        />
                    )}

                    {participantSettings.AutoDialogueEnabled && (
                        <DialogSkipComponent
                            dialogName={dialog ? dialog.name : ""}
                            styleOverride={dialogSkipStyleOverride}
                        />
                    )}
                </div>
            </div>
        </>
    );
};

export default SceneComponent;

const DrawSelectedElement = ({
    element,
    scene,
    window,
    sceneStyleOverride
}: {
    element: SceneElement,
    scene: Scene,
    sceneStyleOverride?: any,
    window: { x: number; y: number; dx: number; dy: number },
}) => {
    const boundingBoxes = [];

    if (element.type === "bounding_box") {
        boundingBoxes.push(element);
    }

    if (
        element.type === "conditional_bounding_box" &&
        CheckCondition(element)
    ) {
        for (const nestedElement of element.elements) {
            if (nestedElement.type === "bounding_box") {
                boundingBoxes.push(nestedElement);
            }
        }
    }

    return (
        <>
            {boundingBoxes.map((boundingBox, index) => {
                const [x, y] = [
                    boundingBox.x * window.dx,
                    boundingBox.y * window.dy,
                ];
                const [width, height] = [
                    (boundingBox.x2 - boundingBox.x) * window.dx,
                    (boundingBox.y2 - boundingBox.y) * window.dy,
                ];

                return (
                    <div
                        key={index}
                        className={joinWithOverride(
                            styles,
                            sceneStyleOverride,
                            `scene-element-selector${boundingBox.secret ? "-secret" : ""}`
                        )}
                        style={{
                            width: `${width}px`,
                            height: `${height}px`,
                            left: `${x}px`,
                            top: `${y}px`,
                        }}
                    />
                );
            })}
        </>
    );
};

// eslint-disable-next-line
const DebugDrawElements = ({
    scene,
    window,
}: {
    scene: Scene;
    window: { x: number; y: number; dx: number; dy: number };
}) => {
    const boundingBoxes = [];

    for (const element of scene.elements) {
        if (element.type === "bounding_box") {
            boundingBoxes.push(element);
        }

        if (element.type === "conditional_bounding_box") {
            for (const nestedElement of element.elements) {
                if (nestedElement.type === "bounding_box") {
                    boundingBoxes.push(nestedElement);
                }
            }
        }
    }

    return (
        <>
            {boundingBoxes.map((boundingBox, index) => {
                const [x, y] = [
                    boundingBox.x * window.dx,
                    boundingBox.y * window.dy,
                ];
                const [width, height] = [
                    (boundingBox.x2 - boundingBox.x) * window.dx,
                    (boundingBox.y2 - boundingBox.y) * window.dy,
                ];

                return (
                    <div
                        key={index}
                        style={{
                            border: `1px solid ${boundingBox.secret ? "blue" : "red"}`,
                            position: `absolute`,
                            width: `${width}px`,
                            height: `${height}px`,
                            left: `${x}px`,
                            top: `${y}px`,
                        }}
                    />
                );
            })}
        </>
    );
};
