import { useCallback, useEffect } from "react";
import { GlobalState, useGlobalState } from "../../state/GlobalState";
import styles from "#styles/popup/Save.module.css";
import { useKeyDown, useSelectedIndex } from "engine/src/system/Keyboard";
import { join } from "engine/src/system/Styles";
import {
    generateLoadScene,
    generateSavableState,
    saveCustomGame,
} from "engine/src/system/SaveSystem";

export const SaveGame = () => {
    const { playerState, gameState, phoneState, settingsState, coreState } =
        useGlobalState();

    const [, setPopup] = coreState.popup;
    const [keybinds] = settingsState.keybinds;

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        2,
        keybinds.General.Left,
        keybinds.General.Right
    );

    const save = () => {
        const state = generateSavableState();
        state.coreState.scene = generateLoadScene("home/room");

        saveCustomGame(state);

        returnToTitle();
    };

    const returnToTitle = useCallback(() => {
        GlobalState.getInstance().resetState(
            coreState,
            playerState,
            gameState,
            phoneState,
            settingsState
        );
        setPopup("titleScreen");
        // eslint-disable-next-line
    }, [coreState, playerState, phoneState]);

    useKeyDown(
        keybinds.General.Select,
        () => {
            selectedIndex === 0 ? save() : returnToTitle();
        },
        selectedIndex === -1
    );

    useEffect(() => {
        setSelectedIndex(-1);
    }, [setSelectedIndex]);

    return (
        <div className={join(styles, "endgame-save")}>
            <section>
                <h1>Thanks for playing!</h1>
                <p>
                    If you would like to access your saved documents, or access
                    any minigames or activities, make sure to save your game!
                </p>
                <div>
                    <button
                        className={
                            selectedIndex === 0 ? join(styles, "selected") : ""
                        }
                        onClick={save}
                    >
                        Save
                    </button>
                    <button
                        className={
                            selectedIndex === 1 ? join(styles, "selected") : ""
                        }
                        onClick={returnToTitle}
                    >
                        Don't Save
                    </button>
                </div>
            </section>
        </div>
    );
};
