import { Fragment, useEffect, useRef, useState } from "react";
import { useGlobalState } from "../../state/GlobalState";
import { join } from "engine/src/system/Styles";
import { LoadDialog } from "engine/src/system/DataLoader";

import styles from "#styles/popup/Controls.module.css";
import activityStyles from "#styles/popup/Activity.module.css";
import documentStyles from "#styles/popup/document.module.css";
import Flags from "engine/src/system/Flags";
import {
    humanReadableKey,
    KeyEvent,
    resetKeybind,
    resetKeybinds,
    setKeybind,
} from "engine/src/system/Keyboard";
import { ParticipantSettings } from "../../system/ParticipantSettings";

const Controls = () => {
    const { coreState, settingsState } = useGlobalState();

    const [popup, setPopup] = coreState.popup;
    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    const [editingKeybind, setEditing] = useState<[string, string] | null>(
        null
    );

    const topRef = useRef<HTMLDivElement | null>(null);
    const editRef = useRef<HTMLDivElement | null>(null);

    const onClose = () => {
        setPopup(null);

        if (!Flags.checkFlag("seen_controls")) {
            coreState.transitioning[1](true);
            setTimeout(() => {
                LoadDialog("home/opening/1a").then((dialog) => {
                    coreState.dialog[1](dialog);
                    coreState.transitioning[1](false);
                });
            }, 1000);
        }
    };

    useEffect(() => {
        if (editingKeybind === null) {
            topRef.current?.focus();
        } else {
            editRef.current?.focus();
        }
    }, [popup, editingKeybind]);

    const onKeyDown = (event: KeyboardEvent) => {
        if (popup !== "controls" || event.code === "Tab") return;
        if (editingKeybind === null) {
            if (event.code === "Escape") onClose();
            return;
        }

        if (document.activeElement !== editRef.current) {
            if (event.code === "Enter" || event.code === "Escape") {
                setEditing(null);
            }
            return;
        }

        setKeybind<ParticipantSettings>(
            settingsState,
            editingKeybind,
            event.code
        );
    };

    useEffect(() => {
        window.addEventListener(KeyEvent.KeyPress, onKeyDown, false);

        return () => {
            window.removeEventListener(KeyEvent.KeyPress, onKeyDown, false);
        };
    });

    return (
        <div className={join(documentStyles, "document-wrapper")}>
            <div ref={topRef} tabIndex={0}></div>
            <div className={join(styles, "controls-page")}>
                {editingKeybind === null ? (
                    <>
                        <h1>Controls</h1>
                        <span className={join(styles, "controls-description")}>
                            This game is entirely playable with a mouse or
                            keyboard, the keyboard controls are listed below.
                        </span>
                        <span className={join(styles, "controls-description")}>
                            You can view this again at any time in the settings
                            app.
                        </span>

                        {participantSettings.EnableKeyRebinding && (
                            <button
                                className={join(styles, "key", "global-reset")}
                                onClick={() => {
                                    resetKeybinds(settingsState);
                                }}
                            >
                                Reset controls to default
                            </button>
                        )}

                        {Object.entries(keybinds).map(([header, content]) => {
                            if (header === "Combo")
                                return <Fragment key={header}></Fragment>;

                            return (
                                <Fragment key={header}>
                                    <h2>{header.replaceAll("_", " ")}</h2>
                                    <div className={join(styles, "list")}>
                                        {Object.entries(content).map(
                                            ([subHeader, value]) => {
                                                return keyRow(
                                                    participantSettings.EnableKeyRebinding,
                                                    subHeader,
                                                    value,
                                                    () =>
                                                        setEditing([
                                                            header,
                                                            subHeader,
                                                        ]),
                                                    () =>
                                                        resetKeybind(
                                                            settingsState,
                                                            [header, subHeader]
                                                        )
                                                );
                                            }
                                        )}
                                    </div>
                                </Fragment>
                            );
                        })}
                        <div
                            className={join(
                                activityStyles,
                                "activity-controls"
                            )}
                        >
                            <button onClick={onClose}>Close</button>
                        </div>
                    </>
                ) : (
                    <>
                        <h1>Change Keybind</h1>
                        <span className={join(styles, "controls-description")}>
                            Editing keybind{" "}
                            {editingKeybind[1].replaceAll("_", " ")} for{" "}
                            {editingKeybind[0].replaceAll("_", " ")}
                        </span>
                        <span className={join(styles, "controls-description")}>
                            Press a new key to add it. Press a current keybind
                            to remove it.
                        </span>
                        <span className={join(styles, "controls-description")}>
                            The first key listed will be used for hints in
                            dialog.
                        </span>

                        <div
                            className={join(styles, "list-editing")}
                            tabIndex={0}
                            ref={editRef}
                        >
                            <span>
                                {keybinds[editingKeybind[0]][
                                    editingKeybind[1]
                                ].map((key) => {
                                    return (
                                        <button
                                            key={key}
                                            className={join(
                                                styles,
                                                "key",
                                                "editing"
                                            )}
                                            tabIndex={-1}
                                        >
                                            <div>{humanReadableKey(key)}</div>
                                        </button>
                                    );
                                })}
                            </span>
                        </div>

                        <div
                            className={join(
                                activityStyles,
                                "activity-controls"
                            )}
                        >
                            <button onClick={() => setEditing(null)}>
                                Close
                            </button>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
};

function keyRow(
    rebindingEnabled: boolean,
    name: string,
    keys: string[],
    setEditing: () => void,
    reset: () => void
) {
    return (
        <span key={name}>
            <p>{name.replaceAll("_", " ")}</p>
            <div>
                <button
                    className={join(
                        styles,
                        "key",
                        rebindingEnabled ? "" : "no-hover"
                    )}
                    onClick={rebindingEnabled ? setEditing : () => {}}
                >
                    {keys.map((key) => {
                        return <div key={key}>{humanReadableKey(key)}</div>;
                    })}
                </button>
                {rebindingEnabled && (
                    <button className={join(styles, `reset`)} onClick={reset}>
                        &#8634;
                        <p className={join(styles, `tooltip`)}>
                            reset to default
                        </p>
                    </button>
                )}
            </div>
        </span>
    );
}

export default Controls;
