type DialogFragment =
    | {
          type: "br";
      }
    | {
          type: "string";
          text: string;
      }
    | {
          type: "word";
          word: string;
          title: string;
          definition: string;
          index: number;
      };

export const generateDialog = (message: string, seenWords: string[], dictionary: Record<string, DictionaryWords>, newWordCallback: (word: string) => void) => {
    const messageWordsArray = message.split(" ");
    const cleanWordsArray = messageWordsArray.map((w) =>
        w.toLowerCase().replace(/[^a-z]/gi, "")
    );
    const usedIndices = new Set<number>();
    const duplicateDefsSet = new Set<string>();

    let currentString = "";
    let numHighlighted = 0;
    const outputDialog: DialogFragment[] = [];

    let i = 0;
    while (i < messageWordsArray.length) {
        let matched = false;

        for (const dictionaryKey of Object.keys(dictionary)) {
            if (seenWords.includes(dictionaryKey)) continue;
            const dictionaryEntry = dictionary[dictionaryKey];
            const entryWords = dictionaryEntry.words.map((w) =>
                w.toLowerCase().replace(/[^a-z]/gi, "")
            );
            const entryLength = entryWords.length;

            if (i + entryLength > messageWordsArray.length) continue;
            // eslint-disable-next-line
            if (entryWords.some((_, j) => usedIndices.has(i + j))) continue;

            const windowWords = cleanWordsArray.slice(i, i + entryLength);
            const matches = entryWords.every((dictWord, j) => {
                if (dictWord === windowWords[j]) return true;

                if (dictionaryEntry.plural) {
                    if (windowWords[j] === dictWord + "s") return true;
                }

                return false;
            });

            if (matches) {
                const key = entryWords.join(" ");
                for (let j = 0; j < entryLength; j++) usedIndices.add(i + j);
                if (duplicateDefsSet.has(key)) break;

                const originalPhrase = messageWordsArray
                    .slice(i, i + entryLength)
                    .join(" ");

                outputDialog.push({
                    type: "string",
                    text: dialogClean(currentString) + " ",
                });
                currentString = "";

                outputDialog.push({
                    type: "word",
                    word: originalPhrase,
                    title: dictionaryEntry.words.join(" "),
                    definition: dialogClean(dictionaryEntry.definition),
                    index: numHighlighted,
                });
                numHighlighted += 1;

                duplicateDefsSet.add(key);

                newWordCallback(dictionaryKey);
                i += entryLength;
                matched = true;
                break;
            }
        }

        if (!matched) {
            const parts = messageWordsArray[i].split("<br>");
            // eslint-disable-next-line
            parts.forEach((part, index) => {
                currentString = `${currentString} ${part}`;
                if (parts.length !== 1 && index < parts.length - 1) {
                    if (currentString !== " ") {
                        outputDialog.push({
                            type: "string",
                            text: dialogClean(currentString) + " ",
                        });
                    }
                    outputDialog.push({ type: "br" });
                    currentString = "";
                }
            });
            i++;

            if (i === messageWordsArray.length) {
                outputDialog.push({
                    type: "string",
                    text: dialogClean(currentString),
                });
            }
        }
    }

    return {
        numHighlighted,
        dialog: outputDialog,
    };
};

const getSeenWords = (message: string, seenWords: Record<string, number>, dictionary: Record<string, DictionaryWords>) => {
    const messageWordsArray = message.split(" ");
    const cleanWordsArray = messageWordsArray.map((w) =>
        w.toLowerCase().replace(/[^a-z]/gi, "")
    );
    const newSeenWords = structuredClone(seenWords);
    const usedIndices = new Set<number>();

    let i = 0;
    while (i < messageWordsArray.length) {
        let matched = false;

        for (const dictionaryKey of Object.keys(dictionary)) {
            const dictionaryEntry = dictionary[dictionaryKey];
            const entryWords = dictionaryEntry.words.map((w) =>
                w.toLowerCase().replace(/[^a-z]/gi, "")
            );
            const entryLength = entryWords.length;

            if (i + entryLength > messageWordsArray.length) continue;
            // eslint-disable-next-line
            if (entryWords.some((_, j) => usedIndices.has(i + j))) continue;

            const windowWords = cleanWordsArray.slice(i, i + entryLength);
            const matches = entryWords.every(
                (word, j) => word === windowWords[j]
            );

            if (matches) {
                const key = entryWords.join(" ");
                if (!newSeenWords[key]) {
                    newSeenWords[key] = 0;
                }
                newSeenWords[key]++;
                for (let j = 0; j < entryLength; j++) {
                    usedIndices.add(i + j);
                }
                i += entryLength;
                matched = true;
                break;
            }
        }

        if (!matched) {
            // eslint-disable-next-line
            i++;
        }
    }

    return newSeenWords;
};

const createHistoryDialog = (
    dialog: MessageDialog | MessageActionDialog | OptionDialog,
    name?: string,
    index?: number
): DialogHistoryDialog => {
    return {
        message: dialog.message,
        source: dialog.source,
        dialog_name: name,
        dialog_index: index,
    };
};

/**
 * This component is responsible for rendering basic digital_dialog at the bottom of the screen.
 */
const DialogComponent = ({
    setPhoneOpen,
    pitch,
    character,
    dictionary,
    newWordCallback,
    additionalComponent,
    dialogStyleOverride,
}: {
    setPhoneOpen: ReactSetter<boolean>;
    pitch: 'high-pitch' | 'low-pitch',
    character: string,
    dictionary: Record<string, DictionaryWords>,
    newWordCallback: (word: string) => void,
    additionalComponent: (dialog: Dialog["dialog"][0]) => [React.ReactNode, boolean],
    dialogStyleOverride: any,
}) => {
    // Get the digital_dialog and scene state from the global context
    const {coreState, settingsState} = useBaseGlobalState();

    const [dialog, setDialog] = coreState.dialog;
    const [loadingDialog] = coreState.loadingDialog;
    const [scene] = coreState.scene;
    const [dialogIndex, setDialogIndex] = coreState.dialogIndex;
    const [popup] = coreState.popup;
    const [, setDialogHistory] = coreState.dialogHistory;

    const [participantSettings] = settingsState.participantSettings;

    const [allowContinue, setAllowContinue] = useState(false);
    const [audio, setAudio] = useState<AudioBufferSourceNode | null>(null);
    const audioRef = useRef<AudioBufferSourceNode | null>(null);
    const [currentCharacter, setCurrentCharacter] = useState<string | null>(
        null
    );
    const [currentDialog, setCurrentDialog] = useState<
        MessageDialog | MessageActionDialog | OptionDialog | null
    >(null);

    const [playerVisible, setPlayerVisible] = useState<boolean>(false);

    const [seenWords, setSeenWords] = useState<Record<string, number>>({});

    const updateCurrentDialog = useCallback(
        (index: number) => {
            const newDialog = dialog?.dialog[index] ?? null;

            if (newDialog === null || newDialog.type !== "conditional") {
                setCurrentDialog(newDialog);
                return;
            }

            for (const flag of newDialog.conditions) {
                if (!Flags.checkFlag(flag)) {
                    setCurrentDialog(newDialog.falseDialog);
                    return;
                }
            }
            setCurrentDialog(newDialog.trueDialog);
        },
        [dialog]
    );

    useEffect(() => {
        audioRef.current = audio;
    });

    useEffect(() => {
        setDialogIndex(0);
        updateCurrentDialog(0);

        if (dialog !== null) {
            setPhoneOpen(false);
        } else {
            setSeenWords({});
        }
    }, [
        dialog,
        setPhoneOpen,
        setSeenWords,
        setDialogIndex,
        updateCurrentDialog,
    ]);

    useEffect(() => {
        if (dialogIndex !== 0) {
            updateCurrentDialog(dialogIndex);
        }
    }, [dialogIndex, updateCurrentDialog]);

    useEffect(() => {
        StopAllAudio("voice-lines");

        if (!nextIsDialog && dialog && dialogIndex >= dialog.dialog.length) {
            setDialog(null);
        }

        if (dialog && dialog.dialog[dialogIndex]) {
            setSeenWords(seen => {
                return getSeenWords(dialog.dialog[dialogIndex].message, seen, dictionary)
            });
        }
    }, [dialog, dialogIndex, setDialog, setSeenWords]);

    useEffect(() => {
        if (dialog) {
            setAllowContinue(false);

            if (currentDialog) {
                setDialogHistory((dialogs) => [
                    ...dialogs,
                    createHistoryDialog(
                        currentDialog,
                        dialog.name,
                        dialogIndex
                    ),
                ]);
            }
        } else if (!IsActionQueued("open_dialog")) {
            if (!nextIsDialog) {
                setCurrentCharacter(null);
                setPlayerVisible(false);
            }
        }
        // eslint-disable-next-line
    }, [currentDialog]);

    useEffect(() => {
        if (dialog) {
            if (currentDialog 
                && popup === null
                && !IsActionQueued("open_dialog")
            ) {
                PlayVoiceLine(
                    dialog.name,
                    dialogIndex,
                    currentDialog.source,
                    pitch,
                ).then((audio) => {
                    if (audio) {
                        setAudio(audio);
                        audio.addEventListener("ended", () => setAudio(null));
                    }
                    setTimeout(
                        () => setAllowContinue(true),
                        participantSettings.DebugEnabled ? 0 : 500
                    );
                });
                // update character
                if (
                    currentDialog.setCharacter !== undefined &&
                    currentDialog.setCharacter !== null
                ) {
                    setCurrentCharacter(currentDialog.setCharacter);
                } else if (
                    Object.keys(characterImages).includes(currentDialog.source)
                ) {
                    setCurrentCharacter(currentDialog.source);
                }
                if (currentDialog.setCharacter !== "") setPlayerVisible(true);
            }
        }
        // eslint-disable-next-line
    }, [currentDialog, audioRef, popup, participantSettings]);

    useEffect(() => {
        setDialogHistory([]);
    }, [scene, setDialogHistory]);

    useEffect(() => {
        if (popup !== null && audio) {
            StopAllAudio("voice-lines");
        }
    }, [popup, audio]);

    // If there is currently no dialog to display, don't render anything
    if (
        !dialog ||
        dialogIndex >= dialog.dialog.length ||
        popup !== null ||
        loadingDialog
    ) {
        return (
            <>
                {loadingDialog && (
                    <div className={joinWithOverride(styles, dialogStyleOverride, "loading-dialog-scene")}></div>
                )}
                <DialogPlayer
                    character={character}
                    visible={playerVisible && popup === null}
                    dialogStyleOverride={dialogStyleOverride}
                />
                <DialogCharacter visible={null} dialogStyleOverride={dialogStyleOverride} />
            </>
        );
    }
    // Get the data for the current digital_dialog.
    const dialogName = dialog.name;
    const noSource = currentDialog?.source === "";

    return (
        <>
            <DialogPlayer visible={!noSource} character={character} dialogStyleOverride={dialogStyleOverride} />
            <DialogCharacter visible={currentCharacter} dialogStyleOverride={dialogStyleOverride} />
            {currentDialog !== null && <DialogContent
                dialog={currentDialog}
                allowContinue={allowContinue}
                dialogName={dialogName}
                seenWords={Object.keys(seenWords).filter(
                    (word: string) => seenWords[word] > 1
                )}
                newWordCallback={newWordCallback}
                dictionary={dictionary}
                additionalComponent={additionalComponent}
                dialogStyleOverride={dialogStyleOverride}
            />}
        </>
    );
};

export function DialogHtml({
    message,
    seenWords,
    enableInput,
    dictionary,
    newWordCallback,
    dialogStyleOverride,
}: {
    message: string;
    seenWords: string[];
    enableInput: boolean;
    dictionary: Record<string, DictionaryWords>,
    newWordCallback: (word: string) => void,
    dialogStyleOverride: any,
}) {
    const {settingsState} = useBaseGlobalState();
    const [keybinds] = settingsState.keybinds;

    const [data, setData] = useState<{
        numHighlighted: number;
        dialog: DialogFragment[];
    }>({ numHighlighted: 0, dialog: [] });

    useEffect(() => {
        setData(generateDialog(message, seenWords, dictionary, newWordCallback));
    }, [message, seenWords]);

    const [selectedHighlight, setSelected] = useSelectedIndex(
        data.numHighlighted,
        keybinds.General.Left,
        keybinds.General.Right,
        !enableInput
    );

    useKeyDown(keybinds.General.Select, () => setSelected(-1));

    useEffect(() => {
        if (!enableInput) setSelected(-1);
    }, [enableInput, setSelected]);

    return (
        <p>
            {data.dialog.map((fragment, index) => {
                if (fragment.type === "br") {
                    return <br key={index} />;
                }
                if (fragment.type === "string") {
                    return <Fragment key={index}>{fragment.text}</Fragment>;
                }
                return (
                    <strong
                        className={
                            fragment.index === selectedHighlight
                                ? joinWithOverride(styles, dialogStyleOverride, "selected")
                                : ""
                        }
                        key={index}
                    >
                        {fragment.word}
                        <span className={joinWithOverride(styles, dialogStyleOverride, "tooltiptext")}>
                            <span className={joinWithOverride(styles, dialogStyleOverride, "word-title")}>
                                {fragment.title} Definition:{" "}
                            </span>
                            <br />
                            {fragment.definition}
                        </span>
                    </strong>
                );
            })}
        </p>
    );
}

const DialogText = ({
    currentDialog,
    seenWords,
    dictionary,
    newWordCallback,
    additionalComponent,
    dialogStyleOverride,
}: {
    currentDialog: Dialog["dialog"][0];
    seenWords: string[];
    dictionary: Record<string, DictionaryWords>,
    newWordCallback: (word: string) => void,
    additionalComponent: (dialog: Dialog["dialog"][0]) => [React.ReactNode, boolean],
    dialogStyleOverride: any,
}) => {
    return (
        <div className={joinWithOverride(styles, dialogStyleOverride, "dialog-text")}>
            <b>{dialogClean(currentDialog.source)}</b>
            <DialogHtml
                message={currentDialog.message}
                seenWords={seenWords}
                enableInput={true}
                dictionary={dictionary}
                newWordCallback={newWordCallback}
                dialogStyleOverride={dialogStyleOverride}
            />
            {
                additionalComponent(currentDialog)
            }
        </div>
    );
};

const DialogPlayer = ({ visible, character, dialogStyleOverride }: { visible: boolean, character: string, dialogStyleOverride: any }) => {

    return (
        <div
            className={joinWithOverride(
                styles,
                dialogStyleOverride,
                `dialog-player-view`,
                visible ? "show" : ""
            )}
        >
            <img
                src={character}
                draggable={false}
                alt="player character"
            />
        </div>
    );
};

const DialogCharacter = ({ visible, dialogStyleOverride }: { visible: string | null, dialogStyleOverride: any }) => {
    return (
        <div>
            {Object.keys(characterImages).map((name) => (
                <div
                    className={joinWithOverride(
                        styles,
                        dialogStyleOverride,
                        `dialog-character-view`,
                        visible === name ? "show" : ""
                    )}
                    key={name}
                    draggable={false}
                    onDragStart={(e) => {
                        e.preventDefault();
                    }}
                >
                    <img
                        src={characterImages[name]}
                        draggable={false}
                        alt={name}
                    />
                </div>
            ))}
        </div>
    );
};

const DialogContent = ({
    dialog,
    allowContinue,
    dialogName,
    seenWords,
    dictionary,
    newWordCallback,
    additionalComponent,
    dialogStyleOverride,
}: {
    dialog: MessageDialog | MessageActionDialog | OptionDialog;
    allowContinue: boolean;
    dialogName: string;
    seenWords: string[];
    dictionary: Record<string, DictionaryWords>,
    newWordCallback: (word: string) => void,
    additionalComponent: (dialog: Dialog["dialog"][0]) => [React.ReactNode, boolean],
    dialogStyleOverride: any,
}) => {
    switch (dialog.type) {
        case "message":
        case "action":
            return (
                <BasicDialogComponent
                    currentDialog={dialog}
                    allowContinue={allowContinue}
                    seenWords={seenWords}
                    newWordCallback={newWordCallback}
                    dictionary={dictionary}
                    additionalComponent={additionalComponent}
                    dialogStyleOverride={dialogStyleOverride}
                />
            );
        case "option":
            return (
                <OptionDialogComponent
                    currentDialog={dialog}
                    allowContinue={allowContinue}
                    seenWords={seenWords}
                    newWordCallback={newWordCallback}
                    dictionary={dictionary}
                    additionalComponent={additionalComponent}
                    dialogStyleOverride={dialogStyleOverride}
                />
            );
    }
};

const BasicDialogComponent = ({
    currentDialog,
    allowContinue,
    seenWords,
    dictionary,
    newWordCallback,
    additionalComponent,
    dialogStyleOverride,
}: {
    currentDialog: MessageDialog | MessageActionDialog;
    allowContinue: boolean;
    seenWords: string[];
    dictionary: Record<string, DictionaryWords>,
    newWordCallback: (word: string) => void,
    additionalComponent: (dialog: Dialog["dialog"][0]) => [React.ReactNode, boolean],
    dialogStyleOverride: any,
}) => {
    const {coreState, settingsState} = useBaseGlobalState();

    const [keybinds] = settingsState.keybinds;

    const [dialogIndex, setDialogIndex] = coreState.dialogIndex;
    
    const additionalComponentBlocks = additionalComponent(currentDialog)[1];
    const [dialog] = coreState.dialog;
    const [dialogHistoryOpen] = coreState.dialogHistoryOpen;
    const [transitioning] = coreState.transitioning;

    const advanceDialog = useCallback(() => {
        if (!dialog) return;

        SendDialogEvents(dialog, coreState.appEnabled[1], dialogIndex);
        PlayAudio("dialog.mp3", "sounds");

        if (currentDialog.type === "action") {
            HandleActions(currentDialog.actions);

            nextIsDialog =
                currentDialog.actions.filter(
                    (action) => action.type === "open_dialog"
                ).length > 0;
        } else {
            nextIsDialog = false;
        }

        if (nextIsDialog) {
            setDialogIndex(0);
        } else {
            setDialogIndex((val) => val + 1);
        }
    }, [
        currentDialog,
        dialog,
        dialogIndex,
        coreState.appEnabled,
        setDialogIndex,
    ]);

    useKeyDown(
        keybinds.General.Select,
        advanceDialog,
        dialogHistoryOpen || transitioning || additionalComponentBlocks
    );


    if (!dialog) return <></>;

    return (
        <div
            className={joinWithOverride(
                styles,
                dialogStyleOverride,
                `dialog`,
                currentDialog.source === "%player%" ? "player" : "",
                allowContinue ? "enabled" : "disabled"
            )}
            onClick={(e: MouseEvent) => {
                if (!allowContinue) return;
                if ((e.target as HTMLElement).tagName === "A") return;

                advanceDialog();
            }}
        >
            <div className={joinWithOverride(styles, dialogStyleOverride, "clickable-dialog-scene")}></div>
            <DialogText
                currentDialog={currentDialog}
                seenWords={seenWords}
                newWordCallback={newWordCallback}
                dictionary={dictionary}
                additionalComponent={additionalComponent}
                dialogStyleOverride={dialogStyleOverride}
            />
        </div>
    )
};

const OptionDialogComponent = ({
    currentDialog,
    allowContinue,
    seenWords,
    dictionary,
    newWordCallback,
    additionalComponent,
    dialogStyleOverride,
}: {
    currentDialog: OptionDialog;
    allowContinue: boolean;
    seenWords: string[];
    dictionary: Record<string, DictionaryWords>,
    newWordCallback: (word: string) => void,
    additionalComponent: (dialog: Dialog["dialog"][0]) => [React.ReactNode, boolean],
    dialogStyleOverride: any,
}) => {
    const { coreState, settingsState} = useBaseGlobalState();
    
    
    const [dialogIndex, setDialogIndex] = coreState.dialogIndex;
    const [, setDialogHistory] = coreState.dialogHistory;
    const [dialog] = coreState.dialog;
    const [dialogHistoryOpen] = coreState.dialogHistoryOpen;
    
    const [keybinds] = settingsState.keybinds;

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        currentDialog.options.length,
        [...keybinds.General.Up, ...keybinds.General.Right],
        [...keybinds.General.Down, ...keybinds.General.Left],
        dialogHistoryOpen
    );

    const playerName = Registers.getTextRegister("player");

    const chooseOption = useCallback(
        (index: number) => {
            if (!dialog || index === -1) return;

            const option = currentDialog.options[index];

            HandleActions(option.actions);
            SendDialogEvents(dialog, coreState.appEnabled[1], dialogIndex);
            SendDialogOptionsSelected(
                dialog,
                coreState.appEnabled[1],
                dialogIndex,
                index
            );

            PlayAudio("dialog.mp3", "sounds");

            nextIsDialog =
                option.actions.filter((action) => action.type === "open_dialog")
                    .length > 0;

            if (nextIsDialog) {
                setDialogIndex(0);
            } else {
                setDialogIndex((val) => val + 1);
            }

            const chosenOptionDialog = {
                type: "message",
                source: "%player%",
                message: "OPTION: " + option.text,
            } as MessageDialog;

            setDialogHistory((dialogs) => [
                ...dialogs,
                createHistoryDialog(
                    chosenOptionDialog,
                    dialog.name,
                    dialogIndex
                ),
            ]);
        },
        [
            currentDialog,
            dialog,
            dialogIndex,
            coreState.appEnabled,
            setDialogHistory,
            setDialogIndex,
        ]
    );

    useKeyDown(
        keybinds.General.Select,
        useCallback(() => {
            chooseOption(selectedIndex);
            setSelectedIndex(-1);
        }, [chooseOption, selectedIndex, setSelectedIndex]),
        dialogHistoryOpen
    );

    if (!dialog) return <></>;

    return (
        <div
            className={joinWithOverride(
                styles,
                dialogStyleOverride,
                `dialog`,
                `dialog-option-box`,
                currentDialog.source === "%player%" ? "player" : "",
                currentDialog.option_location === "beside" ? "beside" : ""
            )}
        >
            <DialogText
                dictionary={dictionary}
                newWordCallback={newWordCallback}
                currentDialog={currentDialog}
                seenWords={seenWords}
                additionalComponent={additionalComponent}
                dialogStyleOverride={dialogStyleOverride}
            />
            <div
                className={joinWithOverride(
                    styles,
                    dialogStyleOverride,
                    `dialog-option-holder`,
                    allowContinue ? "" : "disabled"
                )}
            >
                {currentDialog.options.map((option, index) => (
                    <div
                        className={joinWithOverride(
                            styles,
                            dialogStyleOverride,
                            "dialog-option",
                            index === selectedIndex ? "selected-option" : "",
                            option.flag && Flags.checkFlag(option.flag)
                                ? "visited"
                                : ""
                        )}
                        key={`${index}`}
                        onClick={(e: MouseEvent) => {
                            if (!allowContinue) return;
                            if ((e.target as HTMLElement).tagName === "A")
                                return;

                            if (option.flag) {
                                Flags.setOrUnsetFlag([
                                    {
                                        flag_action: "give",
                                        flag_name: option.flag,
                                    },
                                ]);
                            }

                            setTimeout(() => {
                                chooseOption(index);
                            }, 10);
                        }}
                    >
                        <b>{playerName}</b>
                        <p>{dialogClean(option.text)}</p>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default DialogComponent;
