import React from "react";
import styles from "#styles/activities/renderers/quoteblock.module.css";
import { join } from "engine/src/system/Styles";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const QuoteBlockActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "quoteblock"
> = (element, playerData, updateState) => {
    const innerhtml = {
        __html: element.html,
    };

    return {
        appView: (
            <React.Fragment key={element.html}>
                <div
                    className={join(styles, "quoteblock")}
                    dangerouslySetInnerHTML={innerhtml}
                />
            </React.Fragment>
        ),
        printView: (
            <React.Fragment key={element.html}>
                <div
                    className={join(styles, "quoteblock")}
                    dangerouslySetInnerHTML={innerhtml}
                />
            </React.Fragment>
        ),
    };
};

export const DefaultQuoteBlockActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "quoteblock"
> = () => {
    return {
        type: "quoteblock",
        complete: true,
    };
};
