import { BaseGlobalState } from "engine/src/state/GlobalState";
import { RegisterActionHandler } from "engine/src/system/ActionExecutor";
import Flags from "engine/src/system/Flags";
import { SendNotification } from "engine/src/system/Notification";
import Registers from "engine/src/system/Registers";
import { DocumentAction } from "engine/src/types/Action";
import { GlobalState } from "../state/GlobalState";
import {
    AddTodoItemAction,
    BadgeAction,
    BumperStickerAction,
    ChangeChapterAction,
    CompleteTodoItemAction,
    FailTodoItemAction,
    OpenMinigameAction,
    OpenZoomAction,
    SendEmailAction,
    SendTextAction,
} from "../types/Action";
import { SendTodoList } from "./BackendSystem";
import ChapterChanger from "./ChapterChanger";
import { LoadEmail, LoadTextMessage, LoadZoomChat } from "./DataLoader";
import { Badges, BumperStickers, Documents, Minigames } from "./Unlockables";

export const RegisterCustomActions = () => {
    RegisterActionHandler<AddTodoItemAction>("add_todo_item", (action) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const currentChapter = Registers.getRegister("chapter");
        const playerState = GlobalState.getInstance().playerState[0];
        const setTodoList = playerState.todoList[1];
        setTodoList((val) => {
            let list = structuredClone(val);

            list[action.list] = [
                ...list[action.list],
                {
                    item: action.item,
                    complete: false,
                    failed: false,
                    chapter: currentChapter,
                },
            ];

            SendTodoList(
                action.item,
                coreState.appEnabled[1],
                action.list,
                false
            );
            return list;
        });

        if (Flags.checkFlag("todo_unlocked") && action.list === "story")
            SendNotification({
                type: "regular",
                title: "New Todo Item",
                description: action.item,
                sound: "hint",
            });
    });

    RegisterActionHandler<CompleteTodoItemAction>(
        "complete_todo_item",
        (action) => {
            const coreState = BaseGlobalState.getBaseInstance().coreState[0];
            const playerState = GlobalState.getInstance().playerState[0];
            const setTodoList = playerState.todoList[1];
            setTodoList((list) => {
                list[action.list as keyof typeof list].forEach(
                    (item, index) => {
                        list[action.list as keyof typeof list][index].complete =
                            item.item === action.item ? true : item.complete;
                    }
                );
                SendTodoList(
                    action.item,
                    coreState.appEnabled[1],
                    action.list,
                    true
                );
                return list;
            });
        }
    );

    RegisterActionHandler<FailTodoItemAction>("fail_todo_item", (action) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const playerState = GlobalState.getInstance().playerState[0];
        const setTodoList = playerState.todoList[1];
        setTodoList((list) => {
            list[action.list as keyof typeof list].forEach((item, index) => {
                if (item.item === action.item) {
                    list[action.list as keyof typeof list][index].failed = true;
                    list[action.list as keyof typeof list][index].complete =
                        false;
                }
            });
            SendTodoList(
                action.item,
                coreState.appEnabled[1],
                action.list,
                false
            );
            return list;
        });
    });

    RegisterActionHandler<OpenZoomAction>("zoom", (action) => {
        const coreState = BaseGlobalState.getBaseInstance().coreState[0];
        const [, setPopup] = coreState.popup;
        const gameState = GlobalState.getInstance().gameState[0];
        LoadZoomChat(action.presentation).then((zoom) => {
            gameState.zoom[1](zoom);
            setPopup("zoom");
        });
    });

    RegisterActionHandler<ChangeChapterAction>("set_chapter", (action) => {
        BumperStickers.unlock(action.bumper_sticker);
        ChapterChanger.setChapter(action.new_chapter);
    });

    RegisterActionHandler<BadgeAction>("badge", (action) => {
        Badges.unlock(action.badge);
    });

    RegisterActionHandler<BumperStickerAction>("sticker", (action) => {
        BumperStickers.unlock(action.sticker);
    });

    RegisterActionHandler<SendTextAction>("send_text", (action) => {
        const phoneState = GlobalState.getInstance().phoneState[0];
        const [, setLoadedTextConversations] =
            phoneState.loadedTextConversations;
        const [, setCurrentTextConversation] =
            phoneState.currentTextConversation;
        // Load the dialog
        LoadTextMessage(action.text).then((dialog) => {
            // Edit the state
            setLoadedTextConversations((val) => {
                let newVal = structuredClone(val);
                let existingConvo = -1;
                newVal = val.map((convo, index) => {
                    if (convo.dialog.from === dialog.from) {
                        convo.dialog.messages = [
                            ...convo.dialog.messages,
                            ...dialog.messages,
                        ];
                        existingConvo = index;
                    }

                    return convo;
                });

                if (existingConvo === -1) {
                    newVal.push({ dialog: dialog, lastHandled: 0 });
                    existingConvo = newVal.length - 1;
                }

                setCurrentTextConversation(existingConvo);

                return newVal;
            });
        });
    });

    RegisterActionHandler<SendEmailAction>("send_email", (action) => {
        const phoneState = GlobalState.getInstance().phoneState[0];
        const [, setRepliedEmails] = phoneState.repliedEmails;
        const [emails, setEmails] = phoneState.emails;
        // Load the email
        Promise.all(
            action.email.map((emailFile: string) => LoadEmail(emailFile))
        ).then((newEmails) => {
            setEmails((val) => [...val, ...newEmails]);
            emails.forEach((email, index) => {
                if (email.ignoreFlag && Flags.checkFlag(email.ignoreFlag)) {
                    setRepliedEmails((val) => [...val, index]);
                }
            });
        });
    });

    RegisterActionHandler<OpenMinigameAction>("minigame", (action) => {
        Minigames.unlock(action.minigame);
    });

    RegisterActionHandler<DocumentAction>("document", (action) => {
        Documents.unlock(action.document);
    });
};
