import React from "react";
import styles from "#styles/activities/renderers/checklist_advanced.module.css";
import { join } from "engine/src/system/Styles";
import { Activities } from "../../../types/Activity";
import {
    ActivityElementPlayerData,
    AdvancedChecklistActivityPlayerData,
} from "../../../types/ActivityPlayerData";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { editState } from "../../../state/Util";
import { keyDownHandler } from "engine/src/system/Keyboard";

export const AdvancedChecklistActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "checklist_advanced"
> = (element, playerData, updateState, [_0, updateBinding, _1]) => {
    const computeCategoryStats = (
        questions: { question: string; category: string }[],
        indices: number[]
    ) => {
        const categoryMap: Record<string, number[]> = {};

        // Group scores by category
        questions.forEach((q, idx) => {
            const category = q.category;
            const score = indices[idx];

            if (!categoryMap[category]) {
                categoryMap[category] = [];
            }
            categoryMap[category].push(score);
        });

        // Compute sums + means
        const results: Record<string, { sum: number; mean: number }> = {};

        for (const category in categoryMap) {
            const scores = categoryMap[category];
            const sum = scores.reduce((a, b) => a + b, 0);
            const mean = sum / scores.length;

            results[category] = { sum, mean };
        }

        return results;
    };
    const handleChangeSelection = (index: number, localIndex: number) => {
        editState(playerData, updateState, (data) => {
            if (!data.indices) {
                data.indices = [];
            }
            data.indices[index] = localIndex;
            let complete = true;
            for (let i = 0; i < element.questions.length; i++) {
                if (data.indices[i] === undefined) {
                    complete = false;
                    break;
                }
            }
            data.complete = complete;

            updateBindings(data);

            return data;
        });
    };

    const updateBindings = (data: AdvancedChecklistActivityPlayerData) => {
        if (!data.complete) return;

        const stats = computeCategoryStats(element.questions, data.indices);

        for (const category in stats) {
            const { sum, mean } = stats[category];

            updateBinding(element, `${category}-sum`, sum.toString());
            updateBinding(element, `${category}-mean`, mean.toString());
        }
    };

    return {
        appView: (
            <React.Fragment key={element.header}>
                {element.header && (
                    <div className={join(styles, "checklist-header")}>
                        <p>{element.header}</p>
                    </div>
                )}
                <table className={join(styles, "checklist")}>
                    <tbody>
                        {element.questions.map((question, qindex) => {
                            return (
                                <tr>
                                    <td>{question.question}</td>
                                    {element.scaleTitles.map((title, i) => {
                                        return (
                                            <td
                                                className={join(
                                                    styles,
                                                    playerData.indices
                                                        ? `${
                                                              playerData
                                                                  .indices[
                                                                  qindex
                                                              ] === i
                                                          }`
                                                        : false,
                                                    `radio-container`
                                                )}
                                                key={`${question.question}-${title}`}
                                            >
                                                <input
                                                    type="radio"
                                                    id={`${qindex}-${i}`}
                                                    checked={
                                                        playerData.indices
                                                            ? playerData
                                                                  .indices[
                                                                  qindex
                                                              ] === i
                                                            : false
                                                    }
                                                    onChange={() =>
                                                        handleChangeSelection(
                                                            qindex,
                                                            i
                                                        )
                                                    }
                                                />
                                                <label
                                                    htmlFor={`${qindex}-${i}`}
                                                    tabIndex={0}
                                                    onKeyDown={keyDownHandler(
                                                        ["Enter"],
                                                        () => {
                                                            handleChangeSelection(
                                                                qindex,
                                                                i
                                                            );
                                                        }
                                                    )}
                                                >
                                                    <span>{title}</span>
                                                </label>
                                            </td>
                                        );
                                    })}
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </React.Fragment>
        ),
        printView: <></>,
    };
};

export const AdvancedDefaultChecklistActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "checklist_advanced"
> = () => ({
    type: "checklist_advanced",
    complete: false,
    indices: [],
});
