import styles from "#styles/activities/renderers/text.module.css";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { join } from "engine/src/system/Styles";
import { Activities } from "../../../types/Activity";
import { ActivityElementPlayerData } from "../../../types/ActivityPlayerData";

export const TextActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "text"
> = (element) => {
    const innerhtml = {
        __html: element.html,
    };

    return {
        appView: (
            <div
                className={join(styles, "text", element.textType)}
                key={element.html}
                dangerouslySetInnerHTML={innerhtml}
            ></div>
        ),
        printView: (
            <div className={join(styles, "container")}>
                <div
                    className={join(styles, "text", element.textType)}
                    key={element.html}
                    dangerouslySetInnerHTML={innerhtml}
                ></div>
                {element.textType === "title" && (
                    <img
                        className={join(styles, "logo")}
                        src="assets/images/elements/Logo.png"
                    />
                )}
            </div>
        ),
    };
};

export const DefaultTextActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "text"
> = () => {
    return {
        type: "text",
        complete: true,
    };
};
