import { ReactState } from "engine/src/state/GlobalState";

interface BaseUnlockableModule<T> {
    list: () => Record<string, T>;
    unlocked: (identifier: string) => boolean;
    get: (identifier: string) => T;
    unlock: (identifier: string) => boolean;
    lastUnlocked: () => T | null;
    unlockAll: (identifiers: string[]) => void;
}

type UnlockableModuleMixinSignature<T> = (identifier: string, obj: T) => void;

type UnlockableModuleMixins<T> = {
    unlockedMixin?: UnlockableModuleMixinSignature<T>;
    getMixin?: UnlockableModuleMixinSignature<T>;
    unlockMixin?: UnlockableModuleMixinSignature<T>;
    unlockAllMixin?: (identifiers: string[]) => void;
};

type UnlockableModule<T> = BaseUnlockableModule<T> & { [x: string]: Function };

const masterList: Record<string, Record<string, any>> = {};

export function createStateProvider<StateType extends Record<string, ReactState<any>>>(
    state: () => StateType,
    property: {
        [x in keyof StateType]: StateType[x][0] extends string[]
            ? string[] extends StateType[x][0]
                ? x
                : never
            : never;
    }[keyof StateType]
): () => ReactState<Array<string>> {
    return () => state()[property];
}

export function createUnlockable<T>(
    fileName: string,
    stateProvider: () => ReactState<Array<string>>,
    mixins: UnlockableModuleMixins<T> = {},
    additionalMethods: {
        [x: string]: (list: () => Record<string, T>) => Function;
    } = {}
): UnlockableModule<T> {
    fetch(`data/${fileName}.json`)
        .then((data) =>
            data
                .json()
                .then((json) => {
                    masterList[fileName] = json;
                })
                .catch((err) => console.error(err))
        )
        .catch((err) => console.error(err));

    const list = () => masterList[fileName] as Record<string, T>;

    const additionalParams: { [x: string]: Function } = {};
    Object.keys(additionalMethods).forEach(
        (key) => (additionalParams[key] = additionalMethods[key](list))
    );

    let lastUnlocked: T | null = null;

    return {
        list: list,
        unlocked: (identifier: string) => {
            const [unlocked] = stateProvider();

            if (mixins.unlockedMixin)
                mixins.unlockedMixin(identifier, list()[identifier]);

            return unlocked.includes(identifier);
        },
        get: (identifier): T => {
            if (mixins.getMixin)
                mixins.getMixin(identifier, list()[identifier]);

            return list()[identifier];
        },
        unlock: (identifier: string) => {
            const [unlocked, setUnlocked] = stateProvider();
            if (unlocked.includes(identifier)) return false;

            setUnlocked((ul) => [...ul, identifier]);
            lastUnlocked = list()[identifier];

            if (mixins.unlockMixin)
                mixins.unlockMixin(identifier, list()[identifier]);

            return true;
        },
        lastUnlocked: () => {
            return lastUnlocked;
        },
        unlockAll: (identifiers: string[]) => {
            const [, setUnlocked] = stateProvider();

            setUnlocked((ul) => [...ul, ...identifiers]);
            if (mixins.unlockAllMixin) mixins.unlockAllMixin(identifiers);
        },
        ...additionalParams,
    };
}
