import React, { createContext, useContext, useState } from "react";
import {
    BaseGlobalState,
    CoreState,
    ReactState,
    SettingsState,
    useNewSettingsState,
    useNewCoreState,
    resetSettingsState,
    useBaseGlobalState,
    getBaseGlobalState,
    resetCoreState,
} from "engine/src/state/GlobalState";
import { Activity } from "../types/Activity";
import { ActivityPlayerData } from "../types/ActivityPlayerData";
import {
    Email,
    TextDialog,
    TextMessageConversation,
    TextMessageOptions,
} from "../types/Dialog";
import { Minigame } from "../types/Minigame";
import { SlideShowData } from "../types/Zoom";
import {
    defaultParticipantSettings,
    ParticipantSettings,
} from "../system/ParticipantSettings";

/**
 * The character type
 */
export type Character = {
    image: string;
    data: string[];
};

export type TodoList = {
    story: {
        item: string;
        complete: boolean;
        failed?: boolean;
        chapter?: number;
    }[];
    optional: {
        item: string;
        complete: boolean;
        failed?: boolean;
        chapter?: number;
    }[];
};

/**
 * The player state
 */
export type PlayerState = {
    playerPitch: ReactState<"low-pitch" | "high-pitch">;
    playerPronouns: ReactState<[string, string]>;
    character: ReactState<Character>;
    todoList: ReactState<TodoList>;
    unlockedBadges: ReactState<string[]>;
    unlockedBumperStickers: ReactState<string[]>;
    unlockedDocuments: ReactState<string[]>;
    unlockedDictionary: ReactState<string[]>;
    unlockedMinigames: ReactState<string[]>;
    unlockedStrategies: ReactState<string[]>;
    activityData: ReactState<Record<string, ActivityPlayerData>>;
};

/**
 * The game state
 */
export type GameState = {
    zoom: ReactState<SlideShowData | null>;
};

/**
 * The phone state
 */
export type PhoneState = {
    textConversations: ReactState<TextMessageConversation[]>;
    loadedTextConversations: ReactState<
        { dialog: TextDialog; lastHandled: number }[]
    >;
    currentTextConversation: ReactState<number>;
    textMessageOptions: ReactState<TextMessageOptions>;
    openMessages: ReactState<{ name: string; index: number }>;
    unreadMessages: ReactState<number[]>;
    existingTextConversations: ReactState<number[]>;

    emails: ReactState<Email[]>;
    repliedEmails: ReactState<number[]>;
    replies: ReactState<string[]>;

    browserPage: ReactState<"search" | "strategy">;
    activeStrategyId: ReactState<string | null>;
};

/**
 * The global state
 */
export class GlobalState extends BaseGlobalState<
    Activity,
    Minigame,
    ParticipantSettings
> {
    // The react states
    public playerState: [PlayerState, React.Context<PlayerState>];
    public gameState: [GameState, React.Context<GameState>];
    public phoneState: [PhoneState, React.Context<PhoneState>];

    // Create a global state
    constructor(
        coreState: CoreState<Activity, Minigame>,
        playerState: PlayerState,
        gameState: GameState,
        phoneState: PhoneState,
        settingsState: SettingsState<ParticipantSettings>
    ) {
        super(coreState, settingsState);
        this.playerState = [playerState, createContext(playerState)];
        this.gameState = [gameState, createContext(gameState)];
        this.phoneState = [phoneState, createContext(phoneState)];

        GlobalState.instance = this;
    }

    public static getInstance() {
        return GlobalState.instance as GlobalState;
    }

    // Set the current player state
    public setPlayerState(current: PlayerState) {
        this.playerState[0] = current;
    }

    // Set the current game state
    public setGameState(current: GameState) {
        this.gameState[0] = current;
    }

    public resetState(
        coreState: CoreState<any, any>,
        playerState: PlayerState,
        gameState: GameState,
        phoneState: PhoneState,
        _settingsState: SettingsState<ParticipantSettings>,
        resetScene?: string
    ) {
        resetCoreState(coreState, resetScene);
        resetPlayerState(playerState);
        resetGameState(gameState);
        resetPhoneState(phoneState);
    }
    // Set the current phone state
    public setPhoneState(current: PhoneState) {
        this.phoneState[0] = current;
    }
}

export function getGlobalState(globalState?: GlobalState): {
    playerState: PlayerState;
    gameState: GameState;
    phoneState: PhoneState;
    settingsState: SettingsState<ParticipantSettings>;
    coreState: CoreState<Activity, Minigame>;
} {
    const gs = globalState ?? GlobalState.getInstance();

    return {
        playerState: gs.playerState[0],
        gameState: gs.gameState[0],
        phoneState: gs.phoneState[0],
        ...getBaseGlobalState(gs),
    };
}

export function useGlobalState(globalState?: GlobalState): {
    playerState: PlayerState;
    gameState: GameState;
    phoneState: PhoneState;
    settingsState: SettingsState<ParticipantSettings>;
    coreState: CoreState<Activity, Minigame>;
} {
    const gs = globalState ?? GlobalState.getInstance();

    return {
        playerState: useContext(gs.playerState[1]),
        gameState: useContext(gs.gameState[1]),
        phoneState: useContext(gs.phoneState[1]),
        ...useBaseGlobalState(gs),
    };
}

export function resetPlayerState(playerState: PlayerState) {
    let key: keyof PlayerState;
    for (key in playerState) {
        playerState[key][1](structuredClone(defaultPlayerState[key]));
    }
}

export function resetGameState(gameState: GameState) {
    let key: keyof GameState;
    for (key in gameState) {
        gameState[key][1](structuredClone(defaultGameState[key]));
    }
}

export function resetPhoneState(settingsState: PhoneState) {
    let key: keyof PhoneState;
    for (key in settingsState) {
        settingsState[key][1](structuredClone(defaultPhoneState[key]));
    }
}

export function useNewState<ActivityType, MinigameType>(): {
    coreState: CoreState<ActivityType, MinigameType>;
    settingsState: SettingsState<ParticipantSettings>;
    gameState: GameState;
    playerState: PlayerState;
    phoneState: PhoneState;
} {
    const playerState: PlayerState = {
        playerPitch: useState<"low-pitch" | "high-pitch">(
            defaultPlayerState.playerPitch
        ),
        character: useState<Character>(defaultPlayerState.character),
        playerPronouns: useState<[string, string]>(
            defaultPlayerState.playerPronouns
        ),
        todoList: useState<TodoList>(defaultPlayerState.todoList),
        unlockedDocuments: useState<string[]>(
            defaultPlayerState.unlockedDocuments
        ),
        unlockedBadges: useState<string[]>(defaultPlayerState.unlockedBadges),
        unlockedDictionary: useState<string[]>(
            defaultPlayerState.unlockedDictionary
        ),
        unlockedMinigames: useState<string[]>(
            defaultPlayerState.unlockedMinigames
        ),
        unlockedBumperStickers: useState<string[]>(
            defaultPlayerState.unlockedBumperStickers
        ),
        unlockedStrategies: useState<string[]>(
            defaultPlayerState.unlockedStrategies
        ),
        activityData: useState<Record<string, ActivityPlayerData>>(
            defaultPlayerState.activityData
        ),
    };

    const gameState: GameState = {
        zoom: useState<SlideShowData | null>(defaultGameState.zoom),
    };

    const phoneState: PhoneState = {
        textConversations: useState<TextMessageConversation[]>(
            defaultPhoneState.textConversations
        ),
        loadedTextConversations: useState<
            { dialog: TextDialog; lastHandled: number }[]
        >(defaultPhoneState.loadedTextConversations),
        currentTextConversation: useState<number>(
            defaultPhoneState.currentTextConversation
        ),
        textMessageOptions: useState<TextMessageOptions>(
            defaultPhoneState.textMessageOptions
        ),
        openMessages: useState<{ name: string; index: number }>(
            defaultPhoneState.openMessages
        ),
        unreadMessages: useState<number[]>(defaultPhoneState.unreadMessages),
        existingTextConversations: useState<number[]>(
            defaultPhoneState.existingTextConversations
        ),

        emails: useState<Email[]>(defaultPhoneState.emails),
        repliedEmails: useState<number[]>(defaultPhoneState.repliedEmails),
        replies: useState<string[]>(defaultPhoneState.replies),

        browserPage: useState<"search" | "strategy">("search"),
        activeStrategyId: useState<string | null>(null),
    };

    const settingsState = useNewSettingsState(defaultParticipantSettings);
    const coreState: CoreState<ActivityType, MinigameType> = useNewCoreState();
    return {
        coreState,
        settingsState,
        gameState,
        playerState,
        phoneState,
    };
}

