function ChapterPage({
    coreState,
    gameState,
    playerState,
    phoneState,
    settings,
}: {
    coreState: CoreState<Activity, Minigame>;
    gameState: GameState;
    playerState: PlayerState;
    phoneState: PhoneState;
    settings: SettingsState<ParticipantSettings>;
}) {
    const [chapterNumber, setChapterNumber] = useState<number>(
        Registers.getRegister("chapter") as number
    );

    return (
        <>
            <h1>ChapterChanger</h1>
            <input
                type="number"
                min={1}
                max={10}
                step={1}
                value={chapterNumber}
                onChange={(e) => {
                    setChapterNumber(parseInt(e.target.value));
                    Registers.setRegisters([
                        {
                            register: "chapter",
                            action: "set",
                            value: parseInt(e.target.value),
                        },
                    ]);
                }}
            />
        </>
    );
}

