function FlagsPage({
    coreState,
    gameState,
    playerState,
    phoneState,
    settings,
}: {
    coreState: CoreState<Activity, Minigame>;
    gameState: GameState;
    playerState: PlayerState;
    phoneState: PhoneState;
    settings: SettingsState<ParticipantSettings>;
}) {
    const [unlockedFlags] = coreState.unlockedFlags;
    const Flag = ({ flag }: { flag: string }) => {
        const handleEditFlag = (e: FocusEvent<HTMLInputElement>) => {
            Flags.setOrUnsetFlag([
                {
                    flag_name: flag,
                    flag_action: "revoke",
                },
                {
                    flag_name: (e.target as HTMLInputElement).value,
                    flag_action: "give",
                },
            ]);
        };
        const handleDeleteFlag = () => {
            Flags.setOrUnsetFlag([
                {
                    flag_name: flag,
                    flag_action: "revoke",
                },
            ]);
        };

        return (
            <div className={join(phoneStyles, "section", "column-auto-small")}>
                <input
                    type="text"
                    defaultValue={flag}
                    onBlur={handleEditFlag}
                />
                <button onClick={handleDeleteFlag}>🗑</button>
            </div>
        );
    };

    const addFlag = (input: HTMLInputElement) => {
        if (input.value.trim() === "") return;

        Flags.setOrUnsetFlag([
            {
                flag_name: input.value,
                flag_action: "give",
            },
        ]);
        input.value = "";
    };

    return (
        <>
            <h1>Flags</h1>
            <div className={join(phoneStyles, "column-auto-small")}>
                <input
                    type="text"
                    placeholder="Add new flag..."
                    onBlur={(e: FocusEvent<HTMLInputElement>) =>
                        addFlag(e.target)
                    }
                    onKeyUp={(e: KeyboardEvent<HTMLInputElement>) => {
                        if (e.key === "Enter") {
                            e.preventDefault();
                            addFlag(e.target as HTMLInputElement);
                        }
                    }}
                />
            </div>
            {unlockedFlags
                .map((flag) => <Flag key={flag} flag={flag} />)
                .reverse()}
        </>
    );
}

function RegistersPage({
    coreState,
    gameState,
    playerState,
    phoneState,
    settings,
}: {
    coreState: CoreState<Activity, Minigame>;
    gameState: GameState;
    playerState: PlayerState;
    phoneState: PhoneState;
    settings: SettingsState<ParticipantSettings>;
}) {
    const [registers] = coreState.registers;
    const [textRegisters] = coreState.textRegisters;
    const addRegister = (input: HTMLInputElement) => {
        if (input.value.trim() === "") return;

        Registers.setRegisters([
            {
                register: input.value,
                action: "set",
                value: 0,
            },
        ]);

        input.value = "";
    };

    const addTextRegister = (input: HTMLInputElement) => {
        if (input.value.trim() === "") return;

        Registers.setTextRegisters([
            {
                register: input.value,
                action: "set",
                value: "",
            },
        ]);

        input.value = "";
    };

    const RegisterItem = ({ name, value }: { name: string; value: number }) => {
        const setRegister = (value: number) => {
            Registers.setRegisters([
                {
                    register: name,
                    action: "set",
                    value: value || 0,
                },
            ]);
        };

        const handleDeleteRegister = () => {
            Registers.setRegisters([
                {
                    register: name,
                    action: "delete",
                },
            ]);
        };

        return (
            <div className={join(phoneStyles, "section", "column-auto-small")}>
                <input type="text" defaultValue={name} />
                <button
                    className={join(phoneStyles, "debug")}
                    onClick={() => {
                        Registers.setRegisters([
                            {
                                register: name,
                                action: "add",
                                value: 1,
                            },
                        ]);
                    }}
                >
                    +
                </button>
                <button
                    className={join(phoneStyles, "debug")}
                    onClick={() => {
                        Registers.setRegisters([
                            {
                                register: name,
                                action: "subtract",
                                value: 1,
                            },
                        ]);
                    }}
                >
                    -
                </button>
                <input
                    className={join(phoneStyles, "debug")}
                    type="number"
                    defaultValue={value}
                    onBlur={(e: FocusEvent<HTMLInputElement>) =>
                        setRegister(parseInt(e.target.value))
                    }
                    onKeyUp={(e: KeyboardEvent<HTMLInputElement>) => {
                        if (e.key === "Enter") {
                            e.preventDefault();
                            setRegister(
                                parseInt((e.target as HTMLInputElement).value)
                            );
                        }
                    }}
                />
                <button onClick={handleDeleteRegister}>🗑</button>
            </div>
        );
    };

    const TextRegisterItem = ({
        name,
        value,
    }: {
        name: string;
        value: string;
    }) => {
        const setRegister = (value: string) => {
            Registers.setTextRegisters([
                {
                    register: name,
                    action: "set",
                    value: value || "",
                },
            ]);
        };

        const handleDeleteRegister = () => {
            Registers.setTextRegisters([
                {
                    register: name,
                    action: "delete",
                },
            ]);
        };

        return (
            <div className={join(phoneStyles, "section", "column-auto-small")}>
                <input type="text" defaultValue={name} />
                <input
                    className={join(phoneStyles, "debug")}
                    type="text"
                    defaultValue={value}
                    onBlur={(e: FocusEvent<HTMLInputElement>) =>
                        setRegister(e.target.value)
                    }
                    onKeyUp={(e: KeyboardEvent<HTMLInputElement>) => {
                        if (e.key === "Enter") {
                            e.preventDefault();
                            setRegister((e.target as HTMLInputElement).value);
                        }
                    }}
                />
                <button onClick={handleDeleteRegister}>🗑</button>
            </div>
        );
    };

    return (
        <>
            <h1>Registers</h1>
            <div className={join(phoneStyles, "column-auto-small")}>
                <input
                    type="text"
                    placeholder="Add new register..."
                    onBlur={(e: FocusEvent<HTMLInputElement>) =>
                        addRegister(e.target)
                    }
                    onKeyUp={(e: KeyboardEvent<HTMLInputElement>) => {
                        if (e.key === "Enter") {
                            e.preventDefault();
                            addRegister(e.target as HTMLInputElement);
                        }
                    }}
                />
            </div>
            {Object.entries(registers).map(([name, value]) => (
                <RegisterItem key={name} name={name} value={value} />
            ))}
            <h1>Text Registers</h1>
            <div className={join(phoneStyles, "column-auto-small")}>
                <input
                    type="text"
                    placeholder="Add new text register..."
                    onBlur={(e: FocusEvent<HTMLInputElement>) =>
                        addTextRegister(e.target)
                    }
                    onKeyUp={(e: KeyboardEvent<HTMLInputElement>) => {
                        if (e.key === "Enter") {
                            e.preventDefault();
                            addTextRegister(e.target as HTMLInputElement);
                        }
                    }}
                />
            </div>
            {Object.entries(textRegisters).map(([name, value]) => (
                <TextRegisterItem key={name} name={name} value={value} />
            ))}
        </>
    );
}

function UnlockablesPage({
    coreState,
    gameState,
    playerState,
    phoneState,
    settings,
    appRegistry,
}: {
    coreState: CoreState<Activity, Minigame>;
    gameState: GameState;
    playerState: PlayerState;
    phoneState: PhoneState;
    settings: SettingsState<ParticipantSettings>;
    appRegistry: AppRegistry;
}) {
    const Unlockable = ({
        state,
        value,
    }: {
        state: ReactState<string[]>;
        value: string;
    }) => {
        const handleChanged = (e: ChangeEvent<HTMLInputElement>) => {
            if (e.target.checked) {
                state[1]((list) => [...list, value]);
            } else {
                state[1]((list) => list.filter((v) => v !== value));
            }
        };

        return (
            <div className={join(phoneStyles, "section", "column-auto-small")}>
                <p>{value}</p>
                <input
                    type="checkbox"
                    defaultChecked={state[0].includes(value)}
                    onChange={handleChanged}
                />
            </div>
        );
    };

    return (
        <>
            <h1>Badges</h1>
            {Object.keys(Badges.list()).map((value) => (
                <Unlockable
                    key={value}
                    state={playerState.unlockedBadges}
                    value={value}
                />
            ))}
            <h1>Documents</h1>
            {Object.keys(Documents.list()).map((value) => (
                <Unlockable
                    key={value}
                    state={playerState.unlockedDocuments}
                    value={value}
                />
            ))}
            <h1>Dictionary</h1>
            {Object.keys(Dictionary.list()).map((value) => (
                <Unlockable
                    key={value}
                    state={playerState.unlockedDictionary}
                    value={value}
                />
            ))}
            <h1>Bumper Stickers</h1>
            {Object.keys(BumperStickers.list()).map((value) => (
                <Unlockable
                    key={value}
                    state={playerState.unlockedBumperStickers}
                    value={value}
                />
            ))}
            <h1>Apps</h1>
            {Object.keys(appRegistry)
                .map((value) => {
                    const app = appRegistry[value];
                    if (app === undefined) return ``;
                    return `${app.name}_unlocked`;
                })
                .map((value) => {
                    if (value === ``) return <Fragment key={value}></Fragment>;

                    return (
                        <Unlockable
                            key={value}
                            state={coreState.unlockedFlags}
                            value={value}
                        />
                    );
                })}
            <h1>Minigames</h1>
            {Object.keys(Minigames.list()).map((value) => (
                <Unlockable
                    key={value}
                    state={playerState.unlockedMinigames}
                    value={value}
                />
            ))}
            <h1>Strategies</h1>
            {Object.keys(Strategies.list()).map((value) => (
                <Unlockable
                    key={value}
                    state={playerState.unlockedStrategies}
                    value={value}
                />
            ))}
            <h1>Activities</h1>
            {Object.keys(activities).map((key) => (
                <button
                    key={key}
                    onClick={() => {
                        LoadActivity<Activity>(key).then((activity) => {
                            SendActivityStarted(
                                activity.name,
                                coreState.appEnabled[1]
                            );
                            coreState.activity[1](activity);
                            coreState.popup[1]("activity");
                        });
                    }}
                >
                    {key}
                </button>
            ))}
        </>
    );
}

function TodoListPage({
    coreState,
    gameState,
    playerState,
    phoneState,
    settings,
}: {
    coreState: CoreState<Activity, Minigame>;
    gameState: GameState;
    playerState: PlayerState;
    phoneState: PhoneState;
    settings: SettingsState<ParticipantSettings>;
}) {
    const state = playerState.todoList;

    const TodoItem = ({
        type,
        value,
    }: {
        type: "story" | "optional";
        value: TodoList["story"][0];
    }) => {
        const handleToggled = (e: ChangeEvent<HTMLInputElement>) => {
            state[1]((todo) => {
                todo[type] = todo[type].map((val) =>
                    val.item === value.item
                        ? {
                              item: val.item,
                              complete: e.target.checked,
                              failed: false,
                          }
                        : val
                );
                return todo;
            });
        };

        const handleToggleFailed = (e: ChangeEvent<HTMLInputElement>) => {
            if (!settings.participantSettings[0].EnableFailedTodo) return;

            state[1]((todo) => {
                todo[type] = todo[type].map((val) =>
                    val.item === value.item
                        ? {
                              item: val.item,
                              complete: false,
                              failed: e.target.checked,
                          }
                        : val
                );
                return todo;
            });
        };

        const handleDelete = () => {
            state[1]((todo) => {
                todo[type] = todo[type].filter(
                    (val) => val.item !== value.item
                );
                return todo;
            });
        };

        const handleEdit = (e: FocusEvent<HTMLInputElement>) => {
            state[1]((todo) => {
                todo[type] = todo[type].map((val) =>
                    val.item === value.item
                        ? {
                              item: e.target.value,
                              complete: val.complete,
                          }
                        : val
                );
                return todo;
            });
        };

        const handleEditChapter = (e: FocusEvent<HTMLInputElement>) => {
            state[1]((todo) => {
                todo[type] = todo[type].map((val) =>
                    val.item === value.item
                        ? {
                              item: val.item,
                              chapter: parseInt(e.target.value),
                              complete: val.complete,
                          }
                        : val
                );
                return todo;
            });
        };

        return (
            <div className={join(phoneStyles, "section", "column-auto-small")}>
                <input
                    type="text"
                    defaultValue={value.item}
                    onBlur={handleEdit}
                />
                <input
                    type="number"
                    className={join(phoneStyles, `debug`, `sm`)}
                    defaultValue={value.chapter || 0}
                    onBlur={handleEditChapter}
                />
                <input
                    type="checkbox"
                    defaultChecked={value.complete}
                    onChange={handleToggled}
                />
                <input
                    type="checkbox"
                    defaultChecked={value.failed}
                    onChange={handleToggleFailed}
                />
                <button onClick={handleDelete}>🗑</button>
            </div>
        );
    };

    const addTodoItem = (
        type: "story" | "optional",
        input: HTMLInputElement
    ) => {
        if (input.value.trim() === "") return;
        state[1]((todo) => {
            todo[type] = [
                {
                    item: input.value,
                    complete: false,
                },
                ...todo[type],
            ];
            return todo;
        });
        input.value = "";
    };

    return (
        <>
            <h1>Story</h1>
            <div className={join(phoneStyles, "column-auto-small")}>
                <input
                    type="text"
                    placeholder="Add new todo item..."
                    onBlur={(e: FocusEvent<HTMLInputElement>) =>
                        addTodoItem("story", e.target)
                    }
                    onKeyUp={(e: KeyboardEvent<HTMLInputElement>) => {
                        if (e.key === "Enter") {
                            e.preventDefault();
                            addTodoItem("story", e.target as HTMLInputElement);
                        }
                    }}
                />
            </div>

            {playerState.todoList[0].story.map((value) => (
                <TodoItem key={value.item} type="story" value={value} />
            ))}
            <h1>Optional</h1>
            <div className={join(phoneStyles, "column-auto-small")}>
                <input
                    type="text"
                    placeholder="Add new todo item..."
                    onBlur={(e: FocusEvent<HTMLInputElement>) =>
                        addTodoItem("optional", e.target)
                    }
                    onKeyUp={(e: KeyboardEvent<HTMLInputElement>) => {
                        if (e.key === "Enter") {
                            e.preventDefault();
                            addTodoItem(
                                "optional",
                                e.target as HTMLInputElement
                            );
                        }
                    }}
                />
            </div>

            {playerState.todoList[0].optional.map((value) => (
                <TodoItem key={value.item} type="optional" value={value} />
            ))}
        </>
    );
}

function ParticipantSettingsPage({
    gameState,
    playerState,
    phoneState,
    settings,
}: {
    gameState: GameState;
    playerState: PlayerState;
    phoneState: PhoneState;
    settings: SettingsState<ParticipantSettings>;
}) {
    const [participant, setParticipant] = settings.participantSettings;
    const [config, setConfig] =
        useState<ParticipantConfiguration<ParticipantSettings>>();
    const [forceDebug, setForceDebug] = useState<boolean>(true);

    const [keys, setKeys] = useState<(keyof ParticipantSettings)[]>();

    useEffect(() => {
        getParticipantConfiguration<ParticipantSettings>().then((data) => {
            setConfig(data);
        });
    }, []);

    function onSetParticipant(option: ParticipantSettings) {
        setKeys([]);
        if (forceDebug) {
            setParticipant({
                ...option,
                DebugEnabled: true,
            });
        } else {
            setParticipant(option);
        }
    }

    const handleChanged = (e: ChangeEvent<HTMLInputElement>) => {
        setForceDebug(e.target.checked);
    };

    function setField(key: keyof ParticipantSettings, value: any) {
        setParticipant((val) => {
            return {
                ...val,
                [key]: value,
            };
        });
    }

    useEffect(() => {
        saveSettings();
        setParticipantFlags(participant);

        const keys: (keyof ParticipantSettings)[] = [];
        let key: keyof ParticipantSettings;
        for (key in participant) {
            keys.push(key);
        }
        setKeys(keys);
    }, [participant]);

    return (
        <>
            <h2>Current Config: {participant.name}</h2>
            Set Config:
            {config?.options.map((option) => {
                return (
                    <button
                        key={option.name}
                        onClick={() => onSetParticipant(option)}
                    >
                        {option.name}
                    </button>
                );
            })}
            <br />
            force debug{" "}
            <input
                type="checkbox"
                defaultChecked={forceDebug}
                onChange={handleChanged}
            />
            <br /> <br /> <br />
            <button onClick={() => localStorage.setItem("settings", "")}>
                Full clear settings
            </button>
            {keys?.map((key) => {
                if (typeof participant[key] === "boolean") {
                    const value = participant[key];
                    if (typeof value !== "boolean")
                        return <Fragment key={key} />;

                    return (
                        <p key={key}>
                            {key}:
                            <input
                                type="checkbox"
                                defaultChecked={value}
                                onChange={(
                                    e: ChangeEvent<HTMLInputElement>
                                ) => {
                                    setField(key, e.target.checked);
                                }}
                            />
                        </p>
                    );
                } else {
                    const value = participant[key];
                    if (typeof value !== "number")
                        return <Fragment key={key} />;

                    return (
                        <p key={key}>
                            {key}:
                            <input
                                type="number"
                                className={join(
                                    phoneStyles,
                                    "debug",
                                    "debug-short"
                                )}
                                defaultValue={value}
                                step={0.01}
                                onChange={(
                                    e: ChangeEvent<HTMLInputElement>
                                ) => {
                                    setField(key, parseFloat(e.target.value));
                                }}
                            />
                        </p>
                    );
                }
            })}
        </>
    );
}
