import { useCallback, useEffect, useRef } from "react";
import styles from "../styles/dialog/Dialog.module.css";
import historyStyles from "../styles/dialog/DialogHistory.module.css";
import { PlayAudio, PlayVoiceLine } from "engine/src/system/AudioSystem";
import { joinWithOverride } from "engine/src/system/Styles";
import { DialogHistoryDialog } from "engine/src/types/Dialog";
import { ReactSetter, useBaseGlobalState } from "engine/src/state/GlobalState";
import { useKeyDown, useSelectedIndex } from "engine/src/system/Keyboard";
import { dialogClean } from "engine/src/system/Dialog";
import { DialogHtml } from "./Dialog";
import { DictionaryWords } from "../types/DictionaryWords";

export const DialogHistoryToggle = ({
    setDialogHistoryOpen,
    styleOverride,
}: {
    setDialogHistoryOpen: ReactSetter<boolean>,
    styleOverride: any,
}) => {
    const {coreState, settingsState} = useBaseGlobalState();
    
    const [keybinds] = settingsState.keybinds;
    const [participantSettings] = settingsState.participantSettings;

    const [phoneOpen] = coreState.phoneOpen;

    function dialogHistoryToggle() {
        PlayAudio("phone-toggle.wav", "sounds");

        setDialogHistoryOpen(value => !value);
    }

    useKeyDown(
        keybinds.General.Open_Dialog_History, 
        dialogHistoryToggle, 
        coreState.transitioning[0] || phoneOpen
    );

    useEffect(() => {
        if(phoneOpen === true) {
            setDialogHistoryOpen(false);
        }
    }, [phoneOpen, setDialogHistoryOpen]);

    return (
        <div>
            <button
                tabIndex={-1}
                onClick={dialogHistoryToggle}
                className={joinWithOverride(historyStyles, styleOverride, "chat-history")}
            >
                {dialogClean(participantSettings.EnableKbControls 
                    ? "Dialog History (%key:general:open_dialog_history%)" 
                    : "Dialog History"
                )}
            </button>
        </div>
    );
};

const DialogHistoryComponent = ({
    dialogHistoryOpen,
    setDialogHistoryOpen,
    dialogHistory,
    pitch,
    dictionary,
    newWordCallback,
    styleOverride,
    dialogStyleOverride,
}: {
    dialogHistoryOpen: boolean;
    setDialogHistoryOpen: ReactSetter<boolean>;
    dialogHistory: DialogHistoryDialog[];
    pitch: 'low-pitch' | 'high-pitch';
    dictionary: Record<string, DictionaryWords>,
    newWordCallback: (word: string) => void,
    styleOverride: any,
    dialogStyleOverride: any,
}) => {
    const {coreState, settingsState} = useBaseGlobalState();
    
    const [popup] = coreState.popup;
    const [keybinds] = settingsState.keybinds;

    const historyRef = useRef<HTMLDivElement>(null);
    const audioRef = useRef<AudioBufferSourceNode | null>(null);

    const selectedRef = useRef<null | HTMLDivElement>(null);

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        dialogHistory.length, keybinds.General.Up, keybinds.General.Down, !dialogHistoryOpen
    );

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (
                historyRef.current &&
                !historyRef.current.contains(event.target as Node)
            ) {
                setDialogHistoryOpen(false);
            }
        }

        if (dialogHistoryOpen) {
            document.addEventListener("mousedown", handleClickOutside);
            setSelectedIndex(-1);
        } else {
            document.removeEventListener("mousedown", handleClickOutside);
        }

        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [dialogHistoryOpen, setDialogHistoryOpen, setSelectedIndex]);

    const playDialog = useCallback((index: number) => {
        if(index === -1) return;
        const dialog = dialogHistory[index];

        if(!dialog) return;
        
        if (
            dialog.dialog_name !== undefined &&
            dialog.dialog_index !== undefined
        ) {
            if (audioRef.current)
                audioRef.current.stop();
            PlayVoiceLine(
                dialog.dialog_name,
                dialog.dialog_index,
                dialog.source,
                pitch,
            ).then((audio) => {
                if (audio === null) return;
                audioRef.current = audio;
            });
        }
    }, [dialogHistory]);

    useEffect(() => {
        selectedRef.current?.scrollIntoView({behavior: "smooth"});
    }, [selectedIndex]);

    useKeyDown(keybinds.General.Back, () => setDialogHistoryOpen(false), !dialogHistoryOpen);
    useKeyDown(keybinds.General.Select, useCallback(() => {
        playDialog(selectedIndex);
    }, [selectedIndex, playDialog]), !dialogHistoryOpen);


    if (popup !== null) {
        return <></>;
    } else if (!dialogHistoryOpen)
        return (
            <>
                <DialogHistoryToggle
                    styleOverride={styleOverride}
                    setDialogHistoryOpen={setDialogHistoryOpen}
                />
            </>
        );
    return (
        <div className={joinWithOverride(historyStyles, styleOverride, "history-wrapper")}>
            <DialogHistoryToggle
                styleOverride={styleOverride}
                setDialogHistoryOpen={setDialogHistoryOpen}
            />
            <div className={joinWithOverride(historyStyles, styleOverride, "center-history")}>
                <div
                    className={joinWithOverride(historyStyles, styleOverride, "history-container")}
                    ref={historyRef}
                >
                    <div className={joinWithOverride(historyStyles, styleOverride, "title")}>
                        Dialog History
                    </div>
                    {dialogHistory.map((dialog, index) => {
                        return (
                            <div
                                key={index}
                                className={joinWithOverride(
                                    styles,
                                    dialogStyleOverride,
                                    dialog.source === "%player%"
                                        ? "player"
                                        : "",
                                    `dialog`,
                                    `sample`,
                                    index === selectedIndex
                                        ? `selected`
                                        : ``
                                )}
                                onClick={() => {
                                    playDialog(index);
                                }}
                                ref={index === selectedIndex ? selectedRef : null}
                            >
                                <div
                                    className={
                                        joinWithOverride(styles, dialogStyleOverride, "dialog-text") +
                                        joinWithOverride(historyStyles, styleOverride, "hoverable")
                                    }
                                >
                                    <b>
                                        {dialogClean(dialog.source)}
                                    </b>
                                    <DialogHtml
                                        message={dialog.message}
                                        seenWords={[]}
                                        enableInput={index === selectedIndex}
                                        newWordCallback={newWordCallback}
                                        dictionary={dictionary}
                                        dialogStyleOverride={dialogStyleOverride}
                                    />
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};

export default DialogHistoryComponent;
