import { ChangeEvent } from "react";
import {
    ActivityElementPlayerData,
    ReflectionActivityPlayerData,
} from "../../../types/ActivityPlayerData";
import styles from "#styles/activities/renderers/reflection.module.css";
import { join, joinExternal } from "engine/src/system/Styles";
import {
    ActivityDefaultStateProvider,
    ActivityRenderer,
} from "engine/src/components/popup/ActivityComponent";
import { Activities } from "../../../types/Activity";

export const ReflectionActivityRenderer: ActivityRenderer<
    Activities,
    ActivityElementPlayerData,
    "reflection"
> = (element, playerData, updateState) => {
    return {
        appView: (
            <div
                className={joinExternal(styles, "reflection")}
                key={element.prompt}
            >
                <div className={joinExternal(styles, "reflection-header")}>
                    {element.number && <span>{element.number}</span>}
                    <h2>{element.prompt}</h2>
                </div>
                <textarea
                    placeholder="Enter Response"
                    value={
                        playerData.response !== ""
                            ? playerData.response
                            : undefined
                    }
                    className={join(styles, "reflection-box")}
                    onChange={(e: ChangeEvent<HTMLTextAreaElement>) => {
                        const newData: ReflectionActivityPlayerData = {
                            type: "reflection",
                            complete: e.target.value.trim().length > 20,
                            response: e.target.value,
                        };
                        updateState(newData);
                    }}
                />
                <i className={join(styles, "feedback")}>
                    {playerData.complete
                        ? ""
                        : "Please enter a reponse of at least 20 characters."}
                </i>
            </div>
        ),
        printView: (
            <div className={join(styles, "reflection")} key={element.prompt}>
                <div className={join(styles, "reflection-header")}>
                    {element.number && <span>{element.number}</span>}
                    <h2>{element.prompt}</h2>
                </div>
                <textarea
                    placeholder="Enter Response"
                    value={
                        playerData.response !== ""
                            ? playerData.response
                            : undefined
                    }
                    className={join(styles, "reflection-box")}
                    readOnly
                />
            </div>
        ),
    };
};

export const DefaultReflectionActivityState: ActivityDefaultStateProvider<
    Activities,
    ActivityElementPlayerData,
    "reflection"
> = () => {
    return {
        type: "reflection",
        complete: false,
        response: "",
    };
};
