import { useEffect } from "react";
import styles from "../styles/popup/Popup.module.css";
import {
    IsAudioPlaying,
    PlayAudio,
    StopAllAudio,
} from "engine/src/system/AudioSystem";
import { ReactState, useBaseGlobalState } from "../state/GlobalState";
import { AcitivityRegistry, ActivityComponent } from "./popup/ActivityComponent";
import { MinigameComponent, MinigameRegistry } from "./popup/MinigameComponent";
import { GenericMinigame } from "../types/Minigame";
import { ActivityElement } from "../types/Activity";
import { GenericActivityPlayerData } from "../types/ActivityPlayerData";
import { joinWithOverride } from "../system/Styles";

type PopupRegistryElement = {
    element: (props: any) => JSX.Element,
    props?: Record<string, any>
    keepAudio: boolean,
}

export type PopupRegistry = Record<string, PopupRegistryElement>;


export function generatePopupRegistry<Activities extends ActivityElement<string>, ActivityElementPlayerData extends GenericActivityPlayerData<string>, MinigameType extends GenericMinigame<string>>(activityRegistry: AcitivityRegistry<Activities, ActivityElementPlayerData>, minigameRegistry: MinigameRegistry<MinigameType>, modifier: (registry: PopupRegistry) => PopupRegistry, documentStyleOverride?: any, activityStyleOverride?: any, minigameStyleOverride?: any) {
    const registry = {
        activity: {
            element: ActivityComponent,
            props: {activityRegistry, documentStyleOverride: documentStyleOverride, styleOverride: activityStyleOverride},
            keepAudio: true,
        },
        minigame: {
            element: MinigameComponent,
            props: {minigameRegistry, documentStyleOverride: documentStyleOverride, styleOverride: minigameStyleOverride},
            keepAudio: false,
        },
    }

    return modifier(registry);
}

/**
 * The popup component
 */
const PopupComponent = ({registry, activityDataState, styleOverride}: {registry: PopupRegistry, activityDataState: ReactState<any>, styleOverride?: any}) => {
    // Get the game state from the global state provider
    const {coreState} = useBaseGlobalState();

    const [popup] = coreState.popup;
    const [scene] = coreState.scene;
    const [backgroundIndex] = coreState.sceneBackground;

    const popups: Record<string, JSX.Element> = Object.fromEntries(
        Object.entries(registry).map(([identifier, popup]) => [identifier, <popup.element {...popup.props} activityDataState={activityDataState} />])
    )

    useEffect(() => {
        if (popup === null) {
            if (scene.backgrounds[backgroundIndex]) {
                if (
                    !IsAudioPlaying(
                        `ambience/${scene.backgrounds[backgroundIndex].ambience}`
                    ) &&
                    scene.backgrounds[backgroundIndex].ambience
                ) {
                    PlayAudio(
                        `ambience/${scene.backgrounds[backgroundIndex].ambience}`,
                        "sounds",
                        true
                    );
                }
                if (
                    !IsAudioPlaying(
                        `music/${scene.backgrounds[backgroundIndex].music}`
                    ) &&
                    scene.backgrounds[backgroundIndex].music
                ) {
                    PlayAudio(
                        `music/${scene.backgrounds[backgroundIndex].music}`,
                        "music",
                        true
                    );
                }
            }
        } else if (!registry[popup].keepAudio) {
            StopAllAudio("ambience");
            StopAllAudio("music");
            StopAllAudio("voice-lines");
        }
    }, [popup, scene, backgroundIndex]);

    if (popup === null) return <></>;

    // Return the popup
    return (
        <div className={joinWithOverride(styles, styleOverride, "popup")}>
            <div>{popups[popup]}</div>
        </div>
    );
};

export default PopupComponent;
