import styles from "#styles/minigames/renderers/SpreadsheetMinigame.module.css";
import { GlobalState } from "../../../state/GlobalState";
import { Minigame, SpreadsheetWheelMinigame } from "../../../types/Minigame";
import { SpreadsheetActivityRenderer } from "../../activities/renderers/SpreadsheetActivity";
import { editState } from "../../../state/Util";
import { Badges } from "../../../system/Unlockables";
import { ProgressBar } from "../MinigameProgressBar";
import { PlayAudio, StopAllAudio } from "engine/src/system/AudioSystem";
import { join } from "engine/src/system/Styles";
import { ReactState } from "engine/src/state/GlobalState";

type State = {
    type: Minigame["type"];
    data: {
        spins: number;
        loseSpins: number;
        additionalResources: Record<string, number>;
        additionalCosts: Record<string, number>;
        currentKey: string | null;
        currentType: "positive" | "negative";
        currentlySpinning: boolean;
        spunKeys: string[];
        adjustableCosts: Record<string, number>;
    };
};

const NUMBER_OF_SEGMENTS = 8;
const COLOURS = ["#d8a67a", "#FDF9E0"];
const radius = 50;

export const SpreadsheetWheelMinigameRenderer = ({
    minigame,
    state,
}: {
    minigame: SpreadsheetWheelMinigame;
    state: ReactState<State>;
}) => {
    const spin = () => {
        state[1]((val) => {
            return {
                ...val,
                data: {
                    ...val.data,
                    currentlySpinning: true,
                },
            };
        });
        const spinner = document.getElementsByClassName(
            styles["wheel-spinner"]
        )[0] as SVGGElement;
        spinner.classList.remove(styles["spin"]);

        PlayAudio("wheel-spin.mp3", "sounds");

        setTimeout(() => {
            spinner.classList.add(styles["spin"]);
            let spinCount = (Math.random() * 3 + 10) * 360;
            if (
                minigame.requiredSpins - state[0].data.spins <=
                minigame.guarenteedLoseSpins - state[0].data.loseSpins
            ) {
                while (
                    (Math.floor(
                        (spinCount % 360) / (360 / NUMBER_OF_SEGMENTS)
                    ) +
                        1) %
                    COLOURS.length
                ) {
                    spinCount = (Math.random() * 3 + 10) * 360;
                }
            }
            spinner.style.setProperty("--spinCount", spinCount + "deg");

            setTimeout(() => {
                // Generate result
                const positive =
                    (Math.floor(
                        (spinCount % 360) / (360 / NUMBER_OF_SEGMENTS)
                    ) +
                        1) %
                    COLOURS.length;
                const type = positive ? "positive" : "negative";

                const keys = Object.keys(minigame.wheelValues[type]).filter(
                    (key) => !state[0].data.spunKeys.includes(key)
                );
                const key = keys[Math.floor(Math.random() * keys.length)];

                state[1]((val) => {
                    return {
                        ...val,
                        data: {
                            ...val.data,
                            currentKey: key,
                            currentType: type,
                            spins: val.data.spins + 1,
                            currentlySpinning: false,
                            spunKeys: [...val.data.spunKeys, key],
                            loseSpins: positive ? 0 : 1,
                        },
                    };
                });
            }, 3000);
        }, 50);
    };

    const current = state[0].data.currentKey
        ? minigame.wheelValues[state[0].data.currentType][
              state[0].data.currentKey
          ]
        : null;

    const resources = [
        ...Object.keys(minigame.defaultResources).map(
            (key) => minigame.defaultResources[key]
        ),
        ...Object.keys(state[0].data.additionalResources).map(
            (key) => state[0].data.additionalResources[key]
        ),
    ];

    const costs = [
        ...Object.keys(state[0].data.adjustableCosts).map(
            (key) => state[0].data.adjustableCosts[key] || 0
        ),
        ...Object.keys(minigame.defaultCosts).map(
            (key) => minigame.defaultCosts[key].default
        ),
        ...Object.keys(state[0].data.additionalCosts).map(
            (key) => state[0].data.additionalCosts[key]
        ),
    ];

    const total =
        resources.reduce((prev, curr) => prev + curr, 0) -
        costs.reduce((prev, curr) => prev + curr, 0);

    return (
        <div className={join(styles, "wrapper")}>
            <div className={join(styles, "wheel-header")}>
                <div className={join(styles, "title-progress")}>
                    <h1 className={join(styles, "wheel-title")}>
                        Budget Wheel
                    </h1>
                    <ProgressBar
                        current={state[0].data.spins}
                        total={minigame.requiredSpins}
                    ></ProgressBar>
                </div>

                <div
                    className={join(styles, "spin-button-area", "instructions")}
                >
                    <p className={join(styles, "instruction-title")}>
                        How to Play
                    </p>
                    <p>
                        Begin with your initial funds. To spin the wheel, you
                        must have positive funds. Each spin can either earn you
                        money or result in unexpected expenses.<br></br>
                        <br></br>If your funds are negative at the end, you
                        cannot exit the game. Adjust your expenses to achieve
                        positive total funds before you can finish. Remember,
                        unexpected costs cannot be adjusted.<br></br>
                        <br></br>Manage your budget wisely!
                    </p>
                </div>
            </div>

            <div className={join(styles, "spreadsheet_wheel-wrapper")}>
                <div>
                    <svg viewBox={`0 0 ${radius * 3} ${radius * 3}`}>
                        <g className={join(styles, "wheel-spinner")}>
                            {new Array(NUMBER_OF_SEGMENTS)
                                .fill(0)
                                .map((_, i) => (
                                    <WheelSegment
                                        key={i}
                                        startAngle={
                                            (i * 360) / NUMBER_OF_SEGMENTS
                                        }
                                        endAngle={
                                            ((i + 1) * 360) / NUMBER_OF_SEGMENTS
                                        }
                                        radius={radius}
                                        color={COLOURS[i % COLOURS.length]}
                                        text={i % 2 === 0 ? "✘" : "💰"}
                                    />
                                ))}
                        </g>
                        <circle
                            cx={radius * 1.5}
                            cy={radius * 1.5}
                            r={radius + 2}
                            fill="transparent"
                            stroke="#5B6EE1"
                            strokeWidth={4}
                        />
                        <circle
                            cx={radius * 1.5 + 1}
                            cy={radius * 1.5 + 1}
                            r={radius / 4}
                            fill="#5B6EE1"
                        />
                        <circle
                            cx={radius * 1.5}
                            cy={radius * 1.5}
                            r={radius / 4}
                            fill="#97E2BD"
                        />
                        {new Array(NUMBER_OF_SEGMENTS - 1)
                            .fill(0)
                            .map((_, i) => ((i + 1) * 360) / NUMBER_OF_SEGMENTS)
                            .map((angle, i) => (
                                <circle
                                    key={i}
                                    cx={
                                        (radius + 2) *
                                            Math.sin((angle * Math.PI) / 180) +
                                        radius * 1.5
                                    }
                                    cy={
                                        (radius + 2) *
                                            -Math.cos((angle * Math.PI) / 180) +
                                        radius * 1.5
                                    }
                                    r={1}
                                    fill={"#97E2BD"}
                                />
                            ))}
                        <path
                            d={`
                            M ${radius * 1.5 + 1} ${radius * 0.5 + 12 + 1}
                            L ${radius * 1.5 - 5 + 1} ${radius * 0.5 - 1 + 1}
                            S ${radius * 1.5 + 1} ${radius * 0.5 - 5 + 1} ${radius * 1.5 + 5 + 1} ${radius * 0.5 - 1 + 1}
                        `}
                            fill="#5B6EE1"
                        />
                        <path
                            d={`
                            M ${radius * 1.5} ${radius * 0.5 + 12}
                            L ${radius * 1.5 - 5} ${radius * 0.5 - 1}
                            S ${radius * 1.5} ${radius * 0.5 - 5} ${radius * 1.5 + 5} ${radius * 0.5 - 1}
                        `}
                            fill="#97E2BD"
                        />
                    </svg>
                </div>
                <div className={join(styles, "button-result")}>
                    <div>
                        {current === null ? (
                            <SpinButton
                                spin={spin}
                                state={state}
                                minigame={minigame}
                                total={total}
                            />
                        ) : (
                            <SpinResult
                                current={current}
                                state={state}
                                total={total}
                            />
                        )}
                        <div className={join(styles, "spin-button-area")}>
                            {
                                SpreadsheetActivityRenderer(
                                    {
                                        type: "spreadsheet",
                                        tables: [
                                            {
                                                header: "Resources",
                                                totalText: "Total Resources",
                                                canAddRows: false,
                                                canRemoveRows: false,
                                                canEditCellName: false,
                                                canEditCellValue: false,
                                                valueHeaders: ["Value"],
                                                categoryHeader: "Item",
                                                initialCategories: ["test1"],
                                            },
                                        ],
                                    },
                                    {
                                        complete: false,
                                        type: "spreadsheet",
                                        tables: [
                                            {
                                                rows: [
                                                    ...Object.keys(
                                                        minigame.defaultResources
                                                    ).map((key) => ({
                                                        name: key,
                                                        columns: [
                                                            minigame
                                                                .defaultResources[
                                                                key
                                                            ],
                                                        ],
                                                    })),
                                                    ...Object.keys(
                                                        state[0].data
                                                            .additionalResources
                                                    ).map((key) => ({
                                                        name: key,
                                                        columns: [
                                                            state[0].data
                                                                .additionalResources[
                                                                key
                                                            ],
                                                        ],
                                                    })),
                                                ],
                                            },
                                        ],
                                    },
                                    () => {},
                                    [{}, () => {}, {}],
                                    {} as any
                                ).appView
                            }
                        </div>
                    </div>
                </div>
                <div className={join(styles, "button-result")}>
                    <div
                        className={join(
                            styles,
                            "spin-button-area",
                            "negative-total"
                        )}
                    >
                        {
                            SpreadsheetActivityRenderer(
                                {
                                    type: "spreadsheet",
                                    tables: [
                                        {
                                            header: "Adjustable Costs (Per Month)",
                                            totalText: "Total Costs",
                                            canAddRows: false,
                                            canRemoveRows: false,
                                            canEditCellName: false,
                                            canEditCellValue: true,
                                            valueHeaders: ["Expense"],
                                            categoryHeader: "Item",
                                            initialCategories: ["test1"],
                                        },
                                    ],
                                },
                                {
                                    complete: false,
                                    type: "spreadsheet",
                                    tables: [
                                        {
                                            rows: [
                                                ...Object.keys(
                                                    minigame.defaultCosts
                                                ).map((key) => ({
                                                    name: key,
                                                    columns: [
                                                        minigame.defaultCosts[
                                                            key
                                                        ].default +
                                                            (state[0].data
                                                                .adjustableCosts[
                                                                key
                                                            ] || 0),
                                                    ],
                                                })),
                                            ],
                                        },
                                    ],
                                },
                                (newState) => {
                                    editState(state[0], state[1], (old) => {
                                        const updatedAdjustableCosts = {
                                            ...old.data.adjustableCosts,
                                        };

                                        newState.tables[0].rows.forEach(
                                            (row) => {
                                                if (
                                                    !updatedAdjustableCosts[
                                                        row.name
                                                    ]
                                                ) {
                                                    updatedAdjustableCosts[
                                                        row.name
                                                    ] = 0;
                                                }

                                                updatedAdjustableCosts[
                                                    row.name
                                                ] =
                                                    (row.columns[0] === -1
                                                        ? 0
                                                        : row.columns[0]) -
                                                    minigame.defaultCosts[
                                                        row.name
                                                    ].default;
                                            }
                                        );

                                        old.data.adjustableCosts =
                                            updatedAdjustableCosts;
                                        return old;
                                    });
                                },
                                [{}, () => {}, {}],
                                {} as any
                            ).appView
                        }
                    </div>
                    <div
                        className={join(
                            styles,
                            "spin-button-area",
                            "negative-total"
                        )}
                    >
                        {
                            SpreadsheetActivityRenderer(
                                {
                                    type: "spreadsheet",
                                    tables: [
                                        {
                                            header: "Unexpected Costs",
                                            totalText: "Total Costs",
                                            canAddRows: false,
                                            canRemoveRows: false,
                                            canEditCellName: false,
                                            canEditCellValue: false,
                                            valueHeaders: ["Expense"],
                                            categoryHeader: "Item",
                                            initialCategories: ["test1"],
                                        },
                                    ],
                                },
                                {
                                    complete: false,
                                    type: "spreadsheet",
                                    tables: [
                                        {
                                            rows: [
                                                ...Object.keys(
                                                    state[0].data
                                                        .additionalCosts
                                                ).map((key) => ({
                                                    name: key,
                                                    columns: [
                                                        state[0].data
                                                            .additionalCosts[
                                                            key
                                                        ],
                                                    ],
                                                })),
                                            ],
                                        },
                                    ],
                                },
                                () => {},
                                [{}, () => {}, {}],
                                {} as any
                            ).appView
                        }
                    </div>
                </div>
            </div>
        </div>
    );
};

const hasAdjustableBelowMinimum = (
    minigame: SpreadsheetWheelMinigame,
    state: State
): null | string => {
    for (const category of Object.keys(minigame.defaultCosts)) {
        const data = minigame.defaultCosts[category];

        if (state.data.adjustableCosts[category] + data.default < data.min) {
            return data.error;
        }
    }
    return null;
};

function SpinButton({
    spin,
    state,
    minigame,
    total,
}: {
    spin: () => void;
    state: ReactState<State>;
    minigame: SpreadsheetWheelMinigame;
    total: number;
}) {
    const coreState = GlobalState.getInstance().coreState[0];
    const setPopup = coreState.popup[1];
    const setMinigame = coreState.minigame[1];

    return (
        <div className={join(styles, "spin-button-area")}>
            {state[0].data.spins >= minigame.requiredSpins ? (
                total < 0 ? (
                    <p>
                        You have negative funds! <br></br>
                        <br></br>Lower your Adjustable Costs to exit
                    </p>
                ) : hasAdjustableBelowMinimum(minigame, state[0]) !== null ? (
                    <p>{hasAdjustableBelowMinimum(minigame, state[0])}</p>
                ) : (
                    <p>You have no more spins!</p>
                )
            ) : hasAdjustableBelowMinimum(minigame, state[0]) !== null ? (
                <p>{hasAdjustableBelowMinimum(minigame, state[0])}</p>
            ) : total >= 0 ? (
                <p>
                    Spin the wheel{" "}
                    {minigame.requiredSpins - state[0].data.spins} more times!
                </p>
            ) : (
                <p>
                    You have negative funds! <br></br>
                    <br></br>Lower your Adjustable Costs to spin!
                </p>
            )}
            <div className={join(styles, "wheel-buttons-wrap")}>
                <button
                    onClick={spin}
                    disabled={
                        state[0].data.spins >= minigame.requiredSpins ||
                        state[0].data.currentlySpinning ||
                        total < 0 ||
                        hasAdjustableBelowMinimum(minigame, state[0]) !== null
                    }
                >
                    Spin!
                </button>
                <button
                    onClick={() => {
                        setMinigame(null);
                        setPopup(null);
                        StopAllAudio("music");
                        Badges.unlock("minigame:cost_balancer");
                    }}
                    disabled={
                        state[0].data.spins < minigame.requiredSpins ||
                        total < 0
                    }
                >
                    Exit
                </button>
            </div>
            <p className={`total-text ${total < 0 ? "negative-total" : ""}`}>
                Total: <span>${total}</span>
            </p>
        </div>
    );
}

function SpinResult({
    current,
    state,
    total,
}: {
    current: {
        description: string;
        options: { value: number; description: string }[];
    };
    state: ReactState<State>;
    total: number;
}) {
    return (
        <div className={join(styles, "spin-button-area")}>
            <div className={join(styles, "spin-result-desc")}>
                <p>{current.description}</p>
                <p>
                    This will{" "}
                    {`${state[0].data.currentType === "positive" ? "give" : "cost"}`}{" "}
                    you $
                </p>
            </div>

            <div className={join(styles, "wheel-buttons-wrap")}>
                {current.options.map(
                    (option: { value: number; description: string }) => (
                        <button
                            key={option.description}
                            className={join(
                                styles,
                                state[0].data.currentType === "positive"
                                    ? ""
                                    : "negative-total"
                            )}
                            onClick={() => {
                                state[1]((val) => {
                                    const old = structuredClone(val);

                                    if (
                                        old.data.currentKey === null ||
                                        option.value === 0
                                    ) {
                                        old.data.currentKey = null;
                                        return old;
                                    }

                                    const list =
                                        old.data.currentType === "positive"
                                            ? old.data.additionalResources
                                            : old.data.additionalCosts;
                                    list[old.data.currentKey] = option.value;

                                    old.data.currentKey = null;
                                    return old;
                                });
                            }}
                        >
                            <span>
                                {option.description}
                                <br />
                                {`${state[0].data.currentType === "positive" ? "+" : "-"}$${option.value}`}
                            </span>
                        </button>
                    )
                )}
            </div>
            <p
                className={join(
                    styles,
                    `total-text`,
                    total < 0 ? "negative-total" : ""
                )}
            >
                Total: <span>${total}</span>
            </p>
        </div>
    );
}

export const WheelSegment = ({
    startAngle,
    endAngle,
    radius,
    color,
    text,
}: {
    startAngle: number;
    endAngle: number;
    radius: number;
    color: string;
    text: string;
}) => {
    const o = [radius * 1.5, radius * 1.5];

    const a = (startAngle * Math.PI) / 180;
    const b = (endAngle * Math.PI) / 180;

    const midAngle = (startAngle + endAngle) / 2;
    const textAngle = midAngle * (Math.PI / 180);
    const textX = o[0] + radius * 0.65 * Math.sin(textAngle);
    const textY = o[1] - radius * 0.65 * Math.cos(textAngle);
    return (
        <g>
            <path
                d={`
            M ${o[0]} ${o[1]}
            L ${o[0] + radius * Math.sin(a)} ${o[1] + radius * -Math.cos(a)}
            A ${radius} ${radius} 0 0 ${endAngle - startAngle > 180 ? 0 : 1} ${o[0] + radius * Math.sin(b)} ${o[1] + radius * -Math.cos(b)}
            L ${o[0]} ${o[1]}
        `}
                fill={color}
            />
            <text
                x={textX}
                y={textY}
                textAnchor="middle"
                fontSize={10}
                fill={text === "💰" ? "" : "#8A1B04"}
                transform={`rotate(${midAngle}, ${textX}, ${textY})`}
            >
                {text}
            </text>
        </g>
    );
};
