import styles from "#styles/minigames/renderers/CardMinigame.module.css";
import { CSSProperties, useEffect, useRef } from "react";
import { useGlobalState } from "../../../state/GlobalState";
import { SendMinigameEnded } from "engine/src/system/BackendSystem";
import { CardMinigame, Minigame } from "../../../types/Minigame";
import { PlayAudio, StopAllAudio } from "engine/src/system/AudioSystem";
import { join } from "engine/src/system/Styles";
import { ReactState } from "engine/src/state/GlobalState";
import { useKeyDown, useSelectedIndex } from "engine/src/system/Keyboard";
import { dialogClean } from "engine/src/system/Dialog";

type State = {
    type: Minigame["type"];
    data: {
        answered: number[];
        score: number;
        currentQuestion: number;
        cardLocation: null | [number, number];
        dragging: boolean;
        placingCard: boolean;
        hovering: null | "tl" | "tr" | "bl" | "br";
        stage: "question" | "animation" | "answer";
        questions: CardMinigame["questions"];
    };
};

const options: (null | "tl" | "tr" | "bl" | "br")[] = ["tl", "tr", "bl", "br"];

let lockState = false;

const clamp = (value: number, min: number, max: number) => {
    return Math.max(min, Math.min(max, value));
};

export const CardMinigameRenderer = ({
    minigame,
    state,
}: {
    minigame: CardMinigame;
    state: ReactState<State>;
}) => {
    const gState = state[0];

    if (gState.type === "cards" && gState.data.questions.length === 0) {
        state[1]((current) => {
            return {
                ...current,
                data: {
                    ...current.data,
                    questions: minigame.questions
                        .map((value) => ({ value, sort: Math.random() }))
                        .sort((a, b) => a.sort - b.sort)
                        .map(({ value }) => value),
                },
            };
        });
    }

    const sectionMap = [
        {
            title: minigame.top_left.title,
            description: minigame.top_left.description,
        },
        {
            title: minigame.top_right.title,
            description: minigame.top_right.description,
        },
        {
            title: minigame.bottom_left.title,
            description: minigame.bottom_left.description,
        },
        {
            title: minigame.bottom_right.title,
            description: minigame.bottom_right.description,
        },
    ];

    const disabled =
        !gState ||
        gState.type !== "cards" ||
        gState.data.questions.length === 0;

    lockState = false;

    const { coreState, settingsState } = useGlobalState();

    const [, setPopup] = coreState.popup;
    const [, setMinigame] = coreState.minigame;
    const [keybinds] = settingsState.keybinds;

    const [participantSettings] = settingsState.participantSettings;

    const [selectedIndex, setSelectedIndex] = useSelectedIndex(
        options.length + 2,
        keybinds.Urgency_Matrix_Minigame.Next_Cell,
        keybinds.Urgency_Matrix_Minigame.Previous_Cell,
        disabled || gState.data.stage === "answer"
    );

    const refs = [
        useRef<null | HTMLDivElement>(null),
        useRef<null | HTMLDivElement>(null),
        useRef<null | HTMLDivElement>(null),
        useRef<null | HTMLDivElement>(null),
    ];
    const rulesCard = useRef<null | HTMLDivElement>(null);
    const currentCard = useRef<null | HTMLDivElement>(null);
    const answerCard = useRef<null | HTMLDivElement>(null);

    useKeyDown(
        keybinds.General.Back,
        () => {
            if (gState.data.answered.length === gState.data.questions.length) {
                exit();
            }
        },
        gState.data.stage !== "answer"
    );

    useKeyDown(
        keybinds.Minigames.Select,
        () => {
            if (gState.data.stage === "answer") {
                newQuestion();
                return;
            }

            if (selectedIndex === -1 || selectedIndex >= options.length) return;

            const ref = refs[selectedIndex];
            if (ref.current) {
                const elem = ref.current.getBoundingClientRect();

                setCardLocation(
                    elem.left + elem.width / 2,
                    elem.top + elem.height / 2
                );

                state[1]((val) => {
                    lockState = true;
                    return {
                        ...val,
                        data: {
                            ...val.data,
                            hovering: options[selectedIndex],
                            placingCard: true,
                        },
                    };
                });

                setSelectedIndex(-1);
            }
        },
        disabled
    );

    const onReleaseCard = () => {
        if (gState.data.stage !== "question" || lockState) return;

        state[1]((val) => {
            const newState = structuredClone(val);

            newState.data.dragging = false;
            if (newState.data.hovering) {
                newState.data.stage = "animation";
            }
            return newState;
        });

        if (gState.data.hovering) {
            setTimeout(() => {
                state[1]((val) => {
                    const newState = structuredClone(val);

                    newState.data.answered.push(newState.data.answered.length);
                    if (
                        gState.data.questions[newState.data.answered.length - 1]
                            .correct === newState.data.hovering
                    ) {
                        newState.data.score++;
                    }
                    newState.data.stage = "answer";
                    newState.data.dragging = false;
                    return newState;
                });
            }, 500);
        }
    };

    const newQuestion = () => {
        if (gState.data.stage !== "answer") return;

        if (gState.data.answered.length === gState.data.questions.length) {
            exit();
            return;
        }
        state[1]((val) => {
            lockState = true;

            return {
                ...val,
                data: {
                    ...val.data,
                    hovering: null,
                    dragging: false,
                    cardLocation: null,
                    stage: "question",
                },
            };
        });
    };

    const placingCard = gState.data.placingCard;
    useEffect(() => {
        if (placingCard) {
            onReleaseCard();
            state[1]((val) => {
                return {
                    ...val,
                    data: {
                        ...val.data,
                        placingCard: false,
                    },
                };
            });
        }
        // eslint-disable-next-line
    }, [placingCard, state]);

    useEffect(() => {
        if (selectedIndex === options.length) {
            rulesCard.current?.focus();
        } else {
            rulesCard.current?.blur();
        }

        if (selectedIndex === options.length + 1) {
            currentCard.current?.focus();
        } else {
            currentCard.current?.blur();
        }
    }, [selectedIndex]);

    const setCardLocation = (x: number, y: number) => {
        state[1]((val) => {
            const elem = document
                .getElementsByClassName(styles["card-area"])[0]
                .getBoundingClientRect();

            return {
                ...val,
                data: {
                    ...val.data,
                    cardLocation: [
                        clamp(((x - elem.left) / elem.width) * 100, 15, 85),
                        clamp(((y - elem.top) / elem.height) * 100, 15, 85),
                    ],
                },
            };
        });
    };

    const exit = () => {
        setTimeout(() => {
            setMinigame(null);
            setPopup(null);
            SendMinigameEnded(minigame.type, coreState.appEnabled[1]);
            StopAllAudio("music");
            PlayAudio("minigame-click.mp3", "sounds");
        }, 1);
    };

    useEffect(() => {
        if (
            !(
                gState.data.stage === "question" ||
                gState.data.stage === "animation"
            )
        ) {
            answerCard.current?.focus();
        }
    }, [gState.data.stage]);

    if (disabled) return <></>;

    return (
        <div className={join(styles, "cards-minigame")}>
            <div className={join(styles, "overlay")}>
                <div className={join(styles, "info-card")} ref={rulesCard}>
                    <h1>{minigame.instruction.title}</h1>
                    <p
                        dangerouslySetInnerHTML={{
                            __html: dialogClean(
                                participantSettings.EnableKbControls
                                    ? minigame.instruction.content
                                    : minigame.instruction.content_no_kb
                            ),
                        }}
                    />
                </div>
                <ProgressCard state={gState} minigame={minigame} />
            </div>
            <div
                className={join(styles, "card-area")}
                onMouseMove={(e) => {
                    if (gState.data.dragging) {
                        if (lockState) return;
                        setCardLocation(e.clientX, e.clientY);
                    }
                }}
                onMouseUp={onReleaseCard}
                onMouseLeave={() => {
                    state[1]((val) => {
                        return {
                            ...val,
                            data: {
                                ...val.data,
                                dragging: false,
                            },
                        };
                    });
                }}
            >
                <div
                    className={join(styles, "category-renderer")}
                    onMouseLeave={() => {
                        if (!gState.data.dragging) return;
                        state[1]((val) => {
                            return {
                                ...val,
                                data: {
                                    ...val.data,
                                    hovering: null,
                                },
                            };
                        });
                    }}
                >
                    {[0, 1, 2, 3].map((option) => {
                        return (
                            <div
                                key={option}
                                className={
                                    option === selectedIndex
                                        ? join(styles, "selected")
                                        : ""
                                }
                                onMouseEnter={() => {
                                    if (!gState.data.dragging) return;
                                    state[1]((val) => {
                                        lockState = true;
                                        return {
                                            ...val,
                                            data: {
                                                ...val.data,
                                                hovering: options[option],
                                            },
                                        };
                                    });
                                }}
                                ref={refs[option]}
                            >
                                <h1>{sectionMap[option].title}</h1>
                                <p>{sectionMap[option].description}</p>
                            </div>
                        );
                    })}
                </div>
                <div className={join(styles, "labels")}>
                    <div className={join(styles, "left")}>
                        <p>{minigame.left_labels[0]}</p>
                        <p>{minigame.left_labels[1]}</p>
                    </div>
                    <div className={join(styles, "top")}>
                        <p>{minigame.top_labels[0]}</p>
                        <p>{minigame.top_labels[1]}</p>
                    </div>
                </div>
                <div
                    className={join(
                        styles,
                        `card-pile`,
                        gState.data.stage === "answer" ? "hint" : ""
                    )}
                    onMouseDown={newQuestion}
                >
                    {gState.data.questions
                        .filter(
                            (_, i) =>
                                i > gState.data.answered.length ||
                                (gState.data.stage === "answer" &&
                                    i >= gState.data.answered.length)
                        )
                        .map((_, i, l) => (
                            <div
                                key={i}
                                className={join(styles, "facedown-card")}
                                style={
                                    { "--index": l.length - i } as CSSProperties
                                }
                            />
                        ))}
                    {gState.data.stage === "answer" && (
                        <p>
                            {dialogClean(
                                participantSettings.EnableKbControls
                                    ? "Click here or press %key:general:back% to Exit"
                                    : "Click here to Exit"
                            )}
                        </p>
                    )}
                </div>
                <div className={join(styles, "current-card-spawn")} />
                {gState.data.stage === "question" ||
                gState.data.stage === "animation" ? (
                    <div
                        ref={currentCard}
                        className={join(
                            styles,
                            `current-card`,
                            gState.data.dragging ? "dragging" : "",
                            gState.data.stage === "animation" ? "flip" : ""
                        )}
                        style={
                            gState.data.cardLocation !== null
                                ? {
                                      left: gState.data.cardLocation[0] + "%",
                                      top: gState.data.cardLocation[1] + "%",
                                      transform: "translate(-50%, -50%)",
                                  }
                                : {}
                        }
                        onMouseDown={() => {
                            state[1]((val) => {
                                return {
                                    ...val,
                                    data: {
                                        ...val.data,
                                        dragging: true,
                                    },
                                };
                            });
                        }}
                    >
                        <h1>Question {gState.data.answered.length + 1}</h1>
                        <p>
                            {
                                gState.data.questions[
                                    gState.data.answered.length
                                ].question
                            }
                        </p>
                    </div>
                ) : (
                    <div
                        className={join(styles, `answer-card`)}
                        ref={answerCard}
                        style={
                            gState.data.cardLocation !== null
                                ? {
                                      left: gState.data.cardLocation[0] + "%",
                                      top: gState.data.cardLocation[1] + "%",
                                      transform: "translate(-50%, -50%)",
                                  }
                                : {}
                        }
                    >
                        <h1>Question {gState.data.answered.length}</h1>
                        <p>
                            {gState.data.questions[
                                gState.data.answered.length - 1
                            ].correct === gState.data.hovering
                                ? "Correct!"
                                : "Incorrect!"}
                        </p>
                        <p>
                            {
                                gState.data.questions[
                                    gState.data.answered.length - 1
                                ].explaination
                            }
                        </p>
                    </div>
                )}
            </div>
        </div>
    );
};

const ProgressCard = ({
    state,
    minigame,
}: {
    state: State;
    minigame: CardMinigame;
}) => {
    return (
        <div className={join(styles, "progress-card")}>
            <h1>Minigame Progress</h1>
            <p>
                <b>Questions:</b> {state.data.answered.length}/
                {state.data.questions.length}
            </p>
            <p>
                <b>Score:</b> {state.data.score * 100}
            </p>
        </div>
    );
};
