import styles from "#styles/minigames/renderers/QuizMinigame.module.css";
import { ReactState } from "engine/src/state/GlobalState";
import { useGlobalState } from "../../../state/GlobalState";
import { join } from "engine/src/system/Styles";
import { Badges } from "../../../system/Unlockables";
import { Minigame, QuizMinigame } from "../../../types/Minigame";
import { StopAllAudio } from "engine/src/system/AudioSystem";

type State = {
    type: Minigame["type"];
    data: [number, number];
};

export const QuizMinigameRenderer = ({
    minigame,
    state,
}: {
    minigame: QuizMinigame;
    state: ReactState<State>;
}) => {
    const { coreState } = useGlobalState();
    const setPopup = coreState.popup[1];

    const setMinigame = coreState.minigame[1];
    if (!state[0] || state[0].type !== "quiz") return <></>;

    const [question, incorrectCount] = state[0].data;
    const setQuestion = (question: number) => {
        state[1]({
            type: "quiz",
            data: [question, state[0].data[1]],
        });
    };
    const setIncorrectCount = (count: number) => {
        state[1]({
            type: "quiz",
            data: [state[0].data[0], count],
        });
    };

    const handle_continue = () => {
        const buttons = Array.from(
            document.getElementsByClassName("quiz-choice")
        );
        buttons.forEach((button) => {
            button.classList.remove(styles.correct);
            button.classList.remove(styles.incorrect);
        });

        (document.getElementById("quiz-reasoning") as HTMLElement).innerText =
            "";
        (document.getElementById("continue") as HTMLButtonElement).disabled =
            true;

        if (question + 1 >= minigame.questions.length) {
            setQuestion(question + 1);
            setMinigame(null);
            setPopup(null);
            StopAllAudio("music");
            if (incorrectCount === 0) Badges.unlock("minigame:flawless");
            return;
        }
        setQuestion(question + 1);
    };

    const handle_submit = (index: number) => {
        const reason = document.getElementById("quiz-reasoning") as HTMLElement;
        const button = document.getElementById(
            `quiz-choice-${index}`
        ) as HTMLButtonElement;
        const continueBtn = document.getElementById(
            `continue`
        ) as HTMLButtonElement;

        reason.innerText = minigame.questions[question].choices[index].reason;

        if (minigame.questions[question].choices[index].correct) {
            button.classList.add(styles.correct);
            continueBtn.disabled = false;
            continueBtn.onclick = handle_continue;
        } else {
            button.classList.add(styles.incorrect);
            setIncorrectCount(incorrectCount + 1);
        }
    };

    if (minigame && question >= minigame.questions.length) {
        setMinigame(null);
        setPopup(null);
        return <></>;
    }

    return (
        <div className={join(styles, "quiz-wrapper")}>
            <div
                className={join(styles, "quiz-avatar")}
                style={{
                    backgroundImage: `url(assets/images/characters/${minigame.avatar}.png)`,
                }}
            ></div>
            <div className={join(styles, "quiz")}>
                <h1>Pop Quiz!</h1>
                <h2>
                    Q{question + 1}.{" "}
                    <b>{minigame.questions[question].question}</b>
                </h2>
                <i id="quiz-reasoning"></i>
                <section className={join(styles, "choices")}>
                    {minigame.questions[question].choices.map(
                        (choice, index) => (
                            <button
                                className={join(styles, "quiz-choice")}
                                key={index}
                                id={`quiz-choice-${index}`}
                                onClick={() => handle_submit(index)}
                            >
                                {choice.text}
                            </button>
                        )
                    )}
                </section>
                <button
                    id="continue"
                    disabled={true}
                    onClick={() => handle_continue()}
                >
                    Continue
                </button>
            </div>
        </div>
    );
};
