import { generatePopupRegistry } from "engine/src/components/Popup";
import { activityRegistry } from "./ActivityRegistry";
import { minigameRegistry } from "./MinigameRegistry";
import CharacterCreator from "./popup/CharacterCreator";
import Controls from "./popup/Controls";
import Preamble from "./popup/Preamble";
import CreditsComponent from "./popup/Credits";
import DocumentPopup from "./popup/Document";
import EndGame from "./popup/Endgame";
import MinigameSelectorComponent from "./popup/MinigameSelector";
import { NewChapter } from "./popup/NewChapter";
import { SaveGame } from "./popup/SaveGame";
import TitleScreen from "./popup/TitleScreen";
import ZoomPopup from "./popup/Zoom";

const NewChapterWrapper = () => {
    return <NewChapter allowContinue={true} />;
};

const PauseChapterWrapper = () => {
    return <NewChapter allowContinue={false} />;
};

export const createPopupRegistry = (
    activityStyleOverride?: any,
    minigameStyleOverride?: any,
    documentStyleOverride?: any
) => {
    return generatePopupRegistry(
        activityRegistry,
        minigameRegistry,
        (registry) => {
            const customPopups = {
                characterCreator: {
                    element: CharacterCreator,
                    keepAudio: true,
                },
                controls: {
                    element: Controls,
                    keepAudio: true,
                },
                credits: {
                    element: CreditsComponent,
                    keepAudio: true,
                },
                newChapter: {
                    element: NewChapterWrapper,
                    keepAudio: false,
                },
                pauseChapter: {
                    element: PauseChapterWrapper,
                    keepAudio: false,
                },
                titleScreen: {
                    element: TitleScreen,
                    keepAudio: true,
                },
                endgame: {
                    element: EndGame,
                    keepAudio: false,
                },
                document: {
                    element: DocumentPopup,
                    keepAudio: true,
                },
                minigameSelector: {
                    element: MinigameSelectorComponent,
                    keepAudio: true,
                },
                zoom: {
                    element: ZoomPopup,
                    keepAudio: false,
                },
                saveGame: {
                    element: SaveGame,
                    keepAudio: false,
                },
                preamble: {
                    element: Preamble,
                    keepAudio: true,
                },
            };

            return {
                ...registry,
                ...customPopups,
            };
        },
        documentStyleOverride,
        activityStyleOverride,
        minigameStyleOverride
    );
};
