import { ChangeEvent, useEffect, useRef, useState } from "react";
import { GlobalState, useGlobalState } from "../../state/GlobalState";
import styles from "#styles/popup/TitleScreen.module.css";
import sceneStyles from "#styles/Scene.module.css";
import { LoadScene } from "engine/src/system/DataLoader";
import {
    importSave,
    loadGame,
    saveSettings,
} from "engine/src/system/SaveSystem";
import { join } from "engine/src/system/Styles";
import { Scene } from "engine/src/types/Scene";
import { PlayAudio } from "engine/src/system/AudioSystem";
import { setParticipantFlags } from "engine/src/ParticipantSettings";
import { keyDownHandler } from "engine/src/system/Keyboard";
import { SwitchSceneInstant } from "engine/src/system/SceneSwitcher";

const has_save = () => window.localStorage.getItem("game-state") !== null;

/**
 * The titlescreen popup
 */
const TitleScreen = () => {
    const { settingsState, coreState } = useGlobalState();

    const [popup] = coreState.popup;

    const [keybinds] = settingsState.keybinds;

    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        PlayAudio(`music/main-menu.mp3`, "music", true);

        document
            .getElementById("scene")
            ?.classList.remove(sceneStyles["fade-out"]);
        document.getElementById("scene")?.classList.add(sceneStyles["fade-in"]);
    }, [popup]);

    useEffect(() => {
        // TODO: Add this back
        saveSettings();
        setParticipantFlags(settingsState.participantSettings[0]);
        // eslint-disable-next-line
    }, []);

    // Function to handle clicking the new game button
    function handle_newGame() {
        // Load the game
        document
            .getElementById("scene")
            ?.classList.remove(sceneStyles["fade-in"]);
        document
            .getElementById("title-screen")
            ?.classList.remove(styles["fade-in"]);
        document
            .getElementById("title-screen")
            ?.classList.add(styles["fade-out"]);
        document
            .getElementById("scene")
            ?.classList.add(sceneStyles["fade-out"]);
        setTimeout(() => {
            //Set the popup to the character creator
            coreState.popup[1]("characterCreator");
            // Load the student_room scene
            LoadScene("home/room").then((scene: Scene) => {
                SwitchSceneInstant(scene, coreState);
            });
        }, 750);
    }

    // Function to handle clicking the load game button
    function handle_loadGame() {
        if (!has_save()) return;

        document
            .getElementById("scene")
            ?.classList.remove(sceneStyles["fade-in"]);
        document
            .getElementById("title-screen")
            ?.classList.remove(styles["fade-in"]);
        document
            .getElementById("title-screen")
            ?.classList.add(styles["fade-out"]);
        document
            .getElementById("scene")
            ?.classList.add(sceneStyles["fade-out"]);
        setTimeout(() => {
            loadGame(GlobalState.getInstance());
        }, 750);
    }

    // Function to handle clicking the import save button
    function handle_importSave(e: ChangeEvent<HTMLInputElement>) {
        // Import the save
        document
            .getElementById("scene")
            ?.classList.remove(sceneStyles["fade-in"]);
        document
            .getElementById("title-screen")
            ?.classList.remove(styles["fade-in"]);
        document
            .getElementById("title-screen")
            ?.classList.add(styles["fade-out"]);
        document
            .getElementById("scene")
            ?.classList.add(sceneStyles["fade-out"]);
        setTimeout(() => {
            importSave(GlobalState.getInstance(), e);
        }, 750);
    }

    // Function to handle clicking hte credits button
    function handle_credits() {
        // Import the save
        document
            .getElementById("scene")
            ?.classList.remove(sceneStyles["fade-in"]);
        document
            .getElementById("title-screen")
            ?.classList.remove(styles["fade-in"]);
        document
            .getElementById("title-screen")
            ?.classList.add(styles["fade-out"]);
        document
            .getElementById("scene")
            ?.classList.add(sceneStyles["fade-out"]);
        setTimeout(() => {
            coreState.popup[1]("credits");
        }, 750);
    }

    const mouseMove = (e: React.MouseEvent<HTMLImageElement>) => {
        const currentX = e.clientX / e.currentTarget.clientWidth;
        const currentY = e.clientY / e.currentTarget.clientHeight;
        document.body.style.setProperty("--move-x", currentX + "px");
        document.body.style.setProperty("--move-y", currentY + "px");
    };

    // Return the rendered title screen
    return (
        <div
            className={join(styles, "title-screen-wrapper")}
            onMouseMove={mouseMove}
        >
            <div
                id="title-screen"
                className={join(styles, "title-screen-background", "fade-in")}
            >
                <div className={join(styles, "title-screen")}>
                    <div className={styles.logo}>
                        <img
                            src="assets/images/elements/Logo.png"
                            alt="logo"
                            draggable={false}
                        />
                    </div>
                    <h2>GEARS</h2>
                    <img
                        alt="new game"
                        src="assets/images/elements/start-button.png"
                        tabIndex={1}
                        onClick={handle_newGame}
                        onKeyDown={keyDownHandler(
                            keybinds.General.Select,
                            handle_newGame
                        )}
                    />
                    <img
                        alt="load game"
                        className={join(styles, has_save() || "disabled")}
                        src="assets/images/elements/load-game-button.png"
                        onClick={handle_loadGame}
                        onKeyDown={keyDownHandler(
                            keybinds.General.Select,
                            handle_loadGame
                        )}
                        tabIndex={2}
                    />
                    <input
                        id="import"
                        type="file"
                        accept=".save"
                        onChange={handle_importSave}
                        ref={fileInputRef}
                    />
                    <label htmlFor="import">
                        <img
                            tabIndex={3}
                            alt="import button"
                            src="assets/images/elements/import-button.png"
                            onKeyDown={keyDownHandler(
                                keybinds.General.Select,
                                () => {
                                    fileInputRef.current?.click();
                                }
                            )}
                        />
                    </label>
                    <img
                        alt="credits button"
                        src="assets/images/elements/credits-button.png"
                        tabIndex={4}
                        onClick={handle_credits}
                        onKeyDown={keyDownHandler(
                            keybinds.General.Select,
                            handle_credits
                        )}
                    />
                </div>
            </div>
            <div className={join(styles, "info-section")}>
                <Version />
                <a
                    onClick={() => {
                        delete_cookie("user");
                        delete_cookie("password");
                    }}
                    href="/"
                >
                    logout
                </a>
            </div>
        </div>
    );
};

function delete_cookie(name: string) {
    if (get_cookie(name)) {
        document.cookie = name + "=;expires=Thu, 01 Jan 1970 00:00:01 GMT";
    }
}

function get_cookie(name: string) {
    return document.cookie.split(";").some((c) => {
        return c.trim().startsWith(name + "=");
    });
}

type DevVersion = {
    type: "dev";
    gitBranch: string;
    gitCommitHash: string;
};

type ReleaseVersion = {
    type: "v";
    version: string;
};

const Version = () => {
    const [type, setType] = useState<string | null>(null);
    const [versionString, setVersionString] = useState<string>("");

    if (type === null || type === "dev") {
        fetch("version_info.json").then(async (value) => {
            const data = (await value.json()) as DevVersion | ReleaseVersion;
            setType(data.type);

            if (data.type === "dev") {
                setVersionString(
                    `dev-${data.gitCommitHash} (${data.gitBranch})`
                );
            } else {
                setVersionString(`v${data.version}`);
            }
        });
    }

    return <p>{versionString}</p>;
};

export default TitleScreen;
